window.HADITH_CACHE["ibnu-majah_6"] = {"3001":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنَا ابْنُ إِسْحَقَ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقِيلَ يَا رَسُولَ اللَّهِ لِمَ ظَاهَرْتَ لِلْمُحَلِّقِينَ ثَلَاثًا وَلِلْمُقَصِّرِينَ وَاحِدَةً قَالَ إِنَّهُمْ لَمْ يَشُكُّوا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Yunus bin Bukair]; telah menceritakan kepada kami [Ibnu Ishaq]; telah menceritakan kepada kami [Ibnu Najid] dari [Mujahid] dari [Ibnu Abbas] berkata; dikatakan pada Rasulullah shallallahu 'alaihi wasallam; Kenapa engkau mendo'akan untuk muhalliqin (yang mencukur) sebanyak tiga kali sedangkan untuk muqasshirin (yang memendekan) hanya sekali?\" Beliau bersabda: 'Sesungguhnya mereka adalah orang-orang yang tidak ragu (untuk mencontoh Nabi shallallahu 'alaihi wasallam).'"},"3002":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ حَفْصَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ مَا شَأْنُ النَّاسِ حَلُّوا وَلَمْ تَحِلَّ أَنْتَ مِنْ عُمْرَتِكَ قَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَا أَحِلُّ حَتَّى أَنْحَرَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Abu Usamah] dari [Ubaidillah bin Umar] dari [Nafi'] dari [Ibnu Umar]; Bahwasanya Hafshah, istri Nabi shallallahu 'alaihi wasallam berkata; \"Aku bertanya; 'Wahai Rasulullah, mengapa orang-orang sudah bertahallul, sedangkan engkau belum juga bertahallul dari umrahmu? ' Beliau menjawab: 'Sesungguhnya aku telah mengempalkan rambut kepalaku dan menggantungkan hewan kurbanku, maka aku tidak akan bertahallul sebelum kusembelih hewan kurban'.\""},"3003":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ مُلَبِّدًا","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh Al Mishri]; telah memberitakan kepada kami [Abdullah bin Wahab]; telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Salim] dari [Ayahnya], ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bertalbiyah sambil mengepang rambut kepalanya.\""},"3004":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنًى كُلُّهَا مَنْحَرٌ وَكُلُّ فِجَاجِ مَكَّةَ طَرِيقٌ وَمَنْحَرٌ وَكُلُّ عَرَفَةَ مَوْقِفٌ وَكُلُّ الْمُزْدَلِفَةِ مَوْقِفٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Usamah bin Zaid] dari [Atha`] dari [Jabir] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Mina seluruhnya adalah tempat penyembelihan, dan seluruh pelosok kota Makkah adalah jalan dan tempat penyembelihan. Seluruh Arafah adalah tempat wukuf, dan seluruh Muzdalifah adalah tempat wukuf.\""},"3005":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَمَا سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّنْ قَدَّمَ شَيْئًا قَبْلَ شَيْءٍ إِلَّا يُلْقِي بِيَدَيْهِ كِلْتَيْهِمَا لَا حَرَجَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam ditanya tentang orang yang mendahulukan sesuatu, (dari rukun haji) sebelum mengerjakan rukun lainnya, kecuali beliau akan menggerakan kedua tangannya, sambil bersabda: 'Tidak mengapa.'"},"3006":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْأَلُ يَوْمَ مِنًى فَيَقُولُ لَا حَرَجَ لَا حَرَجَ فَأَتَاهُ رَجُلٌ فَقَالَ حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ لَا حَرَجَ قَالَ رَمَيْتُ بَعْدَ مَا أَمْسَيْتُ قَالَ لَا حَرَجَ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakar bin Khalaf]; telah menceritakan kepada kami [Yazid bin Zura'i] dari [Khalid Al Hadzdza`] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pada hari Mina ditanya, maka beliau menjawab: 'Tidak mengapa, tidak mengapa.' Maka seorang lelaki mendatangi beliau seraya bertanya: 'Aku telah mencukur sebelum menyembelih.' Beliau menjawab: 'Tidak mengapa.' Lalu lelaki itu bertanya lagi; 'Aku telah melontar setelah sore hari.' Beliau menjawab: 'Tidak mengapa.'"},"3007":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَمَّنْ ذَبَحَ قَبْلَ أَنْ يَحْلِقَ أَوْ حَلَقَ قَبْلَ أَنْ يَذْبَحَ قَالَ لَا حَرَجَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Isa bin Thalhah] dari [Abdullah bin 'Amru] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam ditanya tentang (hukum) siapa saja yang menyembelih sebelum mencukur rambut atau mencukur sebelum menyembelih, maka beliau menjawab: \"Tidak mengapa.\""},"3008":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُقَعَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى يَوْمَ النَّحْرِ لِلنَّاسِ فَجَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ لَا حَرَجَ ثُمَّ جَاءَهُ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي نَحَرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ لَا حَرَجَ فَمَا سُئِلَ يَوْمَئِذٍ عَنْ شَيْءٍ قُدِّمَ قَبْلَ شَيْءٍ إِلَّا قَالَ لَا حَرَجَ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Mishri]; telah menceritakan kepada kami [Abdullah bin Wahab]; telah mengkabarkan kepadaku [Usamah bin Zaid]; telah menceritakan kepadaku [Atha` bin Abu Rabah] dari [Jabir bin Abdullah] radliallahu 'anhu, ia berkata; \"Rasulullah duduk di hadapan orang-orang di Mina saat 'Ied Adha, lalu seorang laki-laki datang kepadanya seraya berkata; 'Wahai Rasulullah, aku telah mencukur rambut sebelum menyembelih. Beliau bersabda: 'Tidak mengapa.' Kemudian datang lelaki lain dan berkata; 'Wahai Rasulullah, aku telah menyembelih sebelum melontar jumrah.' Beliaupun menjawab: 'Tidak mengapa.' Pada hari itu tidaklah beliau ditanya tentang mendahulukan sesuatu (rukun haji) dari lainnya, kecuali beliau akan menjawab: 'Tidak mengapa'.\""},"3009":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى جَمْرَةَ الْعَقَبَةِ ضُحًى وَأَمَّا بَعْدَ ذَلِكَ فَبَعْدَ زَوَالِ الشَّمْسِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya Al Mishri]; telah menceritakan kepada kami [Abdullah bin Wahab]; telah menceritakan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] radliallahu 'anhu, ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam melontar jumrah Aqabah pada waktu Dluha. Sedangkan melontar selanjutnya (beliau lakukan) setelah tergelincirnya matahari.\""},"3010":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُثْمَانَ بْنِ أَبِي شَيْبَةَ أَبُو شَيْبَةَ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْمِي الْجِمَارَ إِذَا زَالَتْ الشَّمْسُ قَدْرَ مَا إِذَا فَرَغَ مِنْ رَمْيِهِ صَلَّى الظُّهْرَ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallas]; telah menceritakan kepada kami [Ibrahim bin Utsman bin Abu Syaibah Abu Syaibah] dari [Al Hakam] dari [Miqsam] dari [Ibnu 'Abbas]; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melempar jumrah apabila matahari telah condong sedikit, apabila selesai dari melemparnya beliau shalat zhuhur."},"3011":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي حَجَّةِ الْوَدَاعِ يَا أَيُّهَا النَّاسُ أَلَا أَيُّ يَوْمٍ أَحْرَمُ ثَلَاثَ مَرَّاتٍ قَالُوا يَوْمُ الْحَجِّ الْأَكْبَرِ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ بَيْنَكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا لَا يَجْنِي جَانٍ إِلَّا عَلَى نَفْسِهِ وَلَا يَجْنِي وَالِدٌ عَلَى وَلَدِهِ وَلَا مَوْلُودٌ عَلَى وَالِدِهِ أَلَا إِنَّ الشَّيْطَانَ قَدْ أَيِسَ أَنْ يُعْبَدَ فِي بَلَدِكُمْ هَذَا أَبَدًا وَلَكِنْ سَيَكُونُ لَهُ طَاعَةٌ فِي بَعْضِ مَا تَحْتَقِرُونَ مِنْ أَعْمَالِكُمْ فَيَرْضَى بِهَا أَلَا وَكُلُّ دَمٍ مِنْ دِمَاءِ الْجَاهِلِيَّةِ مَوْضُوعٌ وَأَوَّلُ مَا أَضَعُ مِنْهَا دَمُ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ كَانَ مُسْتَرْضِعًا فِي بَنِي لَيْثٍ فَقَتَلَتْهُ هُذَيْلٌ أَلَا وَإِنَّ كُلَّ رِبًا مِنْ رِبَا الْجَاهِلِيَّةِ مَوْضُوعٌ لَكُمْ رُءُوسُ أَمْوَالِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ أَلَا يَا أُمَّتَاهُ هَلْ بَلَّغْتُ ثَلَاثَ مَرَّاتٍ قَالُوا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Hannad bin As Sari], keduanya mengatakan; telah menceritakan kepada kami [Abul Ahwash] dari [Syabib bin Gharqadah] dari [Sulaiman bin Amru bin Al Ahwash] dari [Ayahnya], ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada haji Wada': 'Wahai manusia sekalian, hari apa yang paling dihormati (haram)? ' Beliau mengulang ucapannya tiga kali. Mereka (orang-orang) menjawab; 'Pada hari haji Akbar.' Beliau bersabda: 'Sesungguhnya darah, harta dan kehormatan kalian haram diantara kalian, seperti haramnya hari kalian ini, pada bulan kalian ini dan negeri kalian ini. Ingatlah! Tidaklah seorang berbuat (kemaksiatan) kecuali atas dirinya sendiri, maka janganlah orang tua menzhalimi anaknya. Ingatlah! Sesungguhnya syaitan telah berputus asa untuk disembah di negeri kalian ini selamanya. Tetapi ia akan mendapatkan ketaatan pada sebagian amal perbuatan yang kalian hinakan, sehingga ia (setan) ridla dengannya. Ingatlah! Bahwa setiap darah dari darah (yang dicecerkan) Jahiliyyah itu dihinakan, dan darah yang pertama aku hinakan adalah darah Harits bin Abdul muththalib (seseorang yang dulu mencari wanita menyusui dari kalangan bani Laits, lalu ia dibunuh oleh kaum Huzail). Ketahuilah bahwa setiap riba dari riba Jahiliyyah itu dihinakan. Bagi kalian adalah harta pokok kalian, selama kalian tidak menzhalimi dan tidak dizhalimi. Ingatlah! Wahai umatku. Apakah aku telah menyampaikannya? ' Beliau mengulang pertanyaannya tiga kali. Orang-orangpun menjawab; 'Ya'. Lalu beliau bersabda: 'Ya Allah saksikanlah.' Beliau mengulang ucapannya ini tiga kali.\""},"3012":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ السَّلَامِ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْخَيْفِ مِنْ مِنًى فَقَالَ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مَقَالَتِي فَبَلَّغَهَا فَرُبَّ حَامِلِ فِقْهٍ غَيْرُ فَقِيهٍ وَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ ثَلَاثٌ لَا يُغِلُّ عَلَيْهِنَّ قَلْبُ مُؤْمِنٍ إِخْلَاصُ الْعَمَلِ لِلَّهِ وَالنَّصِيحَةُ لِوُلَاةِ الْمُسْلِمِينَ وَلُزُومُ جَمَاعَتِهِمْ فَإِنَّ دَعْوَتَهُمْ تُحِيطُ مِنْ وَرَائِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair]; telah menceritakan kepada kami [Ayahku] dari [Muhammad bin Ishaq] dari [Abdussalam] dari [Az Zuhri] dari [Muhammad Jubair bin Muth'im] dari [Bapaknya], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berdiri di kaki bukit Mina seraya bersabda: 'Semoga Allah menyenangkan seseorang yang mendengarkan perkataanku lalu menyampaikannya. Berapa banyak orang yang membawa berita ilmu tetapi ia bukanlah orang yang berilmu, dan beberapa banyak orang yang membawa ilmu kepada orang yang lebih berilmu darinya.' Tiga perkara dimana hati orang beriman tidak akan berkhianat kepadanya: mengikhlaskan perbuatannya hanya karena Allah, memberi nasehat kepada penguasa kaum muslimin dan bergabung dengan jama'ah (kelompok) mereka. Karena doa mereka akan selalu menyelimuti (meliputi) dibelakang mereka.\""},"3013":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ تَوْبَةَ حَدَّثَنَا زَافِرُ بْنُ سُلَيْمَانَ عَنْ أَبِي سِنَانٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى نَاقَتِهِ الْمُخَضْرَمَةِ بِعَرَفَاتٍ فَقَالَ أَتَدْرُونَ أَيُّ يَوْمٍ هَذَا وَأَيُّ شَهْرٍ هَذَا وَأَيُّ بَلَدٍ هَذَا قَالُوا هَذَا بَلَدٌ حَرَامٌ وَشَهْرٌ حَرَامٌ وَيَوْمٌ حَرَامٌ قَالَ أَلَا وَإِنَّ أَمْوَالَكُمْ وَدِمَاءَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا فِي يَوْمِكُمْ هَذَا أَلَا وَإِنِّي فَرَطُكُمْ عَلَى الْحَوْضِ وَأُكَاثِرُ بِكُمْ الْأُمَمَ فَلَا تُسَوِّدُوا وَجْهِي أَلَا وَإِنِّي مُسْتَنْقِذٌ أُنَاسًا وَمُسْتَنْقَذٌ مِنِّي أُنَاسٌ فَأَقُولُ يَا رَبِّ أُصَيْحَابِي فَيَقُولُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ","id":"Telah menceritakan kepada kami [Isma'il bin Taubah]; telah menceritakan kepada kami [Zafir bin Sulaiman] dari [Abu Sinan] dari [Amru bin Murrah] dari [Murrah] dari [Abdullah bin Mas'ud] radliallahu 'anhu, ia berkata; \"Rasulullah bersabda saat di Arafah ketika berada di atas untanya yang terpotong ujung telinganya: 'Tahukah kalian hari apakah ini? Bulan apakah ini? Dan negeri apakah ini? ' Mereka menjawab; 'Ini adalah negeri haram, bulan haram, dan hari haram.' Beliau bersabda: 'Ingatlah! Sesungguhnya harta dan darah kalian diharamkan atas kalian, seperti keharaman bulan kalian ini, di negeri kalian ini, dan pada hari kalian ini. Ingatlah! Sesungguhnya aku orang yang mendahului kalian di telaga surga, dan aku akan memperbanyak umat dengan kalian, maka janganlah kalian mencoreng wajahku. Ingatlah! Sesungguhnya aku adalah orang yang menyelamatkan manusia, dan mereka akan meminta bantuan keselamatan dariku.' Aku berkata kepada tuhanku: 'Wahai Tuhan, bagaimana dengan para sahabatku? ' Allah menjawab: 'Sesungguhnya kamu tidak tahu apa yang mereka perbuat (ada-adakan) setelah kamu tiada'.\""},"3014":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا هِشَامُ بْنُ الْغَازِ قَالَ سَمِعْتُ نَافِعًا يُحَدِّثُ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ يَوْمَ النَّحْرِ بَيْنَ الْجَمَرَاتِ فِي الْحَجَّةِ الَّتِي حَجَّ فِيهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ يَوْمٍ هَذَا قَالُوا يَوْمُ النَّحْرِ قَالَ فَأَيُّ بَلَدٍ هَذَا قَالُوا هَذَا بَلَدُ اللَّهِ الْحَرَامُ قَالَ فَأَيُّ شَهْرٍ هَذَا قَالُوا شَهْرُ اللَّهِ الْحَرَامُ قَالَ هَذَا يَوْمُ الْحَجِّ الْأَكْبَرِ وَدِمَاؤُكُمْ وَأَمْوَالُكُمْ وَأَعْرَاضُكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ هَذَا الْبَلَدِ فِي هَذَا الشَّهْرِ فِي هَذَا الْيَوْمِ ثُمَّ قَالَ هَلْ بَلَّغْتُ قَالُوا نَعَمْ فَطَفِقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اشْهَدْ ثُمَّ وَدَّعَ النَّاسَ فَقَالُوا هَذِهِ حَجَّةُ الْوَدَاعِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Shadaqah bin Khalid]; telah menceritakan kepada kami [Hisyam bin Al Ghaz] berkata; Aku mendengar [Nafi'] menceritakan dari [Ibnu Umar] radliallahu 'anhu, bahwa pada waktu haji, Rasulullah shallallahu 'alaihi wasallam melakukan wukuf diantara jamarat pada hari 'Ied Adha. Lantas beliau bersabda: \"Hari apakah ini?\" Para sahabat menjawab; 'Hari Nahr ('Ied Adha).' Lalu beliau kembali bertanya: 'Negeri apakah ini? ' Mereka menjawab; 'Ini adalah negeri Allah yang haram.' Kemudian beliau bertanya lagi: 'Bulan apakah ini? ' Mereka menjawab bulan Allah yang haram.' Kemudian beliau bersabda: 'Ini adalah haji Akbar. Darah, harta dan kehormatan kalian adalah haram atas diri kalian, seperti keharaman negeri ini, pada bulan ini, dan hari ini.' Kemudian beliau bertanya: 'Apakah aku telah menyampaikannya? ' Mereka menjawab; 'Ya'. Nabi shallallahu 'alaihi wasallam lantas bersabda: 'Ya Allah saksikanlah.' Kemudian beliau menyampaikan salam perpisahan kepada semua orang. Hingga mereka menyebutnya 'Ini adalah haji Wada'.\""},"3015":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي مُحَمَّدُ بْنُ طَارِقٍ عَنْ طَاوُسٍ وَأَبِي الزُّبَيْرِ عَنْ عَائِشَةَ وَابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَّرَ طَوَافَ الزِّيَارَةِ إِلَى اللَّيْلِ","id":"Telah menceritakan kepada kami [Bakar bin Khalaf Abu Bisyr]; telah menceritakan kepada kami [Yahya bin Sa'id]; telah menceritakan kepada kami [Sufyan]; telah menceritakan kepadaku [Muhammad bin Thariq] dari [Thawush] dan [Abu Zubair] dari [Aisyah] dan [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam mengakhirkan thawaf ziyarah hingga malam hari."},"3016":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ وَهْبٍ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَرْمُلْ فِي السَّبْعِ الَّذِي أَفَاضَ فِيهِ قَالَ عَطَاءٌ وَلَا رَمَلَ فِيهِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya]; telah menceritakan kepada kami [Ibnu Wahab]; telah memberitakan kepada kami [Ibnu Juraij] dari [Atha`] dari [Abdullah bin Abbas] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam belum pernah berlari kecil pada tujuh putaran dalam thawaf Ifadhah. 'Atha berkata; \"Dan beliau tidak pernah berlari kecil dalam thawaf itu.\""},"3017":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ قَالَكُنْتُ عِنْدَ ابْنِ عَبَّاسٍ جَالِسًا فَجَاءَهُ رَجُلٌ فَقَالَ مِنْ أَيْنَ جِئْتَ قَالَ مِنْ زَمْزَمَ قَالَ فَشَرِبْتَ مِنْهَا كَمَا يَنْبَغِي قَالَ وَكَيْفَ قَالَ إِذَا شَرِبْتَ مِنْهَا فَاسْتَقْبِلْ الْقِبْلَةَ وَاذْكُرْ اسْمَ اللَّهِ وَتَنَفَّسْ ثَلَاثًا وَتَضَلَّعْ مِنْهَا فَإِذَا فَرَغْتَ فَاحْمَدْ اللَّهَ عَزَّ وَجَلَّ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ آيَةَ مَا بَيْنَنَا وَبَيْنَ الْمُنَافِقِينَ إِنَّهُمْ لَا يَتَضَلَّعُونَ مِنْ زَمْزَمَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Utsman bin Al Aswad] dari [Muhammad bin Abdurrahman bin Abu Bakar], ia berkata; \"Aku sedang duduk disamping [Ibnu 'Abbas], lalu datanglah seorang lelaki kepadanya, kemudian dia bertanya; 'Dari mana kamu? ' Dia menjawab; 'Dari zamzam.' Dia bertanya lagi; 'Apakah kamu meminum darinya sebagaimana mestinya? ' Dia berkata; 'Bagaimana? ' Dia menjawab: 'Apabila kamu meminumnya, menghadaplah ke Kiblat, bacalah bismillah, bernafas sebanyak tiga kali, dan berpuas-puaslah sampai seperti mau keluar lagi, dan apabila kamu telah selesai, pujilah Allah 'azza wajalla. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya tanda perbedaan diantara kita dan orang-orang munafiq adalah mereka tidak berpuas-puas meminum air zamzam.'"},"3018":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ الْمُؤَمَّلِ أَنَّهُ سَمِعَ أَبَا الزُّبَيْرِ يَقُولُ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَاءُ زَمْزَمَ لِمَا شُرِبَ لَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Al Walid bin Muslim] berkata; [Abdullah bin Mu`ammal] berkata; bahwa ia mendengar [Abu Az Zubair] berkata; Aku mendengar [Jabir bin Abdullah] radliallahu 'anhu, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Air Zamzam (berkhasiat) sesuai dengan niat (tujuan) diminum (oleh penggunanya).'"},"3019":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ الْوَاحِدِ عَنْ الْأَوْزَاعِيِّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ الْكَعْبَةَ وَمَعَهُ بِلَالٌ وَعُثْمَانُ بْنُ شَيْبَةَ فَأَغْلَقُوهَا عَلَيْهِمْ مِنْ دَاخِلٍ فَلَمَّا خَرَجُوا سَأَلْتُ بِلَالًا أَيْنَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَنِي أَنَّهُ صَلَّى عَلَى وَجْهِهِ حِينَ دَخَلَ بَيْنَ الْعَمُودَيْنِ عَنْ يَمِينِهِ ثُمَّ لُمْتُ نَفْسِي أَنْ لَا أَكُونَ سَأَلْتُهُ كَمْ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi]; telah menceritakan kepada kami [Umar bin Abdul Wahid] dari [Al Auza'i]; telah menceritakan kepadaku [Hassan bin 'Athiyyah]; telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, ia berkata; \"Rasulullah pada hari penaklukan kota Makkah (fathul Makkah) memasuki Ka'bah, dan (ikut masuk) bersama beliau Bilal, Utsman bin Syaibah, lalu mereka menutupnya dari dalam. Dan ketika mereka keluar, aku pun bertanya kepada [Bilal]; 'Di mana Rasulullah shallallahu 'alaihi wasallam shalat? ' Bilal mengabariku bahwa beliau shalat di hadapannya. (Yaitu) ketika masuk diantara dua tiang di sisi kanan. Kemudian kusalahkan diriku sendiri karena tidak menanyakan berapa raka'atkah Rasulullah shallallahu 'alaihi wasallam shalat.'"},"3020":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ الْمَلِكِ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِي وَهُوَ قَرِيرُ الْعَيْنِ طَيِّبُ النَّفْسِ ثُمَّ رَجَعَ إِلَيَّ وَهُوَ حَزِينٌ فَقُلْتُ يَا رَسُولَ اللَّهِ خَرَجْتَ مِنْ عِنْدِي وَأَنْتَ قَرِيرُ الْعَيْنِ وَرَجَعْتَ وَأَنْتَ حَزِينٌ فَقَالَ إِنِّي دَخَلْتُ الْكَعْبَةَ وَوَدِدْتُ أَنِّي لَمْ أَكُنْ فَعَلْتُ إِنِّي أَخَافُ أَنْ أَكُونَ أَتْعَبْتُ أُمَّتِي مِنْ بَعْدِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Isma'il bin Abdul Malik] dari [Ibnu Abu Mulaikah] dari [Aisyah], ia berkata; \"Nabi shallallahu 'alaihi wasallam keluar dari sisiku dalam kondisi matanya sejuk dan jiwanya tenang, kemudian kembali kepadaku dalam kondisi sedih, maka aku bertanya; 'Wahai Rasulullah, engkau keluar dari sisiku sedang engkau dalam kondisi sejuk dipandang, dan engkau kembali dalam keadaan sedih.' Beliau bersabda: 'Aku masuk ke dalam Ka'bah, dan aku berkeinginan sekali untuk tidak melakukannya, aku khawatir jika aku membuat umatku mengikuti setelah kepergianku.'"},"3021":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاسْتَأْذَنَ الْعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيتَ بِمَكَّةَ أَيَّامَ مِنًى مِنْ أَجْلِ سِقَايَتِهِ فَأَذِنَ لَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abdullah bin Numair]; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, ia berkata; Abbas bin Abdul Muththalib meminta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk bermalam di Makkah pada hari-hari mabit di Mina untuk (menjalankan tugas) memberi minum (para jama'ah). Lalu beliau pun mengizinkannya.\""},"3022":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمْ يُرَخِّصْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَحَدٍ يَبِيتُ بِمَكَّةَ إِلَّا لِلْعَبَّاسِ مِنْ أَجْلِ السِّقَايَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Hannad bin As Sari], keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Isma'il bin Muslim] dari [Atha`] dari [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam tidak meringankan seorang pun bermalam di Makkah kecuali kepada 'Abbas dikarenakan ia memberikan air minum untuk jama'ah haji."},"3023":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ وَعَبْدَةُ وَوَكِيعٌ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ كُلُّهُمْ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنَّ نُزُولَ الْأَبْطَحِ لَيْسَ بِسُنَّةٍ إِنَّمَا نَزَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَكُونَ أَسْمَحَ لِخُرُوجِهِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari]; telah menceritakan kepada kami [Ibnu Abu Zaidah] dan [Abdah] dan [Waki'] dan [Abu Mu'awiyah]; Demikian juga diriwayatkan dari jalur lainnya, telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah]; Demikian juga diriwayatkan dari jalur lainnya, telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Hafsh bin Ghiyats] semuanya dari [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Sesungguhnya singgah di padang pasir berkerikil bukanlah sunnah. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam singgah agar lebih mudah keluar (dari sana).\""},"3024":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ عَمَّارِ بْنِ زُرَيْقٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْادَّلَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ النَّفْرِ مِنْ الْبَطْحَاءِ ادِّلَاجًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Ammar bin Zuraiq] dari [Al `A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha, ia berkata; \"Nabi shallallahu 'alaihi wasallam keluar dari Batha pada malam hari saat hari Nafar (pulang dari Mina).\""},"3025":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ يَنْزِلُونَ بِالْأَبْطَحِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazak]; telah memberitakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] berkata; bahwa Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman berhenti di Batha'."},"3026":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّاسُ يَنْصَرِفُونَ كُلَّ وَجْهٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْفِرَنَّ أَحَدٌ حَتَّى يَكُونَ آخِرُ عَهْدِهِ بِالْبَيْتِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Sulaiman] dari [Thawush] dari [Ibnu Abbas] berkata; \"Manusia pada bubar dari seluruh penjuru arah, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidak ada seorangpun pergi hingga singgah terakhirnya diBaitullah'.\""},"3027":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَزِيدَ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْفِرَ الرَّجُلُ حَتَّى يَكُونَ آخِرُ عَهْدِهِ بِالْبَيْتِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Ibrahim bin Yazid] dari [Thawush] dari [Ibnu Umar] radliallahu 'anhu, ia berkata; Rasulullah Shallallahu melarang seorang laki-laki pulang kembali hingga ia sampai di Baitullah."},"3028":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَعُرْوَةَ عَنْ عَائِشَةَ قَالَتْحَاضَتْ صَفِيَّةُ بِنْتُ حُيَيٍّ بَعْدَ مَا أَفَاضَتْ قَالَتْ عَائِشَةُ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَابِسَتُنَا هِيَ فَقُلْتُ إِنَّهَا قَدْ أَفَاضَتْ ثُمَّ حَاضَتْ بَعْدَ ذَلِكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَنْفِرْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari [Aisyah]; Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Muhammad bin Rumh]; telah memberitakan kepada kami [Al Laits bin Sa'ad] dari [Ibnu Syihab] dari [Abu Salamah] dan [Urwah] dari [Aisyah] berkata; Shafiyyah binti Huyai terkena haid selepas melakukan thawaf ifadhah, hal itu aku sampaikan kepada Rasulullah shallallahu 'alaihi wasallam dan beliau bersabda: 'Apakah ia tengah di kamarnya? ' Aku menjawab; 'Dia telah melakukan thawaf ifadah dan baru mendapatkan haidnya setelah itu.' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Baiklah kalau begitu ia boleh pergi.'"},"3029":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفِيَّةَ فَقُلْنَا قَدْ حَاضَتْ فَقَالَ عَقْرَى حَلْقَى مَا أُرَاهَا إِلَّا حَابِسَتَنَا فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ طَافَتْ يَوْمَ النَّحْرِ قَالَ فَلَا إِذَنْ مُرُوهَا فَلْتَنْفِرْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepada kami [Al `A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam menyebut Shafiyyah, kami menjawab; \"Ia sedang haid.\" Beliau bertanya: 'Apakah kalian menahannya? ' Aku menajawab; 'Ia telah melakukan thawaf wahai Rasulullah? ' Beliau menjawab: 'Perintahkan agar ia segera pergi'."},"3030":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ قَالَدَخَلْنَا عَلَى جَابِرِ بْنِ عَبْدِ اللَّهِ فَلَمَّا انْتَهَيْنَا إِلَيْهِ سَأَلَ عَنْ الْقَوْمِ حَتَّى انْتَهَى إِلَيَّ فَقُلْتُ أَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحُسَيْنِ فَأَهْوَى بِيَدِهِ إِلَى رَأْسِي فَحَلَّ زِرِّي الْأَعْلَى ثُمَّ حَلَّ زِرِّي الْأَسْفَلَ ثُمَّ وَضَعَ كَفَّهُ بَيْنَ ثَدْيَيَّ وَأَنَا يَوْمَئِذٍ غُلَامٌ شَابٌّ فَقَالَ مَرْحَبًا بِكَ سَلْ عَمَّا شِئْتَ فَسَأَلْتُهُ وَهُوَ أَعْمَى فَجَاءَ وَقْتُ الصَّلَاةِ فَقَامَ فِي نِسَاجَةٍ مُلْتَحِفًا بِهَا كُلَّمَا وَضَعَهَا عَلَى مَنْكِبَيْهِ رَجَعَ طَرَفَاهَا إِلَيْهِ مِنْ صِغَرِهَا وَرِدَاؤُهُ إِلَى جَانِبِهِ عَلَى الْمِشْجَبِ فَصَلَّى بِنَا فَقُلْتُ أَخْبِرْنَا عَنْ حَجَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بِيَدِهِ فَعَقَدَ تِسْعًا وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَثَ تِسْعَ سِنِينَ لَمْ يَحُجَّ فَأَذَّنَ فِي النَّاسِ فِي الْعَاشِرَةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجٌّ فَقَدِمَ الْمَدِينَةَ بَشَرٌ كَثِيرٌ كُلُّهُمْ يَلْتَمِسُ أَنْ يَأْتَمَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَعْمَلَ بِمِثْلِ عَمَلِهِ فَخَرَجَ وَخَرَجْنَا مَعَهُ فَأَتَيْنَا ذَا الْحُلَيْفَةِ فَوَلَدَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ مُحَمَّدَ بْنَ أَبِي بَكْرٍ فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَصْنَعُ قَالَ اغْتَسِلِي وَاسْتَثْفِرِي بِثَوْبٍ وَأَحْرِمِي فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ ثُمَّ رَكِبَ الْقَصْوَاءَ حَتَّى إِذَا اسْتَوَتْ بِهِ نَاقَتُهُ عَلَى الْبَيْدَاءِ قَالَ جَابِرٌ نَظَرْتُ إِلَى مَدِّ بَصَرِي مِنْ بَيْنِ يَدَيْهِ بَيْنَ رَاكِبٍ وَمَاشٍ وَعَنْ يَمِينِهِ مِثْلُ ذَلِكَ وَعَنْ يَسَارِهِ مِثْلُ ذَلِك وَمِنْ خَلْفِهِ مِثْلُ ذَلِكَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِنَا وَعَلَيْهِ يَنْزِلُ الْقُرْآنُ وَهُوَ يَعْرِفُ تَأْوِيلَهُ مَا عَمِلَ بِهِ مِنْ شَيْءٍ عَمِلْنَا بِهِ فَأَهَلَّ بِالتَّوْحِيدِ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَ وَأَهَلَّ النَّاسُ بِهَذَا الَّذِي يُهِلُّونَ بِهِ فَلَمْ يَرُدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ شَيْئًا مِنْهُ وَلَزِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلْبِيَتَهُ قَالَ جَابِرٌ لَسْنَا نَنْوِي إِلَّا الْحَجَّ لَسْنَا نَعْرِفُ الْعُمْرَةَ حَتَّى إِذَا أَتَيْنَا الْبَيْتَ مَعَهُ اسْتَلَمَ الرُّكْنَ فَرَمَلَ ثَلَاثًا وَمَشَى أَرْبَعًا ثُمَّ قَامَ إِلَى مَقَامِ إِبْرَاهِيمَ فَقَالَ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }فَجَعَلَ الْمَقَامَ بَيْنَهُ وَبَيْنَ الْبَيْتِ فَكَانَ أَبِي يَقُولُ وَلَا أَعْلَمُهُ إِلَّا ذَكَرَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ كَانَ يَقْرَأُ فِي الرَّكْعَتَيْنِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَ قُلْ هُوَ اللَّهُ أَحَدٌ ثُمَّ رَجَعَ إِلَى الْبَيْتِ فَاسْتَلَمَ الرُّكْنَ ثُمَّ خَرَجَ مِنْ الْبَابِ إِلَى الصَّفَا حَتَّى إِذَا دَنَا مِنْ الصَّفَا قَرَأَ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }نَبْدَأُ بِمَا بَدَأَ اللَّهُ بِهِ فَبَدَأَ بِالصَّفَا فَرَقِيَ عَلَيْهِ حَتَّى رَأَى الْبَيْتَ فَكَبَّرَ اللَّهَ وَهَلَّلَهُ وَحَمِدَهُ وَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ أَنْجَزَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ ثُمَّ دَعَا بَيْنَ ذَلِكَ وَقَالَ مِثْلَ هَذَا ثَلَاثَ مَرَّاتٍ ثُمَّ نَزَلَ إِلَى الْمَرْوَةِ فَمَشَى حَتَّى إِذَا انْصَبَّتْ قَدَمَاهُ رَمَلَ فِي بَطْنِ الْوَادِي حَتَّى إِذَا صَعِدَتَا يَعْنِي قَدَمَاهُ مَشَى حَتَّى أَتَى الْمَرْوَةَ فَفَعَلَ عَلَى الْمَرْوَةِ كَمَا فَعَلَ عَلَى الصَّفَا فَلَمَّا كَانَ آخِرُ طَوَافِهِ عَلَى الْمَرْوَةِ قَالَ لَوْ أَنِّي اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ لَمْ أَسُقْ الْهَدْيَ وَجَعَلْتُهَا عُمْرَةً فَمَنْ كَانَ مِنْكُمْ لَيْسَ مَعَهُ هَدْيٌ فَلْيَحْلِلْ وَلْيَجْعَلْهَا عُمْرَةً فَحَلَّ النَّاسُ كُلُّهُمْ وَقَصَّرُوا إِلَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ مَعَهُ الْهَدْيُ فَقَامَ سُرَاقَةُ بْنُ مَالِكِ بْنِ جُعْشُمٍ فَقَالَ يَا رَسُولَ اللَّهِ أَلِعَامِنَا هَذَا أَمْ لِأَبَدِ الْأَبَدِ قَالَ فَشَبَّكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَابِعَهُ فِي الْأُخْرَى وَقَالَ دَخَلَتْ الْعُمْرَةُ فِي الْحَجِّ هَكَذَا مَرَّتَيْنِ لَا بَلْ لِأَبَدِ الْأَبَدِ قَالَ وَقَدِمَ عَلِيٌّ بِبُدْنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ فَاطِمَةَ مِمَّنْ حَلَّ وَلَبِسَتْ ثِيَابًا صَبِيغًا وَاكْتَحَلَتْ فَأَنْكَرَ ذَلِكَ عَلَيْهَا عَلِيٌّ فَقَالَتْ أَمَرَنِي أَبِي بِهَذَا فَكَانَ عَلِيٌّ يَقُولُ بِالْعِرَاقِ فَذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحَرِّشًا عَلَى فَاطِمَةَ فِي الَّذِي صَنَعَتْهُ مُسْتَفْتِيًا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي ذَكَرَتْ عَنْهُ وَأَنْكَرْتُ ذَلِكَ عَلَيْهَا فَقَالَ صَدَقَتْ صَدَقَتْ مَاذَا قُلْتُ حِينَ فَرَضْتَ الْحَجَّ قَالَ قُلْتُ اللَّهُمَّ إِنِّي أُهِلُّ بِمَا أَهَلَّ بِهِ رَسُولُكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنَّ مَعِي الْهَدْيَ فَلَا تَحِلَّ قَالَ فَكَانَ جَمَاعَةُ الْهَدْيِ الَّذِي جَاءَ بِهِ عَلِيٌّ مِنْ الْيَمَنِ وَالَّذِي أَتَى بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ مِائَةً ثُمَّ حَلَّ النَّاسُ كُلُّهُمْ وَقَصَّرُوا إِلَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ مَعَهُ هَدْيٌ فَلَمَّا كَانَ يَوْمُ التَّرْوِيَةِ وَتَوَجَّهُوا إِلَى مِنًى أَهَلُّوا بِالْحَجِّ فَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِمِنًى الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ وَالصُّبْحَ ثُمَّ مَكَثَ قَلِيلًا حَتَّى طَلَعَتْ الشَّمْسُ وَأَمَرَ بِقُبَّةٍ مِنْ شَعَرٍ فَضُرِبَتْ لَهُ بِنَمِرَةَ فَسَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَشُكُّ قُرَيْشٌ إِلَّا أَنَّهُ وَاقِفٌ عِنْدَ الْمَشْعَرِ الْحَرَامِ أَوْ الْمُزْدَلِفَةِ كَمَا كَانَتْ قُرَيْشٌ تَصْنَعُ فِي الْجَاهِلِيَّةِ فَأَجَازَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَى عَرَفَةَ فَوَجَدَ الْقُبَّةَ قَدْ ضُرِبَتْ لَهُ بِنَمِرَةَ فَنَزَلَ بِهَا حَتَّى إِذَا زَاغَتْ الشَّمْسُ أَمَرَ بِالْقَصْوَاءِ فَرُحِلَتْ لَهُ فَرَكِبَ حَتَّى أَتَى بَطْنَ الْوَادِي فَخَطَبَ النَّاسَ فَقَالَ إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا وَإِنَّ كُلَّ شَيْءٍ مِنْ أَمْرِ الْجَاهِلِيَّةِ مَوْضُوعٌ تَحْتَ قَدَمَيَّ هَاتَيْنِ وَدِمَاءُ الْجَاهِلِيَّةِ مَوْضُوعَةٌ وَأَوَّلُ دَمٍ أَضَعُهُ دَمُ رَبِيعَةَ بْنِ الْحَارِثِ كَانَ مُسْتَرْضِعًا فِي بَنِي سَعْدٍ فَقَتَلَتْهُ هُذَيْلٌ وَرِبَا الْجَاهِلِيَّةِ مَوْضُوعٌ وَأَوَّلُ رِبًا أَضَعُهُ رِبَانَا رِبَا الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ فَإِنَّهُ مَوْضُوعٌ كُلُّهُ فَاتَّقُوا اللَّهَ فِي النِّسَاءِ فَإِنَّكُمْ أَخَذْتُمُوهُنَّ بِأَمَانَةِ اللَّهِ وَاسْتَحْلَلْتُمْ فُرُوجَهُنَّ بِكَلِمَةِ اللَّهِ وَإِنَّ لَكُمْ عَلَيْهِنَّ أَنْ لَا يُوطِئْنَ فُرُشَكُمْ أَحَدًا تَكْرَهُونَهُ فَإِنْ فَعَلْنَ ذَلِكَ فَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ وَلَهُنَّ عَلَيْكُمْ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِ وَقَدْ تَرَكْتُ فِيكُمْ مَا لَمْ تَضِلُّوا إِنْ اعْتَصَمْتُمْ بِهِ كِتَابَ اللَّهِ وَأَنْتُمْ مَسْئُولُونَ عَنِّي فَمَا أَنْتُمْ قَائِلُونَ قَالُوا نَشْهَدُ أَنَّكَ قَدْ بَلَّغْتَ وَأَدَّيْتَ وَنَصَحْتَ فَقَالَ بِإِصْبَعِهِ السَّبَّابَةِ إِلَى السَّمَاءِ وَيَنْكُبُهَا إِلَى النَّاسِ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ ثَلَاثَ مَرَّاتٍ ثُمَّ أَذَّنَ بِلَالٌ ثُمَّ أَقَامَ فَصَلَّى الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى الْعَصْرَ وَلَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَى الْمَوْقِفَ فَجَعَلَ بَطْنَ نَاقَتِهِ إِلَى الصَّخَرَاتِ وَجَعَلَ حَبْلَ الْمُشَاةِ بَيْنَ يَدَيْهِ وَاسْتَقْبَلَ الْقِبْلَةَ فَلَ��ْ يَزَلْ وَاقِفًا حَتَّى غَرَبَتْ الشَّمْسُ وَذَهَبَتْ الصُّفْرَةُ قَلِيلًا حَتَّى غَابَ الْقُرْصُ وَأَرْدَفَ أُسَامَةَ بْنَ زَيْدٍ خَلْفَهُ فَدَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ شَنَقَ الْقَصْوَاءَ بِالزِّمَامِ حَتَّى إِنَّ رَأْسَهَا لَيُصِيبُ مَوْرِكَ رَحْلِهِ وَيَقُولُ بِيَدِهِ الْيُمْنَى أَيُّهَا النَّاسُ السَّكِينَةَ السَّكِينَةَ كُلَّمَا أَتَى حَبْلًا مِنْ الْحِبَالِ أَرْخَى لَهَا قَلِيلًا حَتَّى تَصْعَدَ ثُمَّ أَتَى الْمُزْدَلِفَةَ فَصَلَّى بِهَا الْمَغْرِبَ وَالْعِشَاءَ بِأَذَانٍ وَاحِدٍ وَإِقَامَتَيْنِ وَلَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا ثُمَّ اضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى طَلَعَ الْفَجْرُ فَصَلَّى الْفَجْرَ حِينَ تَبَيَّنَ لَهُ الصُّبْحُ بِأَذَانٍ وَإِقَامَةٍ ثُمَّ رَكِبَ الْقَصْوَاءَ حَتَّى أَتَى الْمَشْعَرَ الْحَرَامَ فَرَقِيَ عَلَيْهِ فَحَمِدَ اللَّهَ وَكَبَّرَهُ وَهَلَّلَهُ فَلَمْ يَزَلْ وَاقِفًا حَتَّى أَسْفَرَ جِدًّا ثُمَّ دَفَعَ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ وَأَرْدَفَ ال","id":"Telah menceritakan kepada kami [Hisyam bin Ammar]; telah menceritakan kepada kami [Hatim bin Isma'il]; telah menceritakan kepada kami [Ja'far bin Muhammad] dari [Ayahnya], ia berkata; \"Aku pernah datang menemui [Jabir bin Abdullah]. Ketika kami menjumpainya, ia bertanya tentang kabar orang-orang, hingga ia bertanya tentang diriku. Maka aku menjawab; 'Aku Muhammad bin Ali bin Husain.' Maka ia letakkan tangannya di atas kepalaku sambil membuka kancing atas dan bawahku, lalu meletakkan pundaknya diantara dadaku dan saat itu aku masih kecil yang menginjak dewasa. Ia berkata; 'Selamat datang, tanyakanlah apa saja yang kamu ingini.' Aku bertanya kepadanya sedang ia seorang yang buta. Hingga tiba waktu shalat sedang ia berdiri di atas sajadahnya, yang apabila ia meletakkan tumitnya pada sisi-sisi sajadah maka akan tertarik karena kecilnya sajadah tersebut, adapun selendangnya menggantung di pundaknya dan ia pun shalat mengimami kami.' Lalu aku bertanya; 'Beritahukan pada kami bagaimana Rasulullah shallallahu 'alaihi wasallam berhaji! ' Maka ia mengisyaratkan dengan tangannya dan ia menjulurkan sembilan (jari jemarinya), dan berkata; 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam berdiam tidak berangkat haji selama sembilan tahun, lalu beliau menyerukan orang-orang untuk menunaikan ibadah haji pada tahun kesepuluh. Rasulullah shallallahu 'alaihi wasallam berangkat haji, lalu datanglah banyak orang ke Madinah, mereka semua ingin berkumpul dengan Nabi shallallahu 'alaihi wasallam dan mengerjakan seperti yang beliau kerjakan. Maka beliaupun berangkat, dan kamipun berangkat bersama beliau. Sesampainya kami di Dzul Hulaifah, Asma' binti Umais melahirkan Muhammad bin Abu Bakar, maka diutuslah kepada beliau untuk menanyakan; 'Apa yang patut aku perbuat? ' Lalu beliau bersabda kepada Asma: 'Mandilah dan ikatlah kencang-kencang dengan kain dan berihramlah.' Kemudian Rasulullah shallallahu 'alaihi wasallam shalat di masjid lalu mengendarai unta Qashwa, dan untanya pun berdiri tegak membawa beliau di atas padang Sahara.' Jabir berkata; 'Aku melihat sejauh pandanganku banyak orang yang berada di depan beliau, antara penunggang kendaraan dan pejalan kaki, juga yang berada di sisi kanan dan kiri serta belakang beliau (terlihat banyak orang). Rasulullah shallallahu 'alaihi wasallam berada di tengah-tengah kami, sedangkan Al Qur'an turun kepada beliau, dan beliau sangat tahu akan takwilnya. Apa saja yang beliau kerjakan, maka kami turut mengerjakannya. Beliau mengeraskan suara tauhid dengan mengucapkan: 'Aku penuhi panggilan-Mu, ya Allah. Aku penuhi panggilan-Mu, aku penuhi panggilan-Mu. Tiada sekutu bagi-Mu, Aku penuhi panggilan-Mu. Sesungguhnya pujian, kenikmatan dan kerajaan hanya milik-Mu, yang tiada sekutu bagi-Mu.' Orang-orang juga mengeraskan suara dengan bacaan yang mereka ucapkan, dan beliau shallallahu 'alaihi wasallam tidak mengatakan apapun atas tindakan mereka itu. Beliau shallallahu 'alaihi wasallam terus membaca talbiyahnya.' Jabir radliallahu 'anhu berkata lagi; 'Kami tidak berniat kecuali menunaikan haji saja, dan kami belum mengenal umrah. Sesampainya kami di Baitullah bersama beliau, beliau segera mengusap (mencium) Rukun (awal Thawaf), lalu berlari kecil tiga putaran dan berjalan biasa pada empat putaran (lainnya). Kemudian beliau pergi menuju maqam Ibrahim, seraya membaca ayat: ' Dan jadikanlah Maqam Ibrahim sebagai tempat shalat.' Beliaupun memposisikan dirinya antara Maqam Ibrahim dengan Baitullah (Ka'bah). -Bapakku berkata; - 'dan aku tidak mengetahui kecuali ia menyebutkannya dari Nabi shallallahu 'alaihi wasallam, bahwa Nabi membaca surah Al Kaafiruun dan Al Ikhlaash dalam shalat dua rakaat (di Maqam Ibrahim). Kemudian beliau kembali ke Baitullah, lalu mengusap (mencium atau menyalami) Rukun (awal thawaf), lantas beliau keluar dari pintu (Ka'bah) menuju bukit Shafa. Dan ketika mendekati Shafa, beliau membaca: ' Sesungguhnya Shafa dan Marwa termasuk syiar-syiar Allah, kita memulai (sa'i) dengan apa yang telah Allah Subhanahu Wa Ta'ala mulai.' Beliau mulai bersa'i dari Shafa, lalu menaiki (bukit itu) hingga dapat melihat Ka'bah, kemudian beliau bertakbir, bertahlil dan bertahmid seraya mengucapkan: 'Tidak ada Tuhan selain Allah semata yang tiada sekutu bagi-Nya. Bagi-Nya kerajaan dan bagi-Nya segala pujian. (Dia) yang maha menghidupkan dan maha mematikan, serta Dia maha kuasa atas segala sesuatu. Tidak ada Tuhan selain Allah semata, yang tiada sekutu baginya, yang melaksanakan janji-Nya, menolong hamba-Nya dan mengalahkan seluruh golongan dengan sendirian.' Kemudian beliau berdoa diantara bacaan itu, lalu mengucapkan bacaan seperti itu tiga kali. Beliau lantas turun ke Marwa, sambil berjalan sehingga jika kedua kakinya telah tegak, beliau berlari kecil di tengah lembah. Tatkala kedua kakinya telah mendaki, beliau berjalan sampai tiba di Marwa. Di Marwa beliau melakukan seperti yang beliau lakukan di Shafa. Dan ketika Thawafnya berakhir di Marwa, beliaupun bersabda: 'Seandainya aku menghadap apa yang aku belakangi, maka aku tidak menggiring hewan sembelihan (al hadyu), dan aku menjadikannya umrah. Barang siapa diantara kalian tidak membawa hewan sembelihan, maka bertahllul-lah dan jadikanlah ia sebagai ibadah.' Maka seluruh orangpun bertahallul dan memendekan rambut kecuali Nabi shallallahu 'alaihi wasallam dan orang-orang yang membawa hewan sembelihan. Lalu Suraqah bin Malik bin Ju'syum berdiri seraya berkata; 'Wahai Rasulullah apakah ini berlaku untuk tahun ini, ataukah untuk selamanya'.\" (Perawi) berkata; 'Rasulullah shallallahu 'alaihi wasallam pun merangkai jemarinya dengan jari jemari seraya menjawab: 'Umrah masuk ke dalam haji (haji tamattu') beginilah caranya.' Beliau mengucapkan dua kali lantas bersabda: 'Tidak (ini hanya berlaku untuk tahun ini saja), tetapi untuk selamanya'.' (Perawi) berkata; 'Ali radliallahu 'anhu datang membawa unta (al hadyu) Nabi shallallahu 'alaihi wasallam, maka ia mendapatkan Fathimah termasuk orang yang bertahallul tengah memakai pakaian berwarna dan memakai sipat mata. Ali pun menyalahkannya, maka Fatimah pun berkata; 'Bapakku (Nabi shallallahu 'alaihi wasallam) telah memberitahuku berbuat begini.' Ali radliallahu 'anhu mengatakannya saat di Irak: 'Lalu aku pergi meminta nasehat kepada Rasulullah shallallahu 'alaihi wasallam dan mengeluhkan perbuatan Fatimah yang aku ingkari itu. Maka beliau menjawab: 'Ia (Fatimah) benar, ia benar. Apa yang telah aku katakan ketika kamu ingin melakukan ibadah haji dulu? ' Ali menjawab; 'Aku berkata; 'Ya Allah, aku mengeraskan suara yang dikeraskan oleh Rasul-Mu shallallahu 'alaihi wasallam.' Beliau bersabda: 'Sesungguhnya aku membawa hewan kurban, maka janganlah kamu ikut bertahallul'. (Perawi) berkata; 'Hewan kurban yang dibawa Ali dari Yaman dan yang dibawa Rasulullah shallallahu 'alaihi wasallam dari Madinah berjumlah seratus ekor. Kemudian semua orang bertahallul dan memendekan rambutnya kecuali Nabi shallallahu 'alaihi wasallam dan orang-orang yang membawa hewan kurban. Ketika hari Tarwiyah datang mereka semua menuju Mina dan meneriakkan niat haji. Rasulullah shallallahu 'alaihi wasallam naik kendaraan, dan di sana beliau mengerjakan shalat Dzuhur, Ashar, Maghrib, Isya', dan Subuh. Kemudian menunggu sebentar sampai matahari terbit, lalu memerintahkan untuk mendirikan Kubah di Masy'aril haram maka ditancapkan di Namirah. Rasulullah shallallahu 'alaihi wasallam kemudian berjalan seperti yang biasa kaum Quraisy kerjakan, tetapi beliau berhenti di Masy'aril Haram atau Muzdalifah. Rasulullah shallallahu 'alaihi wasallam membolehkannya sampai tiba di Arafah. Dan ketika mendekati kubah yang telah didirikan di Namirah, beliau singgah di sana. Ketika matahari tergelincir, beliau memerintahkan agar untanya (Qashwa) didatangkan, lalu beliau mengendarainya hingga tiba di perut lembah. Lantas beliau berkhutbah pada khalayak: 'Sesungguhnya darah kalian, harta, kehormatan dan kebahagiaan (kemuliaan) kalian adalah haram sebagaimana keharaman hari kalian ini, dibulan dan negeri kalian ini, camkanlah, sesungguhnya segala perkara jahiliyyah adalah terhina di bawah kakiku ini, darah-darah jahiliyyah telah dihinakan dan darah yang pertama kali aku hinakan adalah darah Rabi'ah bin Harits (yang dahulu meminta susuan dari bani Sa'ad lalu ia dibunuh Hudzail), riba jahiliyyah telah dihapuskan sedang riba yang pertama kali aku hapuskan adalah riba kami, yaitu riba yang dilakukan Abbas bin Abdul Muthallib, semuanya telah dihapuskan. Maka bertakwalah kepada Allah dari para wanita, karena kalian telah menjadikan mereka isteri dengan amanat Allah dan kalian halalkan farji dengan kalimat Allah. Sesungguhnya hak kalian atas mereka adalah agar mereka tidak membiarkan orang lain yang kalian benci tidur di atas ranjang kalian. Jika isteri-isteri kalian melakukannya, maka pukullah mereka dengan pukulan yang tidak melukai. Dan bagi mereka atas kalian untuk dinafkahi dan diberi pakaian dengan jalan yang baik. Aku tinggalkan untuk kalian dua perkara yang jika kalian berpegang teguh pada keduanya maka kalian tidak akan tersesat yaitu Kitabullah. Dan kalian bertanggung jawab kepadaku. Lalu apa yang ingin kalian katakan? ' Mereka menjawab; 'Kami bersaksi bahwa engkau telah menyampaikan, melaksanakan tugas dan memberikan nasehat. Maka beliau bersabda sambil menunjukan jarinya ke langit: 'Ya Allah, saksikanlah! Ya Allah saksikanlah.' Beliau mengucapkannya sampai tiga kali. Kemudian Bilal mengumandangkan adzan, lalu iqamat, maka beliau mendirikan shalat Zhuhur. (Selepas itu) Bilal kembali beriqamat, lalu beliau mendirikan shalat Ashar dan tidak melakukan shalat apapun diantara keduanya. Kemudian Rasulullah shallallahu 'alaihi wasallam mengendarai kendaraannya sehingga sampai ke tempat wukuf. Lalu beliau mendudukkan untanya (menjadikan perut untanya menyentuh padang) dan menjadikan tali pejalan kaki di depannya, lalu beliau menghadap kiblat. Beliau terus berwukuf sampai terbenamnya matahari dan sinar kekuning-kuningan sedikit sirna serta tenggelamnya bola matahari. Lalu beliau membonceng Usamah bin Said dan bertolak. Beliau pun mengikat Qashwa dengan kendali, hingga kepalanya nyaris menyentuh pangkal kaki kendaraan yang beliau tunggangi. Sambil mengisyaratkan dengan tangan kanannya, beliau bersabda: 'Wahai manusia, tenang, tenang! ' Setiap kali beliau mengulurkan tali kendali untanya, maka beliau menenangkan sedikit sehingga untanya agak naik. Kemudian tibalah beliau di Muzdalifah, lalu mengerjakan shalat Maghrib dan Isya' di sana dengan sekali adzan dan dua kali iqamat. Dan beliau tidak melakukan shalat apapun diantara keduanya. Kemudian beliau shallallahu 'alaihi wasallam berbaring sampai terbit fajar. Beliau mendirikan shalat fajar ketika nampak jelas baginya waktu subuh, dengan sekali adzan dan sekali iqamat. Kemudian beliau mengendarai Qashwa sampai tiba di Masy'aril Haram, lalu beliau menaiki bukitnya lantas memuji Allah (bertahmid), mengagungkan-Nya (bertakbir) dan mengesakan-Nya (bertahlil). Beliau terus melakukan Wukuf sampai matahari benar-benar terang, lalu bertolak sebelum terbit matahari. Beliau membonceng Fadl bin Abbas (seorang laki-laki berambut bagus, putih kulitnya dan ganteng). Ketika Rasulullah shallallahu 'alaihi wasallam bertolak, beliau melintasi para wanita yang sedang berlari, maka beliau memandang kepada mereka lalu meletakkan tangannya ke sisi lain. Sementara Fadl pun memalingkan mukanya ke sisi lain. Sesampainya di Muhassar, beliau bergerak sedikit kemudian mengambil jalan pintas menuju jumrah Kubra (Aqabah), dan langsung sampai di jumrah yang berada di sisi pohon. Lalu beliau melontar tujuh kerikil dengan bertakbir pada setiap lemparan, (dengan) kerikil yang besarnya seperti kerikil ketapel. Dan beliau melontarnya dari perut lembah. Lalu ia bertolak ke tempat menyembelih hewan kurban. Di sana beliau menyembelih sendiri enam puluh tiga ekor hewan kurban, dan menyerahkan kepada Ali sisanya berikut hewan kurbannya. Kemudian beliau memerintahkan dari setiap hewan kurban yang disembelihnya agar sepotong dagingnya disisihkan lalu di letakan di kuali, lantas dimasak. Rasulullah dan Ali pun memakan dan menghirup kuahnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bertolak menuju Ka'bah (untuk mengerjakan Thawaf Ifadhah), lalu beliau mengerjakan Shalat Zhuhur di Makkah dan mendatangi Bani Abdul Muththalib yang sedang mengambil air Zamzam. Beliau seraya bersabda: 'Rebutlah wahai Bani Muththalib. Seandainya orang-orang tidak mengungguli kalian dalam pemberian minuman kalian, tentu akan kuperebutkannya bersama kalian.' Lalu mereka pun memberi beliau shallallahu 'alaihi wasallam ember, dan beliau meminum darinya.'"},"3031":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ الْعَبْدِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنِي يَحْيَى بْنُ عَبْدِ الرَّحْمَنِ بْنِ حَاطِبٍ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْحَجِّ عَلَى أَنْوَاعٍ ثَلَاثَةٍ فَمِنَّا مَنْ أَهَلَّ بِحَجٍّ وَعُمْرَةٍ مَعًا وَمِنَّا مَنْ أَهَلَّ بِحَجٍّ مُفْرَدٍ وَمِنَّا مَنْ أَهَلَّ بِعُمْرَةٍ مُفْرَدَةٍ فَمَنْ كَانَ أَهَلَّ بِحَجٍّ وَعُمْرَةٍ مَعًا لَمْ يَحْلِلْ مِنْ شَيْءٍ مِمَّا حَرُمَ مِنْهُ حَتَّى يَقْضِيَ مَنَاسِكَ الْحَجِّ وَمَنْ أَهَلَّ بِالْحَجِّ مُفْرَدًا لَمْ يَحْلِلْ مِنْ شَيْءٍ مِمَّا حَرُمَ مِنْهُ حَتَّى يَقْضِيَ مَنَاسِكَ الْحَجِّ وَمَنْ أَهَلَّ بِعُمْرَةٍ مُفْرَدَةٍ فَطَافَ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ حَلَّ مَا حَرُمَ عَنْهُ حَتَّى يَسْتَقْبِلَ حَجًّا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Muhammad bin Bisyr Al 'Abdi] dari [Muhammad bin Amru]; telah menceritakan kepadaku [Yahya bin Abdurrahman bin Hathib] dari [Aisyah] radliallahu 'anha, ia berkata; \"Kami berangkat bersama Rasulullah shallallahu 'alaihi wasallam untuk menunaikan haji dengan tiga macam cara. Diantara kami ada yang berniat menunaikan haji dan umrah sekaligus, diantara kami ada pula yang berniat mengerjakan haji saja, dan diantara kami ada yang berniat mengerjakan umrah saja. Orang yang berniat mengerjakan haji dan umrah sekaligus, maka ia tidak bertahallul dari suatu yang diharamkan sampai menyelesaikan manasik hajinya. Dan orang yang berniat hanya mengerjakan haji tidak bertahallul dari apa yang diharamkan sampai ia menyelesaikan manasik hajinya. Dan orang yang berniat melaksanakan umrah secara tersendiri, lalu berthawaf di Ka'bah dan mengerjakan Sa'i antara Shafa dan Marwa, (setelah itu) ia dapat bertahallul dari apa yang diharamkan (ketika berihram) sampai datangnya waktu untuk haji.\""},"3032":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ مُحَمَّدِ بْنِ عَبَّادٍ الْمُهَلَّبِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ حَدَّثَنَا سُفْيَانُ قَالَحَجَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ حَجَّاتٍ حَجَّتَيْنِ قَبْلَ أَنْ يُهَاجِرَ وَحَجَّةً بَعْدَ مَا هَاجَرَ مِنْ الْمَدِينَةِ وَقَرَنَ مَعَ حَجَّتِهِ عُمْرَةً وَاجْتَمَعَ مَا جَاءَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا جَاءَ بِهِ عَلِيٌّ مِائَةَ بَدَنَةٍ مِنْهَا جَمَلٌ لِأَبِي جَهْلٍ فِي أَنْفِهِ بُرَةٌ مِنْ فِضَّةٍ فَنَحَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثَلَاثًا وَسِتِّينَ وَنَحَرَ عَلِيٌّ مَا غَبَرَقِيلَ لَهُ مَنْ ذَكَرَهُ قَالَ جَعْفَرٌ عَنْ أَبِيهِ عَنْ جَابِرٍ وَابْنُ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Al Qasim bin Muhammad bin Abbad Al Muhallabi]; telah menceritakan kepada kami [Abdullah bin Dawud]; telah menceritakan kepada kami [Sufyan]; ia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah melaksanakan tiga haji, dua haji sebelum hijrah dan sekali haji setelah hijrah, dan beliau berangkat dari Madinah. Beliau menyertakan umrah beserta hajinya (haji Qiran), lalu hewan kurban yang dibawa Nabi shallallahu 'alaihi wasallam dan yang dibawa oleh Ali radliallahu 'anhu dikumpulkan sehingga seratus ekor. Diantara hewan-hewan tersebut terdapat unta jantan milik Abu Jahal yang hidungnya berantaikan perak. Nabi shallallahu 'alaihi wasallam sendiri menyembelih enam puluh tiga ekor, dan Ali menyembelih sisanya.\" [Ja'far] berkata; dari [Ayahnya] dari [Jabir] dan [Ibnu Abu Laila] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas]."},"3033":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَابْنُ عُلَيَّةَ عَنْ حَجَّاجِ بْنِ أَبِي عُثْمَانَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي عِكْرِمَةُ حَدَّثَنِي الْحَجَّاجُ بْنُ عَمْرٍو الْأَنْصَارِيُّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كُسِرَ أَوْ عَرَجَ فَقَدْ حَلَّ وَعَلَيْهِ حَجَّةٌ أُخْرَىفَحَدَّثْتُ بِهِ ابْنَ عَبَّاسٍ وَأَبَا هُرَيْرَةَ فَقَالَا صَدَقَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah]; telah menceritakan kepada kami [Yahya bin Sa'id] dan [Ibnu Ulayyah] dari [Hajjaj bin Abu Utsman]; Telah menceritakan kepadaku [Yahya bin Abu Katsir]; Telah menceritakan kepadaku ['Ikrimah] dari [Al Hajjaj bin Amru Al Anshari], ia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: 'Barang siapa patah (kakinya) atau pincang, maka ia (dianggap) telah bertahallul, dan ia harusmengerjakan haji lainnya.'\" Aku bicarakan hadist ini kepada [Ibnu Abbas] radliallahu 'anhu dan [Abu Hurairah] radliallahu 'anhu, maka keduanya berkata; 'Benar.'"},"3034":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ مَوْلَى أُمِّ سَلَمَةَ قَالَسَأَلْتُ الْحَجَّاجَ بْنَ عَمْرٍو عَنْ حَبْسِ الْمُحْرِمِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كُسِرَ أَوْ مَرِضَ أَوْ عَرَجَ فَقَدْ حَلَّ وَعَلَيْهِ الْحَجُّ مِنْ قَابِلٍقَالَ عِكْرِمَةُ فَحَدَّثْتُ بِهِ ابْنَ عَبَّاسٍ وَأَبَا هُرَيْرَةَ فَقَالَا صَدَقَ قَالَ عَبْدُ الرَّزَّاقِ فَوَجَدْتُهُ فِي جُزْءِ هِشَامٍ صَاحِبِ الدَّسْتُوَائِيِّ فَأَتَيْتُ بِهِ مَعْمَرًا فَقَرَأَ عَلَيَّ أَوْ قَرَأْتُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Salamah bin Syabib]; telah menceritakan kepada kami [Abdurrazak]; telah memberitakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Abdullah bin Rafi'] mantan budak Ummu Salamah radliallahu 'anha, ia berkata; Aku menanyai [Al Hajjaj bin Amru] tentang terhalangnya orang yang berihram. Maka ia menjawab; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa patah (kakinya) atau sakit atau pincang, maka ia (dianggap) telah bertahallul. Dan ia harus mengganti hajinya di lain waktu.'\" [Ikrimah] berkata; 'Aku ceritakan hadist ini kepada [Ibnu Abbas] radliallahu 'anhu dan [Abu Hurairah] radliallahu 'anhu, maka mereka berkata; 'Benar.' Abdurrazak berkata; 'Aku mendapatkannya dibagian Hisyam sahabat Ad Dastuwa`i, lalu aku menemui Ma'mar dan ia membacakan kepadaku atau aku membacakan untuknya.'"},"3035":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَقَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ فِي الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ كَعْبٌ فِيَّ أُنْزِلَتْ كَانَ بِي أَذًى مِنْ رَأْسِي فَحُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أُرَى الْجُهْدَ بَلَغَ بِكَ مَا أَرَى أَتَجِدُ شَاةً قُلْتُ لَا قَالَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ فَالصَّوْمُ ثَلَاثَةُ أَيَّامٍ وَالصَّدَقَةُ عَلَى سِتَّةِ مَسَاكِينَ لِكُلِّ مِسْكِينٍ نِصْفُ صَاعٍ مِنْ طَعَامٍ وَالنُّسُكُ شَاةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Walid], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dari [Abdullah bin Ma'qil], ia berkata; \"Aku duduk di samping [Ka'ab bin 'Ujrah] di dalam masjid, lalu kutanyai tentang firman Allah; '..maka wajiblah atasnya berfidyah, yaitu berpuasa atau bersedekah atau berkurban…' (Qs Albaqarah 2: 196), Ka'ab pun menjawab; 'Ayat itu diturunkan tentang diriku. Karena dulu aku pernah terserang penyakit di kepalaku, lalu aku dibawa kepada Rasulullah shallallahu 'alaihi wasallam sedang kutu busuk berhamburan di wajahku.' Maka beliau bersabda: 'Aku tidak seharusnya melihat keletihan yang menimpamu seperti yang kulihat ini. Apakah kamu memiliki seekor kambing? ' Aku menjawab; 'Tidak.' (Perawi berkata); 'Maka turunlah ayat ini, '..maka wajiblah atasnya berfidyah, yaitu berpuasa, atau bersedekah atau berkurban..' (Perawi) berkata; 'Puasa tiga hari, sedekah untuk enam orang miskin dan setiap satu orang miskin diberi setengah sha' makanan pokok, serta berkurban dengan seekor kambing.'"},"3036":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَأَمَرَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ آذَانِي الْقَمْلُ أَنْ أَحْلِقَ رَأْسِي وَأَصُومَ ثَلَاثَةَ أَيَّامٍ أَوْ أُطْعِمَ سِتَّةَ مَسَاكِينَ وَقَدْ عَلِمَ أَنْ لَيْسَ عِنْدِي مَا أَنْسُكُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim]; telah menceritakan kepada kami [Abdullah bin Nafi'] dari [Usamah bin Zaid] dari [Muhammad bin Ka'ab] dari [Ka'ab bin 'Ujrah], ia berkata; \"Nabi shallallahu 'alaihi wasallam telah memerintahkanku, ketika kutu busuk menyakitiku agar aku mencukur kepalaku, dan berpuasa tiga hari, atau memberi makan enam orang miskin. Karena beliau tahu aku tidak mempunyai hewan yang dapat kukorbankan.\""},"3037":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ صَائِمٌ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah]; telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Yazid bin Abu Ziyad] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam pernah berbekam, (saat itu) beliau sedang berpuasa dan berihram."},"3038":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الضَّيْفِ عَنْ ابْنِ خُثَيْمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ مُحْرِمٌ عَنْ رَهْصَةٍ أَخَذَتْهُ","id":"Telah menceritakan kepada kami [Bakar bin Khalaf Abu Bisyr]; telah menceritakan kepada kami [Muhammad bin Abu Adl Dlaif] dari [Ibnu Khutsaim] dari [Ibnu Az Zubair] dari [Jabir] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam berbekam sedangkan beliau (saat itu) tengah berihram, karena keletihan yang menimpa beliau."},"3039":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ فَرْقَدٍ السَّبَخِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدَّهِنُ رَأْسَهُ بِالزَّيْتِ وَهُوَ مُحْرِمٌ غَيْرَ الْمُقَتَّتِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Hammad bin Salamah] dari [Farqad As Sabakhi] dari [Sa'id bin Jubair] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam meminyaki kepala beliau dengan minyak (bukan minyak wangi) sedang beliau berihram."},"3040":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا أَوْقَصَتْهُ رَاحِلَتُهُ وَهُوَ مُحْرِمٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْهِ وَلَا تُخَمِّرُوا وَجْهَهُ وَلَا رَأْسَهُ فَإِنَّهُ يُبْعَثُ يَوْمَ الْقِيَامَةِ مُلَبِّيًاحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ مِثْلَهُ إِلَّا أَنَّهُ قَالَ أَعْقَصَتْهُ رَاحِلَتُهُ وَقَالَ لَا تُقَرِّبُوهُ طِيبًا فَإِنَّهُ يُبْعَثُ يَوْمَ الْقِيَامَةِ مُلَبِّيًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu bahwa seorang lelaki patah lehernya karena terjatuh dari kendaraannya saat ia berihram maka Nabi shallallahu 'alaihi wasallam bersabda: \"Mandikanlah ia dengan air dan bidara dan kafankanlah dia dengan dua kain kafan, serta jangan ditutup wajah dan kepalanya, karena ia akan dibangkitkan pada hari kiamat dalam keadaan bertalbiyah.\" Dan telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah mencertikan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] seperti hadits di atas, namun ia mengatakan terpelintir lehernya disebabkan karena kendaraannya dan Rasulullah shallallahu 'alaihi wasallam bersabda: 'Jangan kalian olesi wajahnya dengan wewangian karena ia akan dibangkitkan di hari kiamat dalam keadaan bertalbiyah.'"},"3041":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمَّارٍ عَنْ جَابِرٍ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الضَّبُعِ يُصِيبُهُ الْمُحْرِمُ كَبْشًا وَجَعَلَهُ مِنْ الصَّيْدِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki']; telah menceritakan kepada kami [Jarir bin Hazim] dari [Abdullah bin Ubaid bin Umair] dari [Abdurrahman bin Abu Ammar] dari [Jabir] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda tentang anjing hutan yang diciderai oleh orang yang berihram maka ganjarannya adalah dengan membayar seekor kambing kibas dan beliau menganggap anjing hutan sebagai hewan buruan.\""},"3042":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْقَطَّانُ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ بْنُ مَوْهَبٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ أَبِي الْمُهَزِّمِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي بَيْضِ النَّعَامِ يُصِيبُهُ الْمُحْرِمُ ثَمَنُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Musa Al Qaththan Al Wasithi]; telah menceritakan kepada kami [Yazid bin Mauhab]; telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari]; Telah menceritakan kepada kami [Ali bin Abdul Aziz]; telah menceritakan kepada kami [Husain Al Mu'allim] dari [Abul Muhazzim] dari [Abu Hurairah]; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Telur burung unta yang diambil oleh orang yang sedang ihram maka diganti harganya\"."},"3043":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَمْسٌ فَوَاسِقُ يُقْتَلْنَ فِي الْحِلِّ وَالْحَرَمِ الْحَيَّةُ وَالْغُرَابُ الْأَبْقَعُ وَالْفَأْرَةُ وَالْكَلْبُ الْعَقُورُ وَالْحِدَأَةُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Basysyar] dan [Muhammad bin Al Mutsanna] dan [Muhammad bin Al Walid], semuanya mengatakan; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah]; Aku mendengar [Qatadah] menceritakan dari [Sa'id bin Al Musayyab] dari [Aisyah] radliallahu 'anha Nabi shallallahu 'alaihi wasallam bersabda: \"Lima binatang yang boleh dibunuh baik saat bertahalul maupun dalam waktu yang ihram: Ular, gagak, tikus, anjing buas dan burung rajawali.\""},"3044":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسٌ مِنْ الدَّوَابِّ لَا جُنَاحَ عَلَى مَنْ قَتَلَهُنَّ أَوْ قَالَ فِي قَتْلِهِنَّ وَهُوَ حَرَامٌ الْعَقْرَبُ وَالْغُرَابُ وَالْحُدَيَّاةُ وَالْفَأْرَةُ وَالْكَلْبُ الْعَقُورُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima binatang yang tidak berdosa bagi yang membunuhnya sedang ia dalam keadaan ihram; kalajengking, gagak, rajawali, tikus dan anjing buas.\""},"3045":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَقْتُلُ الْمُحْرِمُ الْحَيَّةَ وَالْعَقْرَبَ وَالسَّبُعَ الْعَادِيَ وَالْكَلْبَ الْعَقُورَ وَالْفَأْرَةَ الْفُوَيْسِقَةَ فَقِيلَ لَهُ لِمَ قِيلَ لَهَا الْفُوَيْسِقَةُ قَالَ لِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَيْقَظَ لَهَا وَقَدْ أَخَذَتْ الْفَتِيلَةَ لِتُحْرِقَ بِهَا الْبَيْتَ","id":"Telah menceritakan kepada kami [Abu Kuraib]; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Yazid bin Abu Ziyad] dari [Ibnu Abi Nu'm] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang yang berihram boleh membunuh ular, kalajengking, gagak, anjing buas dan tikus.\" Dikatakan padanya; 'Kenapa tikus yang nakal? ' Ia berkata; 'Karena Rasulullah shallallahu 'alaihi wasallam bangun dan ia telah mengambil sumbu lampu untuk membakar rumah.'"},"3046":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ جَمِيعًا عَنْ ابْنِ شِهَابٍ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ أَنْبَأَنَا صَعْبُ بْنُ جَثَّامَةَ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَأَهْدَيْتُ لَهُ حِمَارَ وَحْشٍ فَرَدَّهُ عَلَيَّ فَلَمَّا رَأَى فِي وَجْهِيَ الْكَرَاهِيَةَ قَالَ إِنَّهُ لَيْسَ بِنَا رَدٌّ عَلَيْكَ وَلَكِنَّا حُرُمٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Hisyam bin 'Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] semuanya dari [Ibnu Syihab Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dia berkata; telah memberitakan kepada kami [Sha'b bin Jatstsamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melewatiku ketika aku berada di Abwa` atau di daerah Waddan, kemudian aku memberinya hadiah seekor keledai liar, namun beliau mengembalikannya kepadaku, tatkala beliau melihat raut mukaku yang menggambarkan ketidaksukaan, maka beliau bersabda: \"Bukannya saya menolak pemberianmu, akan tetapi kami telah mengharamkan (dagingnya).\""},"3047":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِمْرَانُ بْنُ مُحَمَّدِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ ابْنِ عَبَّاسٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمِ صَيْدٍ وَهُوَ مُحْرِمٌ فَلَمْ يَأْكُلْهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Imran bin Muhammad bin Abu Laila] dari [Ayahnya] dari [Abdul Karim] dari [Abdullah bin Al Harits] dari [Ibnu Abbas] dari [Ali bin Abu Thalib] dia berkata, \"Nabi shallallahu 'alaihi wasallam di beri daging buruan ketika beliau sedang berihram, namun beliau tidak memakannya.\""},"3048":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ حِمَارَ وَحْشٍ وَأَمَرَهُ أَنْ يُفَرِّقَهُ فِي الرِّفَاقِ وَهُمْ مُحْرِمُونَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim At Taimi] dari [Isa bin Thalhah] dari [Thalhah bin 'Ubaidillah], bahwa Nabi shallallahu 'alaihi wasallam memberinya keledai liar, lalu beliau memerintahkan supaya dia mambagikan (dagingnya) kepada rombongan tersebut, padahal mereka dalam keadaan ihram.\""},"3049":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْحُدَيْبِيَةِ فَأَحْرَمَ أَصْحَابُهُ وَلَمْ أُحْرِمْ فَرَأَيْتُ حِمَارًا فَحَمَلْتُ عَلَيْهِ وَاصْطَدْتُهُ فَذَكَرْتُ شَأْنَهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرْتُ أَنِّي لَمْ أَكُنْ أَحْرَمْتُ وَأَنِّي إِنَّمَا اصْطَدْتُهُ لَكَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْحَابَهُ أَنْ يَأْكُلُوهُ وَلَمْ يَأْكُلْ مِنْهُ حِينَ أَخْبَرْتُهُ أَنِّي اصْطَدْتُهُ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] dia berkata, \"Saya keluar bersama Rasulullah shallallahu 'alaihi wasallam pada waktu perjanjian Hudaibiyyah, ketika para sahabat beliau berihram, aku tidak ikut berihram, tiba-tiba aku melihat seekor keledai lantas kuintai dan kuburu keledai tersebut. Kemudian hal itu kuberitahukan kepada Rasulullah shallallahu 'alaihi wasallam, aku sebutkan, 'Sesungguhnya aku tidak dalam berihram, dan aku tangkap ini untuk anda.' Maka Nabi shallallahu 'alaihi wasallam memerintahkan kepada para sahabatnya untuk memakannya, namun beliau tidak memakannya ketika aku beritahukan bahwa aku menangkapnya untuk beliau.\""},"3050":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهْدِي مِنْ الْمَدِينَةِ فَأَفْتِلُ قَلَائِدَ هَدْيِهِ ثُمَّ لَا يَجْتَنِبُ شَيْئًا مِمَّا يَجْتَنِبُ الْمُحْرِمُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dan ['Amrah binti Abdurrahman] bahwa [Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam membawa hewan kurban dari Madinah, kemudian beliau membuat pintalan dan mengalungkannya pada leher hewan kurbannya, dan beliau tidak menjauhi sesuatu dari hal-hal yang harus di jauhi oleh orang-orang yang berihram.\""},"3051":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكُنْتُ أَفْتِلُ الْقَلَائِدَ لِهَدْيِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُقَلِّدُ هَدْيَهُ ثُمَّ يَبْعَثُ بِهِ ثُمَّ يُقِيمُ لَا يَجْتَنِبُ شَيْئًا مِمَّا يَجْتَنِبُهُ الْمُحْرِمُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, dia berkata, \"Saya membuat beberapa pintalan untuk hewan kurban Nabi shallallahu 'alaihi wasallam, lantas beliau mengalungkan pintalan tersebut pada hewan kurbannya, lalu mengirimnya (untuk kurban). Kemudian beliau bermukim dan tidak menjauhkan diri dari suatu hal yang di hindari oleh orang yang tengah berihram.\""},"3052":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْأَهْدَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّةً غَنَمًا إِلَى الْبَيْتِ فَقَلَّدَهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata, \"Suatu kali Rasulullah shallallahu 'alaihi wasallam mempersembahkan hewan kurban seekor kambing menuju Batiullah, beliau lalu memberi kalung pada leher hewan tersebut.\""},"3053":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ أَبِي حَسَّانَ الْأَعْرَجِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْعَرَ الْهَدْيَ فِي السَّنَامِ الْأَيْمَنِ وَأَمَاطَ عَنْهُ الدَّمَ وَقَالَ عَلِيٌّ فِي حَدِيثِهِ بِذِي الْحُلَيْفَةِ وَقَلَّدَ نَعْلَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam Ad Dastuwa`i] dari [Qatadah] dari [Abu Hasan Al A'raj] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam memberi tanda pada hewan kurban yaitu pada pelana sebelah kanan dan menyingkirkan darah darinya.\" Dalam haditsnya Ali menyebutkan, \"Ketika di Dzul Khulaifah, lalu beliau menggantungkan sepasang sandal.\""},"3054":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ عَنْ أَفْلَحَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَلَّدَ وَأَشْعَرَ وَأَرْسَلَ بِهَا وَلَمْ يَجْتَنِبْ مَا يَجْتَنِبُ الْمُحْرِمُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hammad bin Khalid] dari [Aflah] dari [Al Qasim] dari [Asiyah], bahwa Nabi shallallahu 'alaihi wasallam memberi kalung pada hewan kurbannya lalu mengirimkannya, dan beliau tidak menghindari sesuatu yang di hindari oleh orang-orang yang tengah berihram.\""},"3055":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقُومَ عَلَى بُدْنِهِ وَأَنْ أَقْسِمَ جِلَالَهَا وَجُلُودَهَا وَأَنْ لَا أُعْطِيَ الْجَازِرَ مِنْهَا شَيْئًا وَقَالَ نَحْنُ نُعْطِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Abdul Karim] dari [Mujahid] dari [Ibnu Abu Laila] dari [Ali bin Abu Thalib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kepadaku untuk mengatur pembagian hewan kurban dan agar aku membagi-bagikan sesuatu yang ada di punggung dan kulit hewan tersebut, serta tidak memberisesuatu pun darinya kepada penjagalnya. Beliau bersabda; \"Kami sendirilah yang akan memberinya.\""},"3056":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْدَى فِي بُدْنِهِ جَمَلًا لِأَبِي جَهْلٍ بُرَتُهُ مِنْ فِضَّةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Laila] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam menyerahkan hewan kurban berupa unta jantan milik Abu Jahal yang burahnya (gelang pada hidung unta) terbuat dari perak.\""},"3057":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ إِيَاسِ بْنِ سَلَمَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي بُدْنِهِ جَمَلٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Ubaidullah bin Musa] telah memberitakan kepada kami [Musa bin 'Ubaidah] dari [Iyas bin Salamah] dari [Ayahnya], bahwa di antara hewan kurbannya Nabi shallallahu 'alaihi wasallam terdapat unta jantan.\""},"3058":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ سُفْيَانَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى هَدْيَهُ مِنْ قُدَيْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Yahya bin Yaman] dari [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam membeli hewan kurban dari daerah Qudaid.\""},"3059":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَسُوقُ بَدَنَةً فَقَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا وَيْحَكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan Ats Tsauri] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam melihat seorang laki-laki sedang menggiring untanya, maka beliau bersabda: \"Naikilah.\" Laki-laki itu berkata, \"Ini unta untuk kurban! \" Beliau bersabda lagi: \"Celaka kamu! Naikilah.\""},"3060":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ صَاحِبِ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرَّ عَلَيْهِ بِبَدَنَةٍ فَقَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا قَالَ فَرَأَيْتُهُ رَاكِبَهَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عُنُقِهَا نَعْلٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Hisyam] sahabat Ad Dastuwa`i, dari [Qatadah] dari [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam di lewati oleh seekor unta, maka beliau bersabda: \"Naikilah ia.\" Orang itu berkata, \"Ini unta untuk kurban! \" Beliau bersabda lagi: \"Naikilah! \" Anas berkata, \"Lalu aku melihat laki-laki itu menaikinya bersama Nabi shallallahu 'alaihi wasallam dan di leher hewan tersebut di gantungi sandal.\""},"3061":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ الْعَبْدِيُّ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سِنَانِ بْنِ سَلَمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ ذُؤَيْبًا الْخُزَاعِيَّ حَدَّثَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَبْعَثُ مَعَهُ بِالْبُدْنِ ثُمَّ يَقُولُ إِذَا عَطِبَ مِنْهَا شَيْءٌ فَخَشِيتَ عَلَيْهِ مَوْتًا فَانْحَرْهَا ثُمَّ اغْمِسْ نَعْلَهَا فِي دَمِهَا ثُمَّ اضْرِبْ صَفْحَتَهَا وَلَا تَطْعَمْ مِنْهَا أَنْتَ وَلَا أَحَدٌ مِنْ أَهْلِ رُفْقَتِكَ","id":"telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr Al 'Abdi] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Sinan bin Salamah] dari [Ibnu Abbas] bahwa [Dzu`aib Al Khuza'i] menceritakan bahwa Nabi shallallahu 'alaihi wasallam memberinya tugas untuk menjaga unta-unta beliau, kemudian beliau bersabda: \"Apabila di antara ternak tersebut ada yang sakit dan kamu khawatir ia akan mati, maka sembelihlah ia, kemudian rendamlah sepatunya ke dalam darahnya lalu pukulkanlah di sisi lehernya. dan janganlah kamu dan orang-orang yang bersamamu memakannya.\""},"3062":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ نَاجِيَةَ الْخُزَاعِيِّ قَالَ عَمْرٌو فِي حَدِيثِهِ وَكَانَ صَاحِبَ بُدْنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَصْنَعُ بِمَا عَطِبَ مِنْ الْبُدْنِ قَالَ انْحَرْهُ وَاغْمِسْ نَعْلَهُ فِي دَمِهِ ثُمَّ اضْرِبْ صَفْحَتَهُ وَخَلِّ بَيْنَهُ وَبَيْنَ النَّاسِ فَلْيَأْكُلُوهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] serta ['Amru bin Abdullah] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Najiyah Al Khuza'i]. 'Amru menyebutkan dalam haditsnya -salah seorang yang bertugas menjaga hewan kurban milik Nabi shallallahu 'alaihi wasallam- ia berkata, \"Aku bertanya, \"Wahai Rasulullah, apa yang harus aku perbuat jika sebagian hewan kurban terkena penyakit?\" beliau menjawab: \"Sembelihlah ia, rendamlah sepatunya ke dalam darahnya kemudian pukulkankan di sisi lehernya dan biarkanlah orang-orang memakannya.\""},"3063":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُمَرَ بْنِ سَعِيدِ بْنِ أَبِي حُسَيْنٍ عَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَ عَنْ عَلْقَمَةَ بْنِ نَضْلَةَ قَالَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ وَمَا تُدْعَى رِبَاعُ مَكَّةَ إِلَّا السَّوَائِبَ مَنْ احْتَاجَ سَكَنَ وَمَنْ اسْتَغْنَى أَسْكَنَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isa bin Yunus] dari [Umar bin Sa'id bin Abu Husain] dari [Utsman bin Abu Sulaiman] dari ['Alqamah bin Nadllah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah wafat, begitu juga Abu Bakar dan Umar, dan tidaklah rumah-rumah yang ada di Makkah didatangi, kecuali tempat-tempat itu kosong, siapa yang membutuhkan maka ia berhak untuk menempatinya, namun jika ia tidak membutuhkannya maka ia memberikan tempat tersebut (kepada yang lainnya).\""},"3064":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ أَخْبَرَنِي عُقَيْلٌ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ أَنَّهُ قَالَ إِنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَدِيِّ بْنِ الْحَمْرَاءِ قَالَ لَهُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى نَاقَتِهِ وَاقِفٌ بِالْحَزْوَرَةِ يَقُولُ وَاللَّهِ إِنَّكِ لَخَيْرُ أَرْضِ اللَّهِ وَأَحَبُّ أَرْضِ اللَّهِ إِلَيَّ وَاللَّهِ لَوْلَا أَنِّي أُخْرِجْتُ مِنْكِ مَا خَرَجْتُ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] telah memberitakan kepada kami [Al Laits bin Sa'd] telah mengabarkan kepadaku ['Uqail] dari [Muhammad bin Muslim] bahwa dia berkata; bahwasanya [Abu Salamah bin Abdurrahman bin 'Auf] mengabarkan kepadanya, bahwa [Abdullah bin 'Adi bin Al Hamra`] berkata kepadanya, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam di atas untanya berhenti di dekat Al Hazwarah, beliau bersabda: \"Demi Allah, sungguh kamu adalah sebaik-baik bumi Allah dan bumi Allah yang paling aku cintai. Demi Allah, seandainya aku tidak di keluarkan darimu, tentu aku tidak akan keluar.\""},"3065":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنَا أَبَانُ بْنُ صَالِحٍ عَنْ الْحَسَنِ بْنِ مُسْلِمِ بْنِ يَنَّاقٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَامَ الْفَتْحِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ اللَّهَ حَرَّمَ مَكَّةَ يَوْمَ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ فَهِيَ حَرَامٌ إِلَى يَوْمِ الْقِيَامَةِ لَا يُعْضَدُ شَجَرُهَا وَلَا يُنَفَّرُ صَيْدُهَا وَلَا يَأْخُذُ لُقْطَتَهَا إِلَّا مُنْشِدٌ فَقَالَ الْعَبَّاسُ إِلَّا الْإِذْخِرَ فَإِنَّهُ لِلْبُيُوتِ وَالْقُبُورِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الْإِذْخِرَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Yunus bin Bukair] telah menceritakan kepada kami [Muhammad bin Ishaq] telah menceritakan kepada kami [Aban bin Shalih] dari [Al Hasan bin Muslim bin Yannaq] dari [Shafiyyah binti Syaibah] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam berkhutbah pada saat penaklukan kota Makkah, beliau bersabda: \"Wahai manusia, sesungguhnya Allah telah mengharamkan (mensucikan) Makkah semenjak mencipatakan langit dan bumi, dan dia suci sampai hari kiamat; tidak dicabut pohonnya, tidak diusir hewan buruannya dan tidak diambil barang temuannya kecuali orang yang hendak mengumumkannya.\" 'Abbas berkata, \"Kecuali idzkhir, sesungguhnya ia untuk rumah-rumah dan kuburan.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kecuali idzkhir.\""},"3066":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَابْنُ الْفُضَيْلِ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ سَابِطٍ عَنْ عَيَّاشِ بْنِ أَبِي رَبِيعَةَ الْمَخْزُومِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ هَذِهِ الْأُمَّةُ بِخَيْرٍ مَا عَظَّمُوا هَذِهِ الْحُرْمَةَ حَقَّ تَعْظِيمِهَا فَإِذَا ضَيَّعُوا ذَلِكَ هَلَكُوا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dan [Ibnu Al Fudlail] dari [Yazid bin Abu Ziyad] telah memberitakan kepada kami [Abdurrahman bin Sabith] dari ['Ayyasy bin Abu Rabi'ah Al Makhzumi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ummat ini akan senantiasa dalam kebaikan selama mereka mengagungkan tanah haram ini dengan sebaik-baik pengagungan, dan apabila mereka menyia-nyiakannya maka mereka akan binasa.\""},"3067":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْإِيمَانَ لَيَأْرِزُ إِلَى الْمَدِينَةِ كَمَا تَأْرِزُ الْحَيَّةُ إِلَى جُحْرِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari ['Ubaidullah bin Umar] dari [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya keimanan akan masuk ke dalam kota Madinah seperti seekor ular yang masuk ke dalam sarangnya.\""},"3068":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَمُوتَ بِالْمَدِينَةِ فَلْيَفْعَلْ فَإِنِّي أَشْهَدُ لِمَنْ مَاتَ بِهَا","id":"Telah menceritakan kepada kami [Bakr bin Khalaf] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepada kami [Ayahku] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian mampu meninggal dunia di kota Madinah hendaknya ia melaksanakannya, sesungguhnya aku akan bersaksi bagi siapa saja yang meninggal di kota Madinah.\""},"3069":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ إِنَّ إِبْرَاهِيمَ خَلِيلُكَ وَنَبِيُّكَ وَإِنَّكَ حَرَّمْتَ مَكَّةَ عَلَى لِسَانِ إِبْرَاهِيمَ اللَّهُمَّ وَأَنَا عَبْدُكَ وَنَبِيُّكَ وَإِنِّي أُحَرِّمُ مَا بَيْنَ لَابَتَيْهَاقَالَ أَبُو مَرْوَانَ لَابَتَيْهَا حَرَّتَيْ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al 'Utsmani] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala` bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya Ibrahim adalah kekasih dan Nabi-Mu, dan Engkau telah mengharamkan kota Makkah melalui lisan Ibrahim. Ya Allah, aku adalah hamba dan Nabi-Mu, dan aku mengharamkan apa-apa yang berada di antara dua lembah berbatu (Madinah).\" Abu Marwan berkata, \"Yang dimaksud dua lembah berbatu adalah kedua sisi kota Madinah.\""},"3070":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَرَادَ أَهْلَ الْمَدِينَةِ بِسُوءٍ أَذَابَهُ اللَّهُ كَمَا يَذُوبُ الْمِلْحُ فِي الْمَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin berbuat buruk terhadap penduduk kota Madinah, niscaya Allah akan meleburkannya sebagaimana meleburnya garam di dalam air.\""},"3071":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ مِكْنَفٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أُحُدًا جَبَلٌ يُحِبُّنَا وَنُحِبُّهُ وَهُوَ عَلَى تُرْعَةٍ مِنْ تُرَعِ الْجَنَّةِ وَعَيْرٌ عَلَى تُرْعَةٍ مِنْ تُرَعِ النَّارِ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami ['Abdah] dari [Muhammad bin Ishaq] dari [Abdullah bin Miknaf] dia berkata; saya mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Uhud adalah suatu gunung yang mencintai kita dan kita pun mencintainya, dan ia merupakan salah satu pintu dari pintu-pintu surga atau kecelakaan (yang dapat mengantarkan) ke salah satu pintu dari pintu-pintu Neraka.\""},"3072":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ الشَّيْبَانِيِّ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ شَقِيقٍ قَالَبَعَثَ رَجُلٌ مَعِيَ بِدَرَاهِمَ هَدِيَّةً إِلَى الْبَيْتِ قَالَ فَدَخَلْتُ الْبَيْتَ وَشَيْبَةُ جَالِسٌ عَلَى كُرْسِيٍّ فَنَاوَلْتُهُ إِيَّاهَا فَقَالَ لَهُ أَلَكَ هَذِهِ قُلْتُ لَا وَلَوْ كَانَتْ لِي لَمْ آتِكَ بِهَا قَالَ أَمَا لَئِنْ قُلْتَ ذَلِكَ لَقَدْ جَلَسَ عُمَرُ بْنُ الْخَطَّابِ مَجْلِسَكَ الَّذِي جَلَسْتَ فِيهِ فَقَالَ لَا أَخْرُجُ حَتَّى أَقْسِمَ مَالَ الْكَعْبَةِ بَيْنَ فُقَرَاءِ الْمُسْلِمِينَ قُلْتُ مَا أَنْتَ فَاعِلٌ قَالَ لَأَفْعَلَنَّ قَالَ وَلِمَ ذَاكَ قُلْتُ لِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ رَأَى مَكَانَهُ وَأَبُو بَكْرٍ وَهُمَا أَحْوَجُ مِنْكَ إِلَى الْمَالِ فَلَمْ يُحَرِّكَاهُ فَقَامَ كَمَا هُوَ فَخَرَجَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Muharibi] dari [As Syaibani] dari [Washil Al Ahdab] dari [Syaqiq] dia berkata, \"Seorang laki-laki menitipkan dirham kepadaku untuk dihadiahkan kepada Ka'bah, ternyata Syaibah tengah duduk-duduk di atas kursi, lalu kuserahkan uang itu kepadanya, Syaibah pun bertanya, \"Apakah uang ini milikmu?\" aku menjawab, \"Bukan, seandainya itu milikku, niscaya tidak akan kuserahkan kepadamu.\" [Syaibah] berkata, \"Jika kamu mengatakan hal itu, sungguh Umar bin Khatthab pernah duduk di tempat yang engkau duduki, ia mengatakan, 'Aku tidak akan keluar hingga kubagi-bagikan harta Ka'bah kepada orang-orang fakir kaum Muslimin.' Aku (Syu'bah) pun bertanya, \"Kenapa kamu melakukannya?\" Umar menjawab, \"Sungguh aku akan tetap melakukannya.\" Umar melanjutkan, \"Memang ada apa?\" Aku (Syu'bah) menjawab, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam melihat keadaannya, begitu juga Abu Bakar, keduanya lebih membutuhkan uang tersebut daripada kamu, sehingga keduanya tidak melakukannya.\" Lalu Syu'bah berdiri dan pergi keluar.\""},"3073":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ زَيْدٍ الْعَمِّيُّ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ رَمَضَانَ بِمَكَّةَ فَصَامَ وَقَامَ مِنْهُ مَا تَيَسَّرَ لَهُ كَتَبَ اللَّهُ لَهُ مِائَةَ أَلْفِ شَهْرِ رَمَضَانَ فِيمَا سِوَاهَا وَكَتَبَ اللَّهُ لَهُ بِكُلِّ يَوْمٍ عِتْقَ رَقَبَةٍ وَكُلِّ لَيْلَةٍ عِتْقَ رَقَبَةٍ وَكُلِّ يَوْمٍ حُمْلَانَ فَرَسٍ فِي سَبِيلِ اللَّهِ وَفِي كُلِّ يَوْمٍ حَسَنَةً وَفِي كُلِّ لَيْلَةٍ حَسَنَةً","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] telah menceritakan kepada kami [Abdurrahim bin Zaid Al 'Ammi] dari [Ayahnya] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjumpai Ramadan di kota Makkah, kemudian dia berpuasa dan melaksanakan qiyamullail semampunya, maka Allah akan menuliskan baginya seratus ribu bulan Ramadan selainnya, dan Allah akan menuliskan baginya setiap hari sepertimemerdekakan budak, dan setiap malam memerdekakan budak, dan setiap hari menunggang kuda di jalan Allah (perang), dan setiap hari satu kebaikan dan setiap malam satu kebaikan.\""},"3074":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا دَاوُدُ بْنُ عَجْلَانَ قَالَ طُفْنَا مَعَ أَبِي عِقَالٍ فِي مَطَرٍ فَلَمَّا قَضَيْنَا طَوَافَنَا أَتَيْنَا خَلْفَ الْمَقَامِ فَقَالَطُفْتُ مَعَ أَنَسِ بْنِ مَالِكٍ فِي مَطَرٍ فَلَمَّا قَضَيْنَا الطَّوَافَ أَتَيْنَا الْمَقَامَ فَصَلَّيْنَا رَكْعَتَيْنِ فَقَالَ لَنَا أَنَسٌ ائْتَنِفُوا الْعَمَلَ فَقَدْ غُفِرَ لَكُمْ هَكَذَا قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطُفْنَا مَعَهُ فِي مَطَرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] telah menceritakan kepada kami [Daud bin 'Ajlan] dia berkata, \"Kami pernah thawaf bersama Abu 'Iqal ketika hujan turun, selesai thawaf kami menuju belakang maqam.\" kemudian [Abu 'Iqal] berkata, \"Aku juga pernah thawaf dengan [Anas bin Malik] ketika hujan turun, selesai thawaf kami menuju ke belakang maqam dan shalat dua rakaat, setelah itu Anas berkata kepada kami, \"Mulailah untuk melakukan amalan, sesungguhnya kalian telah diampuni. Seperti inilah Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami dan kami melakukan thawaf di waktu hujan.\""},"3075":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ حَفْصٍ الْأُبُلِّيُّ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ حَمْزَةَ بْنِ حَبِيبٍ الزَّيَّاتِ عَنْ حُمْرَانَ بْنِ أَعْيَنَ عَنْ أَبِي الطُّفَيْلِ عَنْ أَبِي سَعِيدٍ قَالَحَجَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ مُشَاةً مِنْ الْمَدِينَةِ إِلَى مَكَّةَ وَقَالَ ارْبُطُوا أَوْسَاطَكُمْ بِأُزُرِكُمْ وَمَشَى خِلْطَ الْهَرْوَلَةِ","id":"Telah menceritakan kepada kami [Isma'il bin Hafsh Al Ubulli] telah menceritakan kepada kami [Yahya bin Yaman] dari [Hamzah bin Habib Az Zayyat] dari [Humran bin A'yan] dari [Abu At Thufail] dari [Abu Sa'id] dia berkata, \"Nabi shallallahu 'alaihi wasallam dan para sahabatnya menunaikan haji dengan berjalan kaki dari Madinah sampai ke Makkah, lalu beliau bersabda: 'Ikatlah tengah-tengah kalian dengan sarung-sarung kalian.' Kemudian beliau berjalan cepat.\""},"3076":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنِي أَبِي ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُضَحِّي بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ وَيُسَمِّي وَيُكَبِّرُ وَلَقَدْ رَأَيْتُهُ يَذْبَحُ بِيَدِهِ وَاضِعًا قَدَمَهُ عَلَى صِفَاحِهِمَا","id":"Telah menceritakan kepada kami [Nahsr bin Ali Al Jahdlami] telah menceritakan kepadaku [Ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] saya mendengar [Qatadah] menceritakan dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih dua ekor kambing belang (putih hitam) dan bertanduk, lalu beliau membaca basmallah dan bertakbir. Sungguh aku telah melihat beliau menyembelih hewan kurbannya dengan tangannya sendiri sambil meletakkan kakinya di atas leher hean kurbannya.\""},"3077":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي عَيَّاشٍ الزُّرَقِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عِيدٍ بِكَبْشَيْنِ فَقَالَ حِينَ وَجَّهَهُمَا إِنِّي وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَوَاتِ وَالْأَرْضَ حَنِيفًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا أَوَّلُ الْمُسْلِمِينَ اللَّهُمَّ مِنْكَ وَلَكَ عَنْ مُحَمَّدٍ وَأُمَّتِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Abu 'Ayyasy Az Zuraqi] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyembelih dua ekor kambing kurban pada waktu Idul Kurban. Saat menghadapkan keduanya beliau mengucapkan: \"Sesungguhnya Aku menghadapkan diriku kepada Rabb yang menciptakan langit dan bumi, dengan cenderung kepada agama yang benar, dan aku bukanlah termasuk orang-orang yang mempersekutukan Allah. Sesungguhnya shalatku, ibadatku, hidupku dan matiku hanyalah untuk Allah, Tuhan semesta alam. Tiada sekutu bagi-Nya; dan demikian Itulah yang diperintahkan kepadaku dan aku adalah orang yang pertama-tama menyerahkan diri (kepada Allah). Ya Allah (ini adalah) dari-Mu dan untuk-Mu, dari Muhammad dan ummatnya.\""},"3078":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ وَعَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يُضَحِّيَ اشْتَرَى كَبْشَيْنِ عَظِيمَيْنِ سَمِينَيْنِ أَقْرَنَيْنِ أَمْلَحَيْنِ مَوْجُوءَيْنِ فَذَبَحَ أَحَدَهُمَا عَنْ أُمَّتِهِ لِمَنْ شَهِدَ لِلَّهِ بِالتَّوْحِيدِ وَشَهِدَ لَهُ بِالْبَلَاغِ وَذَبَحَ الْآخَرَ عَنْ مُحَمَّدٍ وَعَنْ آلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Sufyan Ats Tsauri] dari [Abdullah bin Muhammad bin 'Aqil] dari [Abu Salamah] dari [Aisyah] dan dari [Abu Hurairah], bahwa apabila Rasulullah shallallahu 'alaihi wasallam hendak melaksanakan kurban, maka beliau membeli dua ekor domba yang besar, gemuk, bertanduk dan berwarna belang (hitam dan putih). Kemudian beliau menyembelih salah satunya untuk umatnya yang telah bersaksi akan keesaan Allah dan bersaksi atas risalah beliau, lalu menyembelih yang satunya untuk Muhammad dan keluarga Muhammad shallallahu 'alaihi wasallam.\""},"3079":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَيَّاشٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ لَهُ سَعَةٌ وَلَمْ يُضَحِّ فَلَا يَقْرَبَنَّ مُصَلَّانَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Al Hubbab] telah menceritakan kepada kami [Abdullah bin 'Ayyasy] dari [Abdurrahman Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki keluasaan (untuk berkorban) namun tidak berkorban, maka janganlah ia mendekati tempat shalat kami.\""},"3080":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَسَأَلْتُ ابْنَ عُمَرَ عَنْ الضَّحَايَا أَوَاجِبَةٌ هِيَ قَالَ ضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمُونَ مِنْ بَعْدِهِ وَجَرَتْ بِهِ السُّنَّةُحَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ حَدَّثَنَا جَبَلَةُ بْنُ سُحَيْمٍ قَالَ سَأَلْتُ ابْنَ عُمَرَ فَذَكَرَ مِثْلَهُ سَوَاءً","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad bin Sirin] dia berkata, \"Saya bertanya [Ibnu Umar] mengenai kurban, apakah ia wajib?\" Ibnu Umar lalu menjawab, \"Rasulullah shallallahu 'alaihi wasallam dan orang-orang muslim setelahnya melaksanakan kurban, namun mereka memberlakukannya sebagai sunnah.\" Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepada kami [Al Hajjaj bin Arthah] telah menceritakan kepada kami [Jabalah bin Suhaim] dia berkata, \"Saya bertanya [Ibnu Umar] …lalu dia menyebutkan hadits seperti di atas.\""},"3081":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ ابْنِ عَوْنٍ قَالَ أَنْبَأَنَا أَبُو رَمْلَةَ عَنْ مِخْنَفِ بْنِ سُلَيْمٍ قَالَكُنَّا وَقُوفًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ عَلَى كُلِّ أَهْلِ بَيْتٍ فِي كُلِّ عَامٍ أُضْحِيَّةً وَعَتِيرَةً أَتَدْرُونَ مَا الْعَتِيرَةُ هِيَ الَّتِي يُسَمِّيهَا النَّاسُ الرَّجَبِيَّةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Ibnu 'Aun] dia berkata; telah memberitakan kepada kami [Abu Ramlah] dari [Mikhnaf bin Sulaim] dia berkata, \"Kami sedang wukuf di Arafah di sisi Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Wahai manusia, sesungguhnya wajib atas setiap keluarga untuk berkurban dan menyembelih hewan kurban setiap tahunnya, tahukah kalian apa yang dimaksud dengan menyembelih hewan? Itulah yang biasa disebut-sebut oleh orang-orang dengan sebutan Rajabiyah (menyembelih hewan pada bulan Rajab).\""},"3082":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عَبْدُ اللَّهِ ابْنُ نَافِعٍ حَدَّثَنِي أَبُو الْمُثَنَّى عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا عَمِلَ ابْنُ آدَمَ يَوْمَ النَّحْرِ عَمَلًا أَحَبَّ إِلَى اللَّهِ عَزَّ وَجَلَّ مِنْ هِرَاقَةِ دَمٍ وَإِنَّهُ لَيَأْتِي يَوْمَ الْقِيَامَةِ بِقُرُونِهَا وَأَظْلَافِهَا وَأَشْعَارِهَا وَإِنَّ الدَّمَ لَيَقَعُ مِنْ اللَّهِ عَزَّ وَجَلَّ بِمَكَانٍ قَبْلَ أَنْ يَقَعَ عَلَى الْأَرْضِ فَطِيبُوا بِهَا نَفْسًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Abdullah bin Nafi'] telah menceritakan kepadaku [Abu Al Mutsanna] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada amalan yang dikerjakan anak Adam ketika hari (raya) kurban yang lebih dicintai oleh Allah Azza Wa Jalla dari mengalirkan darah, sesungguhnya pada hari kiamat ia akan datang dengan tanduk-tanduknya, kuku-kukunya dan bulu-bulunya. Dan sesungguhnya darah tersebut akan sampai kepada Allah Azza Wa Jalla sebelum jatuh ke tanah, maka perbaguslah jiwa kalian dengannya.\""},"3083":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا سَلَّامُ بْنُ مِسْكِينٍ حَدَّثَنَا عَائِذُ اللَّهِ عَنْ أَبِي دَاوُدَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ مَا هَذِهِ الْأَضَاحِيُّ قَالَ سُنَّةُ أَبِيكُمْ إِبْرَاهِيمَ قَالُوا فَمَا لَنَا فِيهَا يَا رَسُولَ اللَّهِ قَالَ بِكُلِّ شَعَرَةٍ حَسَنَةٌ قَالُوا فَالصُّوفُ يَا رَسُولَ اللَّهِ قَالَ بِكُلِّ شَعَرَةٍ مِنْ الصُّوفِ حَسَنَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al 'Asqalani] telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Sallam bin Miskin] telah menceritakan kepada kami [A'idzullah] dari [Abu Daud] dari [Zaid bin Arqam] dia berkata, \"Para sahabat Rasulullah shallallahu 'alaihi wasallam bertanya, \"Wahai Rasulullah, apakah maksud dari hewan-hewan kurban seperti ini?\" beliau bersabda: \"Ini merupakan sunnah (ajaran) bapak kalian, Ibrahim.\" Mereka bertanya, \"Wahai Rasulullah, lantas apa yang akan kami dapatkan dengannya?\" beliau menjawab: \"Setiap rambut terdapat kebaikan.\" Mereka berkata, \"Bagaimana dengan bulu-bulunya wahai Rasulullah?\" beliau menjawab: \"Dari setiap rambut pada bulu-bulunya terdapat suatu kebaikan.\""},"3084":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشٍ أَقْرَنَ فَحِيلٍ يَأْكُلُ فِي سَوَادٍ وَيَمْشِي فِي سَوَادٍ وَيَنْظُرُ فِي سَوَادٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Hafsh bin Ghiyast] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkurban dengan seekor kambing kibas pejantan (kuat) yang bertanduk dan sekitar mulutnya berwarna hitam, kaki-kakinya berwarna hitam dan di sekitar matanya juga berwarna hitam.\""},"3085":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ أَخْبَرَنِي سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا يُونُسُ بْنُ مَيْسَرَةَ بْنِ حَلْبَسٍ قَالَخَرَجْتُ مَعَ أَبِي سَعِيدٍ الزُّرَقِيِّ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شِرَاءِ الضَّحَايَا قَالَ يُونُسُ فَأَشَارَ أَبُو سَعِيدٍ إِلَى كَبْشٍ أَدْغَمَ لَيْسَ بِالْمُرْتَفِعِ وَلَا الْمُتَّضِعِ فِي جِسْمِهِ فَقَالَ لِي اشْتَرِ لِي هَذَا كَأَنَّهُ شَبَّهَهُ بِكَبْشِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Muhammad bin Syu'aib] telah mengabarkan kepadaku [Sa'id bin Abdul Aziz] telah menceritakan kepada kami [Yunus bin Maisarah bin Halbas] dia berkata, \"Aku pergi bersama [Abu Sa'id Az Zuraqi] seorang sahabat Rasulullah shallallahu 'alaihi wasallam, untuk membeli beberapa hewan kurban.\" Yunus melanjutkan, \"Abu Sa'id lalu menunjuk ke arah seekor kambing kibas yang sedikit warna hitamnya, yang tidak tinggi dan tidak kurus badannya, lalu ia berkata kepadaku, 'Belikanlah saya yang seperti ini.' Sepertinya dia menyamakan dengan kibas Rasulullah shallallahu 'alaihi wasallam.\""},"3086":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو عَائِذٍ أَنَّهُ سَمِعَ سُلَيْمَ بْنَ عَامِرٍ يُحَدِّثُ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الْكَفَنِ الْحُلَّةُ وَخَيْرُ الضَّحَايَا الْكَبْشُ الْأَقْرَنُ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Utsman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abu A'idz] bahwa dia mendengar [Sulaim bin 'Amir] menceritakan dari [Abu Umamah Al Bahili], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kain kafan adalah hullah (kain yang lembut) dan sebaik-baik kurban adalah kambing kibasyang bertanduk.\""},"3087":{"ar":"حَدَّثَنَا هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى أَنْبَأَنَا الْحُسَيْنُ بْنُ وَاقِدٍ عَنْ عِلْبَاءَ بْنِ أَحْمَرَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَحَضَرَ الْأَضْحَى فَاشْتَرَكْنَا فِي الْجَزُورِ عَنْ عَشَرَةٍ وَالْبَقَرَةِ عَنْ سَبْعَةٍ","id":"Telah menceritakan kepada kami [Hadiyyah bin Abdul Wahhab] telah memberitakan kepada kami [Al Fadl bin Musa] telah memberitakan kepada kami [Al Husain bin Waqid] dari ['Ilba` bin Ahmar] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, kemudian beliau mendatangi hewan kurban (menyembelih). Maka kami turut berkurban dengan seekor unta betina untuk sepuluh orang dan seekor sapi untuk tujuh orang.\""},"3088":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَحَرْنَا بِالْحُدَيْبِيَةِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَدَنَةَ عَنْ سَبْعَةٍ وَالْبَقَرَةَ عَنْ سَبْعَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] dari [Malik bin Anas] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Kami berkurban seekor unta untuk tujuh orang dan sapi juga untuk tujuh orang ketika berada di Hudaibiyyah.\""},"3089":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَذَبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّنْ اعْتَمَرَ مِنْ نِسَائِهِ فِي حَجَّةِ الْوَدَاعِ بَقَرَةً بَيْنَهُنَّ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyembelih seekor sapi untuk isteri-isteri yang sedang menunaikan 'Umrah di waktu haji Wada'.\""},"3090":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِي حَاضِرٍ الْأَزْدِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَلَّتْ الْإِبِلُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُمْ أَنْ يَنْحَرُوا الْبَقَرَ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari ['Amru bin Maimun] dari [Abu Hadlir Al Azdi] dari [Ibnu Abbas] dia berkata, \"Saat jumlah unta terbatas pada zaman Rasulullah shallallahu 'alaihi wasallam, maka beliau memerintahkan mereka menyembelih sapi.\""},"3091":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ أَبُو طَاهِرٍ أَنْبَأَنَا ابْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحَرَ عَنْ آلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ بَقَرَةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh Al Mishri Abu Thahir] telah memberitakan kepada kami [Ibnu Wahb] telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab] dari ['Amrah] dari [Asiyah], bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih seekor sapi untuk keluarga Muhammad shallallahu 'alaihi wasallam saat melaksanakan haji wada'.\""},"3092":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ قَالَ عَطَاءٌ الْخُرَاسَانِيُّ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُ رَجُلٌ فَقَالَ إِنَّ عَلَيَّ بَدَنَةً وَأَنَا مُوسِرٌ بِهَا وَلَا أَجِدُهَا فَأَشْتَرِيَهَا فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبْتَاعَ سَبْعَ شِيَاهٍ فَيَذْبَحَهُنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Muhammad bin Bakr Al Bursani] telah menceritakan kepada kami [Ibnu Juraij] dia berkata; ['Atha Al Khurasani] berkata dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam didatangi oleh seorang laki-laki seraya berkata, \"Aku berkewajiban untuk menyembelih seekor unta dan aku mampu untuk membelinya, namun aku tidak bisa mendapatkannya?\" Nabi shallallahu 'alaihi wasallam lalu memerintahkannya untuk membeli tujuh ekor kambing dan menyembelihnya.\""},"3093":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا الْمُحَارِبِيُّ وَعَبْدُ الرَّحِيمِ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ و حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ بِذِي الْحُلَيْفَةِ مِنْ تِهَامَةَ فَأَصَبْنَا إِبِلًا وَغَنَمًا فَعَجِلَ الْقَوْمُ فَأَغْلَيْنَا الْقُدُورَ قَبْلَ أَنْ تُقْسَمَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهَا فَأُكْفِئَتْ ثُمَّ عَدَلَ الْجَزُورَ بِعَشَرَةٍ مِنْ الْغَنَمِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Al Muharibi] dan [Abdurrahim] dari [Sufyan At Tsauri] dari [Sa'id bin Masruq] dan telah menceritakan kepada kami [Al Husain bin Ali] dari [Zaidah] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari [Rafi' bin Khadij] dia berkata, \"Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam di Dzul Khulaifah -bagian dari daerah Tihamah-, kami menangkap seekor unta dan kambing, maka orang-orang pun segera menyembelihnya dan menyalakan tungku api (untuk masak) sebelum dibagi-bagikan. Kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi kami dan memerintahkan untuk menumpahkannya, maka periuk itu pun ditumpahkan. Kemudian beliau menyamakan (dalam pembagiannya) satu ekor unta dengan sepuluh kambing.\""},"3094":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ غَنَمًا فَقَسَمَهَا عَلَى أَصْحَابِهِ ضَحَايَا فَبَقِيَ عَتُودٌ فَذَكَرَهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِّ بِهِ أَنْتَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir Al Juhani], bahwa Rasulullah shallallahu 'alaihi wasallam memberinya beberapa ekor kambing, lalu beliau membagi-bagikannya kepada para sahabat hingga tidak ada yang tersisa kecuali hanya seekor kambing yang masih muda. Kemudian hal itu diberitahukan kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Berkurbanlah kamu dengan kambing itu.\""},"3095":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي يَحْيَى مَوْلَى الْأَسْلَمِيِّينَ عَنْ أُمِّهِ قَالَتْ حَدَّثَتْنِي أُمُّ بِلَالٍ بِنْتُ هِلَالٍ عَنْ أَبِيهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجُوزُ الْجَذَعُ مِنْ الضَّأْنِ أُضْحِيَّةً","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Anas bin 'Iyadl] telah menceritakan kepadaku [Muhammad bin Abu Yahya] bekas budak Al Aslamiyyiin, dari [ibunya] dia berkata, telah menceritakan kepadaku [Ummu Bilal binti Hilal] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Jad'u (kambing yang berusia enam bulan hingga satu tahun) dari seekor kambing boleh digunakan untuk berkurban.\""},"3096":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ قَالَكُنَّا مَعَ رَجُلٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ مُجَاشِعٌ مِنْ بَنِي سُلَيْمٍ فَعَزَّتْ الْغَنَمُ فَأَمَرَ مُنَادِيًا فَنَادَى أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِنَّ الْجَذَعَ يُو��ِي مِمَّا تُوفِي مِنْهُ الثَّنِيَّةُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ats Tsauri] dari ['Ashim bin Kulaib] dari [Ayahnya] dia berkata, \"Kami bersama dengan salah seorang dari sahabat Nabi shallallahu 'alaihi wasallam yang dikenal dengan [Mujasyi'] dari Bani Sulaim, saat kambing sangat sulit didapat maka ia memerintahkan seseorang untuk berseru, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya al Jadza' dapat menggantikan kambing yang berumur dua tahun.\" "},"3097":{"ar":"حَدَّثَنَا هَارُونُ بْنُ حَيَّانَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ أَنْبَأَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَذْبَحُوا إِلَّا مُسِنَّةً إِلَّا أَنْ يَعْسُرَ عَلَيْكُمْ فَتَذْبَحُوا جَذَعَةً مِنْ الضَّأْنِ","id":"Telah menceritakan kepada kami [Harun bin Hayyan] telah menceritakan kepada kami [Abdurrahman bin Abdullah] telah memberitakan kepada kami [Zuhair] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyembelih kecuali Musinnah (kambing yang telah berusia dua tahun), kecuali jika kalian kesulitan mendapatkannya, maka sembelihlah kambing jadza'ah.\" "},"3098":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ شُرَيْحِ بْنِ النُّعْمَانِ عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُضَحَّى بِمُقَابَلَةٍ أَوْ مُدَابَرَةٍ أَوْ شَرْقَاءَ أَوْ خَرْقَاءَ أَوْ جَدْعَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Abu Ishaq] dari [Syuraih bin An Nu'man] dari [Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menyembelih hewan kurban yang ujung telinganya terpotong, pangkal telinganya terpotong, telinganya terbelah, kharqa` (yang telinganya dibakar sebagai tanda) atau Jad'a` (hewan telinga atau hidungnya terpotong).\""},"3099":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجَيَّةَ بْنِ عَدِيٍّ عَنْ عَلِيٍّ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَشْرِفَ الْعَيْنَ وَالْأُذُنَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Salamah bin Kuhail] dari [Hujjayah bin 'Adi] dari [Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami supaya meneliti mata dan telinga (hewan kurban).\""},"3100":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ وَأَبُو دَاوُدَ وَابْنُ أَبِي عَدِيٍّ وَأَبُو الْوَلِيدِ قَالُوا حَدَّثَنَا شُعْبَةُ سَمِعْتُ سُلَيْمَانَ بْنَ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ عُبَيْدَ بْنَ فَيْرُوزَ قَالَقُلْتُ لِلْبَرَاءِ بْنِ عَازِبٍ حَدِّثْنِي بِمَا كَرِهَ أَوْ نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَضَاحِيِّ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا بِيَدِهِ وَيَدِي أَقْصَرُ مِنْ يَدِهِ أَرْبَعٌ لَا تُجْزِئُ فِي الْأَضَاحِيِّ الْعَوْرَاءُ الْبَيِّنُ عَوَرُهَا وَالْمَرِيضَةُ الْبَيِّنُ مَرَضُهَا وَالْعَرْجَاءُ الْبَيِّنُ ظَلْعُهَا وَالْكَسِيرَةُ الَّتِي لَا تُنْقِيقَالَ فَإِنِّي أَكْرَهُ أَنْ يَكُونَ نَقْصٌ فِي الْأُذُنِ قَالَ فَمَا كَرِهْتَ مِنْهُ فَدَعْهُ وَلَا تُحَرِّمْهُ عَلَى أَحَدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] dan [Abdurrahman] dan [Abu Daud] dan [Ibnu Abu 'Adi] dan [Abu Al Walid] mereka berkata; telah menceritakan kepada kami [Syu'bah] saya mendengar [Sulaiman bin Abdurrahman] berkata; saya mendengar ['Ubaid bin Fairuz] berkata, \"Saya berkata kepada [Al Barra` bin 'Azib], \"Bacakanlah kepadaku hadits tentang apa yang dibenci atau dilarang oleh Rasulullah shallallahu 'alaihi wasallam dari hewan kurban! \" Al Barra` menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda seperti ini -sambil memperagakan dengan tangannya, dan tanganku lebih pendek dari tangan beliau- beliau katakan: \"Empat jenis yang tidak bisa dijadikan hewan kurban; hewan yang matanya buta sebelah dan kebutaannya itu nampak jelas, hewan yang jelas-jelas sakit, yang jelas-jelas pincangnya dan yang patah sumsumnya.\" Al Barra` berkata, \"Aku sungguh membenci hewan yang cacat pada telinganya.\" Dia berkata, \"Apa yang kamu benci tinggalkanlah dan janganlah kamu mengharamkannya kepada siapa pun juga.\""},"3101":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ أَنَّهُ ذَكَرَ أَنَّهُ سَمِعَ جُرَيَّ بْنَ كُلَيْبٍ يُحَدِّثُ أَنَّهُ سَمِعَ عَلِيًّا يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُضَحَّى بِأَعْضَبِ الْقَرْنِ وَالْأُذُنِ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dia menyebutkan bahwa dirinya pernah mendengar [Jurayya bin Kulaib] menceritakan bahwa dia mendengar [Ali] menceritakan, bahwa Rasulullah shallallahu 'alaihi wasallam melarang berkurban dengan hewan yang tanduk dan telinganya terpotong (cacat).\""},"3102":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ أَبُو بَكْرٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ الثَّوْرِيِّ عَنْ جَابِرِ بْنِ يَزِيدَ عَنْ مُحَمَّدِ بْنِ قَرَظَةَ الْأَنْصَارِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَابْتَعْنَا كَبْشًا نُضَحِّي بِهِ فَأَصَابَ الذِّئْبُ مِنْ أَلْيَتِهِ أَوْ أُذُنِهِ فَسَأَلْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنَا أَنْ نُضَحِّيَ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Muhammad bin Abdul Malik Abu Bakr] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] dari [Ats Tsauri] dari [Jabir bin Yazid] dari [Muhammad bin Qarazhah Al Anshari] dari [Abu Sa'id Al Khudri] dia berkata, \"Kami membeli kambing untuk berkurban, lantas ada seekor serigala yang memakan ekor kambing tersebut atau telinganya, maka kami bertanya kepada Nabi shallallahu 'alaihi wasallam, beliau pun memerintahkan supaya kami menyembelihnya (berkurban dengannya).\""},"3103":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ عُمَارَةَ بْنِ عَبْدِ اللَّهِ بْنِ صَيَّادٍ عَنْ عَطَاءِ بْنِ يَسَارٍ قَالَسَأَلْتُ أَبَا أَيُّوبَ الْأَنْصَارِيَّ كَيْفَ كَانَتْ الضَّحَايَا فِيكُمْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ الرَّجُلُ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُضَحِّي بِالشَّاةِ عَنْهُ وَعَنْ أَهْلِ بَيْتِهِ فَيَأْكُلُونَ وَيُطْعِمُونَ ثُمَّ تَبَاهَى النَّاسُ فَصَارَ كَمَا تَرَى","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah menceritakan kepadaku [Adl Dlahak bin Utsman] dari ['Umarah bin Abdullah bin Shayyad] dari ['Atha bin Yasar] dia berkata, \"Saya bertanya kepada [Abu Ayyub Al Anshari], \"Bagaimanakah dengan hewan kurban kalian pada masa Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab, \"Pada masa Nabi shallallahu 'alaihi wasallam, seseorang berkurban dengan seekor kambing untuk dirinya sendiri dan keluarganya, lalu mereka memakan (sebagiannya) dan memberi makan kepada orang lain sehingga orang-orang pun bergembira karenanya. Dan hal itu terus berlanjut sebagaimana yang kamu lihat seperti saat ini.\""},"3104":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَمُحَمَّدُ بْنُ يُوسُفَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ جَمِيعًا عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ بَيَانٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي سَرِيحَةَ قَالَحَمَلَنِي أَهْلِي عَلَى الْجَفَاءِ بَعْدَ مَا عَلِمْتُ مِنْ السُّنَّةِ كَانَ أَهْلُ الْبَيْتِ يُضَحُّونَ بِالشَّاةِ وَالشَّاتَيْنِ وَالْآنَ يُبَخِّلُنَا جِيرَانُنَا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah memberitakan kepada kami [Abdurrahman bin Mahdi] dan [Muhammad bin Yusuf]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] semuanya dari [Sufyan Ats Tsauri] dari [Bayan] dari [As Sya'bi] dari [Abu Sarihah] dia berkata, \"Keluargaku membuatku marah setelah kuketahui sunnah bahwa ahlul bait berkurban dengan satu atau dua kambing, dan sekarang tetangga kami menganggap bahwa kami adalah orang yang bakhil.\""},"3105":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ الْعَشْرُ وَأَرَادَ أَحَدُكُمْ أَنْ يُضَحِّيَ فَلَا يَمَسَّ مِنْ شَعَرِهِ وَلَا بَشَرِهِ شَيْئًا","id":"Telah menceritakan kepada kami [Harun bin Abdullah Al Hammal] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdurrahman bin Humaid bin Abdurrahman bin 'Auf] dari [Sa'id bin Al Musayyab] dari [Ummu Salamah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika telah masuk tanggal sepuluh (Dzul Hijjah), dan salah seorang dari kalian ingin berkurban, maka janganlah ia menyentuh rambut dan kulitnya (hewan kurban yang hendak disembelih) sedikitpun.\""},"3106":{"ar":"حَدَّثَنَا حَاتِمُ بْنُ بَكْرٍ الضَّبِّيُّ أَبُو عَمْرٍو حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدِ بْنِ يَزِيدَ بْنِ إِبْرَاهِيمَ حَدَّثَنَا أَبُو قُتَيْبَةَ وَيَحْيَى بْنُ كَثِيرٍ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عَمْرِو بْنِ مُسْلِمٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَأَى مِنْكُمْ هِلَالَ ذِي الْحِجَّةِ فَأَرَادَ أَنْ يُضَحِّيَ فَلَا يَقْرَبَنَّ لَهُ شَعَرًا وَلَا ظُفْرًا","id":"Telah menceritakan kepada kami [Hatim bin Bakr Ad Dlabbi Abu 'Amru] telah menceritakan kepada kami [Muhammad bin Bakr Al Bursani]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Sa'id bin Yazid bin Ibrahim] telah menceritakan kepada kami [Abu Qutaibah] dan [Yahya bin Katsir] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Malik bin Anas] dari ['Amru bin Muslim] dari [Sa'id bin Musayyab] dari [Ummu Salamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa salah seorang dari kalian melihat hilal di bulan Dzul Hijjah dan ia hendak berkurban, maka hendaknya ia tidak mendekati rambut dan kukunya.\""},"3107":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا ذَبَحَ يَوْمَ النَّحْرِ يَعْنِي قَبْلَ الصَّلَاةِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Ayyub] dari [Muhammad bin Sirin] dari [Anas bin Malik], bahwa pada hari raya kurban seorang laki-laki menyembelih hewan kurbannya sebelum shalat, maka Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya untuk mengulangi kurbannya.\""},"3108":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَسْوَدِ ابْنِ قَيْسٍ عَنْ جُنْدُبٍ الْبَجَلِيِّأَنَّهُ سَمِعَهُ يَقُولُ شَهِدْتُ الْأَضْحَى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَبَحَ أُنَاسٌ قَبْلَ الصَّلَاةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ ذَبَحَ مِنْكُمْ قَبْلَ الصَّلَاةِ فَلْيُعِدْ أُضْحِيَّتَه�� وَمَنْ لَا فَلْيَذْبَحْ عَلَى اسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Al Aswad bin Qais] dari [Jundub Al Bajjali] bahwa dia mendengar darinya berkata, \"Saya menyaksikan penyembelihan kurban bersama Rasulullah shallallahu 'alaihi wasallam, dan orang-orang menyembelih sebelum shalat. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian menyembelih sebelum shalat hendaknya ia mengulangi kurbannya, dan barangsiapa belum menyembelih hendaknya menyembelih dengan menyebut nama Allah.\""},"3109":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عُوَيْمِرِ بْنِ أَشْقَرَأَنَّهُ ذَبَحَ قَبْلَ الصَّلَاةِ فَذَكَرَهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعِدْ أُضْحِيَّتَكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Yahya bin Sa'id] dari ['Abbad bin Tamim] dari ['Uwaimir bin Asyqar], bahwa dia menyembelih kurbannya sebelum shalat (ied), lantas hal itu diberitahukan kepada Nabi shallallahu 'alaihi wasallam hingga beliau pun bersabda: \"Ulangilah kurbanmu itu.\""},"3110":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي زَيْدٍ قَالَ أَبُو بَكْرٍ وَقَالَ غَيْرُ عَبْدِ الْأَعْلَى عَنْ عَمْرِو بْنِ بُجْدَانَ عَنْ أَبِي زَيْدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى أَبُو مُوسَى حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا أَبِي عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ بُجْدَانَ عَنْ أَبِي زَيْدٍ الْأَنْصَارِيِّ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِدَارٍ مِنْ دُورِ الْأَنْصَارِ فَوَجَدَ رِيحَ قُتَارٍ فَقَالَ مَنْ هَذَا الَّذِي ذَبَحَ فَخَرَجَ إِلَيْهِ رَجُلٌ مِنَّا فَقَالَ أَنَا يَا رَسُولَ اللَّهِ ذَبَحْتُ قَبْلَ أَنْ أُصَلِّيَ لِأُطْعِمَ أَهْلِي وَجِيرَانِي فَأَمَرَهُ أَنْ يُعِيدَ فَقَالَ لَا وَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ مَا عِنْدِي إِلَّا جَذَعٌ أَوْ حَمَلٌ مِنْ الضَّأْنِ قَالَ اذْبَحْهَا وَلَنْ تُجْزِئَ جَذَعَةٌ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Khalid Al Khadza`] dari [Abu Qilabah] dari [Abu Zaid], [Abu Bakar] mengatakan -selain Abdul A'la juga berkata- dari ['Amru bin Bujdan] dari [Abu Zaid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna Abu Musa] telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami [Ayahku] dari [Khalid Al Khaddza`] dari [Abu Qilabah] dari ['Amru bin Bujdan] dari [Abu Zaid Al Anshari] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati rumah dari rumah-rumah penduduk Anshar, lalu beliau mencium aroma masakan, beliau pun bertanya: \"Siapakah orang yang sudah menyembelih?\" maka keluarlah seorang laki-laki Anshar seraya berkata, \"Aku wahai Rasulullah, aku menyembelih sebelum shalat karena hendak memberi makan keluarga dan tetanggaku.\" Maka beliau memerintahkan kepadanya untuk kembali mengulangi kurbannya, laki-laki itu berkata, \"Tidak, demi Allah yang tidak ada tuhan yang berhak disembah selain Dia, aku tidak memiliki kecuali Jadza' atau kambing yang lebih muda dari Jadza'.\" Maka beliau bersabda: \"Sembelihlah ia, dan tidak boleh ada lagi orang yang menyembelih Jadza' setelahmu.\" "},"3111":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ لَقَدْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْبَحُ أُضْحِيَّتَهُ بِيَدِهِ وَاضِعًا قَدَمَهُ عَلَى صِفَاحِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] saya mendengar [Qatadah] menceritakan dari [Anas bin Malik] dia berkata, \"Sungguh saya telah melihat Rasulullah shallallahu 'alaihi wasallam menyembelih hewan kurbannya dengan tangan beliau sendiri sambil meletakkan kaki beliau di leher hewan kurban tersebut.\""},"3112":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ مُؤَذِّنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَبَحَ أُضْحِيَّتَهُ عِنْدَ طَرَفِ الزُّقَاقِ طَرِيقِ بَنِي زُرَيْقٍ بِيَدِهِ بِشَفْرَةٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abdurrahman bin Sa'd bin 'Ammar bin Sa'd] muadzin Rasulullah shallallahu 'alaihi wasallam, telah menceritakan kepada kami [Ayahku] dari [Ayahnya] dari [Kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih hewan kurban disamping ujung lorong jalan Bani Zuraiq, dengan tangan beliau sendiri menggunakan parang.\""},"3113":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ أَنْبَأَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي الْحَسَنُ بْنُ مُسْلِمٍ أَنَّ مُجَاهِدًا أَخْبَرَهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى أَخْبَرَهُ أَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يَقْسِمَ بُدْنَهُ كُلَّهَا لُحُومَهَا وَجُلُودَهَا وَجِلَالَهَا لِلْمَسَاكِينِ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar] telah menceritakan kepada kami [Muhammad bin Bakr Al Bursani] telah memberitakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Al Hasan bin Muslim] bahwa [Mujahid] mengabarkan kepadanya, bahwa [Abdurrahman bin Abu Laila] telah mengabarkan kepadanya, bahwa [Ali bin Abu Thalib] mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan agar dia membagi-bagikan semua dari unta (kurbannya) baik berupa daging, kulit dan pelananya kepada orang-orang miskin.\""},"3114":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ مِنْ كُلِّ جَزُورٍ بِبَضْعَةٍ فَجُعِلَتْ فِي قِدْرٍ فَأَكَلُوا مِنْ اللَّحْمِ وَحَسَوْا مِنْ الْمَرَقِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir bin Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan dari setiap unta yang besar agar diambil sepotong dagingnya, kemudian sepotong daging tersebut diletakkan di dalam periuk, setelah itu mereka memakan dagingnya dan menghirup kuahnya (setelah masak).\""},"3115":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنَّمَا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُحُومِ الْأَضَاحِيِّ لِجَهْدِ النَّاسِ ثُمَّ رَخَّصَ فِيهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdurrahman bin 'Abis] dari [Ayahnya] dari [Aisyah] dia berkata, \"Nabi shallallahu 'alaihi wasallam melarang menyimpan daging kurban ketika orang-orang mengalami kesusahan hidup, kemudian beliau memberi keringanan (untuk menyimpannya).\""},"3116":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنْتُ نَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ فَوْقَ ثَلَاثَةِ أَيَّامٍ فَكُلُوا وَادَّخِرُوا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] dari [Khalid Al Khaddza`] dari [Abu Al Malih] dari [Nubaisyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku pernah melarang kalian menyimpan daging kurban lebih dari tiga hari, sekarang makan dan simpanlah.\""},"3117":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَذْبَحُ بِالْمُصَلَّى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Bakar Al Hanafi] telah menceritakan kepada kami [Usamah bin Zaid] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau menyembelih kurbannya di tempat shalat.\""},"3118":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَنْ الْغُلَامِ شَاتَانِ مُتَكَافِئَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Hisyam bin 'Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ubaidullah bin Abu Yazid] dari [Ayahnya] dari [Siba' bin Tsabit] dari [Ummu Kurzi] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Untuk anak lelaki dua ekor kambing yang sudah pantas, dan anak perempuan seekor kambing.\""},"3119":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَفْصَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَعُقَّ عَنْ الْغُلَامِ شَاتَيْنِ وَعَنْ الْجَارِيَةِ شَاةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Abdullah bin Utsman bin Hutsauim] dari [Yusuf bin Mahak] dari [Hafshah binti Abdurrahman] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk membuat aqiqah seorang anak laki-laki dengan dua ekor kambing, sedangkan untuk anak perempuan dengan satu ekor kambing.\""},"3120":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ سَلْمَانَ بْنِ عَامِرٍأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مَعَ الْغُلَامِ عَقِيقَةً فَأَهْرِيقُوا عَنْهُ دَمًا وَأَمِيطُوا عَنْهُ الْأَذَى","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Hisyam bin Hasan] dari [Hafshah binti Sirin] dari [Salman bin 'Amir], bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya bersama (lahirnya) seorang anak laki-laki ada kewajiban aqiqah, oleh karena itu tumpahkanlah darah untuknya dan singkirkan bahaya (penyakit) darinya.\""},"3121":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ غُلَامٍ مُرْتَهَنٌ بِعَقِيقَتِهِ تُذْبَحُ عَنْهُ يَوْمَ السَّابِعِ وَيُحْلَقُ رَأْسُهُ وَيُسَمَّى","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Syu'aib bin Ishaq] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Al Hasan] dari [Samrah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap anak tergadai dengan aqiqahnya, maka hendaklah disembelihkan untuknya pada hari ketujuh (dari kelahirannya), dicukur rambutnya dan diberi nama.\""},"3122":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ أَيُّوبَ بْنِ مُوسَى أَنَّهُ حَدَّثَهُ أَنَّ يَزِيدَ بْنَ عَبْدٍ الْمُزَنِيَّ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُعَقُّ عَنْ الْغُلَامِ وَلَا يُمَسُّ رَأْسُهُ بِدَمٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku ['Amru bin Al Harits] dari [Ayyub bin Musa] bahwa dia menceritakan kepadanya bahwa [Yazid bin Abdul Muzani] menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang anak diaqiqahi dan kepalanya tidak perlu disentuh (dilumuri) dengan darah (hewan kurbannya).\""},"3123":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ قَالَنَادَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً فِي الْجَاهِلِيَّةِ فِي رَجَبٍ فَمَا تَأْمُرُنَا قَالَ اذْبَحُوا لِلَّهِ عَزَّ وَجَلَّ فِي أَيِّ شَهْرٍ كَانَ وَبَرُّوا لِلَّهِ وَأَطْعِمُوا قَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نُفْرِعُ فَرَعًا فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا بِهِ قَالَ فِي كُلِّ سَائِمَةٍ فَرَعٌ تَغْذُوهُ مَاشِيَتُكَ حَتَّى إِذَا اسْتَحْمَلَ ذَبَحْتَهُ فَتَصَدَّقْتَ بِلَحْمِهِ أُرَهُ قَالَ عَلَى ابْنِ السَّبِيلِ فَإِنَّ ذَلِكَ هُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid Al Khaddza`] dari [Abu Al Malih] dari [Nubaisyah] dia berkata, \"Seorang laki-laki memanggil Rasulullah shallallahu 'alaihi wasallam, katanya, \"Wahai Rasulullah, di masa Jahiliyah kami biasa mempersembahkan kurban di bulan Rajab, lantas apa yang anda perintahkan kepada kami?\" beliau menjawab: \"Sembelihlah untuk Azza Wa Jalla pada bulan apa saja, dan berbuatlah kebajikan untuk Allah, serta berilah makan (kepada orang lain).\"Mereka berkata, \"Wahai Rasulullah, di masa Jahiliyyah kami bisa menyembelih fara', lantas apa yang sekiranya anda perintahkan untuk kami?\" beliau bersabda: \"Pada setiap Sa`imah ada fara' yang diasuh oleh ternakmu, sehingga jika ia telah besar maka kamu dapat menyembelihnya dan menyedekahkan dagingnya -Nubaisyah berkata; saya kira Rasulullah shallallahu 'alaihi wasallam bersabda- kepada Ibnu Sabil, sesungguhnya padanya ada kebaikan.\" "},"3124":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا فَرَعَةَ وَلَا عَتِيرَةَ قَالَ هِشَامٌ فِي حَدِيثِهِ وَالْفَرَعَةُ أَوَّلُ النَّتَاجِ وَالْعَتِيرَةُ الشَّاةُ يَذْبَحُهَا أَهْلُ الْبَيْتِ فِي رَجَبٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Hisyam bin 'Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada fara' dan tidak ada 'atirah.\" Hisyam menyebutkan dalam haditsnya, \"Fara' adalah anak pertama unta, yang baru lahir, sedangkan 'atirah adalah kambing yang disembelih oleh pemiliknya pada bulan Rajab.\""},"3125":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا فَرَعَةَ وَلَا عَتِيرَةَقَالَ ابْن مَاجَةَ هَذَا مِنْ فَرَائِدِ الْعَدَنِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Umar Al 'Adani] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Zaid bin Aslam] dari [Ayahnya] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada fara' dan tidak ada 'atirah.\" "},"3126":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَ��ِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ وَلْيُرِحْ ذَبِيحَتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Khalid Al Khaddza`] dari [Abu Qilabah] dari [Abu Al 'Asy'ats] dari [Syaddad bin Aus], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Azza Wa Jalla mewajibkan untuk berbuat baik terhadap sesuatu, oleh karena itu jika kalian membunuh maka bunuhlah dengan cara yang baik, dan jika kalian menyembelih maka sembelihlah dengan cara yang baik. Hendaklah salah seseorang dari kalian menajamkan mata pisaunya dan menyenangkan sembelihannya (sebelum disembelih).\""},"3127":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ مُوسَى بْنِ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ أَخْبَرَنِي أَبِي عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ وَهُوَ يَجُرُّ شَاةً بِأُذُنِهَا فَقَالَ دَعْ أُذُنَهَا وَخُذْ بِسَالِفَتِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Uqbah bin Khalid] dari [Musa bin Muhammad bin Ibrahim At Taimi] telah memberitakan kepadaku [Ayahku] dari [Abu Sa'id Al Khudri] dia berkata, \"Nabi shallallahu 'alaihi wasallam melewati seorang laki-laki yang sedang menarik telinga kambing, maka beliau bersabda: \"Jangan pegang telinganya, namun peganglah tengkuknya.\""},"3128":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ ابْنُ أَخِي حُسَيْنٍ الْجُعْفِيِّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنِي قُرَّةُ بْنُ حَيْوَئِيلَ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَدِّ الشِّفَارِ وَأَنْ تُوَارَى عَنْ الْبَهَائِمِ وَقَالَ إِذَا ذَبَحَ أَحَدُكُمْ فَلْيُجْهِزْحَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا أَبُو الْأَسْوَدِ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Akhi Husain Al Ju'fi] telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepadaku [Qurrah bin Haiwa`il] dari [Az Zuhri] dari [Salim bin Abdullah bin Umar] dari ayahnya [Abdullah bin Umar] dua berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan supaya kami menajamkan mata pisau dan menutupi dari hewan kurban yang lain, beliau bersabda: \"Jika salah seorang dari kalian menyembelih, hendaknya mempercepat (dalam penyembelihan).\" Telah menceritakan kepada kami [Ja'far bin Musafir] telah menceritakan kepada kami [Abu Al Aswad] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Salim] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"3129":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ{ إِنَّ الشَّيَاطِينَ لَيُوحُونَ إِلَى أَوْلِيَائِهِمْ }قَالَ كَانُوا يَقُولُونَ مَا ذُكِرَ عَلَيْهِ اسْمُ اللَّهِ فَلَا تَأْكُلُوا وَمَا لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهِ فَكُلُوهُ فَقَالَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تَأْكُلُوا مِمَّا لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهِ }","id":"Telah menceritakan kepada kami ['Amru bin Abdullah] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] firman Allah: '(Sesungguhnya syetan membisikkan kepada kawan-kawannya supaya mereka membantah kamu) ' (QS Al An'aam; 121), Ibnu Abbas berkata, \"Dahulu orang-orang berkata, \"Sesuatu (sembelihan) yang disebutkan nama Allah padanya, maka janganlah kalian memakannya, dan sesuatu (sembelihan) yang tidak disebut nama Allah padanya, maka makanlah.\" Karena itulah Allah Azza Wa Jalla berfirman: '(Dan janganlah kamu memakan binatang-binatang yang tidak disebut nama Allah ketika menyembelihnya) ' (QS Al An'aam; 121)."},"3130":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ قَوْمًا قَالُوا يَا رَسُولَ اللَّهِ إِنَّ قَوْمًا يَأْتُونَا بِلَحْمٍ لَا نَدْرِي ذُكِرَ اسْمُ اللَّهِ عَلَيْهِ أَمْ لَا قَالَ سَمُّوا أَنْتُمْ وَكُلُوا وَكَانُوا حَدِيثَ عَهْدٍ بِالْكُفْرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah Ummul Mukminin] bahwa sekelompok orang telah berkata, \"Wahai Rasulullah, sesungguhnya sekelompok orang telah datang kepada kami dengan membawa daging, kami tidak tahu apakah daging tersebut telah dibacakan nama Allah (ketika menyembelih) ataukah tidak.\" Maka beliau menjawab: 'Sebutlah nama Allah lalu makanlah.' Dan mereka adalah sekelompok orang yang baru saja keluar dari kekafiran (baru masuk Islam.\""},"3131":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ مُحَمَّدِ بْنِ صَيْفِيٍّ قَالَذَبَحْتُ أَرْنَبَيْنِ بِمَرْوَةٍ فَأَتَيْتُ بِهِمَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي بِأَكْلِهِمَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari ['Ashim] dari [Asy Sya'bi] dari [Muhammad bin Shaifi] diaberkata, \"Aku menyembelih dua ekor kelinci menggunakan batu putih yang tajam, lalu aku membawa keduanya kepada Nabi shallallahu 'alaihi wasallam, maka beliau memerintahkan aku untuk memakan hasil sembelihan tersebut.\""},"3132":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ سَمِعْتُ حَاضِرَ بْنَ مُهَاجِرٍ يُحَدِّثُ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ ذِئْبًا نَيَّبَ فِي شَاةٍ فَذَبَحُوهَا بِمَرْوَةٍ فَرَخَّصَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَكْلِهَا","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] saya mendengar [Hadlir bin Muhajir] mendengar dari [Sulaiman bin Yasar] dari [Zaid bin Tsabit], bahwa seekor serigala mencengkram seekor kambing kemudian mereka menyembelih kambing tersebut menggunakan batu putih yang tajam, maka Rasulullah shallallahu 'alaihi wasallam memberikan keringanan kepada mereka untuk memakan kambing tersebut.\""},"3133":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُرِّيِّ بْنِ قَطَرِيٍّ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَصِيدُ الصَّيْدَ فَلَا نَجِدُ سِكِّينًا إِلَّا الظِّرَارَ وَشِقَّةَ الْعَصَا قَالَ أَمْرِرْ الدَّمَ بِمَا شِئْتَ وَاذْكُرْ اسْمَ اللَّهِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysrar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Simak bin Harb] dari [Murri bin Qathari] dari ['Adi bin Hatim] dia berkata, \"Saya katakan, \"Wahai Rasulullah, kami sedang berburu hewan buruan dan kami tidak mempunyai pisau kecuali batu atau sisi tongkat (yang tajam).\" Beliau bersabda: \"Alirkanlah darah (sembelihlah) dengan apa saja dan sebutlah nama Allah atas buruan tersebut.\""},"3134":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ سَعِيدِ بْنِ ��َسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَكُونُ فِي الْمَغَازِي فَلَا يَكُونُ مَعَنَا مُدًى فَقَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ فَكُلْ غَيْرَ السِّنِّ وَالظُّفْرِ فَإِنَّ السِّنَّ عَظْمٌ وَالظُّفْرَ مُدَى الْحَبَشَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Umar bin 'Ubaid At Thanafisi] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari kakeknya [Rafi' bin Khadij] dia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, lalu aku berkata, \"Wahai Rasulullah, ketika kami dalam suatu peperangan, kami tidak membawa pisau tajam?\" Maka beliau bersabda: \"Apa saja yang dapat mengalirkan darah (dalam penyembelihan) dan disebut nama Allah maka makanlah, selain gigi dan kuku, sebab gigi adalah tulang sedangkan kuku adalah pisaunya orang-orang Habasyah.\""},"3135":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا هِلَالُ بْنُ مَيْمُونٍ الْجُهَنِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ قَالَ عَطَاءٌ لَا أَعْلَمُهُ إِلَّا عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِغُلَامٍ يَسْلُخُ شَاةً فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَنَحَّ حَتَّى أُرِيَكَ فَأَدْخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ بَيْنَ الْجِلْدِ وَاللَّحْمِ فَدَحَسَ بِهَا حَتَّى تَوَارَتْ إِلَى الْإِبِطِ وَقَالَ يَا غُلَامُ هَكَذَا فَاسْلُخْ ثُمَّ مَضَى وَصَلَّى لِلنَّاسِ وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Hilal bin Maimun Al Juhani] dari ['Atha bin Yazid Al Laitsi] -'Atha mengatakan; saya tidak mengetahuinya selain dari- [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam melewati seorang anak muda yang sedang menguliti seekor kambing, maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Minggirlah agar aku dapat memperlihatkan caranya kepadamu.\" Maka Rasulullah shallallahu 'alaihi wasallam memasukkan tangannya di antara kulit dan daging kemudian mengupasnya hingga belakang ketiak seraya bersabda: \"Wahai anak muda begitulah caranya, maka kulitilah.\" Kemudian beliau berlalu dan shalat bersama orang-orang tanpa berwudlu terlebih dahulu.\""},"3136":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَلَفُ بْنُ خَلِيفَةَ ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ أَنْبَأَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ جَمِيعًا عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى رَجُلًا مِنْ الْأَنْصَارِ فَأَخَذَ الشَّفْرَةَ لِيَذْبَحَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكَ وَالْحَلُوبَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Khalaf bin Khalifah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah memberitakan kepada kami [Marwan bin Mu'awiyah] semuanya dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam mendatangi salah seorang sahabat Anshar, maka laki-laki itu mengambil pisau untuk menyembelih hewan yang disiapkan untuk Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Janganlah kamu menyembelih kambing yang memiliki susu (perahan).\""},"3137":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ يَحْيَى بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي قُحَافَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ وَلِعُمَرَ انْطَلِقَا بِنَا إِلَى الْوَاقِفِيِّ قَالَ فَانْطَلَقْنَا فِي الْقَمَرِ حَتَّى أَتَيْنَا الْحَائِطَ فَقَالَ مَرْحَبًا وَأَهْلًا ثُمَّ أَخَذَ الشَّفْرَةَ ثُمَّ جَالَ فِي الْغَنَمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكَ وَالْحَلُوبَ أَوْ قَالَ ذَاتَ الدَّرِّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdurrahman bin Al Muharibi] dari [Yahya bin 'Ubaidullah] dari [Ayahnya] dari [Abu Hurairah] dia berkata; telah menceritakan kepadaku [Abu Bakar bin Abu Quhafah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya dan kepada Umar: 'Pergilah kalian berdua bersama kami menemui Al Waqifi (yaitu Abu Al Hitsam Al Anshari).\" Abu Bakar berkata, \"Lalu kami pergi menemuinya di bawah sinar rembulan hingga kami menemuinya di suatu kebun.\" Maka Al Waqifi berkata, \"Selamat datang.\" Kemudian dia mengambil pisau dan menyembelih seekor kambing. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Janganlah kamu menyembelih (kambing) yang bersusu.\" Atau beliau bersabda: \"Yang memiliki banyak susu.\""},"3138":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ امْرَأَةً ذَبَحَتْ شَاةً بِحَجَرٍ فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَرَ بِهِ بَأْسًا","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Ka'ab bin Malik] dari [Ayahnya], bahwa seorang wanita menyembelih kambing dengan batu, lantas kejadian itu dilaporkan kepada Rasulullah shallallahu 'alaihi wasallam, namun beliau tidak mempermasalahkan hal itu.\""},"3139":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَنَدَّ بَعِيرٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَهَا أَوَابِدَ أَحْسَبُهُ قَالَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Umar bin 'Ubaid] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari kakeknya [Rafi' bin Khadij] dia berkata, \"kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, tiba-tiba seekor unta lepas hingga seorang laki-laki melemparnya dengan panah, Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Sesungguhnya unta ini memiliki watak buas.\" Menurutku beliau mengatakan \"…seperti binatang buas, dan jika kalian tidak dapat menangkapnya maka perlakukanlah ia seperti ini.\""},"3140":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَبِي الْعُشَرَاءِ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا تَكُونُ الذَّكَاةُ إِلَّا فِي الْحَلْقِ وَاللَّبَّةِ قَالَ لَوْ طَعَنْتَ فِي فَخِذِهَا لَأَجْزَأَكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Hammad bin Salamah] dari [Abu Al 'Usyra] dari [Ayahnya] dia berkata, \"Saya berkata, \"Wahai Rasulullah, bukankah menyembelih (yang syar'i) itu hanya di tenggorokan dan leher bagian bawah?\" Beliau bersabda: \"Apabila kamu menusuk pada pahanya, maka itu sudah cukup bagimu.\""},"3141":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ مُوسَى بْنِ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُمَثَّلَ بِالْبَهَائِمِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abdullah bin Sa'id] keduanya berkata; telah menceritakan kepada kami ['Uqbah bin Khalid] dari [Musa bin Muhammad bin Ibrahim At Taimi] dari [Ayahnya] dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memutilasi hewan ternak.\""},"3142":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَبْرِ الْبَهَائِمِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Hisyam bin Zaid bin Anas bin Malik] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menciderai binatang ternak.\""},"3143":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَتَّخِذُوا شَيْئًا فِيهِ الرُّوحُ غَرَضًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Khallad Al Bahili] telah menceritakan kepada kami [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjadikan sesuatu yang bernyawa sebagai sasaran (memanah atau menembak).\""},"3144":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ أَنْبَأَنَا ابْنُ جُرَيْجٍ حَدَّثَنَا أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْتَلَ شَيْءٌ مِنْ الدَّوَابِّ صَبْرًا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] telah memberitakan kepada kami [Ibnu Juraij] telah menceritakan kepada kami [Abu Az Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menjadikan binatang yang dikurung sebagai sasaran (memanah atau menembak).\""},"3145":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُحُومِ الْجَلَّالَةِ وَأَلْبَانِهَا","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ibnu Abu Za`idah] dari [Muhammad bin Ishaq] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakan daging dan susu binatang jalalah (binatang pemakan kotoran).\""},"3146":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْنَحَرْنَا فَرَسًا فَأَكَلْنَا مِنْ لَحْمِهِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [Fatimah binti Al Mundzir] dari [Asma binti Abu Bakar] dia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami pernah menyembelih kuda dan memakan dagingnya.\""},"3147":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُأَكَلْنَا زَمَنَ خَيْبَرَ الْخَيْلَ وَحُمُرَ الْوَحْشِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata, \"Pada waktu penaklukan Khaibar kami pernah memakan daging kuda dan keledai liar.\""},"3148":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ أَبِي إِسْحَقَ الشَّيْبَانِيِّ قَالَسَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ فَقَالَ أَصَابَتْنَا مَجَاعَةٌ يَوْمَ خَيْبَرَ وَنَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَصَابَ الْقَوْمُ حُمُرًا خَارِجًا مِنْ الْمَدِينَةِ فَنَحَرْنَاهَا وَإِنَّ قُدُورَنَا لَتَغْلِي إِذْ نَادَى مُنَادِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ اكْفَئُوا الْقُدُورَ وَلَا تَطْعَمُوا مِنْ لُحُومِ الْحُمُرِ شَيْئًا فَأَكْفَأْنَاهَا فَقُلْتُ لِعَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى حَرَّمَهَا تَحْرِيمًا قَالَ تَحَدَّثْنَا أَنَّمَا حَرَّمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَتَّةَ مِنْ أَجْلِ أَنَّهَا تَأْكُلُ الْعَذِرَةَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari [Abu Ishaq Asy Syaibani] dia berkata, \"Saya bertanya kepada [Abdullah bin Abu Aufa] tentang daging keledai piaraan, dia menjawab, \"Pada waktu penaklukan Khaibar kami pernah menderita kelaparan, ketika itu kami bersama dengan Nabi shallallahu 'alaihi wasallam. Lalu sekelompok orang menangkap seekor keledai di luar Kota Madinah lalu kami menyembelihnya. Ketika periuk kami telah mendidih, tiba-tiba seorang penyeru Nabi shallallahu 'alaihi wasallam menyerukan, 'Matikanlah (api pada) periuk-periuk kalian, janganlah memakan daging keledai sedikitpun.' Maka kami pun mematikannya.\" Lalu aku bertanya kepada Abdullah bin Abu Aufa, 'Apakah beliau mengharamkannya? ' dia menjawab, \"Kami ceritakan bahwa Rasulullah shallallahu 'alaihi wasallam mengharamkannya karena ia memakan kotoran.\""},"3149":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ حَدَّثَنِي الْحَسَنُ بْنُ جَابِرٍ عَنْ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَ الْكِنْدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ أَشْيَاءَ حَتَّى ذَكَرَ الْحُمُرَ الْإِنْسِيَّةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Hubab] dari [Mu'awiyah bin Shalih] telah menceritakan kepadaku [Al Hasan bin Jabir] dari [Al Miqdam bin Ma'dikarib Al Kindi], bahwa Rasulullah shallallahu 'alaihi wasallam mengharamkan beberapa hal, sampai beliau menyebutkan pula daging keledai jinak.\""},"3150":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُلْقِيَ لُحُومَ الْحُمُرِ الْأَهْلِيَّةِ نِيئَةً وَنَضِيجَةً ثُمَّ لَمْ يَأْمُرْنَا بِهِ بَعْدُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari ['Ashim] dari [Asy Sya'bi] dari [Al Barra` bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami supaya membuang daging keledai jinak baik yang mentah maupun yang telah masak, kemudian beliau tidak pernah lagi memerintahkan kami (memakannya).\""},"3151":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ خَيْبَرَ فَأَمْسَى النَّاسُ قَدْ أَوْقَدُوا النِّيرَانَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَامَ تُوقِدُونَ قَالُوا عَلَى لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ فَقَالَ أَهْرِيقُوا مَا فِيهَا وَاكْسِرُوهَا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَوْ نُهَرِيقُ مَا فِيهَا وَنَغْسِلُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ ذَاكَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'] dia berkata, \"Kami berperang bersama Rasulullah shallallahu 'alaihi wasallam pada Perang Khaibar. Ketika menjelang sore orang-orang menyalakan api, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kenapa kalian menyalakan api?\" Mereka menjawab, \"Kami hendak (memasak) daging keledai jinak.\" Maka beliau bersabda: \"Tumpahkanlah apa yang ada di dalamnya (periuk) dan pecahkanlah (periuk tersebut).\" Lantas salah seorang dari mereka berkata, \"Apa tidak sebaiknya jika kami buang lalu tempatnya kami cuci?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Boleh begitu.\""},"3152":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ مُنَادِيَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَادَى إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَيَانِكُمْ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ فَإِنَّهَا رِجْسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Ibnu Sirin] dari [Anas bin Malik], bahwa seorang penyeru Nabi shallallahu 'alaihi wasallam berseru, \"Sesungguhnya Allah dan Rasul-Nya telah melarang kalian (memakan) daging keledai jinak, sesungguhnya ia kotor (najis).\""},"3153":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا الثَّوْرِيُّ وَمَعْمَرٌ جَمِيعًا عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نَأْكُلُ لُحُومَ الْخَيْلِ قُلْتُ فَالْبِغَالُ قَالَ لَا","id":"Telah menceritakan kepada kami ['Amru bin Abdullah] telah menceritakan kepada kami [Waki'] dari [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ats Tsauri] dan [Ma'mar] semuanya dari [Abdul Karim Al Jazari] dari ['Atha] dari [Jabir bin Abdullah] dia berkata, \"Kami biasa memakan daging kuda.\" Saya bertanya, \"Bagaimana dengan daging bighal?\" dia menjawab, \"Tidak.\""},"3154":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي ثَوْرُ بْنُ يَزِيدَ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ بْنِ مَعْدِ يكَرِبَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ خَالِدِ بْنِ الْوَلِيدِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُحُومِ الْخَيْلِ وَالْبِغَالِ وَالْحَمِيرِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa] telah menceritakan kepada kami [Baqiyah] telah menceritakan kepadaku [Tsaur bin Yazid] dari [Shalih bin Yahya bin Al Miqdam bin Ma'dikarib] dari [Ayahnya] dari [Kakeknya] dari [Khalid bin Walid] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang (memakan) daging kuda, daging bighal dan daging keledai.\""},"3155":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَأَبُو خَالِدٍ الْأَحْمَرُ وَعَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُجَالِدٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ قَالَسَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَنِينِ فَقَالَ كُلُوهُ إِنْ شِئْتُمْ فَإِنَّ ذَكَاتَهُ ذَكَاةُ أُمِّهِقَالَ أَبُو عَبْد اللَّهِ سَمِعْتُ الْكَوْسَجَ إِسْحَقَ بْنَ مَنْصُورٍ يَقُولُ فِي قَوْلِهِمْ فِي الذَّكَاةِ لَا يُقْضَى بِهَا مَذِمَّةٌ قَالَ مَذِمَّةٌ بِكَسْرِ الذَّالِ مِنْ الذِّمَامِ وَبِفَتْحِ الذَّالِ مِنْ الذَّمِّ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dan [Abu Khalid Al Ahmar] serta [Abdah bin Sulaiman] dari [Mujalid] dari [Abu Waddak] dari [Abu Sa'id] dia berkata, \"Kami bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang janin (binatang). Beliau bersabda: \"Makanlah jika kalian mau, sebab penyembelihannya adalah ada pada penyembelihan ibunya.\" Abu Abdullah berkata, \"Saya mendengar Al Kusaj Ishaq bin Manshur berkata mengenai perkataan mereka soal penyembelihan, \"Bukan suatu hal yang tercela.\" Perawi berkata, \"Madzimmah dengan mengkasrahkan huruf 'dzal' berasal dari kata 'Ad Dzimam' (aib), sedangkan jika huruf 'dzal' nya difathah, ia berasal dari kata 'Adz Dzammi (celaan) '.\""},"3156":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ مُطَرِّفًا يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ ثُمَّ قَالَ مَا لَهُمْ وَلِلْكِلَابِ ثُمَّ رَخَّصَ لَهُمْ فِي كَلْبِ الصَّيْدِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dia berkata; saya mendengar [Mutharrif] menceritakan dari [Abdullah bin Mughaffal], bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing, kemudian beliau bersabda: 'Apa manfaat mereka memelihara anjing.' Kemudian beliau memberi keringanan pada anjing buruan.\""},"3157":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ مُطَرِّفًا عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ ثُمَّ قَالَ مَا لَهُمْ وَلِلْكِلَابِ ثُمَّ رَخَّصَ لَهُمْ فِي كَلْبِ الزَّرْعِ وَكَلْبِ الْعِينِقَالَ بُنْدَارٌ الْعِينُ حِيطَانُ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Utsman bin Umar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Walid] telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dia berkata; saya mendengar [Mutharrif] dari [Abdullah bin Mughaffal], bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing, kemudian beliau bersabda: 'Apa manfaat mereka memelihara anjing.' Kemudian beliau memberi keringanan bagi mereka anjing penjaga tanaman dan anjing penjaga ternak.\" Bundar berkata, \"Al 'Ain artinya dinding pembatas kota.\""},"3158":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ أَنْبَأَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ الْكِلَابِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah memberitakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan membunuh anjing.\""},"3159":{"ar":"حَدَّثَنَا أَبُو طَاهِرٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَافِعًا صَوْتَهُ يَأْمُرُ بِقَتْلِ الْكِلَابِ وَكَانَتْ الْكِلَابُ تُقْتَلُ إِلَّا كَلْبَ صَيْدٍ أَوْ مَاشِيَةٍ","id":"Telah menceritakan kepada kami [Abu Thahir] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim] dari [Ayahnya] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam dengan suara keras memerintahkan untuk membunuh anjing, maka semua anjing pun dibunuh kecuali anjing untuk berburu dan anjing penjaga ternak.\""},"3160":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَنَى كَلْبًا فَإِنَّهُ يَنْقُصُ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ إِلَّا كَلْبَ حَرْثٍ أَوْ مَاشِيَةٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing maka amalnya (pahalanya) akan dikurangi satu qirath setiap harinya, kecuali anjing penjaga tanaman atau anjing penjaga ternak.\" "},"3161":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي شِهَابٍ حَدَّثَنِي يُونُسُ بْنُ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنَّ الْكِلَابَ أُمَّةٌ مِنْ الْأُمَمِ لَأَمَرْتُ بِقَتْلِهَا فَاقْتُلُوا مِنْهَا الْأَسْوَدَ الْبَهِيمَ وَمَا مِنْ قَوْمٍ اتَّخَذُوا كَلْبًا إِلَّا كَلْبَ مَاشِيَةٍ أَوْ كَلْبَ صَيْدٍ أَوْ كَلْبَ حَرْثٍ إِلَّا نَقَصَ مِنْ أُجُورِهِمْ كُلَّ يَوْمٍ قِيرَاطَانِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ahmad bin Abdullah] dari [Abu Syihab] telah menceritakan kepadaku [Yunus bin 'Ubaid] dari [Al Hasan] dari [Abdullah bin Mughaffal] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya anjing itu tidak termasuk dari sekelompok ummat dari ummat-ummat, niscaya aku akan perintahkan untuk membunuhnya, oleh karena itu bunuhlah jenis anjing yang hitam pekat. Tidaklah suatu kaum memelihara anjing selain anjing penjaga ternak, atau anjing untuk berburu, atau anjing penjaga kebun, melainkan pahalanya akan berkurang dua qirath setiap harinya.\" "},"3162":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ سُفْيَانَ بْنِ أَبِي زُهَيْرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اقْتَنَى كَلْبًا لَا يُغْنِي عَنْهُ زَرْعًا وَلَا ضَرْعًا نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ فَقِيلَ لَهُ أَنْتَ سَمِعْتَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيْ وَرَبِّ هَذَا الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik bin Anas] dari [Yazid bin Khushaifah] dari [As Sa`ib bin Yazid] dari [Sufyan bin Abu Zuhair] dia berkata, \"Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing bukan untuk menjaga kebun dan tidak pula untuk berburu, maka pahalanya akan terkurangi satu qirath setiap harinya.\" Sufyan ditanya, \"Apakah kamu mendengarnya dari Nabi shallallahu 'alaihi wasallam?\" dia menjawab, \"Ya, demi Rabb pemilik masjid ini.\" "},"3163":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ أَخْبَرَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ أَهْلِ كِتَابٍ نَأْكُلُ فِي آنِيَتِهِمْ وَبِأَرْضِ صَيْدٍ أَصِيدُ بِقَوْسِي وَأَصِيدُ بِكَلْبِي الْمُعَلَّمِ وَأَصِيدُ بِكَلْبِي الَّذِي لَيْسَ بِمُعَلَّمٍ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مَا ذَكَرْتَ أَنَّكُمْ فِي أَرْضِ أَهْلِ كِتَابٍ فَلَا تَأْكُلُوا فِي آنِيَتِهِمْ إِلَّا أَنْ لَا تَجِدُوا مِنْهَا بُدًّا فَإِنْ لَمْ تَجِدُوا مِنْهَا بُدًّا فَاغْسِلُوهَا وَكُلُوا فِيهَا وَأَمَّا مَا ذَكَرْتَ مِنْ أَمْرِ الصَّيْدِ فَمَا أَصَبْتَ بِقَوْسِكَ فَاذْكُرْ اسْمَ اللَّهِ وَكُلْ وَمَا صِدْتَ بِكَلْبِكَ الْمُعَلَّمِ فَاذْكُرْ اسْمَ اللَّهِ وَكُلْ وَمَا صِدْتَ بِكَلْبِكَ الَّذِي لَيْسَ بِمُعَلَّمٍ فَأَدْرَكْتَ ذَكَاتَهُ فَكُلْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Adl Dlahak bin Makhlad] telah menceritakan kepada kami [Haiwah bin Syuraih] telah menceritakan kepadaku [Rabi'ah bin Yazid] telah mengabarkan kepadaku [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani] dia berkata, \"Saya menemui Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, kami tinggal di negeri ahli kitab dan makan dengan bejana mereka. Kami juga tinggal di negeri yang (penduduknya) suka berburu, aku berburu dengan panah dan anjing yang terlatih yang belum terlatih.\" Abu Tsa'labah berkata, \"Rasulullah shallallahu 'alaihi wasallam menjawab: \"Adapun yang kamu katakan bahwa kalian tinggal di negeri Ahlul kitab, maka janganlah kalian makan dengan bejana-bejana mereka kecuali jika kalian tidak mendapatkan yang lain. Jika memang tidak ada yang lain maka cucilah tempat makanan tersebut terlebih dahulu kemudian gunakanlah ia untuk makan. Sedangkan yang kamu sebutkan tentang urusan berburu, maka buruan yang kamu dapat dengan panahmu, sebutlah nama Allah kemudian makanlah. Sedangkan binatang buruan yang kamu dapatkan dari hasil buruan anjing yang terlatih, maka sebutlah nama Allah lalu makanlah (buruan tersebut), sementara hasil buruanmu dengan anjingmu yang tidakterlatih dan kamu dapat menyembelihnya, maka makanlah (buruan tersebut).\""},"3164":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا بَيَانُ بْنُ بِشْرٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّا قَوْمٌ نَصِيدُ بِهَذِهِ الْكِلَابِ قَالَ إِذَا أَرْسَلْتَ كِلَابَكَ الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهَا فَكُلْ مَا أَمْسَكْنَ عَلَيْكَ إِنْ قَتَلْنَ إِلَّا أَنْ يَأْكُلَ الْكَلْبُ فَإِنْ أَكَلَ الْكَلْبُ فَلَا تَأْكُلْ فَإِنِّي أَخَافُ أَنْ يَكُونَ إِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ وَإِنْ خَالَطَهَا كِلَابٌ أُخَرُ فَلَا تَأْكُلْقَالَ ابْن مَاجَةَ سَمِعْتُهُ يَعْنِي عَلِيَّ بْنَ الْمُنْذِرِ يَقُولُ حَجَجْتُ ثَمَانِيَةً وَخَمْسِينَ حِجَّةً أَكْثَرُهَا رَاجِلٌ","id":"Telah menceritakan kepada kami [Ali bin Mundzir] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Bayan bin Bisyr] dari [Asy Sya'bi] dari ['Adi bin Hatim] dia berkata, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Sesungguhnya kami adalah suatu kaum yang berburu dengan anjing ini.\" Maka beliau bersabda: 'Jika kamu melepaskan anjing-anjingmu yang terlatih dengan menyebut nama Allah, maka makanlah sesuatu yang telah didapatkan oleh anjing-anjing tersebut, meskipun (buruan) tersebut telah dibunuhnya. Kecuali jika hasil buruan tersebut dimakan oleh anjing tersebut, dan jika anjing itu telah memakannya maka janganlah kamu memakan (binatang buruannya), karena aku khawatir anjing itu menangkapnya untuk dirinya sendiri. Dan jika anjing itu disertai dengan anjing lain ketika menangkapnya, maka janganlah kamu memakan (buruan tersebut).\"Ibnu Majah berkata, \"Saya mendengar Ali bin Mundzir berkata, \"Saya berhaji lima puluh delapan kali dan kebanyakan haji yang saya laksanakan dengan berjalan kaki.\""},"3165":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ حَجَّاجِ بْنِ أَرْطَاةَ عَنْ الْقَاسِمِ بْنِ أَبِي بَزَّةَ عَنْ سُلَيْمَانَ الْيَشْكُرِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنُهِينَا عَنْ صَيْدِ كَلْبِهِمْ وَطَائِرِهِمْ يَعْنِي الْمَجُوسَ","id":"Telah menceritakan kepada kami ['Amru bin Abdullah] telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Hajjaj bin Arthah] dari [Al Qasim bin Abu Bazzah] dari [Sulaiman Al Yasykuri] dari [Jabir bin Abdullah] dia berkata, \"Kami dilarang makan hasil buruan anjing dan burung mereka. Yakni orang Majusi.\""},"3166":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ حَدَّثَنَا وَكِيعٌ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكَلْبِ الْأَسْوَدِ الْبَهِيمِ فَقَالَ شَيْطَانٌ","id":"Telah memberitakan kepada kami ['Amru bin Abdullah] telah memberitakan kepada kami [Waki'] dari [Sulaiman bin Mughirah] dari [Humaid bin Hilal] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] dia berkata, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai anjing hitam pekat.\" Beliau bersabda: \"Ia adalah setan.\""},"3167":{"ar":"حَدَّثَنَا أَبُو عُمَيْرٍ عِيسَى بْنُ مُحَمَّدٍ النَّحَّاسُ وَعِيسَى بْنُ يُونُسَ الرَّمْلِيُّ قَالَا حَدَّثَنَا ضَمْرَةُ بْنُ رَبِيعَةَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلْ مَا رَدَّتْ عَلَيْكَ قَوْسُكَ","id":"Telah memberitakan kepada kami [Abu 'Umair Isa bin Muhammad An Nahhas] dan [Isa bin Yunus Ar Ramli] keduanya berkata; telah memberitakan kepada kami [Dlamrah bin Rabi'ah] dari [Al Auza'i] dari [Yahya bin Sa'id] dari [Sa'id bin Al Musayyab] dari [Abu Tsa'labah Al Khusani], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Makanlah apa yang diperoleh anak panahmu.\""},"3168":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا مُجَالِدُ بْنُ سَعِيدٍ عَنْ عَامِرٍ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَرْمِي قَالَ إِذَا رَمَيْتَ وَخَزَقْتَ فَكُلْ مَا خَزَقْتَ","id":"Telah memberitakan kepada kami [Ali bin Al Mundzir] telah memberitakan kepada kami [Muhammad bin Fudlail] telah memberitakan kepada kami [Mujalid bin Sa'id] dari ['Amir] dari ['Adi bin Hatim] dia berkata, \"Saya berkata, 'Wahai Rasulullah, kami adalah kaum yang biasa berburu dengan panah?\" Beliau bersabda: \"Jika kamu memanah dan mengenai sasaran, maka makanlah (hewan buruan) dari hasil panahmu.\""},"3169":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرْمِي الصَّيْدَ فَيَغِيبُ عَنِّي لَيْلَةً قَالَ إِذَا وَجَدْتَ فِيهِ سَهْمَكَ وَلَمْ تَجِدْ فِيهِ شَيْئًا غَيْرَهُ فَكُلْهُ","id":"Telah memberitakan kepada kami [Muhammad bin Yahya] telah memberitakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari ['Ashim] dari [Asy Sya'bi] dari ['Adi bin Hatim] dia berkata, \"Saya bertanya, \"Wahai Rasulullah, saya pernah memanah binatang buruan, namun karena malam hari buruan tersebut menghilang dari kami?\" Beliau bersabda: \"Jika kamu menemukannya dan anak panahmu masih ada padanya dan kamu tidak mendapatkan sesuatu pada hewan tersebut selain anak panahmu, maka makanlah ia.\""},"3170":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَا حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ عَامِرٍ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّيْدِ بِالْمِعْرَاضِ قَالَ مَا أَصَبْتَ بِحَدِّهِ فَكُلْ وَمَا أَصَبْتَ بِعَرْضِهِ فَهُوَ وَقِيذٌ","id":"Telah memberitakan kepada kami ['Amru bin Abdullah] telah memberitakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Ali bin Al Mundzir] telah memberitakan kepada kami [Muhammad bin Fudlail] dia berkata; telah memberitakan kepada kami [Zakaria bin Abu Zaidah] dari ['Amir] dari ['Adi bin Hatim] ia berkata, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hasil buruan Mi'radl, beliau menjawab: \"Apa yang terkena bagian tajamnya maka makanlah, dan apa yang terkena pada bagian tumpulnya maka jangan kamu makan.\" "},"3171":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ حَدَّثَنَا وَكِيعٌ عَنْ أَبِيهِ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ النَّخَعِيِّ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَقَالَ لَا تَأْكُلْ إِلَّا أَنْ يَخْزِقَ","id":"Telah memberitakan kepada kami ['Amru bin Abdullah] telah memberitakan kepada kami [Waki'] dari [Ayahnya] dari [Manshru] dari [Ibrahim] dari [Hammam bin Al Harits An Nakha'i] dari ['Adi bin Hatim] dia berkata, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai batang panah (yang mengenai bintang buruan), maka beliau bersabda: \"Janganlah kamu memakannya kecuali jika hewan tersebut terkoyak.\""},"3172":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا مَعْنُ بْنُ عِيسَى عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا قُطِعَ مِنْ الْبَهِيمَةِ وَهِيَ حَيَّةٌ فَمَا قُطِعَ مِنْهَا فَهُوَ مَيْتَةٌ","id":"Telah memberitakan kepada kami [Ya'qub bin Humaid bin Kasib] telah memberitakan kepada kami [Ma'n bin Isa] dari [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang terputus dari anggota tubuh hewan ternak yang masih hidup, maka yang terputus darinya adalah bangkai.\""},"3173":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو بَكْرٍ الْهُذَلِيُّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ تَمِيمٍ الدَّارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ فِي آخِرِ الزَّمَانِ قَوْمٌ يُحِبُّونَ أَسْنِمَةَ الْإِبِلِ وَيَقْطَعُونَ أَذْنَابَ الْغَنَمِ أَلَا فَمَا قُطِعَ مِنْ حَيٍّ فَهُوَ مَيِّتٌ","id":"Telah memberitakan kepada kami [Hisyam bin 'Ammar] telah memberitakan kepada kami [Isma'il bin Ammar] telah memberitakan kepada kami [Abu Bakar Al Hudzali] dari [Syahr bin Hausyab] dari [Tamim Ad Dari] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada di akhir zaman nanti suatu kaum yang menyukai punuk-punuk unta dan memotong ekor kambing. Ketahuilah, daging yang dipotong dari hewan yang masih hidup adalah bangkai.\""},"3174":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُحِلَّتْ لَنَا مَيْتَتَانِ الْحُوتُ وَالْجَرَادُ","id":"Telah memberitakan kepada kami [Abu Mush'ab] telah memberitakan kepada kami [Abdurrahman bin Zaid bin Aslam] dari [Ayahnya] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Telah di halalkan bagi kita dua jenis bangkai; bangkai ikan paus dan belalang.\""},"3175":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ وَنَصْرُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى بْنِ عُمَارَةَ حَدَّثَنَا أَبُو الْعَوَّامِ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ سَلْمَانَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَرَادِ فَقَالَ أَكْثَرُ جُنُودِ اللَّهِ لَا آكُلُهُ وَلَا أُحَرِّمُهُ","id":"Telah memberitakan kepada kami [Abu Bisyr Bakr bin Khalaf] dan [Nashr bin Ali] keduanya berkata; telah memberitakan kepada kami [Zakaria bin Yahya bin 'Umarah] telah memberitakan kepada kami [Abu Al 'Awwam] dari [Abu Utsman An Nahdi] dari [Salman] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya tentang belalang, beliau lalu menjawab: \"Itu adalah tentara Allah yang terbanyak, aku tidak memakannya dan tidak juga mengharamkannya.\""},"3176":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي سَعِيدٍ سَعْدٍ الْبَقَّالِ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكُنَّ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَهَادَيْنَ الْجَرَادَ عَلَى الْأَطْبَاقِ","id":"Telah memberitakan kepada kami [Ahmad bin Mani'] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Sa'id Sa'd Al Baqqal] bahwa dia mendengar [Anas bin Malik] berkata, \"Dahulu para isteri Nabi shallallahu 'alaihi wasallam saling memberi hadiah belalang di atas nampan.\""},"3177":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ بْنِ عُلَاثَةَ عَنْ مُوسَى بْنِ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ جَابِرٍ وَأَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَعَا عَلَى الْجَرَادِ قَالَ اللَّهُمَّ أَهْلِكْ كِبَارَهُ وَاقْتُلْ صِغَارَهُ وَأَفْسِدْ بَيْضَهُ وَاقْطَعْ دَابِرَهُ وَخُذْ بِأَفْوَاهِهَا عَنْ مَعَايِشِنَا وَأَرْزَاقِنَا إِنَّكَ سَمِيعُ الدُّعَاءِ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ كَيْفَ تَدْعُو عَلَى جُنْدٍ مِنْ أَجْنَادِ اللَّهِ بِقَطْعِ دَابِرهِ قَالَ إِنَّ الْجَرَادَ نَثْرَةُ الْحُوتِ فِي الْبَحْرِقَالَ هَاشِمٌ قَالَ زِيَادٌ فَحَدَّثَنِي مَنْ رَأَى الْحُوتَ يَنْثُرُهُ","id":"Telah memberitakan kepada kami [Harun bin Abdullah Al Hammal] telah memberitakan kepada kami [Hasyim bin Al Qasim] telah memberitakan kepada kami [Ziyad bin Abdullah bin 'Ulasah] dari [Musa bin Muhammad bin Ibrahim] dari [Ayahnya] dari [Jabir] dan [Anas bin Malik], bahwa apabila Nabi shallallahu 'alaihi wasallam mendo'akan belalang beliau berseru: \"Ya Allah, musnahkan pembesarnya, bunuhlah yang kecilnya, rusaklah telurnya, putuskan belakangnya, ambil mulut-mulutnya sebagai penghidupan kami dan rizki-rizki kami, sesungguhnya Engkau Maha mendengar doa.\" Seorang laki-laki berkata, \"Wahai Rasulullah, bagaimana anda mendoakan terhadap salah satu dari tentara Allah dengan memutus belakangnya?\" Beliau menjawab: \"Sesungguhnya belalang adalah bersinnya ikan paus di lautan\". Hasyim berkata; Ziyad berkata, \"Dia menceritakan kepadaku orang yang pernah melihat ikan paus sedang bersin.\""},"3178":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا حَمَّادُ ابْنُ سَلَمَةَ عَنْ أَبِي الْمُهَزِّمِ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةٍ أَوْ عُمْرَةٍ فَاسْتَقْبَلَنَا رِجْلٌ مِنْ جَرَادٍ أَوْ ضَرْبٌ مِنْ جَرَادٍ فَجَعَلْنَا نَضْرِبُهُنَّ بِأَسْوَاطِنَا وَنِعَالِنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوهُ فَإِنَّهُ مِنْ صَيْدِ الْبَحْرِ","id":"Telah memberitakan kepada kami [Ali bin Muhammad] telah memberitakan kepada kami [Waki'] telah memberitakan kepada kami [Hammad bin Salamah] dari [Abu Al Muhazzim] dari [Abu Hurairah] dia berkata, \"Kami keluar bersama Nabi shallallahu 'alaihi wasallam dalam suatu ibadah haji atau 'Umrah, tiba-tiba kami bertemu dengan sekumpulan belalang -atau segerombolan belalang-, kemudian kami memukulnya dengan tongkat dan sandal-sandal kami, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Makanlah belalang itu, sebab ia termasuk dari buruan laut.\""},"3179":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَعَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْوَهَّابِ قَالَا حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْفَضْلِ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِ الصُّرَدِ وَالضِّفْدَعِ وَالنَّمْلَةِ وَالْهُدْهُدِ","id":"Telah memberitakan kepada kami [Muhammad bin Basysyar] dan [Abdurrahman bin Abdul Wahab] keduanya berkata; telah memberitakan kepada kami [Abu 'Amir Al 'Aqadi] telah memberitakan kepada kami [Ibrahim bin Al Fadll] dari [Sa'id Al Maqburi] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membunuh Shurad (sejenis burung pipit), katak, semut dan Hudhud.\""},"3180":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِ أَرْبَعٍ مِنْ الدَّوَابِّ النَّمْلَةِ وَالنَّحْلِ وَالْهُدْهُدِ وَالصُّرَدِ","id":"Telah memberitakan kepada kami [Muhammad bin Yahya] telah memberitakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Zubair Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membunuh empat jenis binatang melata; semut, lebah, hudhud dan Shurad (sejenis burung pipit).\""},"3181":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَأَحْمَدُ بْنُ عِيسَى الْمِصْرِيَّانِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ نَبِيًّا مِنْ الْأَنْبِيَاءِ قَرَصَتْهُ نَمْلَةٌ فَأَمَرَ بِقَرْيَةِ النَّمْلِ فَأُحْرِقَتْ فَأَوْحَى اللَّهُ عَزَّ وَجَلَّ إِلَيْهِ فِي أَنْ قَرَصَتْكَ نَمْلَةٌ أَهْلَكْتَ أُمَّةً مِنْ الْأُمَمِ تُسَبِّحُحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو صَالِحٍ حَدَّثَنِي اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ نَحْوَهُ وَقَالَ قَرَصَتْ","id":"Telah memberitakan kepada kami [Ahmad bin 'Amru bin As Sarh] dan [Ahmad bin Isa Al Mishriyani] keduanya berkata, telah memberitakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dahulu ada di antara para Nabi yang digigit oleh seekor semut, kemudian dia memerintahkan untuk mendatangi kampung semut dan membakarnya. Maka Allah 'azza wajalla mewahyukan kepada dirinya, 'Apakah karena seekor semut mengigitmu, kemudian kamu hancurkan satu umat dari umat-umat yang berdzikir! '\" Telah memberitakan kepada kami [Muhammad bin Yahya] telah memberitakan kepada kami [Abu Shalih] telah memberitakan kepadaku [Al Laits] dari [Yunus] dari [Ibnu Syihab] dengan sanadnya seperti hadits di atas, beliau berkata, \"Qarashat (menggigit).\""},"3182":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍأَنَّ قَرِيبًا لِعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ خَذَفَ فَنَهَاهُ وَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْخَذْفِ وَقَالَ إِنَّهَا لَا تَصِيدُ صَيْدًا وَلَا تَنْكَأُ عَدُوًّا وَلَكِنَّهَا تَكْسِرُ السِّنَّ وَتَفْقَأُ الْعَيْنَ قَالَ فَعَادَ فَقَالَ أُحَدِّثُكَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُ ثُمَّ عُدْتَ لَا أُكَلِّمُكَ أَبَدًا","id":"Telah memberitakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami [Isma'il bin 'Ulayyah] dari [Ayyub] dari [Sa'id bin Jubair], bahwa kerabat dekat [Abdullah bin Mughaffal] melempar dengan batu (saat berburu) lantas ia melarangnya seraya berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam melarang (berburu) dengan melempar (batu), beliau bersabda: \"Sesungguhnya melempar dengan batu tidak akan mengenai bintang buruan dan tidak dapat melumpuhkan musuh, tetapi ia hanya sekedar memecahkan gigi dan membuatakan mata.\" Sa'id bin Jubair berkata, \"Kemudian kerabat Abdullah mengulangi perbuatannya lagi, maka Abdullah pun berkata, \"Aku telah memberitahukan kepadamu bahwa Nabi shallallahu 'alaihi wasallam melarang perbuatan tersebut namun kamu tetap mengulanginya, sungguh aku tidak akan lagi berbicara denganmu selamanya.\""},"3183":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ بْنُ سَعِيدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عُقْبَةَ بْنِ صُهْبَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَذْفِ وَقَالَ إِنَّهَا لَا تَقْتُلُ الصَّيْدَ وَلَا تَنْكِي الْعَدُوَّ وَلَكِنَّهَا تَفْقَأُ الْعَيْنَ وَتَكْسِرُ السِّنَّ","id":"Telah memberitakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami ['Ubaid bin Sa'id]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Muhammad bin Basysyar] telah memberitakan kepada kami [Muhammad bin Ja'far] keduanya berkata; telah memberitakan kepada kami [Syu'bah] dari [Qatadah] dari ['Uqbah bin Shuhban] dari [Abdullah bin Mughaffal] dia berkata, \"Nabi shallallahu 'alaihi wasallam melarang (berburu) dengan melempar batu, beliau bersabda: \"Sesungguhnya melempar dengan batu tidak akan mengenai bintang buruan dan tidak pula melumpuhkan musuh, akan tetapi ia hanya sekedar memecahkan gigi dan membuatakan mata.\""},"3184":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جُبَيْرٍ عَ��ْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ شَرِيكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا بِقَتْلِ الْأَوْزَاغِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Abdul Hamid bin Jubair] dari [Sa'id bin Al Musayyab] dari [Ummu Syarik], bahwa Nabi shallallahu 'alaihi wasallam memerintahkan untuk membunuh cicak.\""},"3185":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ وَزَغًا فِي أَوَّلِ ضَرْبَةٍ فَلَهُ كَذَا وَكَذَا حَسَنَةً وَمَنْ قَتَلَهَا فِي الثَّانِيَةِ فَلَهُ كَذَا وَكَذَا أَدْنَى مِنْ الْأُولَى وَمَنْ قَتَلَهَا فِي الضَّرْبَةِ الثَّالِثَةِ فَلَهُ كَذَا وَكَذَا حَسَنَةً أَدْنَى مِنْ الَّذِي ذَكَرَهُ فِي الْمَرَّةِ الثَّانِيَةِ","id":"Telah memberitakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah memberitakan kepada kami [Abdul Aziz bin Al Muhtar] telah memberitakan kepada kami [Suhail] dari [Ayahnya] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membunuh cicak pada pukulan pertama maka ia akan mendapatkan kebaikan sekian dan sekian, barangsiapa membunuh pada pukulan kedua maka baginya sekian dan sekian -kurang sedikit dari yang pertama-, barangsiapa membunuhnya di pukulan ketiga maka baginya sekian dan sekian -kurang sedikit dari kebaikan yang di sebutkan pada pukulan kedua-.\""},"3186":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْوَزَغِ الْفُوَيْسِقَةُ","id":"Telah memberitakan kepada kami [Ahmad bin 'Amru bin As Sarh] telah memberitakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam menyebut cicak sebagai binatang yang merusak.\""},"3187":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ عَنْ جَرِيرِ بْنِ حَازِمٍ عَنْ نَافِعٍ عَنْ سَائِبَةَ مَوْلَاةِ الْفَاكِهِ بْنِ الْمُغِيرَةِأَنَّهَا دَخَلَتْ عَلَى عَائِشَةَ فَرَأَتْ فِي بَيْتِهَا رُمْحًا مَوْضُوعًا فَقَالَتْ يَا أُمَّ الْمُؤْمِنِينَ مَا تَصْنَعِينَ بِهَذَا قَالَتْ نَقْتُلُ بِهِ هَذِهِ الْأَوْزَاغَ فَإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَنَا أَنَّ إِبْرَاهِيمَ لَمَّا أُلْقِيَ فِي النَّارِ لَمْ تَكُنْ فِي الْأَرْضِ دَابَّةٌ إِلَّا أَطْفَأَتْ النَّارَ غَيْرَ الْوَزَغِ فَإِنَّهَا كَانَتْ تَنْفُخُ عَلَيْهِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِهِ","id":"Telah memberitakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami [Yunus bin Muhammad] dari [Jarir bin Hazim] dari [Nafi'] dari [Sa`ibah] bekas budak Al Fakih bin Al Mughirah, bahwa dia menemui [Aisyah] dan melihat di dalam rumahnya ada panah yang tergantung, maka ia pun bertanya, \"Wahai Ummul Mukminin, apa yang kamu perbuat dengan benda ini?\" Aisyah menjawab, \"Untuk membunuh cicak, sebab Nabi Allah shallallahu 'alaihi wasallam telah mengabarkan kepada kami bahwa ketika Ibrahim di lemparkan ke dalam kobaran api, tidak ada satupun dari bintang melata yang tidak berusaha mematikan api, kecuali cicak. Bahkan ia berusaha menghembuskan agar api itu tetap menyala, maka itu Rasulullah shallallahu 'alaihi wasallam memerintahkan kami membunuhnya.\""},"3188":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِقَالَ الزُّهْرِيُّ وَلَمْ أَسْمَعْ بِهَذَا حَتَّى دَخَلْتُ الشَّامَ","id":"Telah memberitakan kepada kami [Muhammad bin Ash Shabah] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] telah mengabarkan kepadaku [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khutsani], bahwa Nabi shallallahu 'alaihi wasallam melarang makan semua jenis binatang buas yang bertaring.\" Az Zuhri berkata, \"Saya tidak mendengar (hadits ini) sampai saya masuk daerah Syam.\""},"3189":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي حَكِيمٍ عَنْ عَبِيدَةَ بْنِ سُفْيَانَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَكْلُ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ حَرَامٌ","id":"Telah memberitakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami [Mu'awiyah bin Hisyam]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Ahmad bin Sinan] dan [Ishaq bin Manshur] keduanya berkata; telah memberitakan kepada kami [Abdurrahman bin Mahdi] keduanya berkata; telah memberitakan kepada kami [Malik bin Anas] dari [Isma'il bin Abu Hakim] dari ['Abidah bin Sufyan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Memakan binatang buas yang bertaring adalah haram.\""},"3190":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ وَعَنْ كُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ","id":"Telah memberitakan kepada kami [Bakr bin Khalaf] telah memberitakan kepada kami [Ibnu Abu 'Adi] dari [Sa'id] dari ['Ali bin Al Hakam] dari [Maimun bin Mihran] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Pada hari penaklukan Khaibar, Rasulullah shallallahu 'alaihi wasallam melarang memakan semua jenis binatang buas yang bertaring dan setiap jenis burung yang mempunyai cakar tajam.\""},"3191":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ وَاضِحٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ الْكَرِيمِ بْنِ أَبِي الْمُخَارِقِ عَنْ حِبَّانَ بْنِ جَزْءٍ عَنْ أَخِيهِ خُزَيْمَةَ بْنِ جَزْءٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ جِئْتُكَ لِأَسْأَلَكَ عَنْ أَحْنَاشِ الْأَرْضِ مَا تَقُولُ فِي الثَّعْلَبِ قَالَ وَمَنْ يَأْكُلُ الثَّعْلَبَ قُلْتُ يَا رَسُولَ اللَّهِ مَا تَقُولُ فِي الذِّئْبِ قَالَ وَيَأْكُلُ الذِّئْبَ أَحَدٌ فِيهِ خَيْرٌ","id":"Telah memberitakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami [Yahya bin Wadlih] dari [Muhammad bin Ishaq] dari [Abdul Karim bin Abu Al Mukhariq] dari [Hibban bin Jaz'i] dari saudaranya [Khuzaimah bin Jaz'i] dia berkata, \"Aku berkata, \"Wahai Rasulullah, aku datang kepadamu untuk menanyakan tentang serangga, apa pendapat anda mengenai rubah?\" beliau menjawab: \"Adakah yang memakan rubah?\" aku menjawab, \"Wahai Rasulullah, apa pendapat anda mengenai serigala?\" beliau menjawab: \"Seseorang memakan serigala itu baik.\""},"3192":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ ابْنِ أَبِي عَمَّارٍ وَهُوَ عَبْدُ الرَّحْمَنِ قَالَسَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ عَنْ الضَّبُعِ أَصَيْدٌ هُوَ قَالَ نَعَمْ قُلْتُ آكُلُهَا قَالَ نَعَمْ قُلْتُ أَشَيْءٌ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ","id":"Telah memberitakan kepada kami [Hisyam bin 'Ammar] dan [Muhammad bin As Shabah] keduanya berkata; telah memberitakan kepada kami [Abdullah bin Raja` Al Makki] dari [Isma'il bin Umayyah] dari [Abdullah bin 'Ubaid bin 'Umair] dari [Ibnu Abu 'Ammar] -yaitu Abdurrahman- dia berkata, \"Saya bertanya kepada [Jabir bin Abdullah] mengenai Ad Dlabu' (sejenis anjing hutan), apakah ia termasuk dari binatang buruan?\" Ia menjawab, \"Ya.\" Aku bertanya lagi, \"Bolehkah aku memakannya?\" dia menjawab, \"Ya.\" Aku bertanya lagi, \"Apakah kamu telah mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab, \"Ya.\""},"3193":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ وَاضِحٍ عَنْ ابْنِ إِسْحَقَ عَنْ عَبْدِ الْكَرِيمِ بْنِ أَبِي الْمُخَارِقِ عَنْ حِبَّانَ بْنِ جَزْءٍ عَنْ خُزَيْمَةَ بْنِ جَزْءٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا تَقُولُ فِي الضَّبُعِ قَالَ وَمَنْ يَأْكُلُ الضَّبُعَ","id":"Telah memberitakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami [Yahya bin Wadlih] dari [Ibnu Ishaq] dari [Abdul Karim bin Abu Al Mukhariq] dari [Hibban bin Juz'i] dari [Khuzaimah bin Juz'i] dia berkata, \"Saya bertanya, \"Wahai Rasulullah, apa pendapat anda mengenai Ad Dlabu' (sejenis anjing hutan)?\" beliau menjawab: \"Adakah yang memakan Ad Dlabu'?\""},"3194":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حُصَيْنٍ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ ثَابِتِ بْنِ يَزِيدَ الْأَنْصَارِيِّ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَصَابَ النَّاسُ ضِبَابًا فَاشْتَوَوْهَا فَأَكَلُوا مِنْهَا فَأَصَبْتُ مِنْهَا ضَبًّا فَشَوَيْتُهُ ثُمَّ أَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ جَرِيدَةً فَجَعَلَ يَعُدُّ بِهَا أَصَابِعَهُ فَقَالَ إِنَّ أُمَّةً مِنْ بَنِي إِسْرَائِيلَ مُسِخَتْ دَوَابَّ فِي الْأَرْضِ وَإِنِّي لَا أَدْرِي لَعَلَّهَا هِيَ فَقُلْتُ إِنَّ النَّاسَ قَدْ اشْتَوَوْهَا فَأَكَلُوهَا فَلَمْ يَأْكُلْ وَلَمْ يَنْهَ","id":"Telah memberitakan kepada kami [Abu Bakar bin Abu Syaibah] telah memberitakan kepada kami [Muhammad bin Fudlail] dari [Hushain] dari [Zaid bin Wahb] dari [Tsabit bin Yazid Al Anshari] dia berkata, \"Kami bepergian bersama Nabi shallallahu 'alaihi wasallam, lalu orang-orang menangkap seekor biawak kemudian mereka memanggangnya di atas api dan memakannya, aku juga mendapatkan seekor biawak dan memanggangnya di atas api. Kemudian aku membawakannya untuk Rasulullah shallallahu 'alaihi wasallam, beliau mengambil selembar pelepah kurma, kemudian beliau mulai menghitung jari-jarinya dengan pelepah kurma tersebut sambil bersabda: \"Sungguh, dahulu ada sekelompok Bani Israil yang di ubah bentuknya menjadi binatang melata di muka bumi, dan aku tidak tahu barangkali binatang tersebut adalah ini.\" Aku berkata, 'Orang-orang telah memanggangnya di atas api lalu memakannya! ' namun beliau tidak memakannya dan tidak pula melarangnya.\""},"3195":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الْهَرَوِيُّ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاتِمٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سُلَيْمَانَ الْيَشْكُرِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُحَرِّمْ الضَّبَّ وَلَكِنْ قَذِرَهُ وَإِنَّهُ لَطَعَامُ عَامَّةِ الرِّعَاءِ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَيَنْفَعُ بِهِ غَيْرَ وَاحِدٍ وَلَوْ كَانَ عِنْدِي لَأَكَلْتُهُحَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سُلَيْمَانَ عَنْ جَابِرٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah memberitakan kepada kami [Abu Ishaq Al Harawi Ibrahim bin Abdullah bin Hatim] telah memberitakan kepada kami [Isma'il bin 'Ulayyah] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Sulaiman Al Yasykuri] dari [Jabir bin Abdullah], bahwa Nabi shallallahu 'alaihi wasallam tidak mengharamkan daging biawak, hanya beliau merasa jijik. Biawak biasa dijadikan makanan oleh para penggembala pada umumnya, dan sesungguhnya Allah Azza Wa Jalla memberi manfaat dengannya bukan hanya pada satu orang saja, sekiranya daging tersebut ada di sisiku, niscaya saya akan memakannya.\" Telah bercerita kepada kami [Abu Salamah Yahya bin Khalaf] telah bercerita kepada kami [Abdul A'la] telah bercerita kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Sulaiman] dari [Jabir] dari [Umar bin Al Khatthab] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"3196":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَادَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ مِنْ أَهْلِ الصُّفَّةِ حِينَ انْصَرَفَ مِنْ الصَّلَاةِ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَرْضَنَا أَرْضٌ مَضَبَّةٌ فَمَا تَرَى فِي الضِّبَابِ قَالَ بَلَغَنِي أَنَّهُ أُمَّةً مُسِخَتْ فَلَمْ يَأْمُرْ بِهِ وَلَمْ يَنْهَ عَنْهُ","id":"Telah memberitakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Daud bin Abu Hind] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] dia berkata, \"Seorang laki-laki dari kalangan ahli shuffah memanggil Rasulullah shallallahu 'alaihi wasallam selepas shalat, katanya, 'Wahai Rasulullah, sesungguhnya negeri kami adalah negeri yang banyak biawaknya, lantas bagaimanakah pendapat anda mengenai (daging) biawak? ' beliau menjawab: 'Telah sampai kepadaku bahwa biawak adalah jelmaan dari suatu ummat yang telah di ubah bentuknya.' Namun beliau tidak memerintahkan (memakannya) dan tidak pula melarangnya.\""},"3197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ خَالِدِ بْنِ الْوَلِيدِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِضَبٍّ مَشْوِيٍّ فَقُرِّبَ إِلَيْهِ فَأَهْوَى بِيَدِهِ لِيَأْكُلَ مِنْهُ فَقَالَ لَهُ مَنْ حَضَرَهُ يَا رَسُولَ اللَّهِ إِنَّهُ لَحْمُ ضَبٍّ فَرَفَعَ يَدَهُ عَنْهُ فَقَالَ لَهُ خَالِدٌ يَا رَسُولَ اللَّهِ أَحَرَامٌ الضَّبُّ قَالَ لَا وَلَكِنَّهُ لَمْ يَكُنْ بِأَرْضِي فَأَجِدُنِي أَعَافُهُ قَالَ فَأَهْوَى خَالِدٌ إِلَى الضَّبِّ فَأَكَلَ مِنْهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ إِلَيْهِ","id":"Telah memberitakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] telah memberitakan kepada kami [Muhammad bin Harb] telah menceritakan kepada kami [Muhammad bin Al Walid Az Zubaidi] dari [Az Zuhri] dari [Abu Umamah bin Sahl bin Hunaif] dari [Abdullah bin 'Abbas] dari [Khalid bin Walid], bahwa telah di hidangkan untuk Rasulullah shallallahu 'alaihi wasallam daging biawak yang di panggang, kemudian beliau mendekatinya dan merentangkan tangan untuk memakannya, lalu salah seorang yang ikut serta berkata kepada beliau, 'Wahai Rasulullah, sesungguhnya itu adalah daging biawak.' Maka beliau menarik kembali tangannya. Khalid lalu berkata kepada beliau, \"Wahai Rasulullah, apakah daging biawak itu haram?\" beliau menjawab: \"Tidak, akan tetapi di negeriku tidak ada biawak sehingga aku enggan memakannya.\" Abdullah bin Abbas berkata, \"Kemudian Khalid mendekati daging biawak tersebut dan memakannya, sementara Rasulullah shallallahu 'alaihi wasallam melihat kepadanya.\""},"3198":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أُحَرِّمُ يَعْنِي الضَّبَّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Saya tidak mengharamkannya.' Yaitu daging biawak.\""},"3199":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَرَرْنَا بِمَرِّ الظَّهْرَانِ فَأَنْفَجْنَا أَرْنَبًا فَسَعَوْا عَلَيْهَا فَلَغَبُوا فَسَعَيْتُ حَتَّى أَدْرَكْتُهَا فَأَتَيْتُ بِهَا أَبَا طَلْحَةَ فَذَبَحَهَا فَبَعَثَ بِعَجُزِهَا وَوَرِكِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبِلَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] dari [Anas bin Malik] dia berkata, \"Kami pergi melewati Marra Dzahran, kemudian kami di kejutkan dengan lompatan seekor kelinci, maka orang-orang berusaha menangkapnya namun tidak mendapatkannya. Maka aku pun ikut menangkapnya dan berhasil, lalu kelinci itu kuserahkan kepada Abu Thalhah, dia menyembelihnya dan mengirim daging paha depan dan paha belakang kepada Nabi shallallahu 'alaihi wasallam, dan beliau pun menerimanya.\""},"3200":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مُحَمَّدِ بْنِ صَفْوَانَأَنَّهُ مَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْنَبَيْنِ مُعَلِّقَهُمَا فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ هَذَيْنِ الْأَرْنَبَيْنِ فَلَمْ أَجِدْ حَدِيدَةً أُذَكِّيهِمَا بِهَا فَذَكَّيْتُهُمَا بِمَرْوَةٍ أَفَآكُلُ قَالَ كُلْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Daud bin Abu Hind] dari [Asy Sya'bi] dari [Muhammad bin Shafwan], bahwa dia lewat di hadapan Nabi shallallahu 'alaihi wasallam dengan membawa dua ekor kelinci yang di gantung seraya berkata, \"Wahai Rasulullah, saya berhasil menangkap dua ekor kelinci, namun saya belum mendapatkan senjata tajam untuk menyembelihnya, lalu kelinci itu aku sembelih dengan batu tajam, bolehkah aku memakannya?\" beliau menjawab: \"Ya, makanlah.\""},"3201":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ وَاضِحٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ الْكَرِيمِ بْنِ أَبِي الْمُخَارِقِ عَنْ حِبَّانَ بْنِ جَزْءٍ عَنْ أَخِيهِ خُزَيْمَةَ بْنِ جَزْءٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ جِئْتُكَ لِأَسْأَلَكَ عَنْ أَحْنَاشِ الْأَرْضِ مَا تَقُولُ فِي الضَّبِّ قَالَ لَا آكُلُهُ وَلَا أُحَرِّمُهُ قَالَ قُلْتُ فَإِنِّي آكُلُ مِمَّا لَمْ تُحَرِّمْ وَلِمَ يَا رَسُولَ اللَّهِ قَالَ فُقِدَتْ أُمَّةٌ مِنْ الْأُمَمِ وَرَأَيْتُ خَلْقًا رَابَنِي قُلْتُ يَا رَسُولَ اللَّهِ مَا تَقُولُ فِي الْأَرْنَبِ قَالَ لَا آكُلُهُ وَلَا أُحَرِّمُهُ قُلْتُ فَإِنِّي آكُلُ مِمَّا لَمْ تُحَرِّمْ وَلِمَ يَا رَسُولَ اللَّهِ قَالَ نُبِّئْتُ أَنَّهَا تَدْمَى","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Wadlih] dari [Muhammad bin Ishaq] dari [Abdul Karim bin Abu Al Mukhariq] dari [Hibban bin Juz'in] dari sudaranya [Khuzaimah bin Ju'i] dia berkata, \"Saya bertanya, \"Wahai Rasulullah, saya datang kepadamu hendak menanyakan tentang serangga bumi, apa pendapat anda tentang daging biawak?\" Beliau menjawab: \"Saya tidak memakannya dan tidak pula mengharamkannya.\" Khuzaimah berkata, \"Lalu aku berkata, \"Sesungguhnya aku makan sesuatu yang tidak anda haramkan, memang kenapa wahai Rasulullah?\" beliau menjawab: \"Sekelompok ummat dari beberapa ummat telah menghilang, dan saya lihat makhluk yang membuatku ragu.\" Saya berkata, \"Wahai Rasulullah, bagaimana pendapat anda dengan daging kelinci?\" beliau menjawab: \"Aku tidak memakannya dan tidak pula mengharamkannya.\" Aku berkata, \"Sesungguhnya saya memakan sesuatu yang tidak anda haramkan, memang kenapa wahai Rasulullah?\" beliau menjawab: \"Saya telah di beritahu bahwa kelinci adalah (hewan) yang mengalirkan darah.\""},"3202":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنِي صَفْوَانُ بْنُ سُلَيْمٍ عَنْ سَعِيدِ بْنِ سَلَمَةَ مِنْ آلِ ابْنِ الْأَزْرَقِ أَنَّ الْمُغِيرَةَ بْنَ أَبِي بُرْدَةَ وَهُوَ مِنْ بَنِي عَبْدِ الدَّارِ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَحْرُ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُقَالَ أَبُو عَبْد اللَّهِ بَلَغَنِي عَنْ أَبِي عُبَيْدَةَ الْجَوَادِ أَنَّهُ قَالَ هَذَا نِصْفُ الْعِلْمِ لِأَنَّ الدُّنْيَا بَرٌّ وَبَحْرٌ فَقَدْ أَفْتَاكَ فِي الْبَحْرِ وَبَقِيَ الْبَرُّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Malik bin Anas] telah menceritakan kepadaku [Shafwan bin Sulaim] dari [Sa'id bin Salamah] dari keluarga Ibnu Al Azraq, bahwa [Al Mughirah bin Abu Burdah] salah seorang dari Bani Abdud Daar, dia menceritakan kepadanya, bahwa dia mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lautan itu suci airnya dan halal bangkainya.\" Abu Abdullah berkata, \"Telah sampai (kabar) dari Abu 'Ubaidah Al Jawwad kepadaku bahwa dia berkata, \"Ini ibarat setengahnya ilmu, sebab dunia itu terdiri dari daratan dan lautan. Aku telah memberi fatwa kepadamu mengenai hewan laut, tinggal hewan darat.\""},"3203":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ أُمَيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَلْقَى الْبَحْرُ أَوْ جَزَرَ عَنْهُ فَكُلُوهُ وَمَا مَاتَ فِيهِ فَطَفَا فَلَا تَأْكُلُوهُ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] telah menceritakan kepada kami [Yahya bin Sulaim Ath Tha`ifi] telah menceritakan kepada kami [Isma'il bin Umayyah] dari [Abu Az Zubair] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang hempaskan air laut atau mati karena surut maka makanlah, dan apa yang mati di laut kemudian mengapung maka janganlah kamu memakannya.\""},"3204":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ النَّيْسَابُورِيُّ حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ حَدَّثَنَا شَرِيكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَمَنْ يَأْكُلُ الْغُرَابَ وَقَدْ سَمَّاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسِقًا وَاللَّهِ مَا هُوَ مِنْ الطَّيِّبَاتِ","id":"Telah menceritakan kepada kami [Ahmad bin Al Azhar An Naisaburi] telah menceritakan kepada kami [Al Haitsam bin Jamil] telah menceritakan kepada kami [Syarik] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Ibnu Umar] dia berkata, \"Barangsiapa makan burung gagak -dan Rasulullah shallallahu 'alaihi wasallam telah menyebutnya dengan fasiq-, demi Allah, dia bukanlah makanan yang baik.\""},"3205":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا الْمَسْعُودِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ بْنِ مُحَمَّدِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَيَّةُ فَاسِقَةٌ وَالْعَقْرَبُ فَاسِقَةٌ وَالْفَأْرَةُ فَاسِقَةٌ وَالْغُرَابُ فَاسِقٌفَقِيلَ لِلْقَاسِمِ أَيُؤْكَلُ الْغُرَابُ قَالَ مَنْ يَأْكُلُهُ بَعْدَ قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسِقًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Al Mas'udi] telah menceritakan kepada kami [Abdurrahman bin Al Qasim bin Muhammad bin Abu Bakr Ash Shidiq] dari [Ayahnya] dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ular adalah binatang yang fasik, kalajengking adalah binatang yang fasik, tikus adalah binatang fasik dan burung gagak juga binatang fasik.\" Kemudian di tanyakan kepada Al Qasim, \"Apakah burung gagak boleh di makan?\" dia menjawab, \"Adakah orang yang mau memakannya setelah sabda Rasulullah shallallahu 'alaihi wasallam (yang menyebutkan) bahwa dia adalah binatang yang fasik?\""},"3206":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مَهْدِيٍّ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا عُمَرُ بْنُ زَيْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ الْهِرَّةِ وَثَمَنِهَا","id":"Telah menceritakan kepada kami [Al Husain bin Mahdi] telah memberitakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Umar bin Zaid] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang makan (daging) kucing dan harganya.\""},"3207":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَوْفٍ عَنْ زُرَارَةَ بْنِ أَوْفَى حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سَلَامٍ قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ انْجَفَلَ النَّاسُ قِبَلَهُ وَقِيلَ قَدْ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَدِمَ رَسُولُ اللَّهِ قَدْ قَدِمَ رَسُولُ اللَّهِ ثَلَاثًا فَجِئْتُ فِي النَّاسِ لِأَنْظُرَ فَلَمَّا تَبَيَّنْتُ وَجْهَهُ عَرَفْتُ أَنَّ وَجْهَهُ لَيْسَ بِوَجْهِ كَذَّابٍ فَكَانَ أَوَّلُ شَيْءٍ سَمِعْتُهُ تَكَلَّمَ بِهِ أَنْ قَالَ يَا أَيُّهَا النَّاسُ أَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ وَصِلُوا الْأَرْحَامَ وَصَلُّوا بِاللَّيْلِ وَالنَّاسُ نِيَامٌ تَدْخُلُوا الْجَنَّةَ بِسَلَامٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari ['Auf] dari [Zurarah bin Aufa] telah menceritakan kepadaku [Abdullah bin Salam] dia berkata, \"Tatkala Nabi shallallahu 'alaihi wasallam tiba di Madinah, maka orang-orang bergegas menyambut kedatangan beliau dengan menyerukan, \"Rasulullah shallallahu 'alaihi wasallam datang! Rasulullah datang! Rasulullah datang! \" hingga tiga kali. Maka aku ikut berjubel di tengah-tengah kerumunan manusia untuk melihat beliau, ketika telah jelas kupandang wajahnya, maka bisa kuketahui bahwa raut muka beliau bukanlah raut muka seorang pendusta. Ucapan pertama kali yang aku dengar dari beliau adalah: \"Wahai manusia, tebarkanlah salam, berilah makan, sambunglah tali persaudaraan, shalatlah di malam hari ketika manusia terlelap tidur, niscaya kalian masuk surga dengan selamat.\""},"3208":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى الْأَزْدِيُّ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ سُلَيْمَانُ بْنُ مُوسَى حَدَّثَنَا عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَكَانَ يَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ وَكُونُوا إِخْوَانًا كَمَا أَمَرَكُمْ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya Al Azdi] telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij] berkata, [Sulaiman bin Musa] menceritakan kepada kami dari [Nafi'] bahwa [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tebarkanlah salam, berilah makan dan jadilah kalian semua bersaudara sebagaimana kalian telah di perintahkan oleh Allah Azza Wa Jalla.\""},"3209":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الْإِسْلَامِ خَيْرٌ قَالَ تُطْعِمُ الطَّعَامَ وَتَقْرَأُ السَّلَامَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِفْ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Abdullah bin 'Amru], bahwa seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam, katanya, \"Wahai Rasulullah, Islam bagaimanakah yang baik?\" beliau menjawab: \"Kamu memberi makan, menebarkan salam baik terhadap orang yang kamu kenal maupun terhadap orang yang tidak kamu kenal.\""},"3210":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا يَحْيَى بْنُ زِيَادٍ الْأَسَدِيُّ أَنْبَأَنَا ابْنُ جُرَيْجٍ أَنْبَأَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامُ الْوَاحِدِ يَكْفِي الِاثْنَيْنِ وَطَعَامُ الِاثْنَيْنِ يَكْفِي الْأَرْبَعَةَ وَطَعَامُ الْأَرْبَعَةِ يَكْفِي الثَّمَانِيَةَ","id":"Telah memberitakan kepada kami [Muhammad bin Abdullah Ar Raqqi] telah menceritakan kepada kami [Yahya bin Ziyad Al Asadi] telah memberitakan kepada kami [Ibnu Juraij] telah memberitakan kepada kami [Abu Az Zubair] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu makanan cukup untuk dua orang, dua makanan cukup untuk empat orang dan empat makanan cukup untuk delapan orang.\""},"3211":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَهْرَمَانُ آلِ الزُّبَيْرِ قَالَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَنْ جَدِّهِ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ طَعَامَ الْوَاحِدِ يَكْفِي الِاثْنَيْنِ وَإِنَّ طَعَامَ الِاثْنَيْنِ يَكْفِي الثَّلَاثَةَ وَالْأَرْبَعَةَ وَإِنَّ طَعَامَ الْأَرْبَعَةِ يَكْفِي الْخَمْسَةَ وَالسِّتَّةَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Sa'id bin Zaid] telah menceritakan kepada kami ['Amru bin Dinar Qahraman] dari keluarga Az Zubair, dia berkata; saya mendengar [Salim bin Abdullah bin Umar] dari [Ayahnya] dari kakeknya [Umar bin Al Khaththab] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, satu makanan cukup untuk dua orang, dua makanan cukup untuk tiga dan empat orang, dan empat makanan cukup untuk lima dan enam orang.\""},"3212":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍ وَالْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dari [Abu Hazim] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin makan dengan satu usus, sedangkan orang kafir makan dengan tujuh usus.\""},"3213":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ وَالْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdullah bin Numair] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang kafir makan dengan tujuh usus sedangkan orang mukmin makan dengan satu usus.\""},"3214":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍ وَالْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari kakeknya [Abu Burdah] dari [Abu Musa] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang Mukmin makan dengan satu usus, sedangkan orang kafir makan dengan tujuh usus.\""},"3215":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا عَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا قَطُّ إِنْ رَضِيَهُ أَكَلَهُ وَإِلَّا تَرَكَهُحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي يَحْيَى عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ أَبُو بَكْرٍ نُخَالِفُ فِيهِ يَقُولُونَ عَنْ أَبِي حَازِمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam sama sekali tidak pernah mencela makanan, jika suka beliau memakannya, namun jika tidak maka beliau meninggalkannya.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Yahya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\" Abu Bakar berkata, \"Kami tidak sejutu dengan sanad tersebut, mereka mengatakan 'Dari Abu Hazim'.\""},"3216":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا كَثِيرُ بْنُ سُلَيْمٍ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ أَنْ يُكْثِرَ اللَّهُ خَيْرَ بَيْتِهِ فَلْيَتَوَضَّأْ إِذَا حَضَرَ غَدَاؤُهُ وَإِذَا رُفِعَ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallas] telah menceritakan kepada kami [Katsir bin Sulaim] saya mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin supaya Allah memperbanyak kebaikan rumahnya, maka hendaknya ia berwudlu jika makan paginya telah dihidangkan, atau ketika selesai (dari makan).\""},"3217":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا صَاعِدُ بْنُ عُبَيْدٍ الْجَزَرِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ الْمَكِّيُّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَرَجَ مِنْ الْغَائِطِ فَأُتِيَ بِطَعَامٍ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَلَا آتِيكَ بِوَضُوءٍ قَالَ أُرِيدُ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] telah menceritakan kepada kami [Sha'id bin 'Ubaid Al Jazari] telah menceritakan kepada kami [Zuhair bin Mu'awiyah] telah menceritakan kepada kami [Muhammad bin Juhadah] telah menceritakan kepada kami ['Amru bin Dinar Al Makki] dari ['Atha bin Yasar] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa ketika beliau selesai dari buang hajat maka dihidangkanlah makanan untuk beliau, lalu seorang laki-laki berkata, \"Wahai Rasulullah, maukah aku sediakan buat anda air untuk berwudlu?\" Beliau menjawab: \"Aku ingin shalat.\""},"3218":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مِسْعَرٍ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ أَبِي جُحَيْفَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا آكُلُ مُتَّكِئًا","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Mis'ar] dari [Ali bin Al Aqmar] dari [Abu Juhaifah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak (pernah) makan sambil bersandar.\""},"3219":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا أَبِي أَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عِرْقٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُسْرٍ قَالَأَهْدَيْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةً فَجَثَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رُكْبَتَيْهِ يَأْكُلُ فَقَالَ أَعْرَابِيٌّ مَا هَذِهِ الْجِلْسَةُ فَقَالَ إِنَّ اللَّهَ جَعَلَنِي عَبْدًا كَرِيمًا وَلَمْ يَجْعَلْنِي جَبَّارًا عَنِيدًا","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] telah menceritakan kepada kami [Ayahku] telah memberitakan kepada kami [Muhammad bin Abdurrahman bin 'Irq] telah menceritakan kepada kami [Abdullah bin Busr] dia berkata, \"Saya menghadiahkan kambing (bakar) kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau makan sambil duduk berlutut di atas kedua tumitnya. Maka berkatalah seorang Arab badui, \"Duduk apakah ini?\" beliau menjawab: \"Sesungguhnya Allah menjadikanku sebagai seorang hamba yang lemah lembut (mulia), dan tidak menjadikanku hamba yang keras dan sombong.\""},"3220":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ طَعَامًا فِي سِتَّةِ نَفَرٍ مِنْ أَصْحَابِهِ فَجَاءَ أَعْرَابِيٌّ فَأَكَلَهُ بِلُقْمَتَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا أَنَّهُ لَوْ كَانَ قَالَ بِسْمِ اللَّهِ لَكَفَاكُمْ فَإِذَا أَكَلَ أَحَدُكُمْ طَعَامًا فَلْيَقُلْ بِسْمِ اللَّهِ فَإِنْ نَسِيَ أَنْ يَقُولَ بِسْمِ اللَّهِ فِي أَوَّلِهِ فَلْيَقُلْ بِسْمِ اللَّهِ فِي أَوَّلِهِ وَآخِرِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Hisyam Ad Dastuwa`i] dari [Budail bin Maisarah] dari [Abdullah bin 'Ubaid bin Umair] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam makan bersama enam orang dari sahabatnya, kemudian datanglah seorang Arab badui makan dengan dua suapan sekaligus, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sekiranya ia mengucapkan 'Bismillah' niscaya (dua suapannya) dapat mencukupi kalian. Jika salah seorang dari kalian menyantap makanan, hendaknya ia membaca 'Bismillah', jika lupa membacanya hendaknya ia mengucapkan, 'Bismillahi fi awwalihi wa akhirihi (dengan nama Allah untuk permulaan dan selesainya) '.\""},"3221":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا آكُلُ سَمِّ اللَّهَ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Umar bin Abu Salamah] dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda kepadaku ketika aku sedang makan: \"Sebutlah nama Allah Azza Wa Jalla.\""},"3222":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْهِقْلُ بْنُ زِيَادٍ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَأْكُلْ أَحَدُكُمْ بِيَمِينِهِ وَلْيَشْرَبْ بِيَمِينِهِ وَلْيَأْخُذْ بِيَمِينِهِ وَلْيُعْطِ بِيَمِينِهِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِشِمَالِهِ وَيَشْرَبُ بِشِمَالِهِ وَيُعْطِي بِشِمَالِهِ وَيَأْخُذُ بِشِمَالِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Hiql bin Ziyad] telah menceritakan kepada kami [Hisyam bin Hassan] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Hendaknya salah seorang dari kalian makan dengan tangan kanan, minum dengan tangan kanan, mengambil dengan tangan kanan dan memberi dengan menggunakan tangan kanannya, sesungguhnya setan makan dengan tangan kiri dan minum dengan tangan kirinya serta mengambil (sesuatu) dengan tangan kiri.\""},"3223":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ وَهْبِ بْنِ كَيْسَانَ سَمِعَهُ مِنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَكُنْتُ غُلَامًا فِي حِجْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ يَدِي تَطِيشُ فِي الصَّحْفَةِ فَقَالَ لِي يَا غُلَامُ سَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin As Shabah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al Walid bin Katsir] dari [Wahb bin Kaisan] dia mendengar dari [Umar bin Abu Salamah] dia berkata, \"Ketika kecil aku berada di pangkuan Nabi shallallahu 'alaihi wasallam, saat tanganku memegang piring, maka Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai anak kecil, sebutlah nama Allah, makanlah dengan tangan kanan dan ambillah dari yang dekat.\""},"3224":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَأْكُلُوا بِالشِّمَالِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِالشِّمَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kamu makan dengan tangan kiri, sesungguhnya setan makan dengan tangan kiri.\""},"3225":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ طَعَامًا فَلَا يَمْسَحْ يَدَهُ حَتَّى يَلْعَقَهَا أَوْ يُلْعِقَهَاقَالَ سُفْيَانُ سَمِعْتُ عُمَرَ بْنَ قَيْسٍ يَسْأَلُ عَمْرَو بْنَ دِينَارٍ أَرَأَيْتَ حَدِيثَ عَطَاءٍ لَا يَمْسَحْ أَحَدُكُمْ يَدَهُ حَتَّى يَلْعَقَهَا أَوْ يُلْعِقَهَا عَمَّنْ هُوَ قَالَ عَنْ ابْنِ عَبَّاسٍ قَالَ فَإِنَّهُ حُدِّثْنَاهُ عَنْ جَابِرٍ قَالَ حَفِظْنَاهُ مِنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَبْلَ أَنْ يَقْدَمَ جَابِرٌ عَلَيْنَا وَإِنَّمَا لَقِيَ عَطَاءٌ جَابِرًا فِي سَنَةٍ جَاوَرَ فِيهَا بِمَكَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru bin Dinar] dari ['Atha] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang selesai makan maka janganlah ia mencuci makanannya terlebih dahulu sampai ia menjilatinya atau menjilatkannya kepada orang lain.\" [Sufyan] berkata; Saya mendengar [Umar bin Qais] bertanya kepada 'Amru bin Dinar, \"Apa pendapatmu dengan riwayat Atha, (yaitu) 'Janganlah salah seorang dari kalian mencuci tangannya sebelum menjilatinya atau menjilatkannya kepada orang lain', dari siapakah riwayat haditsnya?\" 'Atha menjawab, \"Dari Ibnu Abbas.\" Sufyan berkata, \"Kami mendapatkan cerita bahwa itu riwayat dari [Jabir].\" Sufyan melanjutkan, \"Kami menghafalnya dari 'Atha dari Ibnu Abbas, sebelum Jabir datang kepada kami. Dan 'Atha bertemu dengan Jabir pada tahun ketika ia ke Makkah.\""},"3226":{"ar":"حَدَّثَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ أَنْبَأَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَمْسَحْ أَحَدُكُمْ يَدَهُ حَتَّى يَلْعَقَهَا فَإِنَّهُ لَا يَدْرِي فِي أَيِّ طَعَامِهِ الْبَرَكَةُ","id":"Telah menceritakan kepada kami [Musa bin Abdurrahman] telah memberitakan kepada kami [Abu Daud Al Hafari] dari [Sufyan] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mencuci tangannya terlebih dahulu sebelum menjilatinya, sebab dia tidak mengetahui pada makanan yang manakah terdapat keberkahannya.\""},"3227":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا أَبُو الْيَمَانِ الْبَرَّاءُ قَالَ حَدَّثَتْنِي جَدَّتِي أُمُّ عَاصِمٍ قَالَتْدَخَلَ عَلَيْنَا نُبَيْشَةُ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَأْكُلُ فِي قَصْعَةٍ فَقَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ فِي قَصْعَةٍ فَلَحِسَهَا اسْتَغْفَرَتْ لَهُ الْقَصْعَةُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Abu Al Yaman Al Barra`] dia berkata; telah menceritakan kepadaku nenekku [Ummu 'Ashim] dia berkata, \" [Nubaisyah] bekas budak Nabi shallallahu 'alaihi wasallam datang menemui kami ketika kami sedang makan di dengan tempayan, dia lalu berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan di atas piring kemudian ia menjilatinya, maka piring tersebut akan memintakan ampun untuknya.\""},"3228":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ وَنَصْرُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا الْمُعَلَّى بْنُ رَاشِدٍ أَبُو الْيَمَانِ حَدَّثَتْنِي جَدَّتِي عَنْ رَجُلٍ مِنْ هُذَيْلٍ يُقَالُ لَهُ نُبَيْشَةُ الْخَيْرِ قَالَتْدَخَلَ عَلَيْنَا نُبَيْشَةُ وَنَحْنُ نَأْكُلُ فِي قَصْعَةٍ لَنَا فَقَالَ حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ فِي قَصْعَةٍ ثُمَّ لَحِسَهَا اسْتَغْفَرَتْ لَهُ الْقَصْعَةُ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] dan [Nashr bin Ali] keduanya berkata; telah menceritakan kepada kami [Al Mu'ali bin Rasyid Abu Al Yaman] telah menceritakan kepadaku [Nenekku] dari seorang laki-laki penduduk Hudzail yang di sebut [Nubaisyah Al Khair], ia berkata, \"Nubaisyah datang menemui kami ketika itu kami sedang makan di atas piring milik kami, maka dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menceritakan kepada kami, beliau katakan: \"Barangsiapa makan di atas piring kemudian ia menjilatinya, maka piring tersebut akan memintakan ampun untuknya.\""},"3229":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَتْ الْمَائِدَةُ فَلْيَأْكُلْ مِمَّا يَلِيهِ وَلَا يَتَنَاوَلْ مِنْ بَيْنِ يَدَيْ جَلِيسِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al Asqalani] telah menceritakan kepada kami ['Ubaidullah] telah menceritakan kepada kami [Abdul A'la] dari [Yahya bin Abu Katsir] dari ['Urwah bin Az Zubiar] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila makanan telah di hidangkan maka makanlah yang terdekat darinya, dan jangan mengambil (makanan yang berada) di tengah-tengah teman duduknya.\""},"3230":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْفَضْلِ بْنِ عَبْدِ الْمَلِكِ بْنِ أَبِي السَّوِيَّةِ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عِكْرَاشٍ عَنْ أَبِيهِ عِكْرَاشِ بْنِ ذُؤَيْبٍ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَفْنَةٍ كَثِيرَةِ الثَّرِيدِ وَالْوَدَكِ فَأَقْبَلْنَا نَأْكُلُ مِنْهَا فَخَبَطْتُ يَدِي فِي نَوَاحِيهَا فَقَالَ يَا عِكْرَاشُ كُلْ مِنْ مَوْضِعٍ وَاحِدٍ فَإِنَّهُ طَعَامٌ وَاحِدٌ ثُمَّ أُتِينَا بِطَبَقٍ فِيهِ أَلْوَانٌ مِنْ الرُّطَبِ فَجَالَتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الطَّبَقِ وَقَالَ يَا عِكْرَاشُ كُلْ مِنْ حَيْثُ شِئْتَ فَإِنَّهُ غَيْرُ لَوْنٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Al 'Ala' bin Fadll bin Abdul Malik bin Abu As Sawiyah] telah menceritakan kepadaku ['Ubaidullah bin 'Ikrasy] dari ayahnya ['Ikrasy bin Dzu`aib] dia berkata, \"Nabi shallallahu 'alaihi wasallam dibawakan semangkuk roti dan lemak, lantas kami datang dan memakannya. Aku meletakkan tanganku di sisi-sisi makanan tersebut, maka beliau pun menegur: \"Wahai 'Ikrasy, makanlah dari satu tempat! Sesungguhnya makanan ini hanya satu macam.\" Kemudian kami di bawakan satu nampan yang bersisi beberapa macam kurma basah, maka tangan Rasulullah shallallahu 'alaihi wasallam merambah nampan itu sambil bersabda: \"Wahai 'Ikrasy, makanlah dari mana saja yang kamu senangi, karena makanan ini bukan satu macam.\""},"3231":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عِرْقٍ الْيَحْصَبِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُسْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِقَصْعَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا مِنْ جَوَانِبِهَا وَدَعُوا ذُرْوَتَهَا يُبَارَكْ فِيهَا","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Abdurrahman bin 'Irq Al Yahshabi] telah menceritakan kepada kami [Abdullah bin Busr], bahwa dihidangkan semangkuk makanan kepada Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah bagian sampingnya dan biarkan yang tengah, semoga akan memberi keberkahan.\""},"3232":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا أَبُو حَفْصٍ عُمَرُ بْنُ الدَّرَفْسِ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي قَسِيمَةَ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ اللَّيْثِيِّ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَأْسِ الثَّرِيدِ فَقَالَ كُلُوا بِسْمِ اللَّهِ مِنْ حَوَالَيْهَا وَاعْفُوا رَأْسَهَا فَإِنَّ الْبَرَكَةَ تَأْتِيهَا مِنْ فَوْقِهَا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abu Hafsh Umar bin Ad Darafsi] telah menceritakan kepadaku [Abdurrahman bin Abu Qasimah] dari [Watsilah bin Al Asqa' Al Laitsi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengambil bagian atas bubur sambil bersabda: \"Makanlah kalian dengan menyebut nama Allah dari sampingnya dan hindarilah bagian atasnya (tengahnya), sesungguhnya keberkahan datang dari bagian atas.\""},"3233":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَ الطَّعَامُ فَخُذُوا مِنْ حَافَتِهِ وَذَرُوا وَسَطَهُ فَإِنَّ الْبَرَكَةَ تَنْزِلُ فِي وَسَطِهِ","id":"Telah menceritakan kepada kami [Ali bin Mundzir] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami ['Atha bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam: \"Apabila makanan telah di hidangkan maka ambillah dari pinggirnya dan tinggalkan tengahnya, sesungguhnya barakah itu turun di bagian tengahnya.\""},"3234":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَبَيْنَمَا هُوَ يَتَغَدَّى إِذْ سَقَطَتْ مِنْهُ لُقْمَةٌ فَتَنَاوَلَهَا فَأَمَاطَ مَا كَانَ فِيهَا مِنْ أَذًى فَأَكَلَهَا فَتَغَامَزَ بِهِ الدَّهَاقِينُ فَقِيلَ أَصْلَحَ اللَّهُ الْأَمِيرَ إِنَّ هَؤُلَاءِ الدَّهَاقِينَ يَتَغَامَزُونَ مِنْ أَخْذِكَ اللُّقْمَةَ وَبَيْنَ يَدَيْكَ هَذَا الطَّعَامُ قَالَ إِنِّي لَمْ أَكُنْ لِأَدَعَ مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِهَذِهِ الْأَعَاجِمِ إِنَّا كُنَّا نَأْمُرُ أَحَدُنَا إِذَا سَقَطَتْ لُقْمَتُهُ أَنْ يَأْخُذَهَا فَيُمِيطَ مَا كَانَ فِيهَا مِنْ أَذًى وَيَأْكُلَهَا وَلَا يَدَعَهَا لِلشَّيْطَانِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Yunus] dari [Al Hasan] dari [Ma'qil bin Yasar] dia berkata, \"Tatkala dia sedang sarapan pagi sesuap makanan jatuh dari (tangannya), dia lalu mengambilnya seraya membersihkan kotoran yang menempel pada makanan tersebut. Maka para pemimpin kabilah saling berisyarat dengan matanya, lalu dikatakan kepada Ma'qil, \"Semoga Allah memberi kebaikan kepada Amir (pemimpin), para pemimpin kabilah saling berisyarat mata karena kamu mengambil sesuap makanan yang jatuh, padahal di depanmu banyak makanan.\" Ma'qil menjawab, \"Sesungguhnya aku tidak ingin meninggalkan apa yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam karena orang-orang asing ini. Sungguh, jika ada sesuap makanan terjatuh, maka kami akan memerintahkan untuk mengambilnya kemudian membersihkan kotoran yang menempel pada makanan tersebut lalu memakannya, dan janganlah meninggalkannya untuk setan.\""},"3235":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَقَعَتْ اللُّقْمَةُ مِنْ يَدِ أَحَدِكُمْ فَلْيَمْسَحْ مَا عَلَيْهَا مِنْ الْأَذَى وَلْيَأْكُلْهَا","id":"Telah menceritakan kepada kami [Ali bin Al Mundzir] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila sesuap makanan jatuh dari tangan salah seorang dari kalian, hendaknya ia membersihkan kotoran yang menempel padanya kemudian memakannya.\""},"3236":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ مُرَّةَ الْهَمْدَانِيِّ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَمَلَ مِنْ الرِّجَالِ كَثِيرٌ وَلَمْ يَكْمُلْ مِنْ النِّسَاءِ إِلَّا مَرْيَمُ بِنْتُ عِمْرَانَ وَآسِيَةُ امْرَأَةُ فِرْعَوْنَ وَإِنَّ فَضْلَ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Murrah Al Hamdani] dari [Abu Musa Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kaum laki-laki yang sempurna banyak jumlahnya, sedangkan tidak ada kaum wanita yang sempurna kecuali Maryam binti 'Imran dan Asiyah isteri Fir'aun. Sesungguhnya keutamaan Aisyah atas semua wanita seperti keutamaan bubur atas semua makanan.\""},"3237":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا مُسْلِمُ بْنُ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepada kami [Muslim bin Khalid] dari [Abdullah bin Abdurrahman] bahwa dia mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keutamaan Aisyah atas semua wanita seperti keutamaan bubur di atas semua makanan.\""},"3238":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْمِصْرِيُّ أَبُو الْحَارِثِ الْمُرَادِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ مُحَمَّدِ بْنِ أَبِي يَحْيَى عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا زَمَانَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَلِيلٌ مَا نَجِدُ الطَّعَامَ فَإِذَا نَحْنُ وَجَدْنَاهُ لَمْ يَكُنْ لَنَا مَنَادِيلُ إِلَّا أَكُفُّنَا وَسَوَاعِدُنَا وَأَقْدَامُنَا ثُمَّ نُصَلِّي وَلَا نَتَوَضَّأُقَالَ أَبُو عَبْد اللَّهِ غَرِيبٌ لَيْسَ إِلَّا عَنْ مُحَمَّدِ بْنِ سَلَمَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Maslamah Al Mishri Abu Harits Al Muradi] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Muhammad bin Abu Yahya] dari [Ayahnya] dari [Sa'id bin Al Harits] dari [Jabir bin Abdullah] dia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam jarang sekali kami menemui makanan, jika kami mendapatkannya maka kami tidak memiliki tissue (sapu tangan) kecuali telapak tangan kami, lengan-lengan kami dan telapak kaki kami, kemudian kami shalat tanpa berwudlu terlebih dahulu.\" Abu Abdullah berkata, \"Ini adalah hadits gharib, tidak ada yang meriwayatkan kecuali dari Muhammad bin Salamah.\""},"3239":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَجَّاجٍ عَنْ رِيَاحِ بْنِ عَبِيدَةَ عَنْ مَوْلًى لِأَبِي سَعِيدٍ عَنْ أَبِي سَعِيدٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ طَعَامًا قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنَا وَسَقَانَا وَجَعَلَنَا مُسْلِمِينَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hajjaj] dari [Riyah bin 'Abidah] dari [bekas budak Abu Sa'id] dari [Abu Sa'id] dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam selesai makan, beliau mengucapkan: 'AL HAMDULILLAHILLADZII ATH'AMANAA WA SAQAANAA WAJ'ALANAA MUSLIMIIN (Segala puji bagi Allah Dzat yang telah memberi makan dan minum kami, serta menjadikan kami sebagai orang-orang yang berserah diri) '.\""},"3240":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ إِذَا رُفِعَ طَعَامُهُ أَوْ مَا بَيْنَ يَدَيْهِ قَالَ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا غَيْرَ مَكْفِيٍّ وَلَا مُوَدَّعٍ وَلَا مُسْتَغْنًى عَنْهُ رَبَّنَا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abu Umamah Al Bahili] dari Nabi shallallahu 'alaihi wasallam, bahwa ketika makanan telah di angkat atau masih di hadapannya, beliau mengucapkan: 'AL HAMDULILLAH HAMDAN KATSIIRA THAYYIBAN MUBAARAKAN GHAIRU MAKFI'IYYIN WALAA MUWADDI'IN WALAA MUSTGHNA 'ANHU RABBANI (Segala puji bagi Allah dengan pujian yang banyak dan baik serta membawa keberkahan. (Dzat) yang tidak setara dan bukan yang terakhir serta tidak membutuhkan (kepada sesuatu pun), wahai Rabb kami) '.\""},"3241":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ أَبِي مَرْحُومٍ عَبْدِ الرَّحِيمِ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ طَعَامًا فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنِي هَذَا وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Sa'id bin Abu Ayyub] dari [Abu Marhum Abdurrahim] dari [Sahl bin Mu'adz bin Anas Al Juhani] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa makan makanan kemudian mengucapkan 'Segala puji bagi Allah, yang telah memberiku makanan ini dan memberiku rizki ini dengan tidak ada daya dan kekuatan dariku'. Maka akan diampuni dosa-dosanya yang telah lalu.\""},"3242":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَدَاوُدُ بْنُ رُشَيْدٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالُوا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا وَحْشِيُّ بْنُ حَرْبِ بْنِ وَحْشِيِّ بْنِ حَرْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ وَحْشِيٍّأَنَّهُمْ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا نَأْكُلُ وَلَا نَشْبَعُ قَالَ فَلَعَلَّكُمْ تَأْكُلُونَ مُتَفَرِّقِينَ قَالُوا نَعَمْ قَالَ فَاجْتَمِعُوا عَلَى طَعَامِكُمْ وَاذْكُرُوا اسْمَ اللَّهِ عَلَيْهِ يُبَارَكْ لَكُمْ فِيهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Daud bin Rusyaid] dan [Muhammad bin As Shabah] mereka berkata; telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Wahsyi bin Harb bin Wahsyi bin Harb] dari [Ayahnya] dari kakeknya [Wahsyi], sesungguhnya para sahabat bertanya, \"Wahai Rasulullah, kami makan namun tidak pernah merasa kenyang?\" Beliau bersabda: \"Mungkin kalian makan dengan berpencar (tidak bersama-sama).\" Mereka berkata, \"Ya, benar.\" Beliau bersabda: \"Berkumpullah pada makanan kalian (untuk makan bersama) dan sebutlah nama Allah, niscaya kalian akan di berkahi.\""},"3243":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَهْرَمَانُ آلِ الزُّبَيْرِ قَالَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا جَمِيعًا وَلَا تَفَرَّقُوا فَإِنَّ الْبَرَكَةَ مَعَ الْجَمَاعَةِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Sa'id bin Zaid] telah menceritakan kepada kami ['Amru bin Dinar Qahraman] keluarga Az Zubair, dia berkata; saya mendengar [Salim bin Abdullah bin Umar] berkata; saya mendengar [Ayahku] berkata, \"Saya mendengar [Umar bin Al Khaththab] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah bersama-sama dan jangan berpencar, sesungguhnya barakah itu bersama jama'ah.\""},"3244":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ عَبْدِ الرَّحْمَنِ الْمُحَارِبِيُّ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ الْكَرِيمِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْفُخُ فِي طَعَامٍ وَلَا شَرَابٍ وَلَا يَتَنَفَّسُ فِي الْإِنَاءِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdurrahim bin Abdurrahman Al Muharibi] telah menceritakan kepada kami [Syarik] dari [Abdul Karim] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah meniup pada makanan dan minuman, dan beliau juga tidak bernafas dalam bejana.\""},"3245":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ أَبِيهِ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ أَحَدَكُمْ خَادِمُهُ بِطَعَامِهِ فَلْيُجْلِسْهُ فَلْيَأْكُلْ مَعَهُ فَإِنْ أَبِي فَلْيُنَاوِلْهُ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Ayahnya] saya mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika pembantu salah seorang dari kalian datang dengan membawa makanan, hendaknya dia meminta pembantunya untuk duduk dan makan bersama, jika pembantunya enggan hendaklah ia berikan (sedikit) makanan itu kepadanya.\""},"3246":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَحَدُكُمْ قَرَّبَ إِلَيْهِ مَمْلُوكُهُ طَعَامًا قَدْ كَفَاهُ عَنَاءَهُ وَحَرَّهُ فَلْيَدْعُهُ فَلْيَأْكُلْ مَعَهُ فَإِنْ لَمْ يَفْعَلْ فَلْيَأْخُذْ لُقْمَةً فَلْيَجْعَلْهَا فِي يَدِهِ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ja'far bin Rabi'ah] dari [Abdurrahman Al A'raj] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika budak salah seorang dari kalian mendekat dengan membawa makanan yang telah dimasak dan terasa lelahnya, maka hendaklah ia panggil budak tersebut untuk makan bersama, jika budak tersebut enggan hendaklah ia ambil sesuap makanan dan memberikan dalam genggamannya.\""},"3247":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ ثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ ثَنَا إِبْرَاهِيمُ الْهَجَرِيُّ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ خَادِمُ أَحَدِكُمْ بِطَعَامِهِ فَلْيُقْعِدْهُ مَعَهُ أَوْ لِيُنَاوِلْهُ مِنْهُ فَإِنَّهُ هُوَ الَّذِي وَلِيَ حَرَّهُ وَدُخَانَهُ","id":"Telah menceritakan kepada kami [Ali bin Al Mundzir] telah menceritakan kepada kami [Muhammad bin Fudhail] telah menceritakan kepada kami [Ibrahim Al Hajari] dari [Abu Al Ahwash] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika pembantu salah seorang dari kalian datang membawa makanan, maka hendaknya ia perintahkan kepada pembantunya untuk duduk (makan bersama), atau memberinya makan dengan makanan tersebut. Sebab dialah yang telah memasak dan mematangkannya.\""},"3248":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ يُونُسَ بْنِ أَبِي الْفُرَاتِ الْإِسْكَافِ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا أَكَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خِوَانٍ وَلَا فِي سُكُرُّجَةٍ قَالَ فَعَلَامَ كَانُوا يَأْكُلُونَ قَالَ عَلَى السُّفَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepada kami [Ayahku] dari [Yunus bin Abu Al furat Al Iskaf] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Nabi shallallahu 'alaihi wasallam tidak pernah makan dengan menggunakan Khiwan (tempayan besar) atau dengan sukurrajah (mangkuk kecil).\" Dia berkata, \"Lantas dengan apa mereka makan?\" Anas menjawab, \"Dengan menggunakan sufar (piring yang terbuat dari kulit).\""},"3249":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ يُوسُفَ الْجُبَيْرِيُّ حَدَّثَنَا أَبُو بَحْرٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ عَلَى خِوَانٍ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Yusuf Al Jubairi] telah menceritakan kepada kami [Abu Bahr] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] dia berkata, \"Saya tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam makan di atas Khiwan (tempayan besar) sampai beliau meninggal dunia.\""},"3250":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ بَشِيرِ بْنِ ذَكْوَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مُنِيرِ بْنِ الزُّبَيْرِ عَنْ مَكْحُولٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُقَامَ عَنْ الطَّعَامِ حَتَّى يُرْفَعَ","id":"Telah menceritakan kepada kami [Abdullah bin Ahmad bin Basyir bin Dzakwan Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Munir bin Az Zubair] dari [Makhul] dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam melarang meninggalkan makanan sehingga (makanan tersebut) diangkat.\""},"3251":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ أَنْبَأَنَا عَبْدُ الْأَعْلَى عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَتْ الْمَائِدَةُ فَلَا يَقُومُ رَجُلٌ حَتَّى تُرْفَعَ الْمَائِدَةُ وَلَا يَرْفَعُ يَدَهُ وَإِنْ شَبِعَ حَتَّى يَفْرُغَ الْقَوْمُ وَلْيُعْذِرْ فَإِنَّ الرَّجُلَ يُخْجِلُ جَلِيسَهُ فَيَقْبِضُ يَدَهُ وَعَسَى أَنْ يَكُونَ لَهُ فِي الطَّعَامِ حَاجَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al 'Asqalani] telah menceritakan kepada kami [Ubaidullah] telah memberitakan kepada kami [Abdul A'la] dari [Yahya bin Abu Katsir] dari ['Urwah bin Az Zubair] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila makanan diletakkan maka janganlah seseorang bangkit sehingga makanan itu diangkat, dan janganlah ia mengangkat tangannya meski dia sudah kenyang sehingga orang-orang selesai makan lalu meminta izin. Sebab seseorang merasa malu kepada teman duduknya hingga ia menahan tangannya, bisa jadi dia masih mempunyai hajat terhadap makanan tersebut.\""},"3252":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا عُبَيْدُ بْنُ وَسِيمٍ الْجَمَّالُ حَدَّثَنِي الْحَسَنُ بْنُ الْحَسَنِ عَنْ أُمِّهِ فَاطِمَةَ بِنْتِ الْحُسَيْنِ عَنْ الْحُسَيْنِ بْنِ عَلِيٍّ عَنْ أُمِّهِ فَاطِمَةَ ابْنَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا لَا يَلُومَنَّ امْرُؤٌ إِلَّا نَفْسَهُ يَبِيتُ وَفِي يَدِهِ رِيحُ غَمَرٍ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallas] telah menceritakan kepada kami ['Ubaid bin Wasim Al Jammal] telah menceritakan kepadaku [Al Hasan bin Al Hasan] dari ibunya [Fatimah binti Husain] dari [Al Husain bin Ali] dari ibunya [Fatimah] puteri Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, jangan sekali-kali seseorang menyalahkan kecuali pada dirinya sendiri; dia bermalam sementara di tangannya masih ada minyak sisa makanan (yang belum dibersihkan).\""},"3253":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَامَ أَحَدُكُمْ وَفِي يَدِهِ رِيحُ غَمَرٍ فَلَمْ يَغْسِلْ يَدَهُ فَأَصَابَهُ شَيْءٌ فَلَا يَلُومَنَّ إِلَّا نَفْسَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] telah menceritakan kepada kami [Abdul Aziz bin Al Muhtar] telah menceritakan kepada kami [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang dari kalian tidur sedang di tangannya masih menyisakan aroma masakan dan dia tidak mencuci tangannya kemudian mengenainya, maka jangan sekali-kali ia menyalahkan kecuali pada dirinya sendiri.\""},"3254":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي حُسَيْنٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِطَعَامٍ فَعَرَضَ عَلَيْنَا فَقُلْنَا لَا نَشْتَهِيهِ فَقَالَ لَا تَجْمَعْنَ جُوعًا وَكَذِبًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibnu Abu Husain] dari [Syahr bin Hausyab] dari [Asma binti Yazid] dia berkata, \"Dihidangkan makanan kepada Nabi shallallahu 'alaihi wasallam, lalu beliau menawarkannya kepada kami, namun kami mengatakan, \"Kami tidak selera.\" Maka beliau pun bersabda: \"Janganlah kalian mencampur rasa lapar dengan kedustaan.\""},"3255":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ أَبِي هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ سَوَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَجُلٌ مِنْ بَنِي عَبْدِ الْأَشْهَلِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَغَدَّى فَقَالَ ادْنُ فَكُلْ فَقُلْتُ إِنِّي صَائِمٌ فَيَا لَهْفَ نَفْسِي هَلَّا كُنْتُ طَعِمْتُ مِنْ طَعَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Abu Hilal] dari [Abdullah bin Sawadah] dari [Anas bin Malik] seorang laki-laki dari Bani Asyhal, dia berkata, \"Saya datang menemui Nabi shallallahu 'alaihi wasallam di saat beliau sedang makan, beliau lalu bersabda: 'Mendekatlah dan makanlah.' Aku lalu menjawab, 'Aku sedang berpuasa.' Duh…betapa menyesalnya aku! Andai saja aku dapat mencicipi makanan Rasulullah shallallahu 'alaihi wasallam.\""},"3256":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ حَدَّثَنِي سُلَيْمَانُ بْنُ زِيَادٍ الْحَضْرَمِيُّ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ الْحَارِثِ بْنِ جَزْءٍ الزُّبَيْدِيَّ يَقُولُكُنَّا نَأْكُلُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ الْخُبْزَ وَاللَّحْمَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] dan [Harmalah bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepadaku ['Amru bin Al Harits] telah menceritakan kepadaku [Sulaiman bin Ziyad Al Hadlrami] bahwa dia mendengar [Abdullah bin Al Harits bin Juz` Az Zubaidi] dia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami pernah makan roti dan daging di dalam masjid.\""},"3257":{"ar":"حَدَّثَنَا أَبُو السَّائِبِ سَلْمُ بْنُ جُنَادَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَأْكُلُ وَنَحْنُ نَمْشِي وَنَشْرَبُ وَنَحْنُ قِيَامٌ","id":"Telah menceritakan kepada kami [Abu As Sa`ib Salm bin Junadah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami pernah makan sambil berjalan dan minum sambil berdiri.\""},"3258":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ أَنْبَأَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْقَرْعَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah memberitakan kepada kami ['Abidah bin Humaid] dari [Humaid] dari [Anas] dia berkata, \"Nabi shallallahu 'alaihi wasallam menyukai buah labu.\""},"3259":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَبَعَثَتْ مَعِي أُمُّ سُلَيْمٍ بِمِكْتَلٍ فِيهِ رُطَبٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أَجِدْهُ وَخَرَجَ قَرِيبًا إِلَى مَوْلًى لَهُ دَعَاهُ فَصَنَعَ لَهُ طَعَامًا فَأَتَيْتُهُ وَهُوَ يَأْكُلُ قَالَ فَدَعَانِي لِآكُلَ مَعَهُ قَالَ وَصَنَعَ ثَرِيدَةً بِلَحْمٍ وَقَرْعٍ قَالَ فَإِذَا هُوَ يُعْجِبُهُ الْقَرْعُ قَالَ فَجَعَلْتُ أَجْمَعُهُ فَأُدْنِيهِ مِنْهُ فَلَمَّا طَعِمْنَا مِنْهُ رَجَعَ إِلَى مَنْزِلِهِ وَوَضَعْتُ الْمِكْتَلَ بَيْنَ يَدَيْهِ فَجَعَلَ يَأْكُلُ وَيَقْسِمُ حَتَّى فَرَغَ مِنْ آخِرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Humaid] dari [Anas] dia berkata, \"Ummu Sulaim mengutusku kepada Rasulullah shallallahu 'alaihi wasallam untuk memberikan keranjang yang di dalamnya ada buah kurma muda, namun aku tidak menjumpai beliau. Sebab saat itu beliau sedang pergi ke tempat mantan budak yang ia merdekakan, budak itu mengundang beliau makan dan telah menyediakan makanan untuknya. Kemudian aku menemui beliau ketika sedang menyantap makanan.\" Anas berkata, \"Beliau lalu memanggilku supaya makan bersamanya. Mantan budak beliau tersebut membuatkan bubur dari daging dan buah labu. Dan sungguh beliau sangat menyukai buah labu.\" Anas melanjutkan, \"Maka aku pun mengumpulkan (mencari-cari) potongan buah labu dan aku berikan kepada beliau. Selesai makan beliau kembali pulang, aku lalu meletakkan keranjang kurma di hadapan beliau, beliau lalu memakannya sampai selesai.\""},"3260":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ حَكِيمِ بْنِ جَابِرٍ عَنْ أَبِيهِ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ وَعِنْدَهُ هَذَا الدُّبَّاءُ فَقُلْتُ أَيُّ شَيْءٍ هَذَا قَالَ هَذَا الْقَرْعُ هُوَ الدُّبَّاءُ نُكْثِرُ بِهِ طَعَامَنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Isma'il bin Abu Khalid] dari [Hakim bin Jabir] dari [Ayahnya] dia berkata, \"Saya menemui Nabi shallallahu 'alaihi wasallam di rumahnya dan di sisi beliau terdapat buah labu.\" Aku bertanya, \"Buah apa ini?\" beliau menjawab: \"Ini adalah buah labu yang kami jadikan untuk memperbanyak makanan kami.\""},"3261":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الْخَلَّالُ الدِّمَشْقِيُّ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنِي سُلَيْمَانُ بْنُ عَطَاءٍ الْجَزَرِيُّ حَدَّثَنِي مَسْلَمَةُ بْنُ عَبْدِ اللَّهِ الْجُهَنِيُّ عَنْ عَمِّهِ أَبِي مَشْجَعَةَ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيِّدُ طَعَامِ أَهْلِ الدُّنْيَا وَأَهْلِ الْجَنَّةِ اللَّحْمُ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Al Khallal Ad Dimasyqi] telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepadaku [Sulaiman bin 'Atha Al Jazari] telah menceritakan kepadaku [Maslamah bin Abdullah Al Juhani] dari pamannya [Abu Masyja'ah] dari [Abu Darda] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanan istimewa penduduk dunia dan penduduk surga adalah daging.\""},"3262":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا سُلَيْمَانُ بْنُ عَطَاءٍ الْجَزَرِيُّ حَدَّثَنَا مَسْلَمَةُ بْنُ عَبْدِ اللَّهِ الْجُهَنِيُّ عَنْ عَمِّهِ أَبِي مَشْجَعَةَ عَنْ أَبِي الدَّرْدَاءِ قَالَمَا دُعِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى لَحْمٍ قَطُّ إِلَّا أَجَابَ وَلَا أُهْدِيَ لَهُ لَحْمٌ قَطُّ إِلَّا قِبَلَهُ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Al Khallal Ad Dimasyqi] telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepadaku [Sulaiman bin 'Atha Al Jazari] telah menceritakan kepada kami [Maslamah bin Abdullah Al Juhani] dari pamannya [Abu Masyja'ah] dari [Abu Darda] dia berkata, \"Tidaklah Rasulullah shallallahu 'alaihi wasallam diundang untuk makan daging kecuali beliau akan memenuhinya, dan tidak pula beliau diberi hadiah berupa daging melainkan beliau akan menerimanya.\""},"3263":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ الْعَبْدِيُّ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَا حَدَّثَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ بِلَحْمٍ فَرُفِعَ إِلَيْهِ الذِّرَاعُ وَكَانَتْ تُعْجِبُهُ فَنَهَسَ مِنْهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr Al 'Abdi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Muhammad bin Fudlail] keduanya berkata; telah menceritakan kepada kami [Abu Hayyan 'Atha At Taimi] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Pada suatu hari pernah dihidangkan daging kepada Rasulullah shallallahu 'alaihi wasallam, kemudian beliau diambilkan daging paha -dan beliau sangat menyukainya- lalu menggigitnya dengan gigi serinya.\""},"3264":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مِسْعَرٍ حَدَّثَنِي شَيْخٌ مِنْ فَهْمٍ قَالَ وَأَظُنُّهُ يُسَمَّى مُحَمَّدَ بْنَ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ جَعْفَرٍيُحَدِّثُ ابْنَ الزُّبَيْرِ وَقَدْ نَحَرَ لَهُمْ جَزُورًا أَوْ بَعِيرًا أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالْقَوْمُ يُلْقُونَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّحْمَ يَقُولُ أَطْيَبُ اللَّحْمِ لَحْمُ الظَّهْرِ","id":"Telah menceritakan kepada kami [Bakar bin Khalaf Abu Bisyr] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Mis'ar] -seorang Syaikh dari Fahm menceritakan kepadaku, (Mis'ar) berkata; dan menurutku ia bernama- [Muhammad bin Abdullah] bahwa dia mendengar [Abdullah bin Ja'far] menceritakan kepada Ibnu Zubair -ketika itu dia sedang menyembelih unta-, bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika ada sekelompok orang memberi daging kepada beliau, sabdanya: \"Sebaik-baik daging adalah daging punggung.\""},"3265":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا أَعْلَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى شَاةً سَمِيطًا حَتَّى لَحِقَ بِاللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam melihat kambing panggang (guling) hingga beliau bertemu dengan Allah Azza Wa Jalla.\""},"3266":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا كَثِيرُ بْنُ سُلَيْمٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا رُفِعَ مِنْ بَيْنِ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضْلُ شِوَاءٍ قَطُّ وَلَا حُمِلَتْ مَعَهُ طِنْفِسَةٌ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallas] telah menceritakan kepada kami [Katsir bin Sulaim] dari [Anas bin Malik] dia berkata, \"Tidak pernah diangkat sisa daging panggang dari hadapan Rasulullah shallallahu 'alaihi wasallam dan tidak pula tikar dibawa bersamanya.\""},"3267":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا ابْنُ لَهِيعَةَ أَخْبَرَنِي سُلَيْمَانُ بْنُ زِيَادٍ الْحَضْرَمِيُّ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ جَزْءٍ الزُّبَيْدِيِّ قَالَأَكَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فِي الْمَسْجِدِ لَحْمًا قَدْ شُوِيَ فَمَسَحْنَا أَيْدِيَنَا بِالْحَصْبَاءِ ثُمَّ قُمْنَا نُصَلِّي وَلَمْ نَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Ibnu Lahi'ah] telah mengabarkan kepadaku [Sulaiman bin Ziyad Al Hadlrami] dari [Abdullah bin Al Harits bin Juz` Az Zubaidi] dia berkata, \"Kami pernah makan daging panggang bersama Rasulullah shallallahu 'alaihi wasallam di dalam masjid, kemudian kami membersihkan tangan kami dengan kerikil lalu mengerjakan shalat tanpa berwudlu terlebih dahulu, \""},"3268":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَسَدٍ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَكَلَّمَهُ فَجَعَلَ تُرْعَدُ فَرَائِصُهُ فَقَالَ لَهُ هَوِّنْ عَلَيْكَ فَإِنِّي لَسْتُ بِمَلِكٍ إِنَّمَا أَنَا ابْنُ امْرَأَةٍ تَأْكُلُ الْقَدِيدَقَالَ أَبُو عَبْد اللَّهِ إِسْمَعِيلُ وَحْدَهُ وَصَلَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Asad] telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Mas'ud] dia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan mengajaknya berbicara dan tiba-tiba dia gemetar ketakutan, maka beliau bersabda: \"Tenangkan dirimu, sesungguhnya aku bukan seorang raja, aku hanyalah anak seorang wanita yang memakan dendeng, \""},"3269":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ قَالَتْلَقَدْ كُنَّا نَرْفَعُ الْكُرَاعَ فَيَأْكُلُهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ خَمْسَ عَشْرَةَ مِنْ الْأَضَاحِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin 'Abis] telah mengabarkan kepadaku [Ayahku] dari [Aisyah] dia berkata, \"Kami menyediakan daging betis, lalu Rasulullah shallallahu 'alaihi wasallam memakannya setelah lima belas hari dari hari Idul Adlha, \""},"3270":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُحِلَّتْ لَكُمْ مَيْتَتَانِ وَدَمَانِ فَأَمَّا الْمَيْتَتَانِ فَالْحُوتُ وَالْجَرَادُ وَأَمَّا الدَّمَانِ فَالْكَبِدُ وَالطِّحَالُ","id":"Telah menceritakan kepada kami [Abu Mush'ab] telah menceritakan kepada kami [Abdurrahman bin Zaid bin Aslam] dari [Ayahnya] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Telah dihalalkan buat kalian dua jenis bangkai dan dua jenis darah, dua jenis bangkai adalah; bangkai ikan paus dan bangkai belalang, sedangkan dua jenis darah adalah darah hati dan limpa.\""},"3271":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا عِيسَى بْنُ أَبِي عِيسَى عَنْ رَجُلٍ أُرَاهُ مُوسَى عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيِّدُ إِدَامِكُمْ الْمِلْحُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Isa bin Abu Isa] dari [seorang laki-laki] yang sepertinya Musa, dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lauk teristimewa kalian adalah garam.\""},"3272":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي الْحَوَارِيِّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الْإِدَامُ الْخَلُّ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Al Hawari] telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik lauk adalah cuka.\""},"3273":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا قَيْسُ بْنُ الرَّبِيعِ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الْإِدَامُ الْخَلُّ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] telah menceritakan kepada kami [Qais bin Ar Rabi'] dari [Muharib bin Ditsar] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik lauk adalah cuka, \""},"3274":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَنْبَسَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ زَاذَانَ أَنَّهُ حَدَّثَهُ قَالَ حَدَّثَتْنِي أُمُّ سَعْدٍ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَائِشَةَ وَأَنَا عِنْدَهَا فَقَالَ هَلْ مِنْ غَدَاءٍ قَالَتْ عِنْدَنَا خُبْزٌ وَتَمْرٌ وَخَلٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الْإِدَامُ الْخَلُّ اللَّهُمَّ بَارِكْ فِي الْخَلِّ فَإِنَّهُ كَانَ إِدَامَ الْأَنْبِيَاءِ قَبْلِي وَلَمْ يَفْتَقِرْ بَيْتٌ فِيهِ خَلٌّ","id":"Telah menceritakan kepada kami [Al Abbas bin Utsman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami ['Anbasah bin Abdurrahman] dari [Muhammad bin Zadzan] bahwa dia telah menceritakan kepadanya, dia berkata; telah menceritakan kepadaku [Ummu Sa'd] dia berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam menemui Aisyah aku sedang berada di sampingnya, beliau bertanya: \"Apakah ada makanan?\" Aisyah menjawab, \"Kita hanya memiliki roti, kurma dan cuka.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik lauk adalah cuka. Ya Allah, berkahilah cuka, sesungguhnya cuka adalah lauk para nabi sebelumku, dan tidak dikatakan fakir rumah yang di dalamnya terdapat cuka.\""},"3275":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْتَدِمُوا بِالزَّيْتِ وَادَّهِنُوا بِهِ فَإِنَّهُ مِنْ شَجَرَةٍ مُبَارَكَةٍ","id":"Telah menceritakan kepada kami [Al Husain bin Mahdi] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari [Ayahnya] dari [Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah minyak (zaitun) sebagai lauk paukmu, dan minyakilah (rambut) kalian dengannya, sesungguhnya ia berasal dari pohon yang berkahi.\""},"3276":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ جَدِّهِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا الزَّيْتَ وَادَّهِنُوا بِهِ فَإِنَّهُ مُبَارَكٌ","id":"Telah menceritakan kepada kami ['Uqbah bin Mukram] telah menceritakan kepada kami [Shafwan bin Isa] telah menceritakan kepada kami [Abdullah bin Sa'id] dari [Kakeknya] dia berkata; saya mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah dengan minyak dan berminyaklah dengannya, sesungguhnya minyak itu diberkahi.\""},"3277":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ جَعْفَرِ بْنِ بُرْدٍ الرَّاسِبِيِّ حَدَّثَتْنِي مَوْلَاتِي أُمُّ سَالِمٍ الرَّاسِبِيَّةُ قَالَتْ سَمِعْتُ عَائِشَةَ تَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُتِيَ بِلَبَنٍ قَالَ بَرَكَةٌ أَوْ بَرَكَتَانِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Zaid bin Al Hubbab] dari [Ja'far bin Burd Ar Rasibi] telah menceritakan kepadaku bekas budak perempuanku [Ummu Salim Ar Rasibiyah] dia berkata; saya mendengar [Aisyah] berkata, \"Apabila Rasulullah shallallahu 'alaihi wasallam diberi susu, maka beliau akan mengatakan: \"Satu berkah.\" Atau, \"Dua berkah, \""},"3278":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَطْعَمَهُ اللَّهُ طَعَامًا فَلْيَقُلْ اللَّهُمَّ بَارِكْ لَنَا فِيهِ وَارْزُقْنَا خَيْرًا مِنْهُ وَمَنْ سَقَاهُ اللَّهُ لَبَنًا فَلْيَقُلْ اللَّهُمَّ بَارِكْ لَنَا فِيهِ وَزِدْنَا مِنْهُ فَإِنِّي لَا أَعْلَمُ مَا يُجْزِئُ مِنْ الطَّعَامِ وَالشَّرَابِ إِلَّا اللَّبَنُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepada kami [Ibnu Juraij] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dianugerahi makanan oleh Allah, maka hendaklah ia mengucapkan, 'Ya Allah berkahilah kami di dalam makanan ini, dan berilah kami rizki kebaikan darinya.' Dan barangsiapa dianugerahi minuman susu oleh Allah, hendaklah ia mengucapkan, \"Ya Allah, berikanlah kami keberkahan padanya dan tambahkanlah kami darinya.' Sesungguhnya aku tidak mengetahui makanan dan minuman yang bermanfaat kecuali susu.\""},"3279":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْحَلْوَاءَ وَالْعَسَلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] dan [Abdurrahman bin Ibrahim] mereka berkata; telah menceritakan kepada kami [Abu Usamah] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyukai manisan dan madu, \""},"3280":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ أُمِّي تُعَالِجُنِي لِلسُّمْنَةِ تُرِيدُ أَنْ تُدْخِلَنِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا اسْتَقَامَ لَهَا ذَلِكَ حَتَّى أَكَلْتُ الْقِثَّاءَ بِالرُّطَبِ فَسَمِنْتُ كَأَحْسَنِ سِمْنَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Yunus bin Bukair] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Ibuku mengobatiku agar aku kelihatan gemuk, saat dia hendak mempertemukan aku dengan Rasulullah shallallahu 'alaihi wasallam, dan usaha itu tidak membuahkan hasil sehingga aku memakan timun dengan kurma basah. Kemudian aku menjadi gemuk dengan bentuk yang ideal.\""},"3281":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ وَإِسْمَعِيلُ بْنُ مُوسَى قَالَا حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الْقِثَّاءَ بِالرُّطَبِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] dan [Isma'il bin Musa] keduanya berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ayahnya] dari [Abdullah bin Ja'far] dia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam makan mentimun dengan kurma basah, \""},"3282":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَعَمْرُو بْنُ رَافِعٍ قَالَا حَدَّثَنَا يَعْقُوبُ بْنُ الْوَلِيدِ بْنِ أَبِي هِلَالٍ الْمَدَنِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الرُّطَبَ بِالْبِطِّيخِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah] dan ['Amru bin Rafi'] keduanya berkata; telah menceritakan kepada kami [Ya'qub bin Al Walid bin Abu Hilal Al Madani] dari [Abu Hazim] dari [Sahl bin Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam makan kurma basah dengan semangka.\""},"3283":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي الْحَوَارِيِّ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتٌ لَا تَمْرَ فِيهِ جِيَاعٌ أَهْلُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Al Hawari Ad Dimasyqi] telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rumah yang tidak ada kurma di dalamnya, maka akan membuat penghuninya lapar.\""},"3284":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ جَدَّتِهِ سَلْمَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْتٌ لَا تَمْرَ فِيهِ كَالْبَيْتِ لَا طَعَامَ فِيهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah menceritakan kepada kami [Hisyam bin Sa'd] dari ['Ubaidullah bin Abu Rafi'] dari neneknya [Salma], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Rumah yang tidak ada kurma di dalamnya seperti rumah yang di dalamnya tidak ada makanan.\""},"3285":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ أَخْبَرَنِي سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أُتِيَ بِأَوَّلِ الثَّمَرَةِ قَالَ اللَّهُمَّ بَارِكْ لَنَا فِي مَدِينَتِنَا وَفِي ثِمَارِنَا وَفِي مُدِّنَا وَفِي صَاعِنَا بَرَكَةً مَعَ بَرَكَةٍ ثُمَّ يُنَاوِلُهُ أَصْغَرَ مَنْ بِحَضْرَتِهِ مِنْ الْوِلْدَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] telah mengabarkan kepadaku [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah], bahwa jika Rasulullah shallallahu 'alaihi wasallam diberi buah yang masih kecil beliau mengucapkan: \"Ya Allah, berkahilah kami di negeri kami ini, buah-buahan kami, pada mud dan sha' kami, dengan keberkahan yang berlanjut dengan keberkahan yang lainnya.\" Kemudian beliau mengambilkan untuk anak-anak yang paling kecil yang berada di dekat beliau, \""},"3286":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَحْيَى ��ْنُ مُحَمَّدِ بْنِ قَيْسٍ الْمَدَنِيُّ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا الْبَلَحَ بِالتَّمْرِ كُلُوا الْخَلَقَ بِالْجَدِيدِ فَإِنَّ الشَّيْطَانَ يَغْضَبُ وَيَقُولُ بَقِيَ ابْنُ آدَمَ حَتَّى أَكَلَ الْخَلَقَ بِالْجَدِيدِ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Yahya bin Muhammad bin Qais Al Madani] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah kurma mentah dengan kurma matang, dan makanlah kurma usang dengan kurma baru, sesungguhnya setan akan marah dan berkata, 'Anak Adam akan tetap sehingga dia memakan yang usang dicampur dengan yang baru'.\""},"3287":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ جَبَلَةَ بْنِ سُحَيْمٍ سَمِعْتُ ابْنَ عُمَرَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْرِنَ الرَّجُلُ بَيْنَ التَّمْرَتَيْنِ حَتَّى يَسْتَأْذِنَ أَصْحَابَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Jabalah bin Suhaim] saya mendengar [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang makan kurma dua biji-dua biji sekaligus hingga ia minta izin pemiliknya, \""},"3288":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا أَبُو عَامِرٍ الْخَزَّازُ عَنْ الْحَسَنِ عَنْ سَعْدٍ مَوْلَى أَبِي بَكْرٍ وَكَانَ سَعْدٌ يَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ يُعْجِبُهُ حَدِيثُهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْإِقْرَانِ يَعْنِي فِي التَّمْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Abu 'Amir Al Khazzaz] dari [Al Hasan] dari [Sa'd] bekas budak Abu Bakar -dan Sa'd adalah pelayan Nabi shallallahu 'alaihi wasallam, dan ia sangat kagum dengan riwayatnya-, bahwa Nabi shallallahu 'alaihi wasallam melarang iqran saat makan buah kurma.\" "},"3289":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا أَبُو قُتَيْبَةَ عَنْ هَمَّامٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِتَمْرٍ عَتِيقٍ فَجَعَلَ يُفَتِّشُهُ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Abu Qutaibah] dari [Hammam] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam diberi kurma yang telah usang, beliau lalu memeriksanya terlebih dahulu.\""},"3290":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنِي ابْنُ جَابِرٍ حَدَّثَنِي سُلَيْمُ بْنُ عَامِرٍ عَنْ ابْنَيْ بُسْرٍ السُّلَمِيَّيْنِ قَالَادَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْنَا تَحْتَهُ قَطِيفَةً لَنَا صَبَبْنَاهَا لَهُ صَبًّا فَجَلَسَ عَلَيْهَا وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ عَلَيْهِ الْوَحْيَ فِي بَيْتِنَا وَقَدَّمْنَا لَهُ زُبْدًا وَتَمْرًا وَكَانَ يُحِبُّ الزُّبْدَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Shadaqah bin Khalid] telah menceritakan kepadaku [Ibnu Jabir] telah menceritakan kepadaku [Sulaim bin 'Amir] dari kedua anaknya Busr As Sulami ([Abdullah bin Busr] dan [Athiyah bin Busr]) keduanya berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk menemui kami, lantas kami meletakkan selimut milik kami yang kami hamparkan untuk beliau, kemudian beliau duduk di atasnya. Kemudian Allah menurunkan wahyu kepada beliau di rumah kami. Lalu kami menyediakan keju dan kurma untuk beliau, sungguh beliau sangat menyukai keju.\""},"3291":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ حَدَّثَنِي أَبِي قَالَ سَأَلْتُ سَهْلَ بْنَ سَعْدٍهَلْ رَأَيْتَ النَّقِيَّ قَالَ مَا رَأَيْتُ النَّقِيَّ حَتَّى قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ فَهَلْ كَانَ لَهُمْ مَنَاخِلُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا رَأَيْتُ مُنْخُلًا حَتَّى قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ فَكَيْفَ كُنْتُمْ تَأْكُلُونَ الشَّعِيرَ غَيْرَ مَنْخُولٍ قَالَ نَعَمْ كُنَّا نَنْفُخُهُ فَيَطِيرُ مِنْهُ مَا طَارَ وَمَا بَقِيَ ثَرَّيْنَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] dan [Suwaid bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] telah menceritakan kepadaku [Ayahku] dia berkata, \"Saya bertanya kepada [Sahl bin Sa'd], 'Apakah kamu mengetahui alat pemutih (alat pembersih)?\" dia menjawab, \"Aku tidak pernah melihat alat pemutih sampai Rasulullah shallallahu 'alaihi wasallam meninggal dunia.\" Maka aku bertanya, \"Apakah mereka (para sahabat) melihat alat pengayak tepung pada masa Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab, \"Tidak, aku tidak pernah melihat alat pengayak tepung sampai Rasulullah shallallahu 'alaihi wasallam meninggal dunia.\" Aku bertanya lagi, \"Bagaimana kalian memakan gandum yang belum ditapis?\" dia menjawab, \"Ya, kami meniupnya hingga kotoran yang ada padanya terbang, lalu yang tersisa kami basahi dengan air, \""},"3292":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَخْبَرَنِي بَكْرُ بْنُ سَوَادَةَ أَنَّ حَنَشَ بْنَ عَبْدِ اللَّهِ حَدَّثَهُ عَنْ أُمِّ أَيْمَنَأَنَّهَا غَرْبَلَتْ دَقِيقًا فَصَنَعَتْهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَغِيفًا فَقَالَ مَا هَذَا قَالَتْ طَعَامٌ نَصْنَعُهُ بِأَرْضِنَا فَأَحْبَبْتُ أَنْ أَصْنَعَ مِنْهُ لَكَ رَغِيفًا فَقَالَ رُدِّيهِ فِيهِ ثُمَّ اعْجِنِيهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] telah mengabarkan kepadaku [Bakr bin Sawadah] bahwa [Hanasy bin Abdullah] menceritakan kepadanya dari [Ummu Aiman], bahwa dia sedang mengayak gandum, kemudian ia membuatnya menjadi roti untuk Nabi shallallahu 'alaihi wasallam. Beliau lalu bertanya \"Apakah ini?\" dia menjawab, \"Makanan yang aku buat dari hasil bumi (negeri) kami, aku senang menjadikannya roti untuk anda.\" Kemudian beliau pun bersabda: \"Kembalikan ia pada tempatnya, lalu buatlah menjadi adonan, \""},"3293":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ أَبُو الْجَمَاهِرِ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَغِيفًا مُحَوَّرًا بِوَاحِدٍ مِنْ عَيْنَيْهِ حَتَّى لَحِقَ بِاللَّهِ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Ad Dimasyqi] telah menceritakan kepada kami [Muhammad bin Utsman Abu Al Jamahir] telah menceritakan kepada kami [Sa'id bin Basyir] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah sama sekali melihat roti adonan (meskipun) dengan salah satu matanya hingga beliau bertemu Allah, \""},"3294":{"ar":"حَدَّثَنَا أَبُو عُمَيْرٍ عِيسَى بْنُ مُحَمَّدٍ النَّحَّاسُ الرَّمْلِيُّ حَدَّثَنَا ضَمْرَةُ بْنُ رَبِيعَةَ عَنْ ابْنِ عَطَاءٍ عَنْ أَبِيهِ قَالَزَارَ أَبُو هُرَيْرَةَ قَوْمَهُ يَعْنِي قَرْيَةً أَظُنُّهُ قَالَ يُنَا فَأَتَوْهُ بِرُقَاقٍ مِنْ رُقَاقِ الْأُوَلِ فَبَكَى وَقَالَ مَا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا بِعَيْنِهِ قَطُّ","id":"Telah menceritakan kepada kami [Abu 'Umair Isa bin Muhammad An Nahas Ar Ramli] telah menceritakan kepada kami [Dlamrah bin Rabi'ah] dari [Ibnu 'Atha] dari [Ayahnya] dia berkata, \" [Abu Hurairah] mengunjungi kaumnya, yaitu kampungnya. Aku mengira dia berkata, \"Yunaa.\" Lalu mereka membawakan roti empuk dari roti yang paling bagus kepadanya, Abu Hurairah lalu menangis dan berkata; \"Rasulullah shallallahu 'alaihi wasallam sama sekali tidak pernah melihat ini dengan kedua matanya, \""},"3295":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَأَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ قَالَا حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ قَالَكُنَّا نَأْتِي أَنَسَ بْنَ مَالِكٍ قَالَ إِسْحَقُ وَخَبَّازُهُ قَائِمٌ وَقَالَ الدَّارِمِيُّ وَخِوَانُهُ مَوْضُوعٌ فَقَالَ يَوْمًا كُلُوا فَمَا أَعْلَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَغِيفًا مُرَقَّقًا بِعَيْنِهِ حَتَّى لَحِقَ بِاللَّهِ وَلَا شَاةً سَمِيطًا قَطُّ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] dan [Ahmad bin Sa'id Ad Darimi] keduanya berkata; telah menceritakan kepada kami [Abdus Shamad bin Abdul Warits] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dia berkata, \"Kami menemui Anas bin Malik.\" Ishaq menyebutkan, \"Sementara tukang roti berdiri.\" Ad Darimi berkata, \"Sedangkan meja makannya telah tersedia.\" Lalu suatu hari [Anas] berkata, \"Makanlah oleh kalian, sungguh aku tidak menyaksikan Rasulullah shallallahu 'alaihi wasallam pernah melihat roti halus sampai bertemu dengan Allah, dan juga tidak pernah melihat daging kambing guling, \""},"3296":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ الضَّحَّاكِ السُّلَمِيُّ أَبُو الْحَارِثِ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ عُثْمَانَ بْنِ يَحْيَى عَنْ ابْنِ عَبَّاسٍ قَالَأَوَّلُ مَا سَمِعْنَا بِالْفَالُوذَجِ أَنَّ جِبْرِيلَ عَلَيْهِ السَّلَام أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمَّتَكَ تُفْتَحُ عَلَيْهِمْ الْأَرْضُ فَيُفَاضُ عَلَيْهِمْ مِنْ الدُّنْيَا حَتَّى إِنَّهُمْ لَيَأْكُلُونَ الْفَالُوذَجَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا الْفَالُوذَجُ قَالَ يَخْلِطُونَ السَّمْنَ وَالْعَسَلَ جَمِيعًا فَشَهِقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِذَلِكَ شَهْقَةً","id":"Telah menceritakan kepada kami [Abdul Wahab bin Adl Dlahak As Sulami Abu Al Harits] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Utsman bin Yahya] dari [Ibnu Abbas] dia berkata, \"Pertama kali aku mendengar faludzaj (sejenis makanan) adalah ketika Jibril 'Alaihis salam mendatangi Nabi shallallahu 'alaihi wasallam sambil berkata, \"Sesungguhnya bumi akan ditaklukan untuk umatmu, oleh karenanya mereka akan dibanjiri kenikmatan dunia, sampai-sampai mereka memakan faludzaj.\" Nabi shallallahu 'alaihi wasallam bertanya: 'Apakah faludzaj itu? ' Jibril menjawab: 'Mereka mencampur minyak samin dan madu bersama-sama.' Maka Nabi shallallahu 'alaihi wasallam tercengan karena berita itu.\""},"3297":{"ar":"حَدَّثَنَا هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى السِّينَانِيُّ حَدَّثَنَا الْحُسَيْنُ بْنُ وَاقِدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَدِدْتُ لَوْ أَنَّ عِنْدَنَا خُبْزَةً بَيْضَاءَ مِنْ بُرَّةٍ سَمْرَاءَ مُلَبَّقَةٍ بِسَمْنٍ نَأْكُلُهَا قَالَ فَسَمِعَ بِذَلِكَ رَجُلٌ مِنْ الْأَنْصَارِ فَاتَّخَذَهُ فَجَاءَ بِهِ إِلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَيِّ شَيْءٍ كَانَ هَذَا السَّمْنُ قَالَ فِي عُكَّةِ ضَبٍّ قَالَ فَأَبَى أَنْ يَأْكُلَهُ","id":"Telah menceritakan kepada kami [Hadiyyah bin Abdul Wahhab] telah menceritakan kepada kami [Al Fadll bin Musa As Sinani] telah menceritakan kepada kami [Al Husain bin Waqid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku ingin sekali, sekiranya kita memiliki roti putih dari gandum Samra` yang dipolesi dengan minyak samin, lalu kita memakannya.\" Ibnu Umar menuturkan, \"Ternyata salah seorang sahabat Anshar mendengarnya, sehingga dia mengambil (roti yang dipolesi minyak samin) dan datang membawanya kepada beliau. Rasulullah shallallahu 'alaihi wasallam bertanya: \"Dari mana minyak samin ini didapat?\" laki-laki itu menjawab, \"Dari daging biawak.\" Ibnu Umar berkata, \"lalu beliau enggan memakannya.\""},"3298":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَنَعَتْ أُمُّ سُلَيْمٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُبْزَةً وَضَعَتْ فِيهَا شَيْئًا مِنْ سَمْنٍ ثُمَّ قَالَتْ اذْهَبْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَادْعُهُ قَالَ فَأَتَيْتُهُ فَقُلْتُ أُمِّي تَدْعُوكَ قَالَ فَقَامَ وَقَالَ لِمَنْ كَانَ عِنْدَهُ مِنْ النَّاسِ قُومُوا قَالَ فَسَبَقْتُهُمْ إِلَيْهَا فَأَخْبَرْتُهَا فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَاتِي مَا صَنَعْتِ فَقَالَتْ إِنَّمَا صَنَعْتُهُ لَكَ وَحْدَكَ فَقَالَ هَاتِيهِ فَقَالَ يَا أَنَسُ أَدْخِلْ عَلَيَّ عَشَرَةً عَشَرَةً قَالَ فَمَا زِلْتُ أُدْخِلُ عَلَيْهِ عَشَرَةً عَشَرَةً فَأَكَلُوا حَتَّى شَبِعُوا وَكَانُوا ثَمَانِينَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] telah menceritakan kepada kami [Utsman bin Abdurrahman] telah menceritakan kepada kami [Humaid Ath Thawil] dari [Anas bin Malik] dia berkata, \"Ummu Sulaim membuatkan sepotong roti yang diberi minyak samin untuk Nabi shallallahu 'alaihi wasallam, kemudian dia berkata, \"Pergilah kepada Nabi shallallahu 'alaihi wasallam dan undanglah beliau untuk makan.\" Anas berkata, \"Maka aku mendatangi beliau dan aku katakan, \"Ibuku mengundang anda makan.\" Anas berkata, \"Maka beliau berdiri dan berkata kepada orang-orang yang bersamanya: \"Mari kita berangkat! \" Anas melanjutkan, \"Aku lalu segera mendahului mereka untuk menemui Ummu Sulaim dan memberitahukan kepadanya (perihal kedatangan Rasulullah dan para sahabatnya). Kemudian Nabi shallallahu 'alaihi wasallam datang dan bersabda: \"Hidangkanlah apa yang telah kamu buat.\" Ummu Sulaim menjawab, \"Aku hanya membuatkan untukmu saja.\" Beliau bersabda: \"Hidangkanlah.\" Kemudian beliau bersabda lagi: \"Wahai Anas, suruhlah mereka masuk sepuluh orang-sepuluh orang.\" Anas berkata, \"Aku terus saja memasukkan bersama dengannya sepuluh orang-sepuluh orang, sehingga mereka makan semua sampai kenyang, dan waktu itu mereka berjumlah delapan puluh orang.\""},"3299":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَوَالَّذِي نَفْسِي بِيَدِهِ مَا شَبِعَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَيَّامٍ تِبَاعًا مِنْ خُبْزِ الْحِنْطَةِ حَتَّى تَوَفَّاهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] bahwa dia berkata, \"Demi dzat yang jiwaku di tangan-Nya, sesungguhnya Nabi Allah tidak pernah kenyang dengan roti gandum selama tiga hari berturut-turut hingga Allah Azza Wa Jalla mewafatkannya.\""},"3300":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْذُ قَدِمُوا الْمَدِينَةَ ثَلَاثَ لَيَالٍ تِبَاعًا مِنْ خُبْزِ بُرٍّ حَتَّى تُوُفِّيَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah menceritakan kepada kami [Zai`idah] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata, \"Keluarga Muhammad shallallahu 'alaihi wasallam tidak pernah kenyang dari roti gandum selama tiga hari berturut-turut, semenjak para sahabat tiba di Madinah sehingga beliau shallallahu 'alaihi wasallam meninggal dunia, \""},"3301":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَقَدْ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا فِي بَيْتِي مِنْ شَيْءٍ يَأْكُلُهُ ذُو كَبِدٍ إِلَّا شَطْرُ شَعِيرٍ فِي رَفٍّ لِي فَأَكَلْتُ مِنْهُ حَتَّى طَالَ عَلَيَّ فَكِلْتُهُ فَفَنِيَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Sungguh Nabi shallallahu 'alaihi wasallam telah meninggal dunia dan tidaklah di rumahku ada sesuatu yang dapat dimakan oleh orang yang memiliki hati (manusia) kecuali hanya sekantung gandum di rak piringku, lalu aku memakannya sampai sekian lama, barulah gandum tersebut habis, \""},"3302":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خُبْزِ الشَّعِيرِ حَتَّى قُبِضَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] saya mendengar [Abdurrahman bin Yazid] menceritakan dari [Al Aswad] dari [Aisyah] dia berkata, \"Keluarga Muhammad shallallahu 'alaihi wasallam tidak pernah merasa kenyang dengan roti gandum hingga meninggal dunia, \""},"3303":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ عَنْ هِلَالِ بْنِ خَبَّابٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبِيتُ اللَّيَالِي الْمُتَتَابِعَةَ طَاوِيًا وَأَهْلُهُ لَا يَجِدُونَ الْعَشَاءَ وَكَانَ عَامَّةَ خُبْزِهِمْ خُبْزُ الشَّعِيرِ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] telah menceritakan kepada kami [Tsabit bin Yazid] dari [Hilal bin Khabbab] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bermalam beberapa malam berturut-turut dalam keadaan lapar, sementara keluarganya tidak mendapatkan makan malam. Dan kebanyakan roti yang biasa mereka konsumsi adalah roti gandum.\""},"3304":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ وَكَانَ يُعَدُّ مِنْ الْأَبْدَالِ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا يُوسُفُ بْنُ أَبِي كَثِيرٍ عَنْ نُوحِ بْنِ ذَكْوَانَ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَبِسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّوفَ وَاحْتَذَى الْمَخْصُوفَ وَقَالَ أَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشِعًا وَلَبِسَ خَشِنًافَقِيلَ لِلْحَسَنِ مَا الْبَشِعُ قَالَ غَلِيظُ الشَّعِيرِ مَا كَانَ يُسِيغُهُ إِلَّا بِجُرْعَةِ مَاءٍ","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] -dan dia termasuk di antara Al Abdal (perawi yang melompati jalur periwayatannya dari syaikh karena ketinggian derajatnya dari pada syaiknya) - telah menceritakan kepada kami [Baqiyah] telah menceritakan kepada kami [Yusuf bin abu Katsir] dari [Nuh bin Dzakwan] dari [Al Hasan] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai wool dan memakai sepatu kasut yang ditambal.\" Dia juga berkata, \"Rasulullah shallallahu 'alaihi wasallam juga memakan basyi' dan memakai baju yang kasar.\" Al Hasan ditanya: \"Apakah basyi' itu apa? ' dia menjawab, \"Gandum kering yang keras, yang tidak bisa ditelan kecuali dengan seteguk air.\""},"3305":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَتْنِي أُمِّي عَنْ أُمِّهَا أَنَّهَا سَمِعَتْ الْمِقْدَامَ بْنَ مَعْدِ يكَرِبَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مَلَأَ آدَمِيٌّ وِعَاءً شَرًّا مِنْ بَطْنٍ حَسْبُ الْآدَمِيِّ لُقَيْمَاتٌ يُقِمْنَ صُلْبَهُ فَإِنْ غَلَبَتْ الْآدَمِيَّ نَفْسُهُ فَثُلُثٌ لِلطَّعَامِ وَثُلُثٌ لِلشَّرَابِ وَثُلُثٌ لِلنَّفَسِ","id":"Telah menceritakan kepada kami [Hisyam bin Abdul Malik Al Himshi] telah menceritakan kepada kami [Muhammad bin Harb] telah menceritakan kepadaku [Ibuku] dari [Ibunya] bahwa dia berkata; saya mendengar [Al Miqdam bin Ma'dikarib] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah anak Adam memenuhi tempat yang lebih buruk daripada perutnya, ukuran bagi (perut) anak Adam adalah beberapa suapan yang hanya dapat menegakkan tulang punggungnya. Jika jiwanya menguasai dirinya, maka sepertiga untuk makanan, sepertiga untuk minum dan sepertiga untuk bernafas.\""},"3306":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ أَبُو يَحْيَى عَنْ يَحْيَى الْبَكَّاءِ عَنْ ابْنِ عُمَرَ قَالَتَجَشَّأَ رَجُلٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كُفَّ جُشَاءَكَ عَنَّا فَإِنَّ أَطْوَلَكُمْ جُوعًا يَوْمَ الْقِيَامَةِ أَكْثَرُكُمْ شِبَعًا فِي دَارِ الدُّنْيَا","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Abdul Aziz bin Abdullah Abu Yahya] dari [Yahya Al Bakka'] dari [Ibnu Umar] dia berkata, \"Seorang lelaki bersendawa di samping Nabi shallallahu 'alaihi wasallam, beliau pun bersabda: \"Tahanlah sendawamu itu di hadapan kami, sesungguhnya orang yang paling lapar di antara kalian pada hari kiamat adalah orang yang paling banyak kenyang ketika di dunia.\""},"3307":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ سُلَيْمَانَ الْعَسْكَرِيُّ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الثَّقَفِيُّ عَنْ مُوسَى الْجُهَنِيِّ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَطِيَّةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَ سَمِعْتُ سَلْمَانَوَأُكْرِهَ عَلَى طَعَامٍ يَأْكُلُهُ فَقَالَ حَسْبِي أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَكْثَرَ النَّاسِ شِبَعًا فِي الدُّنْيَا أَطْوَلُهُمْ جُوعًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Daud bin Sulaiman Al 'Askari] dan [Muhammad bin Ash Shabah] keduanya berkata; telah menceritakan kepada kami [Sa'id bin Muhammad As Tsaqafi] dari [Musa Al Juhani] dari [Zaid bin Wahb] dari ['Athiyah bin 'Amir Al Juhani] dia berkata, \"Aku mendengar [Salman] dipaksa untuk memakan makanan, maka dia berkata, \"Cukuplah bagiku, sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia yang paling banyak kenyang di dunia adalah manusia yang paling lapar di hari kiamat.\""},"3308":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسُوَيْدُ بْنُ سَعِيدٍ وَيَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ قَالُوا حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنَا يُوسُفُ بْنُ أَبِي كَثِيرٍ عَنْ نُوحِ بْنِ ذَكْوَانَ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ السَّرَفِ أَنْ تَأْكُلَ كُلَّ مَا اشْتَهَيْتَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Suwaid bin Sa'id] serta [Yahya bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] mereka berkata; telah menceritakan kepada kami [Baqiyah bin Al Walid] telah menceritakan kepada kami [Yusuf bin Abu Katsir] dari [Nuh bin Dzakwan] dari [Al Hasan] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk berlebih-lebihan adalah kamu memakan semua yang kamu inginkan.\""},"3309":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ يُوسُفَ الْفِرْيَابِيُّ حَدَّثَنَا وَسَّاجُ بْنُ عُقْبَةَ بْنِ وَسَّاجٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُحَمَّدٍ الْمُوَقَّرِيُّ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ فَرَأَى كِسْرَةً مُلْقَاةً فَأَخَذَهَا فَمَسَحَهَا ثُمَّ أَكَلَهَا وَقَالَ يَا عَائِشَةُ أَكْرِمِي كَرِيمًا فَإِنَّهَا مَا نَفَرَتْ عَنْ قَوْمٍ قَطُّ فَعَادَتْ إِلَيْهِمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Muhammad bin Yusuf Al Firyabi] telah menceritakan kepada kami [Wassaj bin 'Uqbah bin Wassaj] telah menceritakan kepada kami [Al Walid bin Muhammad Al Muwaqqari] telah menceritakan kepada kami [Az Zuhri] dari ['Urwah] dari [Aisyah] dia berkata, \"Nabi shallallahu 'alaihi wasallam masuk ke dalam rumah dan melihat remukan roti yang terbuang, maka beliau mengambilnya lalu mengusap dan memakannya, beliau bersabda: \"Wahai Aisyah, muliakanlah sesuatu yang mulia, tidaklah remukan roti itu pergi dari suatu kaum kecuali ia akan kembali kepada mereka.\""},"3310":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا هُرَيْمٌ عَنْ لَيْثٍ عَنْ كَعْبٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْجُوعِ فَإِنَّهُ بِئْسَ الضَّجِيعُ وَأَعُوذُ بِكَ مِنْ الْخِيَانَةِ فَإِنَّهَا بِئْسَتِ الْبِطَانَةُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Huraim] dari [Laits] dari [Ka'b] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berdo'a: \"Ya Allah, sesungguhnya aku berlindung kepada-Mu dari kelaparan, karena kelaparan adalah seburuk-buruk teman tidur. Dan aku berlindung kepada-Mu dari khianat, karena dia adalah seburuk-buruk sesuatu yang tersembunyi.\""},"3311":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ السَّلَامِ بْنِ عَبْدِ اللَّهِ بْنِ بَابَاهُ الْمَخْزُومِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَيْمُونٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدَعُوا الْعَشَاءَ وَلَوْ بِكَفٍّ مِنْ تَمْرٍ فَإِنَّ تَرْكَهُ يُهْرِمُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Ar Raqqi] telah menceritakan kepada kami [Ibrahim bin Abdussalam bin Abdullah bin Babah Al Mahzumi] telah menceritakan kepada kami [Abdullah bin Maimun] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian meninggalkan makan malam meski dengan segenggam kurma, sesungguhnya meninggalkannya itu akan mempercepat tua.\""},"3312":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا كَثِيرُ بْنُ سُلَيْمٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْرُ أَسْرَعُ إِلَى الْبَيْتِ الَّذِي يُغْشَى مِنْ الشَّفْرَةِ إِلَى سَنَامِ الْبَعِيرِ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] telah menceritakan kepada kami [Katsir bin Sulaim] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kebaikan itu lebih cepat masuk ke dalam rumah yang di dalamnya tamu dijamu, dari cepatnya pisau ke punuk unta, \""},"3313":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا الْمُحَارِبِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ نَهْشَلٍ عَنْ الضَّحَّاكِ بْنِ مُزَاحِمٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْرُ أَسْرَعُ إِلَى الْبَيْتِ الَّذِي يُؤْكَلُ فِيهِ مِنْ الشَّفْرَةِ إِلَى سَنَامِ الْبَعِيرِ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] telah menceritakan kepada kami [Al Muharibi] telah menceritakan kepada kami [Abdurrahman bin Nahsyal] dari [Adl Dlahak bin Muzahim] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kebaikan itu lebih cepat masuk ke dalam rumah yang di dalamnya tamu dijamu, dari cepatnya pisau ke punuk unta, \""},"3314":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا عُثْ��َانُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَلِيِّ بْنِ عُرْوَةَ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ السُّنَّةِ أَنْ يَخْرُجَ الرَّجُلُ مَعَ ضَيْفِهِ إِلَى بَابِ الدَّارِ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqi] telah menceritakan kepada kami [Utsman bin Abdurrahman] dari [Ali bin 'Urwah] dari [Abdul Malik] dari ['Atha] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya termasuk dari perkara yang sunnah adalah seseorang keluar bersama tamunya sampai ke pintu rumah.\""},"3315":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَلِيٍّ قَالَصَنَعْتُ طَعَامًا فَدَعَوْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ فَرَأَى فِي الْبَيْتِ تَصَاوِيرَ فَرَجَعَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Hisyam Ad Dastuwa`i] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Ali] dia berkata, \"Aku membuat makanan kemudian mengundang Rasulullah shallallahu 'alaihi wasallam lalu beliau pun, tetapi beliau kembali pulang setelah melihat gambar yang ada di rumah.\""},"3316":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ الْجَزَرِيُّ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا سَعِيدُ بْنُ جُمْهَانَ حَدَّثَنَا سَفِينَةُ أَبُو عَبْدِ الرَّحْمَنِأَنَّ رَجُلًا أَضَافَ عَلِيَّ بْنَ أَبِي طَالِبٍ فَصَنَعَ لَهُ طَعَامًا فَقَالَتْ فَاطِمَةُ لَوْ دَعَوْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ مَعَنَا فَدَعَوْهُ فَجَاءَ فَوَضَعَ يَدَهُ عَلَى عِضَادَتَيْ الْبَابِ فَرَأَى قِرَامًا فِي نَاحِيَةِ الْبَيْتِ فَرَجَعَ فَقَالَتْ فَاطِمَةُ لِعَلِيٍّ الْحَقْ فَقُلْ لَهُ مَا رَجَعَكَ يَا رَسُولَ اللَّهِ قَالَ إِنَّهُ لَيْسَ لِي أَنْ أَدْخُلَ بَيْتًا مُزَوَّقًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Abdullah Al Jazari] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Sa'id bin Jumhan] telah menceritakan kepada kami [Safinah Abu Abdurrahman], bahwa seorang laki-laki bertamu kepada Ali bin Abu Thalib, lantas Ali membuat makanan untuknya. Fatimah pun berkata, \"Bagaimana kalau kita undang juga Nabi shallallahu 'alaihi wasallam dan makan bersama kita?\" Lalu beliau dipanggil, beliau datang lalu dan meletakkan tangannya di tiang pintu. Ketika melihat tabir tipis di bagian rumah, maka beliau pun kembali pulang. Fatimah lantas berkata kepada Ali, \"Kejar dan tanyakanlah kepada beliau 'Apa yang membuatmu bergegas pulang wahai Rasulullah? ' beliau menjawab: \"Sesungguhnya tidak layak bagiku untuk masuk ke dalam rumah yang dihias (lukisan), \""},"3317":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ الرَّحْمَنِ الْأَرْحَبِيُّ حَدَّثَنَا يُونُسُ بْنُ أَبِي الْيَعْفُورِ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَدَخَلَ عَلَيْهِ عُمَرُ وَهُوَ عَلَى مَائِدَتِهِ فَأَوْسَعَ لَهُ عَنْ صَدْرِ الْمَجْلِسِ فَقَالَ بِسْمِ اللَّهِ ثُمَّ ضَرَبَ بِيَدِهِ فَلَقِمَ لُقْمَةً ثُمَّ ثَنَّى بِأُخْرَى ثُمَّ قَالَ إِنِّي لَأَجِدُ طَعْمَ دَسَمٍ مَا هُوَ بِدَسَمِ اللَّحْمِ فَقَالَ عَبْدُ اللَّهِ يَا أَمِيرَ الْمُؤْمِنِينَ إِنِّي خَرَجْتُ إِلَى السُّوقِ أَطْلُبُ السَّمِينَ لِأَشْتَرِيَهُ فَوَجَدْتُهُ غَالِيًا فَاشْتَرَيْتُ بِدِرْهَمٍ مِنْ الْمَهْزُولِ وَحَمَلْتُ عَلَيْهِ بِدِرْهَمٍ سَمْنًا فَأَرَدْتُ أَنْ يَتَرَدَّدَ عِيَالِي عَظْمًا عَظْمًا فَقَالَ عُمَرُ مَا اجْتَمَعَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطُّ إِلَّا أَكَلَ أَحَدَهُمَا وَتَصَدَّقَ بِالْآخَرِ قَالَ عَبْدُ اللَّهِ خُذْ يَا أَمِيرَ الْمُؤْمِنِينَ فَلَنْ يَجْتَمِعَا عِنْدِي إِلَّا فَعَلْتُ ذَلِكَ قَالَ مَا كُنْتُ لِأَفْعَلَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Yahya bin Abdurrahman Al Arhabi] telah menceritakan kepada kami [Yunus bin Abu Al Ya'fur] dari [Ayahnya] dari [Ibnu Umar] mengatakan, bahwa Umar datang kepadanya saat ia berada di meja makannya. Ia lalu memberi tempat duduk kepadanya, Umar lalu mengucapkan 'Bismillah' seraya mengambil satu suapan dan mengambil lagi. Kemudian Umar berkata, \"Sesungguhnya aku merasakan rasa lemak, tetapi bukan lemak daging.\" Abdullah berkata, \"Wahai Amirul Mukminin, tadi aku keluar ke pasar untuk membeli minyak samin, namun aku mendapatkan harganya terlalu mahal, maka aku membeli tulang yang ada sedikit daging dengan harga satu dirham dan mencampurnya dengan sedirham samin, karena aku ingin anak-anakku bergantian mendapatkan satu tulang-satu tulang.\" Maka [Umar] berkata, \"Tidak pernah sama sekali Rasulullah shallallahu 'alaihi wasallam mendapatkan ini kecuali beliau memakan salah satunya dan bersedekah dengan yang lainnya.\" Maka Abdullah berkata, \"Ambillah wahai Amirul Mukminin, sekali-kali tidak akan menjadi satu di hadapanku kecuali aku akan melakukan seperti itu.\" Umar berkata, \"Aku tidak akan melakukannya.\""},"3318":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا أَبُو عَامِرٍ الْخَزَّازُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا عَمِلْتَ مَرَقَةً فَأَكْثِرْ مَاءَهَا وَاغْتَرِفْ لِجِيرَانِكَ مِنْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Abu Amir Al Khazzaz] dari [Abu Imran Al Jauni] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kamu masak sayur perbanyaklah kuahnya, lalu bagikanlah kepada tetanggamu, \""},"3319":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ الْغَطَفَانِيِّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمَرِيِّأَنَّ عُمَرَ بْنَ الْخَطَّابِ قَامَ يَوْمَ الْجُمُعَةِ خَطِيبًا فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَأْكُلُونَ شَجَرَتَيْنِ لَا أُرَاهُمَا إِلَّا خَبِيثَتَيْنِ هَذَا الثُّومُ وَهَذَا الْبَصَلُ وَلَقَدْ كُنْتُ أَرَى الرَّجُلَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوجَدُ رِيحُهُ مِنْهُ فَيُؤْخَذُ بِيَدِهِ حَتَّى يُخْرَجَ بِهِ إِلَى الْبَقِيعِ فَمَنْ كَانَ آكِلَهُمَا لَا بُدَّ فَلْيُمِتْهُمَا طَبْخًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Salim bin Abu Al Ja'd Al Ghathafani] dari [Ma'dan bin Abu Thalhah Al Ya'mari], bahwa [Umar bin Al Khaththab] berkhutbah pada hari Jum'at, setelah memuji Allah dan mengagungkan-Nya dia berkata, \"Wahai sekalian manusia, sesungguhnya kalian kerap memakan dua pohon yang aku kira keduanya adalah pohon yang buruk. Pohon tersebut adalah bawang putih dan bawang merah. Dan aku pernah menyaksikan seorang laki-laki pada masa Rasulullah shallallahu 'alaihi wasallam yang tercium darinya aroma pohon tersebut, sehingga ia ditarik dan dikeluarkan dari Baqi'. Oleh sebab itu, barangsiapa hendak makan keduanya, hendaknya ia memasaknya terlebih dahulu hingga keduanya benar-benar masak, \""},"3320":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ أُمِّ أَيُّوبَ قَالَتْصَنَعْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فِيهِ مِنْ بَعْضِ الْبُقُولِ فَلَمْ يَأْكُلْ وَقَالَ إِنِّي أَكْرَهُ أَنْ أُوذِيَ صَاحِبِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ubaidullah bin Abu Yazid] dari [Ayahnya] dari [Ummu Ayyub] dia berkata, \"Aku membuatkan makanan yang di dalamnya ada beberapa kubis untuk Nabi shallallahu 'alaihi wasallam, namun beliau tidak memakannya. Beliau bersabda: \"Aku tidak ingin menyakiti sahabatku (yaitu Jibril), \""},"3321":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا أَبُو شُرَيْحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ نِمْرَانَ الْحَجْرِيِّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ نَفَرًا أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ مِنْهُمْ رِيحِ الْكُرَّاثِ فَقَالَ أَلَمْ أَكُنْ نَهَيْتُكُمْ عَنْ أَكْلِ هَذِهِ الشَّجَرَةِ إِنَّ الْمَلَائِكَةَ تَتَأَذَّى مِمَّا يَتَأَذَّى مِنْهُ الْإِنْسَانُ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepada kami [Abu Syuraih] dari [Abdurrahman bin Nimran Al Hajri] dari [Abu Az Zubair] dari [Jabir], bahwa sekelompok orang datang menemui Nabi shallallahu 'alaihi wasallam, lantas beliau mendapati aroma bawang bakung (barang perai) dari mereka, beliau lalu bersabda: \"Bukankah aku telah melarang kalian untuk memakan pohon ini? Sesungguhnya para Malaikat terganggu sebagaimana manusia terganggu dari bau aromanya, \""},"3322":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يُحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ عُثْمَانَ بْنِ نُعَيْمٍ عَنْ الْمُغِيرَةِ بْنِ نَهِيكٍ عَنْ دُخَيْنٍ الْحَجْرِيِّ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَصْحَابِهِ لَا تَأْكُلُوا الْبَصَلَ ثُمَّ قَالَ كَلِمَةً خَفِيَّةً النِّيءَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Utsman bin Nu'aim] dari [Al Mughirah bin Nahik] dari [Dukhain Al Hajri] bahwa dia mendengar ['Uqbah bin 'Amir Al Juhani] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Janganlah kalian makan bawang merah.\" Kemudian beliau berkata dengan suara lirih: \"Yang mentah.\""},"3323":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى السُّدِّيُّ حَدَّثَنَا سَيْفُ بْنُ هَارُونَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ سَلْمَانَ الْفَارِسِيِّ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ السَّمْنِ وَالْجُبْنِ وَالْفِرَاءِ قَالَ الْحَلَالُ مَا أَحَلَّ اللَّهُ فِي كِتَابِهِ وَالْحَرَامُ مَا حَرَّمَ اللَّهُ فِي كِتَابِهِ وَمَا سَكَتَ عَنْهُ فَهُوَ مِمَّا عَفَا عَنْهُ","id":"Telah menceritakan kepada kami [Isma'il bin Musa As Suddi] telah menceritakan kepada kami [Saif bin Harun] dari [Sulaiman At Taimi] dari [Abu Utsman An Nahdi] dari [Salman Al Farisi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya tentang minyak samin dan keju serta bulu binatang, beliau menjawab: \"Yang halal adalah apa yang dihalalkan Allah di dalam kitab-Nya, dan yang haram adalah apa yang diharamkan Allah di dalam kitab-Nya, dan apa yang Dia diamkan adalah sesuatu yang Dia maafkan.\" "},"3324":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عِرْقٍ عَنْ أَبِيهِ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَأُهْدِيَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنَبٌ مِنْ الطَّائِفِ فَدَعَانِي فَقَالَ خُذْ هَذَا الْعُنْقُودَ فَأَبْلِغْهُ أُمَّكَ فَأَكَلْتُهُ قَبْلَ أَنْ أُبْلِغَهُ إِيَّاهَا فَلَمَّا كَانَ بَعْدَ لَيَالٍ قَالَ لِي مَا فَعَلَ الْعُنْقُودُ هَلْ أَبْلَغْتَهُ أُمَّكَ قُلْتُ لَا فَسَمَّانِي غُدَرَ","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Muhammad bin Abdurrahman bin 'Irq] dari [Ayahnya] dari [An Nu'man bin Basyir] dia berkata, \"Nabi shallallahu 'alaihi wasallam diberi hadiah anggur dari negeri Tha`if, kemudian beliau memanggilku dan bersabda: \"Ambilah setangkai ini, dan berikan kepada ibumu.\" Maka aku memakannya sebelum aku menyampaikan kepada ibuku. Setelah lewat beberapa malam, beliau bertanya kepadaku: \"Apa yang terjadi dengan setangkai anggur itu? Apakah sudah kamu berikan kepada ibumu.\" Aku menjawab, \"Belum, \" maka beliau pun menyebutku Ghudar (penghianat), \""},"3325":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُحَمَّدٍ الطَّلْحِيُّ حَدَّثَنَا نُقَيْبُ بْنُ حَاجِبٍ عَنْ أَبِي سَعِيدٍ عَنْ عَبْدِ الْمَلِكِ الزُّبَيْرِيِّ عَنْ طَلْحَةَ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِيَدِهِ سَفَرْجَلَةٌ فَقَالَ دُونَكَهَا يَا طَلْحَةُ فَإِنَّهَا تُجِمُّ الْفُؤَادَ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad At Thalhi] telah menceritakan kepada kami [Nuqaib bin Hajib] dari [Abu Sa'id] dari [Abdul Malik Az Zubairi] dari [Thalhah] dia berkata, \"Aku menemui Nabi shallallahu 'alaihi wasallam, dan di tangannya ada buah safarjal (sejenis jambu), beliau lalu bersabda: \"Ambillah buah ini wahai Thalhah, sesungguhnya ia membuat hati bahagia.\""},"3326":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْكُلَ الرَّجُلُ وَهُوَ مُنْبَطِحٌ عَلَى وَجْهِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Katsir bin Hisyam] telah menceritakan kepada kami [Ja'far bin Burqan] dari [Az Zuhri] dari [Salim] dari [Ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang makan sambil telungkup.\""},"3327":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ ح و حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ جَمِيعًا عَنْ رَاشِدٍ أَبِي مُحَمَّدٍ الْحِمَّانِيِّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَأَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَشْرَبْ الْخَمْرَ فَإِنَّهَا مِفْتَاحُ كُلِّ شَرٍّ","id":"Telah menceritakan kepada kami [Al Husain bin Al Hasan Al Mawarzi] telah menceritakan kepada kami [Ibnu Abu 'Adi]. Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] telah menceritakan kepada kami [Abdul Wahhab] semuanya dari [Rasyid Abu Muhammad Al Himmani] dari [Syahr bin Hausyab] dari [Ummu Darda] dari [Abu Darda] dia berkata, \"Kekasihku, shallallahu 'alaihi wasallam, memberi wasiat kepadaku: \"Janganlah kamu meminum khamer, sesungguhnya khamer adalah kunci semua kejahatan.\""},"3328":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مُنِيرُ بْنُ الزُّبَيْرِ أَنَّهُ سَمِعَ عُبَادَةَ بْنَ نُسَيٍّ يَقُولُ سَمِعْتُ خَبَّابَ بْنَ الْأَرَتِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِيَّاكَ وَالْخَمْرَ فَإِنَّ خَطِيئَتَهَا تَفْرَعُ الْخَطَايَا كَمَا أَنَّ شَجَرَتَهَا تَفْرَعُ الشَّجَرَ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Utsman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Munir bin Az Zubair] bahwa dia mendengar ['Ubadah bin Nusai] berkata; saya mendengar [Khabbab bin Al Art] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kamu mendekati khamer, sesungguhnya kesalahannya akan bercabang dengan kesalahan (yang lain), sebagaimana pohon memiliki cabang dengan pohon-pohon (yang lain).\""},"3329":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا لَمْ يَشْرَبْهَا فِي الْآخِرَةِ إِلَّا أَنْ يَتُوبَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdullah bin Numair] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminum khamer di dunia maka ia tidak akan meminumnya di akhirat, kecuali jika dirinya bertaubat, \""},"3330":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ قَالَ حَدَّثَنِي زَيْدُ بْنُ وَاقِدٍ أَنَّ خَالِدَ بْنَ عَبْدِ اللَّهِ بْنِ حُسَيْنٍ حَدَّثَهُ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا لَمْ يَشْرَبْهَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Hamzah] dia berkata; telah menceritakan kepadaku [Zaid bin Waqid] bahwa [Khalid bin Abdullah bin Husain] menceritakan kepadanya, dia berkata; telah menceritakan kepadaku [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer di dunia, niscaya dia tidak akan meminumnya di Akhirat.\""},"3331":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ بْنِ الْأَصْبَهَانِيِّ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُدْمِنُ الْخَمْرِ كَعَابِدِ وَثَنٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin As Shabah] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Sulaiman bin Al Ashbahani] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pecandu khamer seperti penyembah berhala.\""},"3332":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُلَيْمَانُ بْنُ عُتْبَةَ حَدَّثَنِي يُونُسُ بْنُ مَيْسَرَةَ بْنِ حَلْبَسٍ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ مُدْمِنُ خَمْرٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sulaiman bin 'Utbah] telah menceritakan kepadaku [Yunus bin Maisarah bin Halbas] dari [Abu Idris] dari [Abu Darda] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan masuk surga seorang pecandu Khamer, \""},"3333":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ ابْنِ الدَّيْلَمِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَرِبَ الْخَمْرَ وَسَكِرَ لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ صَبَاحًا وَإِنْ مَاتَ دَخَلَ النَّارَ فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ وَإِنْ عَادَ فَشَرِبَ فَسَكِرَ لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ صَبَاحًا فَإِنْ مَاتَ دَخَلَ النَّارَ فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ وَإِنْ عَادَ فَشَرِبَ فَسَكِرَ لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ صَبَاحًا فَإِنْ مَاتَ دَخَلَ النَّارَ فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ وَإِنْ عَادَ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يَسْقِيَهُ مِنْ رَدَغَةِ الْخَبَالِ يَوْمَ الْقِيَامَةِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا رَدَغَةُ الْخَبَالِ قَالَ عُصَارَةُ أَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] dari [Rabi'ah bin Yazid] dari [Ibnu Dailami] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer hingga mabuk, maka shalatnya tidak akan diterima selama empat puluh pagi (hari). Jika meninggal dunia maka ia akan masuk neraka, dan jika ia bertaubat maka Allah akan menerima taubatnya. Jika ia kembali minum khamer lalu mabuk maka shalatnya tidak akan diterima selama empat puluh hari, dan jika ia mati maka ia akan masuk neraka. Dan jika ia bertaubat maka Allah akan menerima taubatnya, dan jika ia kembali mengulanginya lagi maka Allah sangat layak memberinya minuman dari Radaghah Al Khabal di hari Kiamat.\" Mereka bertanya, \"Apakah maksud dari Radaghah Al Khabal wahai Rasulullah?\" beliau menjawab: \"Keringat penghuni neraka.\""},"3334":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ اللَّهِ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا أَبُو كَثِيرٍ السُّحَيْمِيُّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَمْرُ مِنْ هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةِ وَالْعِنَبَةِ","id":"Telah menceritakan kepada kami [Yazid bin Abdullah Al Yamami] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepada kami [Abu Katsir As Suhaimi] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer itu terbuat dari dua jenis pohon ini; kurma dan anggur, \""},"3335":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ خَالِدَ بْنَ كَثِيرٍ الْهَمْدَانِيَّ حَدَّثَهُ أَنَّ السَّرِيَّ بْنَ إِسْمَعِيلَ حَدَّثَهُ أَنَّ الشَّعْبِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْحِنْطَةِ خَمْرًا وَمِنْ الشَّعِيرِ خَمْرًا وَمِنْ الزَّبِيبِ خَمْرًا وَمِنْ التَّمْرِ خَمْرًا وَمِنْ الْعَسَلِ خَمْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] bahwa [Khalid bin Katsir Al Hamdani] meriwayatkan bahwa [As Sari bin Isma'il] menceritakan kepadanya, bahwa [Asy Sya'bi] menceritakan kepadanya, bahwa dia mendengar [An Nu'man bin Basyir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada biji gandum (dapat dibuat) khamer, tepung gandum dapat dibuat khamer, anggur dapat dibuat khamer, kurma dapat dibuat khamer dan madu juga dapat dibuat menjadi khamer.\""},"3336":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ الْغَافِقِيِّ وَأَبِي طُعْمَةَ مَوْلَاهُمْ أَنَّهُمَا سَمِعَا ابْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُعِنَتْ الْخَمْرُ عَلَى عَشْرَةِ أَوْجُهٍ بِعَيْنِهَا وَعَاصِرِهَا وَمُعْتَصِرِهَا وَبَائِعِهَا وَمُبْتَاعِهَا وَحَامِلِهَا وَالْمَحْمُولَةِ إِلَيْهِ وَآكِلِ ثَمَنِهَا وَشَارِبِهَا وَسَاقِيهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abdul Aziz bin Umar bin Abdul Aziz] dari [Abdurrahman bin Abdullah Al Ghafiqi] dan [Abu Thu'mah] bekas budak mereka, keduanya mendengar [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer dilaknat atas sepuluh bagian; dzatnya, yang memerasnya, yang minta diperaskan, penjualnya, yang minta dibelikan, yang membawanya, yang minta dibawakannya, yang memakan hasil penjualannya, peminumnya dan yang menuangkannya, \""},"3337":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدِ بْنِ يَزِيدَ بْنِ إِبْرَاهِيمَ التُّسْتَرِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ شَبِيبٍ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ أَوْ حَدَّثَنِي أَنَسٌ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَمْرِ عَشَرَةً عَاصِرَهَا وَمُعْتَصِرَهَا وَالْمَعْصُورَةَ لَهُ وَحَامِلَهَا وَالْمَحْمُولَةَ لَهُ وَبَائِعَهَا وَالْمَبْيُوعَةَ لَهُ وَسَاقِيَهَا وَالْمُسْتَقَاةَ لَهُ حَتَّى عَدَّ عَشَرَةً مِنْ هَذَا الضَّرْبِ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id bin Yazid bin Ibrahim At Tustari] telah menceritakan kepada kami [Abu 'Ashim] dari [Syabib] saya mendengar [Anas bin Malik], atau telah menceritakan kepadaku Anas bin Malik dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat sepuluh perkara dalam khamer; \"Orang yang memerasnya, yang minta diperaskan, alat untuk memeras, orang yang membawanya, orang yang minta dibawakan, penjualnya, orang yang dibelikan, yang menuangkannya, yang minta menuangkannya.\" Beliau menyebutkan hingga sepuluh perkara dari permisalan ini, \""},"3338":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا نَزَلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي الرِّبَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari [Aisyah] radliallahu 'anha, dia berkata, \"Ketika turun beberapa ayat dari penutup surat Al Baqarah tentang riba, Rasulullah shallallahu 'alaihi wasallam keluar dan mengharamkan jual beli khamer, \""},"3339":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَلَغَ عُمَرَ أَنَّ سَمُرَةَ بَاعَ خَمْرًا فَقَالَ قَاتَلَ اللَّهُ سَمُرَةَ أَلَمْ يَعْلَمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْيَهُودَ حُرِّمَتْ عَلَيْهِمْ الشُّحُومُ فَجَمَلُوهَا فَبَاعُوهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] dia berkata, \"Telah sampai berita kepada Umar bahwa Samrah sedang menjual khamer, maka [Umar] berkata, \"Semoga Allah melaknat Samrah! Apakah dia tidak tahu bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Semoga Allah melaknat orang-orang Yahudi, lemak babi telah diharamkan kepada mereka, namun mereka tetap saja mengemas dan menjualnya, \""},"3340":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ عَبْدِ الْقُدُّوسِ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَذْهَبُ اللَّيَالِي وَالْأَيَّامُ حَتَّى تَشْرَبَ فِيهَا طَائِفَةٌ مِنْ أُمَّتِي الْخَمْرَ يُسَمُّونَهَا بِغَيْرِ اسْمِهَا","id":"Telah menceritakan kepada kami [Al 'Abbas bin Al Walid Ad Dimasyqi] telah menceritakan kepada kami [Abdussalam bin Abdul Quddus] telah menceritakan kepada kami [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abu Umamah Al Bahili] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malam dan siang tidak akan berlalu (menghilang) sehingga sekelompok dari umatku akan meminum khamer, mereka memberi nama dengan nama selainnya, \""},"3341":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ أَبِي السَّرِيِّ حَدَّثَنَا عَبْدُ اللَّهِ حَدَّثَنَا سَعْدُ بْنُ أَوْسٍ الْعَبْسِيُّ عَنْ بِلَالِ بْنِ يَحْيَى الْعَبْسِيِّ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ ثَابِتِ بْنِ السِّمْطِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْرَبُ نَاسٌ مِنْ أُمَّتِي الْخَمْرَ بِاسْمٍ يُسَمُّونَهَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Al Husain bin Abu As Sirri] telah menceritakan kepada kami [Abdullah] telah menceritakan kepada kami [Sa'd bin Aus Al 'Absi] dari [Bilal bin Yahya Al 'Absi] dari [Abu Bakr bin Hafsh] dari [Ibnu Al Muhairiz] dari [Tsabit bin As Simth] dari ['Ubadah bin As Shamit] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beberapa orang dari umatku akan meminum khamer dengan nama yang mereka sematkan sendiri, \""},"3342":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَتَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Abu Salamah] dari [Aisyah] dan sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap minuman yang memabukkan adalah haram, \""},"3343":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا يَحْيَى بْنُ الْحَارِثِ الذِّمَارِيُّ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ يُحَدِّثُ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Shadaqah bin Khalid] telah menceritakan kepada kami [Yahya bin Al Harits Ad Dzimari] saya mendengar [Salim bin Abdullah bin Umar] menceritakan dari [Ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu yang memabukkan adalah haram.\""},"3344":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ أَيُّوبَ بْنِ هَانِئٍ عَنْ مَسْرُوقٍ عَنْ ابْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مُسْكِرٍ حَرَامٌقَالَ ابْن مَاجَةَ هَذَا حَدِيثُ الْمِصْرِيِّينَ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami [Ibnu Juraij] dari [Ayyub bin Hani`] dari [Masruq] dari [Ibnu Mas'ud], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu yang memabukkan adalah haram.\" Ibnu Majah berkata, \"Ini adalah hadits orang-orang Mesir, \""},"3345":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا خَالِدُ بْنُ حَيَّانَ عَنْ سُلَيْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ الزِّبْرِقَانِ عَنْ يَعْلَى بْنِ شَدَّادِ بْنِ أَوْسٍ سَمِعْتُ مُعَاوِيَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ مُسْكِرٍ حَرَامٌ عَلَى كُلِّ مُؤْمِنٍوَهَذَا حَدِيثُ الرَّقِّيِّينَ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] telah menceritakan kepada kami [Khalid bin Hayyan] dari [Sulaiman bin Abdullah bin Az Zabriqan] dari [Ya'la bin Syaddad bin Aus] saya mendengar [Mu'awiyah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah haram bagi setiap mukmin.\" Ini adalah hadits penduduk Raqqiyin."},"3346":{"ar":"حَدَّثَنَا سَهْلٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَلْقَمَةَ عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ خَمْرٌ وَكُلُّ خَمْرٍ حَرَامٌ","id":"Telah menceritakan kepada kami [Sahl] telah menceritakan kepada kami [Yazid bin Harun] dari [Muhammad bin 'Amru bin 'Alqamah] dari [Abu Salamah] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah khamer, dan semua jenis khamer adalah haram.\""},"3347":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Abu Burdah] dari [Ayahnya] dari [Abu Musa] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu yang memabukkan adalah haram, \""},"3348":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا أَبُو يَحْيَى زَكَرِيَّا بْنُ مَنْظُورٍ عَنْ أَبِي حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ وَمَا أَسْكَرَ كَثِيرُهُ فَقَلِيلُهُ حَرَامٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Abu Yahya Zakaria bin Mandlur] dari [Abu Hazim] dari [Abdullah bin Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah haram, dan sesuatu yang banyaknya memabukkan maka sedikitnya pun haram, \""},"3349":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنِي دَاوُدُ بْنُ بَكْرٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَسْكَرَ كَثِيرُهُ فَقَلِيلُهُ حَرَامٌ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Anas bin Iyadl] telah menceritakan kepadaku [Daud bin Bakr] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang banyaknya memabukkan, maka sedikitnya pun haram, \""},"3350":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَسْكَرَ كَثِيرُهُ فَقَلِيلُهُ حَرَامٌ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Anas bin Iyadl] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang banyaknya memabukkan, maka sedikitnya pun haram, \""},"3351":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُنْبَذَ التَّمْرُ وَالزَّبِيبُ جَمِيعًا وَنَهَى أَنْ يُنْبَذَ الْبُسْرُ وَالرُّطَبُ جَمِيعًاقَالَ اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ الْمَكِّيُّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir bin Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam melarang membuat minuman dari perasan anggur kering dan kurma, juga dari perasan kurma muda dan kurma matang, \" [Al Laits bin Sa'd] berkata, telah menceritakan kepadaku ['Atha' bin Abu Rabah Al Makki] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam."},"3352":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ اللَّهِ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ أَبِي كَثِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنْبِذُوا التَّمْرَ وَالْبُسْرَ جَمِيعًا وَانْبِذُوا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى حِدَتِهِ","id":"Telah menceritakan kepada kami [Yazid bin Abdullah Al Yamami] telah menceritakan kepada kami [Ikrimah bin 'Ammar] dari [Abu Katsir] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membuat minuman dari perasan kurma matang dengan kurma muda menjadi satu. Tetapi buatlah minuman dari perasan pada masing-masing jenisnya, \""},"3353":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَجْمَعُوا بَيْنَ الرُّطَبِ وَالزَّهْوِ وَلَا بَيْنَ الزَّبِيبِ وَالتَّمْرِ وَانْبِذُوا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى حِدَتِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Ayahnya], bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencampurkan kurma matang dengan kurma pentil, atau anggur kering dengan kurma, tetapi buatlah perasan nabidz dari masing -masing jenisnya, \""},"3354":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَا حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ حَدَّثَتْنَا بُنَانَةُ بِنْتُ يَزِيدَ الْعَبْشَمِيَّةُ عَنْ عَائِشَةَ قَالَتْكُنَّا نَنْبِذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سِقَاءٍ فَنَأْخُذُ قَبْضَةً مِنْ تَمْرٍ أَوْ قَبْضَةً مِنْ زَبِيبٍ فَنَطْرَحُهَا فِيهِ ثُمَّ نَصُبُّ عَلَيْهِ الْمَاءَ فَنَنْبِذُهُ غُدْوَةً فَيَشْرَبُهُ عَشِيَّةً وَنَنْبِذُهُ عَشِيَّةً فَيَشْرَبُهُ غُدْوَةً وَقَالَ أَبُو مُعَاوِيَةَ نَهَارًا فَيَشْرَبُهُ لَيْلًا أَوْ لَيْلًا فَيَشْرَبُهُ نَهَارًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] keduanya berkata; telah menceritakan kepada kami ['Ashim Al Ahwal] telah menceritakan kepada kami [Bunanah bini Yazid Al 'Absyamiyah] dari [Aisyah] dia berkata, \"Kami membuat minuman untuk Rasulullah shallallahu 'alaihi wasallam dalam bejana minum; kami ambil segenggam kurma atau kismis dan memasukkannya ke dalam bejana tersebut kemudian menuangkan air ke dalamnya. Kami membuatnya di waktu pagi lalu beliau meminumnya di waktu sore, dan jika kami membuatnya di sore hari beliau meminumnya di waktu pagi.\" Abu Mu'awiyah berkata, \"(membuatnya) di waktu siang dan meminumnya di malam hari atau (membuatnya) di malam hari dan meminumnya di siang hari.\""},"3355":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ عَنْ إِسْمَعِيلَ بْنِ صَبِيحٍ عَنْ أَبِي إِسْرَائِيلَ عَنْ أَبِي عُمَرَ الْبَهْرَانِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ يُنْبَذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَشْرَبُهُ يَوْمَهُ ذَلِكَ وَالْغَدَ وَالْيَوْمَ الثَّالِثَ فَإِنْ بَقِيَ مِنْهُ شَيْءٌ أَهْرَاقَهُ أَوْ أَمَرَ بِهِ فَأُهْرِيقَ","id":"Telah menceritakan kepada kami [Abu Kuraib] dari [Isma'il bin Shabih] dari [Abu Israil] dari [Abu Umar Al Bahrani] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam dibuatkan minuman dari perasan anggur, beliau lalu meminumnya di hari itu juga, keesokan harinya dan hari ketiganya. Jika (di hari ketiga) masih tersisa, maka beliau membuangnya atau memerintahkan untuk membuangnya.\""},"3356":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ يُنْبَذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَوْرٍ مِنْ حِجَارَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Az Zubair] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah dibuatkan minuman dari perasan (anggur) dalam wadah yang terbuat dari batu, \""},"3357":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عُمَرَ وَحَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْبَذَ فِي النَّقِيرِ وَالْمُزَفَّتِ وَالدُّبَّاءِ وَالْحَنْتَمَةِ وَقَالَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin Umar], dan telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan nabidz dalam An Naqir, Al Muzaffat, Ad Duba dan Al Hantam. Beliau lalu bersabda: \"Semua yang memabukkan adalah haram.\" "},"3358":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْبَذَ فِي الْمُزَفَّتِ وَالْقَرْعِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membuat minuman dari perasan nabidz dalam Al Muzaffat dan Qar'.\" "},"3359":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبِي عَنْ الْمُثَنَّى بْنِ سَعِيدٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ فِي الْحَنْتَمِ وَالدُّبَّاءِ وَالنَّقِيرِ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Ayahku] dari [Al Mutsanna bin Sa'id] dari [Abu Al Mutawaki] dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang minuman yang berada dibuat dalam Al Hantam, Ad Duba dan An Naqir.\" "},"3360":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ وَالْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ قَالَا حَدَّثَنَا شَبَابَةُ عَنْ شُعْبَةَ عَنْ بُكَيْرِ بْنِ عَطَاءٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَعْمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ","id":"Telah menceritakan kepada kami [Abu Bakar] dan [Al 'Abbas bin Abdul 'Adzim Al 'Anbari] keduanya berkata; telah menceritakan kepada kami [Syababah] dari [Syu'bah] dari [Bukair bin 'Atha] dari [Abdurrahman bin Ya'mar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad duba dan Al Hantam.\" "},"3361":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ عَنْ شَرِيكٍ عَنْ سِمَاكٍ عَنْ الْقَ��سِمِ بْنِ مُخَيْمِرَةَ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنْتُ نَهَيْتُكُمْ عَنْ الْأَوْعِيَةِ فَانْتَبِذُوا فِيهِ وَاجْتَنِبُوا كُلَّ مُسْكِرٍ","id":"Telah menceritakan kepada kami [Abdul Hamid bin Bayan Al Wasithi] telah menceritakan kepada kami [Ishaq bin Yusuf] dari [Syarik] dari [Simak] dari [Al Qasim bin Mukhaimirah] dari [Ibnu Buraidah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku telah melarang kalian menggunakan bejana-bejana, sekarang gunakanlah untuk membuat perasan, dan jauhilah setiap sesuatu yang memabukkan.\""},"3362":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ أَيُّوبَ بْنِ هَانِئٍ عَنْ مَسْرُوقِ بْنِ الْأَجْدَعِ عَنْ ابْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ نَبِيذِ الْأَوْعِيَةِ أَلَا وَإِنَّ وِعَاءً لَا يُحَرِّمُ شَيْئًا كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepada kami [Ibnu Juraij] dari [Ayyub bin Hani] dari [Masruq bin Ajda'] dari [Ibnu Mas'ud], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, aku telah melarang kalian membuat perasan dalam bejana-bejana. Ketahuilah, bejana tidak bisa membuat sesuatu menjadi haram, dan setiap yang memabukkan adalah haram.\""},"3363":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ حَدَّثَتْنِي رُمَيْثَةُ عَنْ عَائِشَةَ أَنَّهَا قَالَتْأَتَعْجِزُ إِحْدَاكُنَّ أَنْ تَتَّخِذَ كُلَّ عَامٍ مِنْ جِلْدِ أُضْحِيَّتِهَا سِقَاءً ثُمَّ قَالَتْ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْبَذَ فِي الْجَرِّ وَفِي كَذَا وَفِي كَذَا إِلَّا الْخَلَّ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Ayahnya] telah menceritakan kepadaku [Rumaitsah] dari [Aisyah] bahwa dia berkata, \"Tidak mampukah salah seorang dari kalian setiap tahunnya membuat bejana dari kulit binatang kurban?\" Kemudian dia berkata lagi, \"Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan dalam bejana yang terbuat dari tembikar, dan dalam bejana begini dan bejana begini, kecuali cuka, \""},"3364":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْخَطْمِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْبَذَ فِي الْجِرَارِ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Khathmi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan dalam bejana yang terbuat dari tembikar, \""},"3365":{"ar":"حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا الْوَلِيدُ عَنْ صَدَقَةَ أَبِي مُعَاوِيَةَ عَنْ زَيْدِ بْنِ وَاقِدٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَبِيذِ جَرٍّ يَنِشُّ فَقَالَ اضْرِبْ بِهَذَا الْحَائِطَ فَإِنَّ هَذَا شَرَابُ مَنْ لَا يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ","id":"Telah menceritakan kepada kami [Mujahid bin Musa] telah menceritakan kepada kami [Al Walid] dari [Shadaqah Abu Mu'awiyah] dari [Zaid bin Waqid] dari [Khalid bin Abdullah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam dibawakan perasan dalam sebuah bejana tembikar (guci) yang telah menguap (mengalami fermentasi), maka beliau pun bersabda: \"Lemparkan ia ke tembok, sesungguhnya ini adalah minuman orang yang tidak beriman kepada Allah dan hari akhir.\""},"3366":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ غَطُّوا الْإِنَاءَ وَأَوْكُوا السِّقَاءَ وَأَطْفِئُوا السِّرَاجَ وَأَغْلِقُوا الْبَابَ فَإِنَّ الشَّيْطَانَ لَا يَحُلُّ سِقَاءً وَلَا يَفْتَحُ بَابًا وَلَا يَكْشِفُ إِنَاءً فَإِنْ لَمْ يَجِدْ أَحَدُكُمْ إِلَّا أَنْ يَعْرُضَ عَلَى إِنَائِهِ عُودًا وَيَذْكُرَ اسْمَ اللَّهِ فَلْيَفْعَلْ فَإِنَّ الْفُوَيْسِقَةَ تُضْرِمُ عَلَى أَهْلِ الْبَيْتِ بَيْتَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir bin Abdullah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Tutuplah tempat minum kalian, rapatkan bejana, matikan lampu dan tutuplah pintu kalian, sesungguhnya setan tidak akan membuka bejana, membuka pintu dan tidak dapat menyingkap tempat air minum, jika salah seorang dari kalian tidak dapat (melakukannya) kecuali hanya dengan merentangkan sebatang kayu di atas tempat minumnya, maka lakukanlah dengan menyebut nama Allah. Sesungguhnya tikus dapat merusak pemilik rumah dengan membakar rumahnya.\""},"3367":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَغْطِيَةِ الْإِنَاءِ وَإِيكَاءِ السِّقَاءِ وَإِكْفَاءِ الْإِنَاءِ","id":"Telah menceritakan kepada kami [Abdul Hamid bin Bayan Al Wasithi] telah menceritakan kepada kami [Khalid bin Abdullah] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami menutup tempat air, merapatkan tutup bejana dan tempayan.\""},"3368":{"ar":"حَدَّثَنَا عِصْمَةُ بْنُ الْفَضْلِ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ بْنِ أَبِي حَفْصَةَ حَدَّثَنَا حَرِيشُ بْنُ خِرِّيتٍ أَنْبَأَنَا ابْنُ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَضَعُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ آنِيَةٍ مِنْ اللَّيْلِ مُخَمَّرَةً إِنَاءً لِطَهُورِهِ وَإِنَاءً لِسِوَاكِهِ وَإِنَاءً لِشَرَابِهِ","id":"Telah menceritakan kepada kami ['Ishmah bin Al Fadll] telah menceritakan kepada kami [Harami bin 'Umarah bin Abu Hafshah] telah menceritakan kepada kami [Harisy bin Khirrit] telah memberitakan kepada kami [Ibnu Abu Mulaikah] dari [Aisyah] dia berkata, \"Aku selalu meletakkan tiga bejana untuk Rasulullah shallallahu 'alaihi wasallam di setiap malamnya, satu bejana untuk bersuci, satu bejana untuk siwak dan satu bejana untuk minum.\""},"3369":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ عَنْ أُمِّ سَلَمَةَأَنَّهَا أَخْبَرَتْهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الَّذِي يَشْرَبُ فِي إِنَاءِ الْفِضَّةِ إِنَّمَا يُجَرْجِرُ فِي بَطْنِهِ نَارَ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Zaid bin Abdullah bin Umar] dari [Abdullah bin Abdurrahman bin Abu Bakr] dari [Ummu Salamah], bahwa dia mengabarkan kepadanya dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang minum dari bejana yang terbuat dari perak, sungguh ia telah mendidihkan api neraka di dalam perutnya.\""},"3370":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ حُذَيْفَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ فِي آنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَقَالَ هِيَ لَهُمْ فِي الدُّنْيَا وَهِيَ لَكُمْ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang minum dari gelas yang terbuat dari emas dan perak, beliau bersabda: \"Ia (gelas dari emas dan perak) untuk mereka di dunia dan untuk kalian di akhirat.\""},"3371":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ نَافِعٍ عَنْ امْرَأَةِ ابْنِ عُمَرَ عَنْ عَائِشَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ فِي إِنَاءِ فِضَّةٍ فَكَأَنَّمَا يُجَرْجِرُ فِي بَطْنِهِ نَارَ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sa'd bin Ibrahim] dari [Nafi'] dari [isterinya Ibnu Umar] dari [Aisyah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa minum dari bejana yang terbuat dari perak, ibarat seseorang yang mendidihkan api neraka Jahannam ke dalam perutnya.\""},"3372":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسٍأَنَّهُ كَانَ يَتَنَفَّسُ فِي الْإِنَاءِ ثَلَاثًا وَزَعَمَ أَنَسٌ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَنَفَّسُ فِي الْإِنَاءِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Mahdi] telah menceritakan kepada kami ['Azrah bin Tsabit Al Anshari] dari [Tsumamah bin Abdullah] dari [Anas], bahwa dia bernafas ke dalam bejana (tempat air minum) sebanyak tiga kali, dan Anas mengaku bahwa Rasulullah shallallahu 'alaihi wasallam juga bernafas tiga kali dalam bejana (saat minum).\""},"3373":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا رِشْدِينُ بْنُ كُرَيْبٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ فَتَنَفَّسَ فِيهِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Muhammad bin Ash Shabah] keduanya berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Risydin bin Kuraib] dari [Ayahnya] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam minum dan bernafas di dalamnya (bejana) dua kali.\""},"3374":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اخْتِنَاثِ الْأَسْقِيَةِ أَنْ يُشْرَبَ مِنْ أَفْوَاهِهَا","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh] telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang langsung dari mulut bejana air minum.\""},"3375":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ سَلَمَةَ بْنِ وَهْرَامَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اخْتِنَاثِ الْأَسْقِيَةِ وَإِنَّ رَجُلًا بَعْدَ مَا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ قَامَ مِنْ اللَّيْلِ إِلَى سِقَاءٍ فَاخْتَنَثَهُ فَخَرَجَتْ عَلَيْهِ مِنْهُ حَيَّةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Zam'ah bin Shalih] dari [Salamah bin Wahram] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang minum langsung dari mulut bejana. Setelah Rasulullah shallallahu 'alaihi wasallam melarang perbuatan itu, ada seorang laki-laki bangun di waktu malam dan minum langsung dari mulut bejana, tiba-tiba keluar seekor ular dari mulut bejana tersebut ke arahnya.\""},"3376":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ مِنْ فِي السِّقَاءِ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawaf] telah menceritakan kepada kami [Abdul Waris bin Sa'id] dari [Ayyub] dari [Ikrimah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang minum langsung dari mulut bejana (ceret).\""},"3377":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُشْرَبَ مِنْ فَمِ السِّقَاءِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid Al Haddza`] dari [Ikrimah] dari [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam melarang minum langsung dari mulut bejana (ceret).\""},"3378":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَسَقَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ زَمْزَمَ فَشَرِبَ قَائِمًا فَذَكَرْتُ ذَلِكَ لِعِكْرِمَةَ فَحَلَفَ بِاللَّهِ مَا فَعَلَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari ['Ashim] dari [Asy Sya'bi] dari [Ibnu Abbas] dia berkata, \"Saya menuangkan air zamzam kepada Nabi shallallahu 'alaihi wasallam, beliau lalu meminumnya sambil berdiri, lalu hal itu aku ceritakan kepada Ikrimah, maka dia bersumpah dengan nama Allah atas apa yang di lakukan oleh Rasulullah.\""},"3379":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَزِيدَ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ جَدَّةٍ لَهُ يُقَالُ لَهَا كَبْشَةُ الْأَنْصَارِيَّةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا قِرْبَةٌ مُعَلَّقَةٌ فَشَرِبَ مِنْهَا وَهُوَ قَائِمٌ فَقَطَعَتْ فَمَ الْقِرْبَةِ تَبْتَغِي بَرَكَةَ مَوْضِعِ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Yazid bin Yazid bin Jabir] dari [Abdurrahman bin Abu 'Amrah] dari neneknya yang bernama [Kabsyah Al Anshariyah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah masuk menemuinya, lalu beliau minum dengan berdiri dari bejana yang tergantung di sisinya. Kabsyah lalu memotong mulut bejana guna mengharap berkah dari bekas mulut Rasulullah shallallahu 'alaihi wasallam.\""},"3380":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشُّرْبِ قَائِمًا","id":"Telah menceritakan kepada kami [Humaid bin Mas'udah] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam melarang minum sambil berdiri.\""},"3381":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَبَنٍ قَدْ شِيبَ بِمَاءٍ وَعَنْ يَمِينِهِ أَعْرَابِيٌّ وَعَنْ يَسَارِهِ أَبُو بَكْرٍ فَشَرِبَ ثُمَّ أَعْطَى الْأَعْرَابِيَّ وَقَالَ الْأَيْمَنُ فَالْأَيْمَنُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Malik bin Anas] dari [Az Zuhri] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pernah di suguhi susu yang telah di campur dengan air, di sisi kanan beliau ada seorang Arab badui dan di sebelah kirinya Abu Bakar. Kemudian beliau meminum susu tersebut lalu memberikan (sisanya) kepada orang Arab badui itu seraya bersabda: \"Dari yang sebelah kanan dan seterusnya.\""},"3382":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَبَنٍ وَعَنْ يَمِينِهِ ابْنُ عَبَّاسٍ وَعَنْ يَسَارِهِ خَالِدُ بْنُ الْوَلِيدِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِابْنِ عَبَّاسٍ أَتَأْذَنُ لِي أَنْ أَسْقِيَ خَالِدًا قَالَ ابْنُ عَبَّاسٍ مَا أُحِبُّ أَنْ أُوثِرَ بِسُؤْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَفْسِي أَحَدًا فَأَخَذَ ابْنُ عَبَّاسٍ فَشَرِبَ وَشَرِبَ خَالِدٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepada kami [Ibnu Juraij] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam di beri susu, sedangkan di sisi kanan beliau ada Ibnu Abbas dan di sisi kiri beliau Khalid bin Walid, Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepada Ibnu Abbas: \"Apakah kamu mengizinkanku memberikan minuman ini kepada Khalid?\" Ibnu Abbas menjawab, \"Aku tidak suka sekiranya aku memberikan sisa minuman Rasulullah shallallahu 'alaihi wasallam selain kepada diriku.\" Lantas Ibnu Abbas mengambil dan meminumnya, baru kemudian dia memberikan sisa minuman itu kepada Khalid.\""},"3383":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ الْحَارِثِ بْنِ أَبِي ذُبَابٍ عَنْ عَمِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَرِبَ أَحَدُكُمْ فَلَا يَتَنَفَّسْ فِي الْإِنَاءِ فَإِذَا أَرَادَ أَنْ يَعُودَ فَلْيُنَحِّ الْإِنَاءَ ثُمَّ لِيَعُدْ إِنْ كَانَ يُرِيدُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Daud bin Abdullah] dari [Abdul Aziz bin Muhammad] dari [Al Harits bin Abu Dzubab] dari [Pamannya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian minum maka janganlah ia bernapas dalam bejana. Jika ingin mengulanginya, maka hendaknya ia menjauhkan bejananya sebentar lalu meminumnya jika ia menginginkan.\""},"3384":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّنَفُّسِ فِي الْإِنَاءِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid Al Hadzdza`] dari ['Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang bernafas dalam bejana (ketika minum).\""},"3385":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْكَرِيمِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْفَخَ فِي الْإِنَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Khallad Al Bahili] telah menceritakan kepada kami [Sufyan] dari [Abdul Karim] dari ['Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang meniup dalam bejana (saat minum).\""},"3386":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ عَبْدِ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ شَرِيكٍ عَنْ عَبْدِ الْكَرِيمِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْفُخُ فِي الشَّرَابِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdurrahim bin Abdurrahman Al Muharibi] dari [Syarik] dari [Abdul Karim] dari ['Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah meniup dalam bejana.\""},"3387":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ مُسْلِمِ بْنِ عَبْدِ اللَّهِ عَنْ زِيَادِ بْنِ عَبْدِ اللَّهِ عَنْ عَاصِمِ بْنِ مُحَمَّدِ بْنِ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَشْرَبَ عَلَى بُطُونِنَا وَهُوَ الْكَرْعُ وَنَهَانَا أَنْ نَغْتَرِفَ بِالْيَدِ الْوَاحِدَةِ وَقَالَ لَا يَلَغْ أَحَدُكُمْ كَمَا يَلَغُ الْكَلْبُ وَلَا يَشْرَبْ بِالْيَدِ الْوَاحِدَةِ كَمَا يَشْرَبُ الْقَوْمُ الَّذِينَ سَخِطَ اللَّهُ عَلَيْهِمْ وَلَا يَشْرَبْ بِاللَّيْلِ مِنْ إِنَاءٍ حَتَّى يُحَرِّكَهُ إِلَّا أَنْ يَكُونَ إِنَاءً مُخَمَّرًا وَمَنْ شَرِبَ بِيَدِهِ وَهُوَ يَقْدِرُ عَلَى إِنَاءٍ يُرِيدُ التَّوَاضُعَ كَتَبَ اللَّهُ لَهُ بِعَدَدِ أَصَابِعِهِ حَسَنَاتٍ وَهُوَ إِنَاءُ عِيسَى ابْنِ مَرْيَمَ عَلَيْهِمَا السَّلَام إِذْ طَرَحَ الْقَدَحَ فَقَالَ أُفٍّ هَذَا مَعَ الدُّنْيَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] telah menceritakan kepada kami [Baqiyah] dari [Muslim bin Abdullah] dari [Ziyad bin Abdullah] dari ['Ashim bin Muhammad bin Zaid bin Abdullah bin Umar] dari [Ayahnya] dari [Kakeknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang kami minum langsung dengan mulut dalam bejana dan melarang mengambil air dengan tangan. Beliau bersabda: \"Janganlah salah seorang dari kalian menjilat sebagaimana anjing menjilat dan jangan minum dengan tangan satu sebagaimana kaum yang Allah murkai. Janganlah minum dalam bejana di malam hari sehingga ia menggoyang-goyangnya terlebih dahulu, kecuali jika bejananya tertutup. Barangsiapa minum dengan tangannya padahal ia mampu minum dengan bejana karena rasa tawadlu', maka Allah akan menuliskan setiap bilangan jarinya dengan kebaikan, dan itu adalah bejana Isa bin Maryam 'Alaihimassalaam, ketika dia melemparkan gelas dan berkata, 'Ah, ini adalah dunia'.\""},"3388":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنْصُورٍ أَبُو بَكْرٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ مِنْ الْأَنْصَارِ وَهُوَ يُحَوِّلُ الْمَاءَ فِي حَائِطِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ عِنْدَكَ مَاءٌ بَاتَ فِي شَنٍّ فَاسْقِنَا وَإِلَّا كَرَعْنَا قَالَ عِنْدِي مَاءٌ بَاتَ فِي شَنٍّ فَانْطَلَقَ وَانْطَلَقْنَا مَعَهُ إِلَى الْعَرِيشِ فَحَلَبَ لَهُ شَاةً عَلَى مَاءٍ بَاتَ فِي شَنٍّ فَشَرِبَ ثُمَّ فَعَلَ مِثْلَ ذَلِكَ بِصَاحِبِهِ الَّذِي مَعَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Manshur Abu Bakar] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi seorang laki-laki Anshar yang sedang membenahi aliran air di kebunnya. Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Jika kamu memiliki air yang yang ada dalam wadah maka berilah kami minum, jika tidak memiliki maka biarkanlah kami meminumnya langsung dari dalam aliran air yang ada.\" Laki-laki itu menjawab, \"Aku memiliki air yang ada dalam wadah.\" Laki-laki itu kemudian berlalu dan kami mengikutinya menuju sebuah gubuk (tempat berteduh), lalu ia memerah susu domba sebagai ganti air yang ada dalam bejana, beliau lalu meminumnya. Dan laki-laki itu juga melakukan hal yang serupa untuk sahabat yang bersama beliau.\""},"3389":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ لَيْثٍ عَنْ سَعِيدِ بْنِ عَامِرٍ عَنْ ابْنِ عُمَرَ قَالَمَرَرْنَا عَلَى بِرْكَةٍ فَجَعَلْنَا نَكْرَعُ فِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكْرَعُوا وَلَكِنْ اغْسِلُوا أَيْدِيَكُمْ ثُمَّ اشْرَبُوا فِيهَا فَإِنَّهُ لَيْسَ إِنَاءٌ أَطْيَبَ مِنْ الْيَدِ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la] telah menceritakan kepada kami [Ibnu Fudlail] dari [Laits] dari [Sa'id bin 'Amir] dari [Ibnu Umar] dia berkata, \"Saat kami melewati suatu kolam, maka kami pun langsung minum dengan mulut ke dalam kolam tersebut. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Janganlah kalian minum langsung dengan mulut (ke dalam kolam), tetapi cucilah tangan-tangan kalian kemudian minumlah dengan tangan. Sesungguhnya tidak ada bejana yang lebih baik daripada tangan.\""},"3390":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاقِي الْقَوْمِ آخِرُهُمْ شُرْبًا","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] dan [Suwaid bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit Al Bunani] dari [Abdullah bin Rabah] dari [Abu Qatadah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang memberi minum kepada suatu kaum, maka ia adalah orang yang terakhir minum dari mereka.\""},"3391":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مَنْدَلُ بْنُ عَلِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدَحٌ مِنْ قَوَارِيرَ يَشْرَبُ فِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] telah menceritakan kepada kami [Zaid bin Al Hubbab] telah menceritakan kepada kami [Mandal bin Ali] dari [Muhammad bin Ishaq] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memiliki gelas dari kaca yang digunakan untuk minum.\""},"3392":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَشَهِدْتُ الْأَعْرَابَ يَسْأَلُونَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعَلَيْنَا حَرَجٌ فِي كَذَا أَعَلَيْنَا حَرَجٌ فِي كَذَا فَقَالَ لَهُمْ عِبَادَ اللَّهِ وَضَعَ اللَّهُ الْحَرَجَ إِلَّا مَنْ اقْتَرَضَ مِنْ عِرْضِ أَخِيهِ شَيْئًا فَذَاكَ الَّذِي حَرِجَ فَقَالُوا يَا رَسُولَ اللَّهِ هَلْ عَلَيْنَا جُنَاحٌ أَنْ لَا نَتَدَاوَى قَالَ تَدَاوَوْا عِبَادَ اللَّهِ فَإِنَّ اللَّهَ سُبْحَانَهُ لَمْ يَضَعْ دَاءً إِلَّا وَضَعَ مَعَهُ شِفَاءً إِلَّا الْهَرَمَ قَالُوا يَا رَسُولَ اللَّهِ مَا خَيْرُ مَا أُعْطِيَ الْعَبْدُ قَالَ خُلُقٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Hisyam bin 'Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ziyad bin 'Ilaqah] dari [Usamah bin Syarik] dia berkata, \"Saya menyaksikan beberapa orang Arab badui bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Berdosakah kami jika melakukan ini? Berdosakah kami jika melakukan seperti ini?\" Beliau lalu bersabda kepada mereka: \"Wahai hamba Allah, Allah akan menghapus dosa kecuali orang yang menyebarluaskan (aib) saudaranya, itulah dosa.\" Mereka bertanya lagi, \"Wahai Rasulullah, berdosakah kami jika kami tidak berobat?\" beliau menjawab: \"Wahai hamba Allah, berobatlah kalian, karena sesungguhnya Allah Subhaanahu tidak menurunkan penyakit melainkan kecuali Dia juga menurunkan obatnya, kecuali sakit pikun.\" Mereka bertanya, \"Wahai Rasulullah, apakah kebaikan yang paling baik di berikan kepada seorang hamba?\" beliau menjawab: \"Akhlak yang mulia.\""},"3393":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ ابْنِ أَبِي خِزَامَةَ عَنْ أَبِي خِزَامَةَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ أَدْوِيَةً نَتَدَاوَى بِهَا وَرُقًى نَسْتَرْقِي بِهَا وَتُقًى نَتَّقِيهَا هَلْ تَرُدُّ مِنْ قَدَرِ اللَّهِ شَيْئًا قَالَ هِيَ مِنْ قَدَرِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Ibnu Abu Khizamah] dari [Abu Khizamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya, \"Bagaimana pendapatmu terhadap obat-obatan yang kami gunakan untuk berobat, ruqyah yang kami amalkan dan ketakwaan yang kami jalankan, apakah ia dapat menolak dari ketentuan Allah?\" beliau menjawab: \"Itu semua termasuk dari takdir Allah.\""},"3394":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَنْزَلَ اللَّهُ دَاءً إِلَّا أَنْزَلَ لَهُ دَوَاءً","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari ['Atha bin As Sa`ib] dari [Abu Abdurrahman] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah tidak akan menurunkan penyakit kecuali Allah juga akan menurunkan baginya obat.\""},"3395":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ عَنْ عُمَرَ بْنِ سَعِيدِ بْنِ أَبِي حُسَيْنٍ حَدَّثَنَا عَطَاءٌ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنْزَلَ اللَّهُ دَاءً إِلَّا أَنْزَلَ لَهُ شِفَاءً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibrahim bin Sa'id Al Jauhari] keduanya berkata; telah menceritakan kepada kami [Abu Ahmad] dari [Umar bin Sa'id bin Abu Husain] telah menceritakan kepada kami ['Atha] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak menurunkan suatu penyakit kecuali menurunkan obat baginya.\""},"3396":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا صَفْوَانُ بْنُ هُبَيْرَةَ حَدَّثَنَا أَبُو مَكِينٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَادَ رَجُلًا فَقَالَ لَهُ مَا تَشْتَهِي فَقَالَ أَشْتَهِي خُبْزَ بُرٍّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ عِنْدَهُ خُبْزُ بُرٍّ فَلْيَبْعَثْ إِلَى أَخِيهِ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَهَى مَرِيضُ أَحَدِكُمْ شَيْئًا فَلْيُطْعِمْهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Shafwan bin Hubairah] telah menceritakan kepada kami [Abu Makin] dari ['Ikrimah] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam menjenguk seorang laki-laki, beliau lalu bersabda kepadanya: \"Apa yang kamu inginkan?\" laki-laki itu menjawab, \"Saya menginginkan roti gandum.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki roti gandum, hendaknya ia memberikan kepada saudaranya.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Jika ada salah seorang di antara kalian sakit dan menginginkan sesuatu, hendaknya ia memberinya makan apa yang ia inginkan.\""},"3397":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبُو يَحْيَى الْحِمَّانِيُّ عَنْ الْأَعْمَشِ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَرِيضٍ يَعُودُهُ قَالَ أَتَشْتَهِي شَيْئًا قَالَ أَشْتَهِي كَعْكًا قَالَ نَعَمْ فَطَلَبُوا لَهُ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Abu Yahya Al Himmani] dari [Al A'masy] dari [Yazid Ar Raqasyi] dari [Anas bin Malik] dia berkata, \"Nabi shallallahu 'alaihi wasallam menjenguk seseorang yang sakit, beliau bersabda: \"Apakah kamu menginginkan sesuatu?\" orang itu menjawab, \"Aku ingin kue.\" Beliau bersabda: \"Baiklah.\" Kemudian orang-orang mencarikan kue untuknya.\""},"3398":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي صَعْصَعَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ وَأَبُو دَاوُدَ قَالَا حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ يَعْقُوبَ بْنِ أَبِي يَعْقُوبَ عَنْ أُمِّ الْمُنْذِرِ بِنْتِ قَيْسٍ الْأَنْصَارِيَّةِ قَالَتْدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عَلِيُّ بْنُ أَبِي طَالِبٍ وَعَلِيٌّ نَاقِهٌ مِنْ مَرَضٍ وَلَنَا دَوَالِي مُعَلَّقَةٌ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مِنْهَا فَتَنَاوَلَ عَلِيٌّ لِيَأْكُلَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ يَا عَلِيُّ إِنَّكَ نَاقِهٌ قَالَتْ فَصَنَعْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِلْقًا وَشَعِيرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ مِنْ هَذَا فَأَصِبْ فَإِنَّهُ أَنْفَعُ لَكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Ayyub bin Abdurrahman bin Abdullah bin Abu Sha'sha'ah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu 'Amir] dan [Abu Daud] keduanya berkata; telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Ayyub bin Abdurrahman] dari [Ya'qub bin Abu Ya'qub] dari [Ummu Al Mundzir binti Qais Al Anshariyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengunjungi kami bersama Ali bin Abu Thalib, saat itu Ali baru saja sembuh dari sakitnya. Dan kami memiliki hasil petikan buah kurma yang masih menggantung, Nabi shallallahu 'alaihi wasallam makan beberapa buah darinya. Kemudian Ali juga ikut mengambilnya dan memakannya, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan wahai Ali, sebab kamu baru saja sembuh.\" Ummu Al Mundzir berkata, \"Kemudian aku membuatkan makanan dari ubi dan gandum untuk Nabi shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Ali, makanlah makanan ini, karena ia sangat bermanfaat bagimu.\""},"3399":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ عَبْدِ الْحَمِيدِ بْنِ صَيْفِيٍّ مِنْ وَلَدِ صُهَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ صُهَيْبٍ قَالَقَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ يَدَيْهِ خُبْزٌ وَتَمْرٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْنُ فَكُلْ فَأَخَذْتُ آكُلُ مِنْ التَّمْرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَأْكُلُ تَمْرًا وَبِكَ رَمَدٌ قَالَ فَقُلْتُ إِنِّي أَمْضُغُ مِنْ نَاحِيَةٍ أُخْرَى فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Abdul Wahab] dia berkata; telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Abdul Hamid bin Shaifi] salah seorang anaknya shuhaib, dari [Ayahnya] dari kakeknya [Shuhaib] dia berkata, \"Aku datang kepada Nabi shallallahu 'alaihi wasallam sedangkan di hadapan beliau terdapat roti dan kurma, lalu beliau bersabda: \"Mendekat dan makanlah.\" Maka aku mengambil kurma dan memakannnya, lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu memakan kurma sedang kamu lagi sakit mata?\" Shuhaib berkata, \"Aku menjawab, \"Aku mengunyah dari sisi yang lain.\" Maka Rasulullah shallallahu 'alaihi wasallam pun tersenyum mendengarnya.\""},"3400":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا بَكْرُ بْنُ يُونُسَ بْنِ بُكَيْرٍ عَنْ مُوسَى بْنِ عَلِيِّ بْنِ رَبَاحٍ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُكْرِهُوا مَرْضَاكُمْ عَلَى الطَّعَامِ وَالشَّرَابِ فَإِنَّ اللَّهَ يُطْعِمُهُمْ وَيَسْقِيهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Bakr bin Yunus bin Bukair] dari [Musa bin Ali bin Rabah] dari [Ayahnya] dari ['Uqbah bin 'Amir Al Juhani] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian paksa orang-orang sakit di antara kalian untuk makan dan minum. Sesungguhnya Allah telah memberi mereka makan dan minum.\""},"3401":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا مُحَمَّدُ بْنُ السَّائِبِ بْنِ بَرَكَةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَخَذَ أَهْلَهُ الْوَعْكُ أَمَرَ بِالْحَسَاءِ قَالَتْ وَكَانَ يَقُولُ إِنَّهُ لَيَرْتُو فُؤَادَ الْحَزِينِ وَيَسْرُو عَنْ فُؤَادِ السَّقِيمِ كَمَا تَسْرُو إِحْدَاكُنَّ الْوَسَخَ عَنْ وَجْهِهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] telah menceritakan kepada kami [Muhammad bin As Sa`ib bin Barakah] dari [Ibunya] dari [Aisyah] dia berkata, \"Apabila dari keluarga beliau ada yang sakit, maka beliau memerintahkan supaya di buatkan sup.\" Aisyah berkata lagi, \"Beliau mengucapkan: \"Sesungguhnya sup tersebut akan menguatkan hati orang yang sedang bersedih dan akan menghilangkan hati orang yang sakit sebagaimana salah seorang dari kalian menghilangkan kotoran (debu) dari wajahnya dengan air.\""},"3402":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ أَبِي الْخَصِيبِ حَدَّثَنَا وَكِيعٌ عَنْ أَيْمَنَ بْنِ نَابِلٍ عَنْ امْرَأَةٍ مِنْ قُرَيْشٍ يُقَالَ لَهَا كُلْثُمٌ عَنْ عَائِشَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالْبَغِيضِ النَّافِعِ التَّلْبِينَةِ يَعْنِي الْحَسَاءَ قَالَتْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَكَى أَحَدٌ مِنْ أَهْلِهِ لَمْ تَزَلْ الْبُرْمَةُ عَلَى النَّارِ حَتَّى يَنْتَهِيَ أَحَدُ طَرَفَيْهِ يَعْنِي يَبْرَأُ أَوْ يَمُوتُ","id":"Telah menceritakan kepada kami [Ali bin Abu Al Khashib] telah menceritakan kepada kami [Waki'] dari [Aiman bin Nabil] dari seorang wanita dari suku Qurasiy yang bernama [Kultsum] dari [Aisyah] dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Makanlah adonan tepung hangat yang bermanfaat, yaitu sup.\" Aisyah berkata, \"Apabila salah seorang dari keluarga Rasulullah shallallahu 'alaihi wasallam sakit, maka periuk akan senantiasa berada di atas tungku api hingga salah satu dari keduanya habis, maksudnya sembuh atau meninggal.\""},"3403":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ وَمُحَمَّدُ بْنُ الْحَارِثِ الْمِصْرِيَّانِ قَالَا حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَسَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُمَاأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ فِي الْحَبَّةِ السَّوْدَاءِ شِفَاءً مِنْ كُلِّ دَاءٍ إِلَّا السَّامَ وَالسَّامُ الْمَوْتُ وَالْحَبَّةُ السَّوْدَاءُ الشُّونِيزُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] dan [Muhammad bin Al Harits Al Mushriyan] keduanya berkata; telah menceritakan kepada kami [Al Laits bin Sa'd] dari ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dan [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] mengabarkan kepada keduanya, bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dalam habbatus sauda' (jintan hitam) terdapat obat dari segala jenis penyakit kecuali as saam, dan as saam adalah kematian, dan habbatus sauda' adalah Asy syuniz.\""},"3404":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عُثْمَانَ بْنِ عَبْدِ الْمَلِكِ قَالَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَيْكُمْ بِهَذِهِ الْحَبَّةِ السَّوْدَاءِ فَإِنَّ فِيهَا شِفَاءً مِنْ كُلِّ دَاءٍ إِلَّا السَّامَ","id":"Telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf] telah menceritakan kepada kami [Abu 'Ashim] dari ['Utsman bin Abdul Malik] dia berkata; saya mendengar [Salim bin Abdullah] menceritakan dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian menggunakan Al Habbah As Sauda (jintan hitam) ini. Sesungguhnya dia mengandung penawar dari setiap penyakit kecuali kematian.\""},"3405":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ أَنْبَأَنَا إِسْرَائِيلُ عَنْ مَنْصُورٍ عَنْ خَالِدِ بْنِ سَعْدٍ قَالَ خَرَجْنَا وَمَعَنَا غَالِبُ بْنُ أَبْجَرَ فَمَرِضَ فِي الطَّرِيقِ فَقَدِمْنَا الْمَدِينَةَ وَهُوَ مَرِيضٌ فَعَادَهُ ابْنُ أَبِي عَتِيقٍ وَقَالَ لَنَا عَلَيْكُمْ بِهَذِهِ الْحَبَّةِ السَّوْدَاءِ فَخُذُوا مِنْهَا خَمْسًا أَوْ سَبْعًا فَاسْحَقُوهَا ثُمَّ اقْطُرُوهَا فِي أَنْفِهِ بِقَطَرَاتِ زَيْتٍ فِي هَذَا الْجَانِبِ وَفِي هَذَا الْجَانِبِ فَإِنَّ عَائِشَةَ حَدَّثَتْهُمْأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ هَذِهِ الْحَبَّةَ السَّوْدَاءَ شِفَاءٌ مِنْ كُلِّ دَاءٍ إِلَّا أَنْ يَكُونَ السَّامُ قُلْتُ وَمَا السَّامُ قَالَ الْمَوْتُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ubaidullah] telah memberitakan kepada kami [Israil] dari [Manshur] dari [Khalid bin Sa'd] dia berkata, \"Kami pergi bersama Ghalib bin Abjar, kemudian di tengah jalan ia menderita sakit hingga kami sampai di Madinah dan dia masih menderita sakit. Lalu [Ibnu Abu 'Atiq] datang menjenguknya seraya berkata kepada kami, \"Gunakanlah Al Habbah As Sauda (Jintan hitam), ambillah darinya lima atau tujuh butir, kemudian tumbuklah sampai halus dan teteskanlah beberapa tetesan ke dalam hidungnya di sisi ini dan ini. Sesungguhnya [Aisyah] pernah menceritakan kepada para sahabat bahwa dia mendengar dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Al habbah As Sauda (jintan hitam) ini adalah penawar dari semua penyakit, kecuali penyakit As Saam.\" Lalu aku bertanya, \"Apakah yang di maksud dengan As Saam?\" beliau menjawab: \"Kematian.\""},"3406":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خِدَاشٍ حَدَّثَنَا سَعِيدُ بْنُ زَكَرِيَّاءَ الْقُرَشِيُّ حَدَّثَنَا الزُّبَيْرُ بْنُ سَعِيدٍ الْهَاشِمِيُّ عَنْ عَبْدِ الْحَمِيدِ بْنِ سَالِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَعِقَ الْعَسَلَ ثَلَاثَ غَدَوَاتٍ كُلَّ شَهْرٍ لَمْ يُصِبْهُ عَظِيمٌ مِنْ الْبَلَاءِ","id":"Telah menceritakan kepada kami [Mahmud bin Khidasy] telah menceritakan kepada kami [Sa'id bin Zakaria Al Qurasyi] telah menceritakan kepada kami [Az Zubair bin Sa'id Al Hasyimi] dari [Abdul Hamid bin Salim] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum madu dalam tiga pagi (tiga kali) dalam setiap bulannya, maka ia tidak akan ditimpa bala' (penyakit) yang berat.\""},"3407":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا عُمَرُ بْنُ سَهْلٍ حَدَّثَنَا أَبُو حَمْزَةَ الْعَطَّارُ عَنْ الْحَسَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأُهْدِيَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَسَلٌ فَقَسَمَ بَيْنَنَا لُعْقَةً لُعْقَةً فَأَخَذْتُ لُعْقَتِي ثُمَّ قُلْتُ يَا رَسُولَ اللَّهِ أَزْدَادُ أُخْرَى قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Umar bin Sahl] telah menceritakan kepada kami [Abu Hamzah Al 'Aththar] dari [Al Hasan] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam diberi hadiah madu, lalu beliau membagikannya di antara kami satu sendok-satu sendok. Lalu aku mengambil dua sendok seraya berkata; \"Wahai Rasulullah, aku nambah lagi.\" Beliau menjawab: \"Ya.\""},"3408":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَلَمَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالشِّفَاءَيْنِ الْعَسَلِ وَالْقُرْآنِ","id":"Telah menceritakan kepada kami [Ali bin Salamah] telah menceritakan kepada kami [Zaid bin Al Hubbab] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gunakanlah dua jenis terapi penyembuhan; madu dan Al Qur'an.\""},"3409":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي سَعِيدٍ وَجَابِرٍ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ وَالْعَجْوَةُ مِنْ الْجَنَّةِ وَهِيَ شِفَاءٌ مِنْ الْجِنَّةِحَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقِّيَّانِ قَالَا حَدَّثَنَا سَعِيدُ بْنُ مَسْلَمَةَ بْنِ هِشَامٍ عَنْ الْأَعْمَشِ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Asbath bin Muhammad] telah menceritakan kepada kami [Al A'masy] dari [Ja'far bin 'Iyas] dari [Syahr bin Hausyab] dari [Abu Sa'id] dan [Jabir] keduanya berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Kam`ah (sejenis tanaman) adalah dari Manna, airnya bisa untuk obat dari sakit 'ain. Dan (kurma) Ajwah adalah dari surga, ia adalah obat dari jin.\" Telah menceritakan kepada kami [Ali bin Maimun] dan [Muhammad bin Abdullah Ar Raqqayan] keduanya berkata; telah menceritakan kepada kami [Sa'id bin Maslamah bin Hisyam] dari [Al A'masy] dari [Ja'far bin Iyas] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"3410":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ سَمِعَ عَمْرَو بْنَ حُرَيْثٍ يَقُولُ سَمِعْتُ سَعِيدَ بْنَ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍيُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْكَمْأَةَ مِنْ الْمَنِّ الَّذِي أَنْزَلَ اللَّهُ عَلَى بَنِي إِسْرَائِيلَ وَمَاؤُهَا شِفَاءُ الْعَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabah] telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Abdul Malik bin 'Umair] bahwa dia mendengar ['Amru bin Huraits] berkata; saya mendengar [Sa'id bin Zaid bin 'Amru bin Nufail] menceritakan dari Nabi shallallahu 'alaihi wasallam, Al Kam`ah (sejenis tanaman) adalah dari surga, (makanan) yang Allah turunkan kepada bani Israil, airnya sebagai obat untuk penyakit 'ain.\""},"3411":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَبْدِ الصَّمَدِ حَدَّثَنَا مَطَرٌ الْوَرَّاقُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا نَتَحَدَّثُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا الْكَمْأَةَ فَقَالُوا هُوَ جُدَرِيُّ الْأَرْضِ فَنُمِيَ الْحَدِيثُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْكَمْأَةُ مِنْ الْمَنِّ وَالْعَجْوَةُ مِنْ الْجَنَّةِ وَهِيَ شِفَاءٌ مِنْ السَّمِّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu 'Abdush Shamad] telah menceritakan kepada kami [Mathar Al Warraq] dari [Syahr bin Hausyab] dari [Abu Hurairah] dia berkata, \"Kami berbincang-bincang di sisi Rasulullah shallallahu 'alaihi wasallam, lalu kami menyebutkan tentang Al Kam`ah, sebagian sahabat mengatakan, \"Kam`ah adalah penyakit cacar di bumi.\" Ternyata pembicaraan tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Kam`ah (sejenis tumbuhan) adalah dari Al Manna dan Ajwah adalah (kurma) dari surga, ia merupakan penawar racun.\" "},"3412":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا الْمُشْمَعِلُّ بْنُ إِيَاسٍ الْمُزَنِيُّ حَدَّثَنِي عَمْرُو بْنُ سُلَيْمٍ قَالَ سَمِعْتُ رَافِعَ بْنَ عَمْرٍو الْمُزَنِيَّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَجْوَةُ وَالصَّخْرَةُ مِنْ الْجَنَّةِقَالَ عَبْدُ الرَّحْمَنِ حَفِظْتُ الصَّخْرَةَ مِنْ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Al Musyma'il bin Iyas Al Muzani] telah menceritakan kepadaku ['Amru bin Sulaim] dia berkata; saya mendengar [Rafi' bin 'Amru Al Muzani] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Kurma) 'Ajwa dan Shahrah (kubah yang berada di Baitul Maqdis) adalah dari surga.\" Abdurrahman berkata, \"Lafadz Ash Shahrakh aku hafal dari mulut beliau.\""},"3413":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ يُوسُفَ بْنِ سَرْحٍ الْفِرْيَابِيُّ حَدَّثَنَا عَمْرُو بْنُ بَكْرٍ السَّكْسَكِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي عَبْلَةَ قَالَ سَمِعْتُ أَبَا أُبَيِّ بْنَ أُمِّ حَرَامٍ وَكَانَ قَدْ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقِبْلَتَيْنِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَيْكُمْ بِالسَّنَى وَالسَّنُّوتِ فَإِنَّ فِيهِمَا شِفَاءً مِنْ كُلِّ دَاءٍ إِلَّا السَّامَ قِيلَ يَا رَسُولَ اللَّهِ وَمَا السَّامُ قَالَ الْمَوْتُقَالَ عَمْرٌو قَالَ ابْنُ أَبِي عَبْلَةَ السَّنُّوتُ الشِّبِتُّ و قَالَ آخَرُونَ بَلْ هُوَ الْعَسَلُ الَّذِي يَكُونُ فِي زِقَاقِ السَّمْنِ وَهُوَ قَوْلُ الشَّاعِرِ هُمْ السَّمْنُ بِالسَّنُّوتِ لَا أَلْسَ فِيهِمْوَهُمْ يَمْنَعُونَ جَارَهُمْ أَنْ يُقَرَّدَا","id":"Telah menceritakan kepada kami [Ibrahim bin Muhammad bin Yusuf bin Sarh Al firyani] telah menceritakan kepada kami ['Amru bin Bakr As Saksaki] telah menceritakan kepada kami [Ibrahim bin Abu 'Ablah] dia berkata; aku mendengar [Abu Ubay bin Ummi Haram] -dan dia ikut serta shalat bersama Rasulullah shallallahu 'alaihi wasallam menghadap dua kiblat- dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian menggunakan pohon sanaa (sejenis pohon yang di gunkan untuk obat) dan sanuut (madu atau sari buah yang kental), karena keduanya mengandung penawar dari semua penyakit, kecuali As Saam.\" Beliau ditanya, \"Wahai Rasulullah, apakah As Saam itu?\" beliau menjawab: \"Kematian.\" Amru berkata, \"Ibnu Abu 'Ablah berkata, \"As sanuut adalah asy syabitu (sejenis tumbuhan).\" Dan yang lain berkata, \"Dia adalah madu yang terdapat pada sela-sela minyak samin. Seperti yang di sebutkan dalam sya'ir: 'Mereka seperti as saanut yang berada di sela-sela minyak samin, tiada khianat atas mereka, mereka menghalangi tetangga mereka untuk melakukan kebohongan'.\""},"3414":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا السَّرِيُّ بْنُ مِسْكِينٍ حَدَّثَنَا ذَوَّادُ بْنُ عُلْبَةَ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ أَبِي هُرَيْرَةَ قَالَهَجَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَجَّرْتُ فَصَلَّيْتُ ثُمَّ جَلَسْتُ فَالْتَفَتَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشِكَمَتْ دَرْدْ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ قُمْ فَصَلِّ فَإِنَّ فِي الصَّلَاةِ شِفَاءًحَدَّثَنَا أَبُو الْحَسَنِ الْقَطَّانُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو سَلَمَةَ حَدَّثَنَا ذَوَّادُ بْنُ عُلْبَةَ فَذَكَرَ نَحْوَهُ وَقَالَ فِيهِ اشِكَمَتْ دَرْدْ يَعْنِي تَشْتَكِي بَطْنَكَ بِالْفَارِسِيَّةِ قَالَ أَبُو عَبْد اللَّهِ حَدَّثَ بِهِ رَجُلٌ لِأَهْلِهِ فَاسْتَعْدَوْا عَلَيْهِ","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] telah menceritakan kepada kami [As Sari bin Miskin] telah menceritakan kepada kami [Dzawwad bin 'Ulbah] dari [Laits] dari [Mujahid] dari [Abu Hurairah] dia berkata, \"Nabi shallallahu 'alaihi wasallam keluar ketika matahari sedang terik, lalu aku datang dan shalat. Setelah itu aku duduk dan menoleh ke arah Nabi shallallahu 'alaihi wasallam, beliau pun bersabda: \"Apakah kamu sakit perut.\" Jawabku, \"Benar wahai Rasulullah.\" Beliau bersabda: \"Shalatlah, karena dalam shalat terdapat kesembuhan.\" Telah menceritakan kepada kami Abu Al Hasan Al Qatthan telah menceritakan kepada kami Ibrahim bin Nashr telah menceritakan kepada kami Abu Salamah telah menceritakan kepada kami Dzawwad bin 'Ulbah kemudian dia menyebutkan hadits semisalnya. Dan dalam haditsnya ia menyebutkan, \"Isykamat dard maksudnya adalah 'Apakah perutmu terasa sakit? ', yaitu dalam bahasa Persi.\" Abu Abdullah berkata, \"Seorang laki-laki menceritakan hadits kepada keluarganya, lalu mereka bersiap atasnya.\""},"3415":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّوَاءِ الْخَبِيثِ يَعْنِي السُّمَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Yunus bin Abu Ishaq] dari [Mujahid] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menggunakan obat yang buruk, yaitu racun.\""},"3416":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَرِبَ سُمًّا فَقَتَلَ نَفْسَهُ فَهُوَ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dari [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum racun lalu membunuh dirinya, maka ia akan merasakan kelak di neraka Jahannam. Ia akan kekal selama-lamanya.\""},"3417":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مَوْلًى لِمَعْمَرٍ التَّيْمِيِّ عَنْ مَعْمَرٍ التَّيْمِيِّ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَاذَا كُنْتِ تَسْتَمْشِينَ قُلْتُ بِالشُّبْرُمِ قَالَ حَارٌّ جَارٌّ ثُمَّ اسْتَمْشَيْتُ بِالسَّنَى فَقَالَ لَوْ كَانَ شَيْءٌ يَشْفِي مِنْ الْمَوْتِ كَانَ السَّنَي وَالسَّنَي شِفَاءٌ مِنْ الْمَوْتِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] dari [Zur'ah bin Abdurrahman] dari [Bekas budak Ma'mar At Taimi] dari [Ma'mar At Taimi] dari [Asma binti 'Umais] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Dengan apa kamu minum untuk menyembuhkan sakit perutmu?\" Aku menjawab, \"Dengan Syubrum.\" Beliau bersabda: \"Panas.\" Aku berkata, \"Kemudian aku meminum obat sakit perut dengan menggunakan sanaa. Lantas beliau bersabda: \"Seandainya ada sesuatu yang bisa menyembuhkan mati, maka itu adalah sanaa, dan sanaa adalah obat dari kematian.\""},"3418":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْدَخَلْتُ بِابْنٍ لِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَعْلَقْتُ عَلَيْهِ مِنْ الْعُذْرَةِ فَقَالَ عَلَامَ تَدْغَرْنَ أَوْلَادَكُنَّ بِهَذَا الْعِلَاقِ عَلَيْكُمْ بِهَذَا الْعُودِ الْهِنْدِيِّ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ يُسْعَطُ بِهِ مِنْ الْعُذْرَةِ وَيُلَدُّ بِهِ مِنْ ذَاتِ الْجَنْبِحَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ قَالَ يُونُسُ أَعْلَقْتُ يَعْنِي غَمَزْتُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Ash Shabah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ummu Qais binti Mihshan] dia berkata, \"Aku mengunjungi Nabi shallallahu 'alaihi wasallam bersama anakku yang baru saja saya obati kerongkongannya dengan tanganku, maka beliau bersabda: \"Dengan maksud apa kamu mengobati penyakit tenggorokan anakmu dengan memasukkan jemari tangan? Gunakanlah kayu India, karena padanya terdapat tujuh ragam penyembuhan, dan dapat di masukkan sebagai obat tetes hidung untuk dapat menyembuhkan penyakit kerongkongan dan dapat pula menjadi penyembuh dari penyakit radang selaput dada.\" Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh Al Mishri] telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Ubaidillah] dari [Ummu Qais binti Mihshan] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, Yunus mengatakan, \"Arti a'laqtu adalah menusuk dengan jari.\""},"3419":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَرَاشِدُ بْنُ سَعِيدٍ الرَّمْلِيُّ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ شِفَاءُ عِرْقِ النَّسَا أَلْيَةُ شَاةٍ أَعْرَابِيَّةٍ تُذَابُ ثُمَّ تُجَزَّأُ ثَلَاثَةَ أَجْزَاءٍ ثُمَّ يُشْرَبُ عَلَى الرِّيقِ فِي كُلِّ يَوْمٍ جُزْءٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Rasyid bin Sa'id Ar Ramli] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Hisyam bin Hassan] telah menceritakan kepada kami [Anas bin Sirin] bahwa dia mendengar [Anas bin Malik] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Obat penyakit encok adalah buntut (ekor) kambing kampung betina yang di keringkan, kemudian di bagi menjadi tiga bagian, lalu di minum dengan air bersih satu bagian setiap harinya.\""},"3420":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَجُرِحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ وَكُسِرَتْ رَبَاعِيَتُهُ وَهُشِمَتْ الْبَيْضَةُ عَلَى رَأْسِهِ فَكَانَتْ فَاطِمَةُ تَغْسِلُ الدَّمَ عَنْهُ وَعَلِيٌّ يَسْكِبُ عَلَيْهِ الْمَاءَ بِالْمِجَنِّ فَلَمَّا رَأَتْ فَاطِمَةُ أَنَّ الْمَاءَ لَا يَزِيدُ الدَّمَ إِلَّا كَثْرَةً أَخَذَتْ قِطْعَةَ حَصِيرٍ فَأَحْرَقَتْهَا حَتَّى إِذَا صَارَ رَمَادًا أَلْزَمَتْهُ الْجُرْحَ فَاسْتَمْسَكَ الدَّمُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Muhammad bin Ash Shabah] keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Sahl bin Sa'd As Sa'idi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam terluka pada waktu Perang Uhud hingga gigi depannya pecah, dan topi besinya pun pecah. Saat itu Fatimah mencuci darah yang keluar sementara Ali menuangkan air dengan menggunakan perisai. Ketika Fatimah melihat bahwa air tidak dapat mengurangi keluarnya darah bahkan (hanya membuatnya) kian deras, maka ia segera mengambil sobekan tikar dan membakarnya, ketika telah menjadi abu ia menempelkannya pada luka tersebut, dan darah pun berhenti.\""},"3421":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ الْمُهَيْمِنِ بْنِ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَإِنِّي لَأَعْرِفُ يَوْمَ أُحُدٍ مَنْ جَرَحَ وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ يُرْقِئُ الْكَلْمَ مِنْ وَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُدَاوِيهِ وَمَنْ يَحْمِلُ الْمَاءَ فِي الْمِجَنِّ وَبِمَا دُووِيَ بِهِ الْكَلْمُ حَتَّى رَقَأَ قَالَ أَمَّا مَنْ كَانَ يَحْمِلُ الْمَاءَ فِي الْمِجَنِّ فَعَلِيٌّ وَأَمَّا مَنْ كَانَ يُدَاوِي الْكَلْمَ فَفَاطِمَةُ أَحْرَقَتْ لَهُ حِينَ لَمْ يَرْقَأْ قِطْعَةَ حَصِيرٍ خَلَقٍ فَوَضَعَتْ رَمَادَهُ عَلَيْهِ فَرَقَأَ الْكَلْمُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Abdul Muhaimin bin 'Abbas bin Sahl bin Sa'd As Sa'idi] dari [Ayahnya] dari [Kakeknya] dia berkata, \"Sungguh saya mengetahui kejadian para waktu Perang Uhud, siapa yang melukai wajah Rasulullah shallallahu 'alaihi wasallam dan siapa yang membuat darah pada luka di wajah Rasulullah shallallahu 'alaihi wasallam berhenti dan yang mengobatinya, serta siapa pula yang membawa air dengan menggunakan perisai dan dengan apa lukanya di obati hingga berhenti mengalirkan darah.\" Sahl melanjutkan, \"Adapun orang yang membawa air di dalam perisai adalah Ali dan yang mengobati lukanya adalah Fatimah. Dia membakar potongan tikar usang ketika (melihat) darahnya tidak juga berhenti mengalir, lalu meletakkan abunya pada luka tersebut, setelah itu lukanya pun mengering.\""},"3422":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَرَاشِدُ بْنُ سَعِيدٍ الرَّمْلِيُّ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَطَبَّبَ وَلَمْ يُعْلَمْ مِنْهُ طِبٌّ قَبْلَ ذَلِكَ فَهُوَ ضَامِنٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Rasyid bin Sa'id Ar Ramli] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Juraij] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengobati sedangkan ia tidak tahu mengenai pengobatan, maka dia harus bertanggung jawab.\""},"3423":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَقَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَيْمُونٍ حَدَّثَنِي أَبِي عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَنَعَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ذَاتِ الْجَنْبِ وَرْسًا وَقُسْطًا وَزَيْتًا يُلَدُّ بِهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Abdul Wahab] telah menceritakan kepada kami [Ya'qub bin Ishaq] telah menceritakan kepada kami [Abdurrahman bin Maimun] telah menceritakan kepadaku [Ayahku] dari [Zaid bin Arqam] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyebutkan wars (sejenis tumbuhan), qusth (kayu hindi) dan minyak zaitun bahwa itu semua dapat mencegah penyakit lambung.\""},"3424":{"ar":"حَدَّثَنَا أَبُو طَاهِرٍ أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ وَابْنُ سَمْعَانَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالْعُودِ الْهِنْدِيِّ يَعْنِي بِهِ الْكُسْتَ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ قَالَ ابْنُ سَمْعَانَ فِي الْحَدِيثِ فَإِنَّ فِيهِ شِفَاءً مِنْ سَبْعَةِ أَدْوَاءٍ مِنْهَا ذَاتُ الْجَنْبِ","id":"Telah menceritakan kepada kami [Abu Thahir Ahmad bin 'Amru As Sarh Al Mishri] telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepada kami [Yunus] dan [Ibnu Sam'an] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ummu Qais binti Mihshan] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gunakanlah dahan kayu India (Al Kust) karena sesungguhnya ia terdapat tujuh macam penyembuh, di antaranya adalah sakit lambung.\" Ibnu Sam'an menyebutkan dalam haditsnya, \"Karena sesungguhnya padanya terdapat obat dari tujuh macam jenis penyakit, di antaranya adalah sakit lambung.\""},"3425":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ مُوسَى بْنِ عُبَيْدَةَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ حَفْصِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ قَالَذُكِرَتْ الْحُمَّى عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَبَّهَا رَجُلٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبَّهَا فَإِنَّهَا تَنْفِي الذُّنُوبَ كَمَا تَنْفِي النَّارُ خَبَثَ الْحَدِيدِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Musa bin 'Ubaidah] dari ['Alqamah bin Martsad] dari [Hafsh bin 'Ubaidullah] dari [Abu Hurairah] dia berkata, \"Disebutkan tentang demam di samping Rasulullah shallallahu 'alaihi wasallam, lalu seorang laki-laki mencacinya, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Janganlah mencacinya, sesungguhnya demam dapat menghapuskan dosa sebagaimana api menghilangkan karat besi.\""},"3426":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ إِسْمَعِيلَ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي صَالِحٍ الْأَشْعَرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ عَادَ مَرِيضًا وَمَعَهُ أَبُو هُرَيْرَةَ مِنْ وَعْكٍ كَانَ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْشِرْ فَإِنَّ اللَّهَ يَقُولُ هِيَ نَارِي أُسَلِّطُهَا عَلَى عَبْدِي الْمُؤْمِنِ فِي الدُّنْيَا لِتَكُونَ حَظَّهُ مِنْ النَّارِ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Abdurrahman bin Yazid] dari [Isma'il bin 'Ubaidullah] dari [Abu Shalih Al Asy'ari] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallamm, bahwa beliau menjenguk seseorang yang tengah tertimpa sakit demam, dan bersama beliau adalah Abu Hurairah, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bergembiralah, sesungguhnya Allah berfirman: 'Ia (demam) adalah api-Ku yang Aku timpakan kepada hamba-Ku yang mukmin di dunia sebagai pengganti bagiannya dari api neraka di Akhirat'.\""},"3427":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْ��ُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ فَابْرُدُوهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya demam itu (berasal) dari hembusan panas neraka Jahannam, maka dinginkanlah ia dengan air.\""},"3428":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ شِدَّةَ الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ فَابْرُدُوهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdullah bin Numair] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: 'Sesungguhnya demam yang menyengat itu (berasal) dari hembusan neraka Jahannam, maka dinginkanlah ia dengan air.\""},"3429":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُصْعَبُ بْنُ الْمِقْدَامِ حَدَّثَنَا إِسْرَائِيلُ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ فَابْرُدُوهَا بِالْمَاءِ فَدَخَلَ عَلَى ابْنٍ لِعَمَّارٍ فَقَالَ اكْشِفْ الْبَاسْ رَبَّ النَّاسْ إِلَهَ النَّاسْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Mush'ab bin Miqdam] telah menceritakan kepada kami [Israil] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari [Rafi' bin Khadij] dia berkata, \"Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Demam berasal dari hembusan neraka Jahannam, maka dinginkanlah dengan air.\" Kemudian beliau datang menemui anak laki-laki 'Ammar dan berdo'a: \"Hilangkanlah rasa sakit wahai Rabb manusia, Dzat yang disembah manusia.\""},"3430":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍأَنَّهَا كَانَتْ تُؤْتَى بِالْمَرْأَةِ الْمَوْعُوكَةِ فَتَدْعُو بِالْمَاءِ فَتَصُبُّهُ فِي جَيْبِهَا وَتَقُولُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْرُدُوهَا بِالْمَاءِ وَقَالَ إِنَّهَا مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Hisyam bin 'Urwah] dari [Fatimah binti Al Mundzir] dari [Asma binti Abu Bakar], bahwa di datangkan kepadanya seorang wanita yang menderita sakit demam, ia lantas memerintahkan supaya di ambilkan air, lalu ia menyemburkan pada bagian dada wanita tersebut. Kemudian dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya demam berasal dari hembusan neraka Jahannam.\""},"3431":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحُمَّى كِيرٌ مِنْ كِيرِ جَهَنَّمَ فَنَحُّوهَا عَنْكُمْ بِالْمَاءِ الْبَارِدِ","id":"Telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf] telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sakit demam itu berasal dari hembusan neraka Jahannam, maka hilangkanlah ia dari kalian dengan air dingin.\""},"3432":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كَانَ فِي شَيْءٍ مِمَّا تَدَاوَوْنَ بِهِ خَيْرٌ فَالْحِجَامَةُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: 'Sekiranya ada sesuatu yang lebih baik yang dapat kalian gunakan untuk pengobatan, maka itu adalah hijamah (bekam).\""},"3433":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا زِيَادُ بْنُ الرَّبِيعِ حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مَرَرْتُ لَيْلَةَ أُسْرِيَ بِي بِمَلَإٍ مِنْ الْمَلَائِكَةِ إِلَّا كُلُّهُمْ يَقُولُ لِي عَلَيْكَ يَا مُحَمَّدُ بِالْحِجَامَةِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Ziyad bin Ar Rabi'] telah menceritakan kepada kami ['Abbad bin Manshur] dari ['Ikrimah] dari [Ibnu 'Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika malam aku diisra`kan, maka tidaklah aku melewati seorang malaikat pun kecuali semuanya berkata kepadaku: 'Wahai Muhammad hendaknya kamu berbekam'.\""},"3434":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الْعَبْدُ الْحَجَّامُ يَذْهَبُ بِالدَّمِ وَيُخِفُّ الصُّلْبَ وَيَجْلُو الْبَصَرَ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami ['Abbad bin Manshur] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik hamba adalah tukang bekam, (karena dengannya) dapat menghilangkan darah kotor, meringankan tulang punggung dan memperjelas pandangan.\""},"3435":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا كَثِيرُ بْنُ سُلَيْمٍ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَرَرْتُ لَيْلَةَ أُسْرِيَ بِي بِمَلَإٍ إِلَّا قَالُوا يَا مُحَمَّدُ مُرْ أُمَّتَكَ بِالْحِجَامَةِ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] telah menceritakan kepada kami [Katsir bin Sulaim] saya mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah aku melewati seorang malaikat ketika malam aku di isra`kan kecuali mereka berkata: 'Wahai Muhammad, perintahkan umatmu untuk berbekam'.\""},"3436":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَأْذَنَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحِجَامَةِ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا طَيْبَةَ أَنْ يَحْجُمَهَاوَقَالَ حَسِبْتُ أَنَّهُ كَانَ أَخَاهَا مِنْ الرِّضَاعَةِ أَوْ غُلَامًا لَمْ يَحْتَلِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] bahwa Ummu Salamah isteri Nabi shallallahu 'alaihi wasallam minta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk berbekam. Maka Nabi shallallahu 'alaihi wasallam memerintahkan Abu Thaibah untuk membekamnya.\" Jabir menjelaskan, \"Aku kira Abu Thaibah adalah saudara laki-laki sepersusuan Ummu Salamah atau seorang anak yang belum baligh.\""},"3437":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي عَلْقَمَةُ بْنُ أَبِي عَلْقَمَةَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ الْأَعْرَجَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ ابْنَ بُحَيْنَةَ يَقُولُاحْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْيِ جَمَلٍ وَهُوَ مُحْرِمٌ وَسَطَ رَأْسِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepadaku ['Alqamah bin Abu 'Alqamah] dia berkata; saya mendengar [Abdurrahman Al A'raj] berkata; saya mendengar [Abdullah bin Buhainah] berkata, \"Ketika sedang ihram Rasulullah shallallahu 'alaihi wasallam melakukan bekam pada kepalanya, di Lahyi Jamal (nama tempat).\""},"3438":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ سَعْدٍ الْإِسْكَافِ عَنْ الْأَصْبَغِ بْنِ نُبَاتَةَ عَنْ عَلِيٍّ قَالَنَزَلَ جِبْرِيلُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحِجَامَةِ الْأَخْدَعَيْنِ وَالْكَاهِلِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari [Sa'd Al Iskaf] dari [Al Asbagh bin Nubatah] dari [Ali] dia berkata, \"Jibril turun kepada Nabi shallallahu 'alaihi wasallam dan membekam beliau di kedua bahunya dan di atas punggung dekat leher.\""},"3439":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ أَبِي الْخَصِيبِ حَدَّثَنَا وَكِيعٌ عَنْ جَرِيرِ بْنِ حَازِمٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ فِي الْأَخْدَعَيْنِ وَعَلَى الْكَاهِلِ","id":"Telah menceritakan kepada kami [Ali bin Abu Al Khashib] telah menceritakan kepada kami [Waki'] dari [Jarir bin Hazim] dari [Qatadah] dari [Anas], bahwa Nabi shallallahu 'alaihi wasallam berbekam pada kedua bahunya dan bagian atas punggung dekat leher.\""},"3440":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ ثَوْبَانَ عَنْ أَبِيهِ عَنْ أَبِي كَبْشَةَ الْأَنْمَارِيِّ أَنَّهُ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَحْتَجِمُ عَلَى هَامَتِهِ وَبَيْنَ كَتِفَيْهِ وَيَقُولُ مَنْ أَهْرَاقَ مِنْهُ هَذِهِ الدِّمَاءَ فَلَا يَضُرُّهُ أَنْ لَا يَتَدَاوَى بِشَيْءٍ لِشَيْءٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Tsauban] dari [Ayahnya] dari [Abu Kabsyah Al Anmari] dia menceritakan, bahwa Nabi shallallahu 'alaihi wasallam berbekam di bagian kepalanya dan kedua pundaknya, lalu beliau bersabda: \"Barangsiapa mengalirkan darah dari daerah ini, maka dia tidak akan mendapatkan bahaya atau penyakit jika dia tidak berobat dengan sesuatu yang lain.\""},"3441":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَقَطَ عَنْ فَرَسِهِ عَلَى جِذْعٍ فَانْفَكَّتْ قَدَمُهُقَالَ وَكِيعٌ يَعْنِي أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ عَلَيْهَا مِنْ وَثْءٍ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir], bahwa Nabi shallallahu 'alaihi wasallam terjatuh dari kudanya dan menimpa batang pohon kurma hingga kaki beliau berdarah.\" Waki' berkata, \"Lalu Nabi shallallahu 'alaihi wasallam membekam kakinya yang memar.\""},"3442":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عُثْمَانُ بْنُ مَطَرٍ عَنْ زَكَرِيَّا بْنِ مَيْسَرَةَ عَنْ النَّهَّاسِ بْنِ قَهْمٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَرَادَ الْحِجَامَةَ فَلْيَتَحَرَّ سَبْعَةَ عَشَرَ أَوْ تِسْعَةَ عَشَرَ أَوْ إِحْدَى وَعِشْرِينَ وَلَا يَتَبَيَّغْ بِأَحَدِكُمْ الدَّمُ فَيَقْتُلَهُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Utsman bin Mathar] dari [Zakaria bin Maisarah] dari [An Nahhas bin Qahm] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin berbekam maka pilihlah tanggal tujuh belas atau sembilan belas atau dua puluh satu, dan janganlah salah seorang dari kalian mengeluarkan darah yang banyak hingga dapat membunuhnya.\""},"3443":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عُثْمَانُ بْنُ مَطَرٍ عَنْ الْحَسَنِ بْنِ أَبِي جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَيَا نَافِعُ قَدْ تَبَيَّغَ بِيَ الدَّمُ فَالْتَمِسْ لِي حَجَّامًا وَاجْعَلْهُ رَفِيقًا إِنْ اسْتَطَعْتَ وَلَا تَجْعَلْهُ شَيْخًا كَبِيرًا وَلَا صَبِيًّا صَغِيرًا فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحِجَامَةُ عَلَى الرِّيقِ أَمْثَلُ وَفِيهِ شِفَاءٌ وَبَرَكَةٌ وَتَزِيدُ فِي الْعَقْلِ وَفِي الْحِفْظِ فَاحْتَجِمُوا عَلَى بَرَكَةِ اللَّهِ يَوْمَ الْخَمِيسِ وَاجْتَنِبُوا الْحِجَامَةَ يَوْمَ الْأَرْبِعَاءِ وَالْجُمُعَةِ وَالسَّبْتِ وَيَوْمَ الْأَحَدِ تَحَرِّيًا وَاحْتَجِمُوا يَوْمَ الِاثْنَيْنِ وَالثُّلَاثَاءِ فَإِنَّهُ الْيَوْمُ الَّذِي عَافَى اللَّهُ فِيهِ أَيُّوبَ مِنْ الْبَلَاءِ وَضَرَبَهُ بِالْبَلَاءِ يَوْمَ الْأَرْبِعَاءِ فَإِنَّهُ لَا يَبْدُو جُذَامٌ وَلَا بَرَصٌ إِلَّا يَوْمَ الْأَرْبِعَاءِ أَوْ لَيْلَةَ الْأَرْبِعَاءِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Utsman bin Mathar] dari [Al Hasan bin Abu Ja'far] dari [Muhammad bin Juhadah] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Wahai Nafi' darahku telah bergelegak, maka carikanlah untukku seorang tukang bekam, jika bisa maka carilah teman sebaya dan jangan yang sudah tua atau anak kecil, sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berbekam di waktu pagi sangatlah bagus, sebab di dalamnya terkandung obat dan keberkahan, menambah kekuatan akal dan hafalan, maka berbekamlah kalian dengan mengharap keberkahan dari Allah pada hari kamis, dan hindarilah berbekam pada hari rabu, hari jum'at, hari sabtu dan minggu. Dan berbekamlah pada hari senin dan selasa, sesungguhnya hari senin dan selasa adalah hari di mana Allah menyembuhkan Ayyub dari bala` yang di timpakan pada hari rabu. Sungguh tidaklah penyakit lepra dan kusta muncul kecuali pada hari rabu atau malam rabu.\""},"3444":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عِصْمَةَ عَنْ سَعِيدِ بْنِ مَيْمُونٍ عَنْ نَافِعٍ قَالَ قَالَ ابْنُ عُمَرَيَا نَافِعُ تَبَيَّغَ بِيَ الدَّمُ فَأْتِنِي بِحَجَّامٍ وَاجْعَلْهُ شَابًّا وَلَا تَجْعَلْهُ شَيْخًا وَلَا صَبِيًّا قَالَ وَقَالَ ابْنُ عُمَرَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحِجَامَةُ عَلَى الرِّيقِ أَمْثَلُ وَهِيَ تَزِيدُ فِي الْعَقْلِ وَتَزِيدُ فِي الْحِفْظِ وَتَزِيدُ الْحَافِظَ حِفْظًا فَمَنْ كَانَ مُحْتَجِمًا فَيَوْمَ الْخَمِيسِ عَلَى اسْمِ اللَّهِ وَاجْتَنِبُوا الْحِجَامَةَ يَوْمَ الْجُمُعَةِ وَيَوْمَ السَّبْتِ وَيَوْمَ الْأَحَدِ وَاحْتَجِمُوا يَوْمَ الِاثْنَيْنِ وَالثُّلَاثَاءِ وَاجْتَنِبُوا الْحِجَامَةَ يَوْمَ الْأَرْبِعَاءِ فَإِنَّهُ الْيَوْمُ الَّذِي أُصِيبَ فِيهِ أَيُّوبُ بِالْبَلَاءِ وَمَا يَبْدُو جُذَامٌ وَلَا بَرَصٌ إِلَّا فِي يَوْمِ الْأَرْبِعَاءِ أَوْ لَيْلَةِ الْأَرْبِعَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] telah menceritakan kepada kami [Utsman bin Abdurrahman] telah menceritakan kepada kami [Abdullah bin 'Ishmah] dari [Sa'id bin Maimun] dari [Nafi'] dia berkata, \" [Ibnu Umar] berkata, \"Wahai Nafi', darahku telah bergelegak, maka carikanlah untukku seorang tukang bekam, jika bisa carilah yang teman sebaya, jangan yang tua atau anak kecil.\" Nafi' berkata, \"Ibnu Umar berkata, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berbekam di waktu pagi sangatlah bagus, sebab akan menambah kekuatan otak dan hafalan. Maka barangsiapa ingin berbekam, berbekamlah pada hari kamis atas nama Allah, dan hindarilah berbekam pada hari Jum'at, hari Sabtu dan Minggu. Dan berbekamlah pada hari Senin dan Selasa, sesungguhnya hari Senin dan Selasa adalah hari di mana Allah menyembuhkan Ayyub dari bala` yang di timpakan pada hari Rabu. Sungguh tidaklah penyakit lepra dan kusta muncul kecuali pada hari Rabu atau malam Rabu.\""},"3445":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ عَقَّارِ بْنِ الْمُغِيرَةِ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اكْتَوَى أَوْ اسْتَرْقَى فَقَدْ بَرِئَ مِنْ التَّوَكُّلِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Laits] dari [Mujahid] dari ['Aqqar bin Mughirah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa melakukan pengobatan dengan cara membakar diri dengan besi atau meminta di ruqyah (mantera-mantera), maka dia tidak memiliki rasa tawakkal.\""},"3446":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ عَنْ مَنْصُورٍ وَيُونُسُ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكَيِّ فَاكْتَوَيْتُ فَمَا أَفْلَحْتُ وَلَا أَنْجَحْتُ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Husyaim] dari [Manshur] dan [Yunus] dari [Al Hasan] dari ['Imran bin Al Hushain] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang berobat dengan (cara) membakar diri dengan besi namun kemudian aku melakukannya, maka aku tidak beruntung dan tidak juga berhasil.\""},"3447":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا مَرْوَانُ بْنُ شُجَاعٍ حَدَّثَنَا سَالِمٌ الْأَفْطَسُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَالشِّفَاء�� فِي ثَلَاثٍ شَرْبَةِ عَسَلٍ وَشَرْطَةِ مِحْجَمٍ وَكَيَّةٍ بِنَارٍ وَأَنْهَى أُمَّتِي عَنْ الْكَيِّ رَفَعَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Marwan bin Syuja'] telah menceritakan kepada kami [Salim Al Afthas] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Penyembahan itu dengan tiga cara; minum madu, pembelahan dengan berbekam dan dengan kay, dan aku larang ummatku untuk melakukan kay.\" "},"3448":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ غُنْدَرٌ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ الْأَنْصَارِيُّسَمِعَهُ عَمِّي يَحْيَى وَمَا أَدْرَكْتُ رَجُلًا مِنَّا بِهِ شَبِيهًا يُحَدِّثُ النَّاسَ أَنَّ أَسَعْدَ بْنَ زُرَارَةَ وَهُوَ جَدُّ مُحَمَّدٍ مِنْ قِبَلِ أُمِّهِ أَنَّهُ أَخَذَهُ وَجَعٌ فِي حَلْقِهِ يُقَالُ لَهُ الذُّبْحَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأُبْلِغَنَّ أَوْ لَأُبْلِيَنَّ فِي أَبِي أُمَامَةَ عُذْرًا فَكَوَاهُ بِيَدِهِ فَمَاتَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِيتَةَ سَوْءٍ لِلْيَهُودِ يَقُولُونَ أَفَلَا دَفَعَ عَنْ صَاحِبِهِ وَمَا أَمْلِكُ لَهُ وَلَا لِنَفْسِي شَيْئًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] -yaitu Ghundar- telah menceritakan kepada kami [Syu'bah]. (Dari jalur lain disebutkan); Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] telah menceritakan kepada kami [An Nadlr bin Syumail] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Sa'd bin Zurarah Al Anshari] dan pamanku [Yahya] telah mendengarnya -dan tidak aku jumpai seorang lelaki dari kami yang menyerupainya- dia menceritakan kepada orang-orang bahwa As'ad bin Zurarah, kakeknya Muhammad dari pihak ibu, tertimpa sakit di tenggorokannya yang biasa di sebut dengan radang tenggorokan. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan menyampaikan.\" Atau, \"Mengemukakan alasan kepada Abu Umamah.\" Maka dia mengobatinya dengan cara menempelkan besi panas kepadanya hingga meninggal, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kematian yang buruk bagi orang Yahudi. Mereka berkata, 'Bukanlah seharusnya ia membayar diat atas saudaranya! Padahal aku tidak memiliki kekuasaan apapun atas dirinya atau atas diriku sedikitpun.\""},"3449":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَمَرِضَ أُبَيُّ بْنُ كَعْبٍ مَرَضًا فَأَرْسَلَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَبِيبًا فَكَوَاهُ عَلَى أَكْحَلِهِ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Muhammad bin 'Ubaid At Thanafisi] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata, \"Ubay bin Ka'b tengah menderita sakit, lantas Nabi shallallahu 'alaihi wasallam mendatangkan seorang tabib untuknya, kemudian tabib itu mengobatinya dengan membakarkan besi panas di alisnya.\""},"3450":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ أَبِي الْخَصِيبِ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَوَى سَعْدَ بْنَ مُعَاذٍ فِي أَكْحَلِهِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Abu Al Khashib] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Az Zubair] dari [Jabir bin Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam mengobati Sa'd bin Mu'adz dengan menggunakan besi panas pada alisnya hingga dua kali.\""},"3451":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنِي عُثْمَانُ بْنُ عَبْدِ الْمَلِكِ قَالَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالْإِثْمِدِ فَإِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعَرَ","id":"Telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepadaku ['Utsman bin Abdul Malik] dia berkata; saya mendengar [Salim bin Abdullah] menceritakan dari [Ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian menggunakan itsmid (semacam tumbuhan untuk celak), sesungguhnya ia dapat memperjelas penglihatan dan menumbuhkan bulu mata.\""},"3452":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَيْكُمْ بِالْإِثْمِدِ عِنْدَ النَّوْمِ فَإِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعَرَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Isma'il bin Muslim] dari [Muhammad bin Al Munkadir] dari [Jabir] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian menggunakan itsmid (semacam tumbuhan untuk celak), sesungguhnya ia dapat memperjelas penglihatan dan menumbuhkan bulu mata.\""},"3453":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ ابْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ أَكْحَالِكُمُ الْإِثْمِدُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعَرَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan] dari [Ibnu Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik celak kalian adalah itsmid (semacam tumbuhan), sebab ia dapata memperjelas penglihatan dan menumbuhkan bulu mata.\""},"3454":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الصَّبَّاحِ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ حُصَيْنٍ الْحِمْيَرِيِّ عَنْ أَبِي سَعْدِ الْخَيْرِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اكْتَحَلَ فَلْيُوتِرْ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لَا فَلَا حَرَجَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Umar] telah menceritakan kepada kami [Abdul Malik bin Ash Shabah] dari [Tsaur bin Yazid] dari [Hushain Al Himyari] dari [Abu Sa'd Al Khair] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakai celak, maka hendaknya dengan bilangan yang ganjil, barangsiapa melakukannya maka dia telah berbuat baik dan barangsiapa tidak melakukannya, maka tidak ada dosa baginya.\""},"3455":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ عَبَّادِ بْنِ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُكْحُلَةٌ يَكْتَحِلُ مِنْهَا ثَلَاثًا فِي كُلِّ عَيْنٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari ['Abbad bin Manshur] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Nabi shallallahu 'alaihi wasallam memiliki tempat celak, dan beliau bercelak darinya tiga kali di tiap-tiap matanya.\""},"3456":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَنْبَأَنَا سِمَاكُ بْنُ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ الْحَضْرَمِيِّ عَنْ طَارِقِ بْنِ سُوَيْدٍ الْحَضْرَمِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ بِأَرْضِنَا أَعْنَابًا نَعْتَصِرُهَا فَنَشْرَبُ مِنْهَا قَالَ لَا فَرَاجَعْتُهُ قُلْتُ إِنَّا نَسْتَشْفِي بِهِ لِلْمَرِيضِ قَالَ إِنَّ ذَلِكَ لَيْسَ بِشِفَاءٍ وَلَكِنَّهُ دَاءٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah memberitakan kepada kami [Simak bin Harb] dari ['Alqamah bin Wa`il Al Hadlrami] dari [Thariq bin Suwaid Al Hadlrami] dia berkata; saya berkata, \"Wahai Rasulullah, di negeri kami banyak perasan anggur, apakah kami boleh meminumnya?\" beliau menjawab: \"Tidak.\" Aku lalu berkata, \"Kami memakainya untuk menyembuhkan orang sakit! \" Beliau bersabda: \"Sesungguhnya perasan anggur itu bukanlah penyembuh (obat), namun ia adalah penyakit.\""},"3457":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ عُتْبَةَ بْنِ عَبْدِ الرَّحْمَنِ الْكِنْدِيُّ حَدَّثَنَا عَلِيُّ بْنُ ثَابِتٍ حَدَّثَنَا سَعَّادُ بْنُ سُلَيْمَانَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الدَّوَاءِ الْقُرْآنُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid bin 'Utbah bin Abdurrahman Al Kindi] telah menceritakan kepada kami [Ali bin Tsabit] telah menceritakan kepada kami [Sa'ad bin Sulaiman] dari [Abu Ishaq] dari [Al Harits] dari [Ali Radiyallahu 'anhu] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik obat adalah Al-Qur'an.\""},"3458":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا فَائِدٌ مَوْلَى عُبَيْدِ اللَّهِ بْنِ عَلِيِّ بْنِ أَبِي رَافِعٍ حَدَّثَنِي مَوْلَايَ عُبَيْدُ اللَّهِ حَدَّثَتْنِي جَدَّتِي سَلْمَى أُمُّ رَافِعٍ مَوْلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ لَا يُصِيبُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرْحَةٌ وَلَا شَوْكَةٌ إِلَّا وَضَعَ عَلَيْهِ الْحِنَّاءَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Al Hubbab] telah menceritakan kepada kami [Fa`id] bekas budak 'Ubaidullah bin Ali bin Abu Rafi', telah menceritakan kepadaku mantan budakku ['Ubaidullah] telah menceritakan kepadaku nenekku [Salma Ummu Rafi'] mantan budak Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Apabila Rasulullah shallallahu 'alaihi wasallam terluka atau terkena koreng, maka beliau memolesinya dengan inai.\""},"3459":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ نَاسًا مِنْ عُرَيْنَةَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ خَرَجْتُمْ إِلَى ذَوْدٍ لَنَا فَشَرِبْتُمْ مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَفَعَلُوا","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Humaid] dari [Anas], bahwa sekelompok orang dari penduduk 'Urainah datang menemui Nabi shallallahu 'alaihi wasallam dan singgah di kota Madinah (beberapa saat), maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Jika kalian pergi ke tempat unta-unta kami, maka minumlah susu dan air kencingnya.' Dan mereka pun melakukannya.\""},"3460":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ عَنْ أَبِي سَلَمَةَ حَدَّثَنِي أَبُو سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي أَحَدِ جَنَاحَيْ الذُّبَابِ سُمٌّ وَفِي الْآخَرِ شِفَاءٌ فَإِذَا وَقَعَ فِي الطَّعَامِ فَامْقُلُوهُ فِيهِ فَإِنَّهُ يُقَدِّمُ السُّمَّ وَيُؤَخِّرُ الشِّفَاءَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Sa'id bin Khalid] dari [Abu Salamah] telah menceritakan kepadaku [Abu Sa'id], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada salah satu sayap lalat itu mengandung racun dan yang satunya lagi mengandung obat, oleh karenanya apabila dia jatuh pada makanan maka benamkanlah ia ke dalamnya, sesungguhnya ia mendahulukan racun dan mengakhirkan penawarnya.\""},"3461":{"ar":"حَدَّثَنَ�� سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مُسْلِمُ بْنُ خَالِدٍ عَنْ عُتْبَةَ بْنِ مُسْلِمٍ عَنْ عُبَيْدِ بْنِ حُنَيْنٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَقَعَ الذُّبَابُ فِي شَرَابِكُمْ فَلْيَغْمِسْهُ فِيهِ ثُمَّ لِيَطْرَحْهُ فَإِنَّ فِي أَحَدِ جَنَاحَيْهِ دَاءً وَفِي الْآخَرِ شِفَاءً","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Muslim bin Khalid] dari ['Utbah bin Muslim] dari ['Ubaid bin Hunain] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seekor lalat terjatuh ke dalam minuman kalian, hendaknya ia mencelupkan ke dalam minuman tersebut kemudian membuangnya, sesungguhnya pada salah satu sayapnya terdapat penyakit dan pada sayap lainnya terdapat penawarnya.\""},"3462":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ أُمَيَّةَ بْنِ هِنْدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَيْنُ حَقٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami ['Ammar bin Ruzaiq] dari [Abdullah bin Isa] dari [Umayyah bin Hind] dari [Abdullah bin 'Amir bin Rabi'ah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Penyakit 'ain itu benar adanya.\""},"3463":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ الْجُرَيْرِيِّ عَنْ مُضَارِبِ بْنِ حَزْنٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَيْنُ حَقٌّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] telah menceritakan kepada kami [Al Jurairi] dari [Mudlarib bin Hazn] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \" 'Ain itu benar adanya.\""},"3464":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو هِشَامٍ الْمَخْزُومِيُّ حَدَّثَنَا وُهَيْبٌ عَنْ أَبِي وَاقِدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعِيذُوا بِاللَّهِ فَإِنَّ الْعَيْنَ حَقٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Hisyam Al Mahzumi] telah menceritakan kepada kami [Wuhaib] dari [Abu Waqid] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mintalah perlindungan kepada Allah, karena sesungguhnya 'ain itu benar adanya.\""},"3465":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ قَالَمَرَّ عَامِرُ بْنُ رَبِيعَةَ بِسَهْلِ بْنِ حُنَيْفٍ وَهُوَ يَغْتَسِلُ فَقَالَ لَمْ أَرَ كَالْيَوْمِ وَلَا جِلْدَ مُخَبَّأَةٍ فَمَا لَبِثَ أَنْ لُبِطَ بِهِ فَأُتِيَ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ لَهُ أَدْرِكْ سَهْلًا صَرِيعًا قَالَ مَنْ تَتَّهِمُونَ بِهِ قَالُوا عَامِرَ بْنَ رَبِيعَةَ قَالَ عَلَامَ يَقْتُلُ أَحَدُكُمْ أَخَاهُ إِذَا رَأَى أَحَدُكُمْ مِنْ أَخِيهِ مَا يُعْجِبُهُ فَلْيَدْعُ لَهُ بِالْبَرَكَةِ ثُمَّ دَعَا بِمَاءٍ فَأَمَرَ عَامِرًا أَنْ يَتَوَضَّأَ فَيَغْسِلْ وَجْهَهُ وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ وَرُكْبَتَيْهِ وَدَاخِلَةَ إِزَارِهِ وَأَمَرَهُ أَنْ يَصُبَّ عَلَيْهِقَالَ سُفْيَانُ قَالَ مَعْمَرٌ عَنْ الزُّهْرِيِّ وَأَمَرَهُ أَنْ يَكْفَأَ الْإِنَاءَ مِنْ خَلْفِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Umamah bin Sahl bin Hunaif] dia berkata, \"'Amir bin Rabi'ah melintasi Sahl bin Hunaif yang sedang mandi, lalu dia berkata, \"Aku tidak pernah melihat seperti hari ini dan tidak ada kulit yang di sembunyikan.\" Maka tidak lama kemudian Sahl bin Hunaif pun pingsan. Kemudian ia di bawa ke hadapan Nabi shallallahu 'alaihi wasallam dan di katakan kepada beliau, \"Sahl pingsan! \" Beliau pun bertanya: \"Siapakah yang menyerangnya?\" Mereka menjawab, \"'Amir bin Rabi'ah.\" Beliau bersabda: \"Atas perkara apa seseorang dari kalian menyakiti saudaranya? Jika salah seorang dari kalian melihat sesuatu yang menakjubkan dari saudaranya, maka hendaknya ia mendo'akan keberkahan padanya.\" Kemudian beliau meminta air dan memerintahkan 'Amir untuk berwudlu, maka 'Amir lantas membasuh muka dan kedua tangannya sampai siku, kedua mata kaki dan apa yang ada di dalam bajunya. Setelah itu Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk menyiram Sahl (dengan bekas air wudlu 'Amir).\" [Sufyan] berkata; [Ma'mar] berkata dari [Az Zuhri], \"Beliau memerintahkan supaya menuangkan tempat air tersebut dari belakang tubuh 'Amir.\""},"3466":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عُرْوَةَ بْنِ عَامِرٍ عَنْ عُبَيْدِ بْنِ رِفَاعَةَ الزُّرَقِيِّ قَالَقَالَتْ أَسْمَاءُ يَا رَسُولَ اللَّهِ إِنَّ بَنِي جَعْفَرٍ تُصِيبُهُمْ الْعَيْنُ فَأَسْتَرْقِي لَهُمْ قَالَ نَعَمْ فَلَوْ كَانَ شَيْءٌ سَابَقَ الْقَدَرَ سَبَقَتْهُ الْعَيْنُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyinah] dari ['Amru bin Dinar] dari ['Urwah bin 'Amir] dari ['Ubaid bin Rifa'ah Az Zuraqi] dia berkata, \"Asma berkata, \"Wahai Rasulullah, anak-anak Ja'far tertimpa penyakit 'ain, maka ruqyahlah mereka! \" Beliau menjawab: \"Ya. Jika ada sesuatu yang mendahului takdir, maka 'ain lah yang mendahuluinya.\""},"3467":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ عَبَّادٍ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ عَيْنِ الْجَانِّ ثُمَّ أَعْيُنِ الْإِنْسِ فَلَمَّا نَزَلَتْ الْمُعَوِّذَتَانِ أَخَذَهُمَا وَتَرَكَ مَا سِوَى ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sa'id bin Sulaiman] dari ['Abbad] dari [Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berlindung dari mata Jin dan manusia, tatkala turun surat Mu'awidzatain, beliau mengambilnya dan meninggalkan yang lainnya.\" "},"3468":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ أَبِي الْخَصِيبِ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ وَمِسْعَرٍ عَنْ مَعْبَدِ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا أَنْ تَسْتَرْقِيَ مِنْ الْعَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Abu Al Khashib] telah menceritakan kepada kami [Waki'] dari [Sufyan] dan [Mis'ar] dari [Ma'bad bin Khalid] dari [Abdullah bin Syadad] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya untuk meruqyah dari penyakit 'ain.\""},"3469":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ بُرَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا رُقْيَةَ إِلَّا مِنْ عَيْنٍ أَوْ حُمَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ishaq bin Sulaiman] dari [Abu Ja'far Ar Razi] dari [Hushain] dari [Asy Sya'bi] dari [Buraidah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak diperbolehkan ruqyah kecuali dari penyakit 'ain atau sengatan kalajengking.\""},"3470":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ عُمَارَةَ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍأَنَّ خَالِدَةَ بِنْتَ أَنَسٍ أُمَّ بَنِي حَزْمٍ السَّاعِدِيَّةَ جَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَضَتْ عَلَيْهِ الرُّقَى فَأَمَرَهَا بِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Muhammad bin 'Umarah] dari [Abu Bakar bin Muhammad] bahwa [Khalidah binti Anas Ummu bani Hazm As Sa'idi] datang menemui Nabi shallallahu 'alaihi wasallam, dia meminta pertimbangan kepada beliau untuk diruqyah, maka beliau memerintahkan terapi dengan ruqyah.\""},"3471":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ أَبِي الْخَصِيبِ حَدَّثَنَا يَحْيَى بْنُ عِيسَى عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَكَانَ أَهْلُ بَيْتٍ مِنْ الْأَنْصَارِ يُقَالُ لَهُمْ آلُ عَمْرِو بْنِ حَزْمٍ يَرْقُونَ مِنْ الْحُمَةِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَى عَنْ الرُّقَى فَأَتَوْهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّكَ قَدْ نَهَيْتَ عَنْ الرُّقَى وَإِنَّا نَرْقِي مِنْ الْحُمَةِ فَقَالَ لَهُمْ اعْرِضُوا عَلَيَّ فَعَرَضُوهَا عَلَيْهِ فَقَالَ لَا بَأْسَ بِهَذِهِ هَذِهِ مَوَاثِيقُ","id":"Telah menceritakan kepada kami [Ali bin Abu Al Khashib] telah menceritakan kepada kami [Yahya bin Isa] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata, \"Kaum Anshar ada satu keluarga yang dipanggil dengan keluarga 'Amru bin Hazm, mereka sering meruqyah (jampi-jampi) dari penyakit humah (racun yang di akibatkan oleh sengatan kalajengking), padahal Rasulullah shallallahu 'alaihi wasallam telah melarang jampi-jampi, maka mereka mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya anda telah melarang untuk meruqyah, dan kami sering melakukan ruqyah dari penyakit humah.\" Maka beliau bersabda: \"Tunjukkanlah (ruqyahmu) kepadaku.\" Mereka pun membacakannya kepada beliau, dan beliau bersabda: \"Tidak apa dengan ini, karena bacaan ini termasuk dari sesuatu yang dapat menguatkan.\""},"3472":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الرُّقْيَةِ مِنْ الْحُمَةِ وَالْعَيْنِ وَالنَّمْلَةِ","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Yusuf bin Abdullah bin Al Harits] dari [Anas], bahwa Nabi shallallahu 'alaihi wasallam memberi keringanan dalam ruqyah (jampi-jampi) dari penyakit humah (racun yang di akibatkan oleh sengatan kalajengking) dan penyakit 'ain serta penyakit luka yang keluar dari rusuk.\""},"3473":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْرَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرُّقْيَةِ مِنْ الْحَيَّةِ وَالْعَقْرَبِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Hannad bin As Sari] keduanya berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Mughirah] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keringanan dalam ruqyah karena sengatan ular dan kalajengking.\""},"3474":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ بَهْرَامَ حَدَّثَنَا عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَلَدَغَتْ عَقْرَبٌ رَجُلًا فَلَمْ يَنَمْ لَيْلَتَهُ فَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فُلَانًا لَدَغَتْهُ عَقْرَبٌ فَلَمْ يَنَمْ لَيْلَتَهُ فَقَالَ أَمَا إِنَّهُ لَوْ قَالَ حِينَ أَمْسَى أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ مَا ضَرَّهُ لَدْغُ عَقْرَبٍ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Isma'il bin Bahram] telah menceritakan kepada kami ['Ubaidullah Al Asyaja'i] dari [Sufyan] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] dia berkata, \"Seorang laki-laki di sengat kalajengking hingga ia tidak dapat tidur pada malam harinya, lantas dikatakan kepada Nabi shallallahu 'alaihi wasallam, \"Fulan telah di sengat kalajengking hingga ia tidak dapat tidur di mala harinya! \" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya menjelang sore harinya ia mengucapkan: 'A'UUDZU BIKA BIKALIMAATILAHITTAAMMTI MIN SYARRI MAA KHALAQA (Aku berlindung dengan kalimat-kalimat Allah yang sempurna dari kejahatan makhluk-Nya) ', niscaya sengatan kalajengking tersebut tidak akan membahayakannya sampai pagi.\" "},"3475":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرِو بْنِ حَزْمٍ قَالَعَرَضْتُ النَّهْشَةَ مِنْ الْحَيَّةِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Utsman bin Hakim] telah menceritakan kepadaku [Abu Bakar bin 'Amru bin Hazm] dari ['Amru bin Hazm] dia berkata, \"Aku memperlihatkan gigitan ular kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau memerintahkan meruqyah.\""},"3476":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَى الْمَرِيضَ فَدَعَا لَهُ قَالَ أَذْهِبْ الْبَاسْ رَبَّ النَّاسْ وَاشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Adl Dluha] dari [Masruq] dari [Aisyah] dia berkata, \"Apabila Rasulullah shallallahu 'alaihi wasallam menjenguk orang sakit, maka beliau akan mendo'akannya, beliau mengucapkan: \"ADZHIBIL BA`SA RABBAN NAASI WASYFI ANTA ASY SYAFI LAA SYIFAA`A ILLA SYIFAA`UKA SYIFAA`AB LAA YUGHAADIRU SAQAMAN (Hilangkanlah kesusahan wahai Rabb manusia, sembuhkanlah, sesungguhnya Engkau Maha Penyembuh, tidak ada kesembuhan selain kesembuhan dari-Mu, dengan kesembuhan yang tidak meninggalkan rasa sakit) '.\""},"3477":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ رَبِّهِ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ مِمَّا يَقُولُ لِلْمَرِيضِ بِبُزَاقِهِ بِإِصْبَعِهِ بِسْمِ اللَّهِ تُرْبَةُ أَرْضِنَا بِرِيقَةِ بَعْضِنَا لِيُشْفَى سَقِيمُنَا بِإِذْنِ رَبِّنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan] dari [Abdu Rabbih] dari ['Amrah] dari [Aisyah], bahwa yang di bacakan Nabi shallallahu 'alaihi wasallam buat orang yang sakit dengan ludahnya dan jemari beliau adalah: 'BISMILLAHI TURBATU ARDLINAA BIRIIQATI BA'DLINAA LIYUSYFA SAQIIMUNAA BI IDZNI RABBINAA (Dengan nama Allah, debu tanah kami dengan kelembutan sebagian kami semoga sembuh orang yang sakit dari kami dengan izin Rabb kami) '.\""},"3478":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ الثَّقَفِيِّ أَنَّهُ قَالَقَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِي وَجَعٌ قَدْ كَادَ يُبْطِلُنِي فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْ يَدَكَ الْيُمْنَى عَلَيْهِ وَقُلْ بِسْمِ اللَّهِ أَعُوذُ بِعِزَّةِ اللَّهِ وَقُدْرَتِهِ مِنْ شَرِّ مَا أَجِدُ وَأُحَاذِرُ سَبْعَ مَرَّاتٍ فَقُلْتُ ذَلِكَ فَشَفَانِيَ اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yahya bin Abu Bukair] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Yazid bin Khushaifah] dari ['Amru bin Abdullah bin Ka'b] dari [Nafi' bin Jubair] dari ['Utsman bin Abu Al 'Ash Ats Tsaqafi] bahwa dia berkata, \"Saya datang menemui Nabi shallallahu 'alaihi wasallam, dan (saat itu) saya menderita penyakit yang sangat menggangguku, maka Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Letakkanlah tanganmu yang kanan di atasnya (anggota badan yang sakit) lalu ucapkanlah: 'BISMILLAHI A'UUDZU BI 'IZZATILLAH WA QUDRATIHI MIN SYARRI MAA AJIDU WA UHAADZIRU (Dengan nama Allah aku berlindung dengan keagungan Allah dan kekuasaan-Nya dari keburukan yang aku rasakan dan aku hindari) ', hingga tujuh kali.\" Lalu saya mengucapkan do'a tersebut, maka (dengan itu) Allah menyembuhkanku.\""},"3479":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍأَنَّ جِبْرَائِيلَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ اشْتَكَيْتَ قَالَ نَعَمْ قَالَ بِسْمِ اللَّهِ أَرْقِيكَ مِنْ كُلِّ شَيْءٍ يُؤْذِيكَ مِنْ شَرِّ كُلِّ نَفْسٍ أَوْ عَيْنٍ أَوْ حَاسِدٍ اللَّهُ يَشْفِيكَ بِسْمِ اللَّهِ أَرْقِيكَ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal As Shawwaf] telah menceritakan kepada kami ['Abdul Warits] dari [Abdul Aziz bin Shuhaib] dari [Abu Nadlrah] dari [Abu Sa'id], bahwa Jibril datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Muhammad, apakah kamu merasakan sakit?\" beliau menjawab: \"Ya, \" Jibril lalu membaca, 'BISMILLAHI ARQIIKA MIN KULLI SYAI`IN YU`DZIIKA MIN SYARRI KULLI NAFSIN AU 'AININ AU HASIDIN ALLAHU YASYFIIKA BISMILLAH ARQIIKA (Dengan nama Allah aku meruqyahmu dari segala sesuatu yang membuatmu sakit, dari kejahatan semua jiwa, atau 'ain, atau orang yang hasad, Allah akan menyembuhkanmu, dengan nama Allah aku meruqyahmu) '.\""},"3480":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَحَفْصُ بْنُ عُمَرَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ زِيَادِ بْنِ ثُوَيْبٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَقَالَ لِي أَلَا أَرْقِيكَ بِرُقْيَةٍ جَاءَنِي بِهَا جِبْرَائِيلُ قُلْتُ بِأَبِي وَأُمِّي بَلَى يَا رَسُولَ اللَّهِ قَالَ بِسْمِ اللَّهِ أَرْقِيكَ وَاللَّهُ يَشْفِيكَ مِنْ كُلِّ دَاءٍ فِيكَ{ مِنْ شَرِّ النَّفَّاثَاتِ فِي الْعُقَدِ وَمِنْ شَرِّ حَاسِدٍ إِذَا حَسَدَ }ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Hafsh bin Umar] keduanya berkata; telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari ['Ashim bin 'Ubaidullah] dari [Ziyad bin Tsuwaib] dari [Abu Hurairah] dia berkata, \"Nabi shallallahu 'alaihi wasallam datang menjengukku, beliau lalu bersabda kepadaku: \"Apakah kamu mau aku ruqyah dengan ruqyah yang telah di ajarkan Jibril kepadaku?\" aku lalu menjawab, \"Demi ayah dan Ibuku, tentu ya Rasulullah.\" Beliau lantas membaca: 'BISMILLAHI URQIIKA WALLAHU YASYFIIKA MIN KULLI DA`IN YU`DZIIKA WA MIN SYARRINNAFFATSATI FIL 'UQADI WA MIN SYARRI HAASIDIN IDZA HASAD (Dengan nama Allah aku meruqyahmu, dan Allah-lah yang menyembuhkanmu dari setiap penyakit yang menimpamu, dari setiap kejahatan wanita-wanita tukang sihir yang menghembus pada buhul-buhul, dan dari kejahatan pendengki bila ia dengki).' Beliau mengucapkannya hingga tiga kali.\""},"3481":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ بْنِ هِشَامٍ الْبَغْدَادِيُّ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا أَبُو عَامِرٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مِنْهَالٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَوِّذُ الْحَسَنَ وَالْحُسَيْنَ يَقُولُ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ كُلِّ شَيْطَانٍ وَهَامَّةٍ وَمِنْ كُلِّ عَيْنٍ لَامَّةٍ قَالَ وَكَانَ أَبُونَا إِبْرَاهِيمُ يُعَوِّذُ بِهَا إِسْمَعِيلَ وَإِسْحَقَ أَوْ قَالَ إِسْمَعِيلَ وَيَعْقُوبَوَهَذَا حَدِيثُ وَكِيعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman bin Hisyam Al Baghdadi] telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Khallad Al Bahili] telah menceritakan kepada kami [Abu 'Amir] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Minhal] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Nabi shallallahu 'alaihi wasallam memohon perlindungan untuk Hasan dan Husain dengan mengucapkan: \"U'ADZUKUMA BI KALIMATILLAH AT-TAAMMAH MIN KULLI SYAITHANIN WA HAAMMATIN WA MIN KULLI 'AININ LAAMMATIN (Aku memintakan perlindungan untuk kalian berdua dengan kalimat Allah yang sempurna, dari segala setan, binatang berbisa dan dari segala mata yang jahat/hasad) '. Kemudian beliau mengatakan: \"Bapak kami, Ibrahim, selalu memohonkan perlindungan untuk Isma'il dan Ishaq.\" Atau beliau mengatakan: \"Isma'il dan Ya'qub.\" Ini adalah hadits riwayatnya Waki'."},"3482":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا إِبْرَاهِيمُ الْأَشْهَلِيُّ عَنْ دَاوُدَ بْنِ حُصَيْنٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُهُمْ مِنْ الْحُمَّى وَمِنْ الْأَوْجَاعِ كُلِّهَا أَنْ يَقُولُوا بِسْمِ اللَّهِ الْكَبِيرِ أَعُوذُ بِاللَّهِ الْعَظِيمِ مِنْ شَرِّ عِرْقٍ نَعَّارٍ وَمِنْ شَرِّ حَرِّ النَّارِقَالَ أَبُو عَامِرٍ أَنَا أُخَالِفُ النَّاسَ فِي هَذَا أَقُولُ يَعَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ بْنِ أَبِي حَبِيبَةَ الْأَشْهَلِيُّ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَقَالَ مِنْ شَرِّ عِرْقٍ يَعَّارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Ibrahim Al Asyhali] dari [Daud bin Hushain] dari [Ikrimah] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam mengajarkan doa kepada para sahabat dari penyakit deman dan semua penyakit, agar mereka mengucapkan: 'BISMILLAHILKABIIR A'UUDZUBILLAHIL 'AZHIIM MIN SYARRI 'IRQIN NA'AR WA MIN SYARRIN NAAR (Dengan menyebut nama Allah yang Maha Besar, aku berlindung kepada Allah yang Maha Agung dari kejahatan penyakit na'ar (yang membangkang) dan dari kejahatan panasnya neraka) '.\" [Abu 'Amir] berkata, \"Aku berbeda dengan orang-orang di dalam lafzad ini, menurutku, \"Ya'ar.\" Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah mengabarkan kepadaku [Ibrahim bin Ismail bin Abu Habibah Al Asyhali] dari [Dawud bin Al Hushain] dari [Ikrimah] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, dan beliau bersabda: \"Dari penyakit ya'ar.\""},"3483":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا أَبِي عَنْ ابْنِ ثَوْبَانَ عَنْ عُمَيْرٍ أَنَّهُ سَمِعَ جُنَادَةَ بْنَ أَبِي أُمَيَّةَ قَالَ سَمِعْتُ عُبَادَةَ بْنَ الصَّامِتِ يَقُولُأَتَى جِبْرَائِيلُ عَلَيْهِ السَّلَام النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُوعَكُ فَقَالَ بِسْمِ اللَّهِ أَرْقِيكَ مِنْ كُلِّ شَيْءٍ يُؤْذِيكَ مِنْ حَسَدِ حَاسِدٍ وَمِنْ كُلِّ عَيْنٍ اللَّهُ يَشْفِيكَ","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] telah menceritakan kepada kami [Ayahku] dari [Ibnu Tsauban] dari [Umair] bahwa dia mendengar [Junadah bin Abu Umayyah] berkata; saya mendengar ['Ubadah bin As Shamit] berkata, \"Jibril 'Alaihis salam datang kepada Nabi shallallahu 'alaihi wasallam saat beliau sedang sakit panas, lalu Jibril membaca: 'BISMILLAHI ARQIIKA MIN KULLI SYAI`IN YU`DZIIKA WA MIN HASADI HAASIDIN WA MIN KULLI 'AININ ALLAHU YUSYFIIKA BISMILLAH ARQIIKA (Dengan nama Allah aku meruqyahmu dari segala sesuatu yang membuatmu sakit, dari setiap kedengkian pendengki dan dari setiap penyakit 'ain semoga Allah menyembuhkanmu) '.\""},"3484":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْفُثُ فِي الرُّقْيَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Maimun Ar Raqqi] dan [Sahl bin Abu Shal] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Malik bin Anas] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam meniupkan udara saat meruqyah.\""},"3485":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ قَالَ حَدَّثَنَا مَعْنُ بْنُ عِيسَى ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا بِشْرُ بْنُ عُمَرَ قَالَا حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اشْتَكَى يَقْرَأُ عَلَى نَفْسِهِ بِالْمُعَوِّذَاتِ وَيَنْفُثُ فَلَمَّا اشْتَدَّ وَجَعُهُ كُنْتُ أَقْرَأُ عَلَيْهِ وَأَمْسَحُ بِيَدِهِ رَجَاءَ بَرَكَتِهَا","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] dia berkata; telah menceritakan kepada kami [Ma'n bin Isa]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Bisyr bin Umar] keduanya berkata; telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah], bahwa jika Nabi shallallahu 'alaihi wasallam menderita sakit, maka beliau membaca do'a untuk perlindungan bagi dirinya dan meniupkan udara, ketika sakitnya semakin parah, maka sayalah yang membaca untuk beliau dan mengusapkan dengan tangan beliau mengharap keberkahan.\""},"3486":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الرَّقِّيُّ حَدَّثَنَا مُعَمَّرُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بِشْرٍ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ ابْنِ أُخْتِ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ عَنْ زَيْنَبَ قَالَتْكَانَتْ عَجُوزٌ تَدْخُلُ عَلَيْنَا تَرْقِي مِنْ الْحُمْرَةِ وَكَانَ لَنَا سَرِيرٌ طَوِيلُ الْقَوَائِمِ وَكَانَ عَبْدُ اللَّهِ إِذَا دَخَلَ تَنَحْنَحَ وَصَوَّتَ فَدَخَلَ يَوْمًا فَلَمَّا سَمِعَتْ صَوْتَهُ احْتَجَبَتْ مِنْهُ فَجَاءَ فَجَلَسَ إِلَى جَانِبِي فَمَسَّنِي فَوَجَدَ مَسَّ خَيْطٍ فَقَالَ مَا هَذَا فَقُلْتُ رُقًى لِي فِيهِ مِنْ الْحُمْرَةِ فَجَذَبَهُ وَقَطَعَهُ فَرَمَى بِهِ وَقَالَ لَقَدْ أَصْبَحَ آلُ عَبْدِ اللَّهِ أَغْنِيَاءَ عَنْ الشِّرْكِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الرُّقَى وَالتَّمَائِمَ وَالتِّوَلَةَ شِرْكٌ قُلْتُ فَإِنِّي خَرَجْتُ يَوْمًا فَأَبْصَرَنِي فُلَانٌ فَدَمَعَتْ عَيْنِي الَّتِي تَلِيهِ فَإِذَا رَقَيْتُهَا سَكَنَتْ دَمْعَتُهَا وَإِذَا تَرَكْتُهَا دَمَعَتْ قَالَ ذَاكِ الشَّيْطَانُ إِذَا أَطَعْتِهِ تَرَكَكِ وَإِذَا عَصَيْتِهِ طَعَنَ بِإِصْبَعِهِ فِي عَيْنِكِ وَلَكِنْ لَوْ فَعَلْتِ كَمَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ خَيْرًا لَكِ وَأَجْدَرَ أَنْ تُشْفَيْنَ تَنْضَحِينَ فِي عَيْنِكِ الْمَاءَ وَتَقُولِينَ أَذْهِبْ الْبَاسْ رَبَّ النَّاسْ اشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا","id":"Telah menceritakan kepada kami [Ayyub bin Muhammad Ar Raqi] telah menceritakan kepada kami [Mu'ammar bin Sulaiman] telah menceritakan kepada kami [Abdullah bin Bisyr] dari [Al A'masy] dari ['Amru bin Murrah] dari [Yahya bin Al Jazzar] dari puteri saudarinya [Zainab] isterinya Abdullah, dari [Zainab] dia berkata, \"Seorang wanita tua menemui kami hendak menjampi-jampi dari penyakit demam. Dan kami memiliki dipan yang panjang kaki-kakinya, dan apabila Abdullah hendak masuk maka ia akan berdehem dan bersuara. Suatu hari ia masuk, ketika wanita tua itu mendengar suaranya, maka ia bersembunyi. Kemudian Abdullah datang dan duduk di sampingku dan membelaiku, ternyata ia menyentuh suatu jahitan benang, maka dia berkata, 'Apa ini? ' aku lalu menjawab, 'Jimat, di dalamnya terdapat jampi-jampiku untuk pengobatan penyakit demam.\" [Abdullah] lalu menariknya dengan paksa, kemudian ia putus dan membuangnya seraya berkata, \"Sungguh saat ini keluarga Abdullah telah melakukan praktek kesyirikkan, saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jampi-jampi, jimat dan pelet adalah syirik.\" Aku berkata, \"Suatu hari aku keluar, lantas si fulan memandangiku hingga mataku selalu berair, jika mataku di jampi maka air matanya akan berhenti, namun jika tidak di jampi maka ia akan selalu berair.\" Abdullah berkata, \"Itu adalah (perbuatan) setan, jika kamu mentaatinya maka setan akan meninggalkanmu, tapi jika kamu tidak mentaatinya maka ia akan menusuk matamu dengan jari-jarinya. Akan tetapi sekiranya kamu melakukan apa yang pernah di lakukan oleh Rasulullah shallallahu 'alaihi wasallam maka itu akan lebih baik bagimu dan lebih layak mendapatkan kesembuhan, kamu mengguyur kedua matamu dengan air sambil membaca: 'ADZHIBIL BA`SA RABBANNASI ISYFI ANTA SYAAFI LAA SYIFAA`A ILLA SYIFAA`UKA SYIFAA`AN LAA YUGHAADIRU SAQAMA (Hilangkanlah kesusahan, wahai Rabb manusia, sembuhkanlah. Sebab Engkaulah Maha penyembuh, yang tidak ada kesembuhan melainkan kesembuhan dari-Mu, kesembuhan yang tidak meninggalkan rasa sakit) '.\""},"3487":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ أَبِي الْخَصِيبِ حَدَّثَنَا وَكِيعٌ عَنْ مُبَارَكٍ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا فِي يَدِهِ حَلْقَةٌ مِنْ صُفْرٍ فَقَالَ مَا هَذِهِ الْحَلْقَةُ قَالَ هَذِهِ مِنْ الْوَاهِنَةِ قَالَ انْزِعْهَا فَإِنَّهَا لَا تَزِيدُكَ إِلَّا وَهْنًا","id":"Telah menceritakan kepada kami [Ali bin Abu Al Khashib] telah menceritakan kepada kami [Waki'] dari [Mubarak] dari [Al Hasan] dari ['Imran bin Al Hushain], bahwa Nabi shallallahu 'alaihi wasallam melihat gelang dari kuningan di tangan seorang laki-laki, maka beliau bertanya: \"Apakah maksud dari gelang ini?\" laki-laki itu menjawab, \"Ini adalah wahinah.\" Beliau bersabda: \"Lepaslah, karena jimat itu tidak akan menambahmu melainkan kesengsaraan.\" "},"3488":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّ جُنْدُبٍ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى جَمْرَةَ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي يَوْمَ النَّحْرِ ثُمَّ انْصَرَفَ وَتَبِعَتْهُ امْرَأَةٌ مِنْ خَثْعَمٍ وَمَعَهَا صَبِيٌّ لَهَا بِهِ بَلَاءٌ لَا يَتَكَلَّمُ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ هَذَا ابْنِي وَبَقِيَّةُ أَهْلِي وَإِنَّ بِهِ بَلَاءً لَا يَتَكَلَّمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْتُونِي بِشَيْءٍ مِنْ مَاءٍ فَأُتِيَ بِمَاءٍ فَغَسَلَ يَدَيْهِ وَمَضْمَضَ فَاهُ ثُمَّ أَعْطَاهَا فَقَالَ اسْقِيهِ مِنْهُ وَصُبِّي عَلَيْهِ مِنْهُ وَاسْتَشْفِي اللَّهَ لَهُ قَالَتْ فَلَقِيتُ الْمَرْأَةَ فَقُلْتُ لَوْ وَهَبْتِ لِي مِنْهُ فَقَالَتْ إِنَّمَا هُوَ لِهَذَا الْمُبْتَلَى قَالَتْ فَلَقِيتُ الْمَرْأَةَ مِنْ الْحَوْلِ فَسَأَلْتُهَا عَنْ الْغُلَامِ فَقَالَتْ بَرَأَ وَعَقَلَ عَقْلًا لَيْسَ كَعُقُولِ النَّاسِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Yazid bin Abu Ziyad] dari [Sulaiman bin 'Amru Al Ahwash] dari [Ummu Jundab] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam melempar jumrah aqabah dari tengah lembah pada hari Idul Adlha (hari penyembelihan) kemudian pergi, sedangkan seorang wanita dari Khats'am bersama bayinya yang menderita sakit tuna wicara mengikuti beliau, wanita itu berkata, \"Wahai Rasulullah, ini adalah anakku dan keluargaku yang masih tersisa, dia menderita sakit tuna wicara.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikanlah air untukku.\" Lantas di bawakanlah air untuk beliau, beliau lalu mencuci kedua tangannya dan berkumur-kumur, kemudian beliau memberikan kepada wanita itu seraya bersabda: \"Berilah ia minum dan tuangkanlah kepadanya sambil meminta kesembuhan kepada Allah.\" Ummu Jundub berkata, \"Maka aku menjumpai wanita itu dan berkata, \"Jika berkenan, berikanlah kepadaku sedikit darinya?\" Dia menjawab, \"Air ini hanya untuk orang yang tertimpa musibah seperti ini.\" Ummu Jundub berkata, \"Kemudian aku bertemu lagi setelah lewat satu tahun dan aku menanyakan perihal anaknya, maka dia menjawab, \"Ia telah sembuh dan cerdas akalnya, tidak seperti kecerdasan otak orang yang lain.\""},"3489":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ ذِي الطُّفْيَتَيْنِ فَإِنَّهُ يَلْتَمِسُ الْبَصَرَ وَيُصِيبُ الْحَبَلَ يَعْنِي حَيَّةً خَبِيثَةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk membunuh ular Dzuth thufain (ular yang punggungnya terdapat dua garis putih), sebab ia dapat membutakan pandangan mata dan membahayakan kandungan, yaitu ular yang sangat berbahaya.\""},"3490":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْتُلُوا الْحَيَّاتِ وَاقْتُلُوا ذَا الطُّفْيَتَيْنِ وَالْأَبْتَرَ فَإِنَّهُمَا يَلْتَمِسَانِ الْبَصَرَ وَيُسْقِطَانِ الْحَبَلَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bunuhlah ular, bunuhlah Dzuth thufain (ular yang punggungnya terdapat dua garis putih) dan al Abtar (sejenis ular yang berekor pendek atau terpotong), karena keduanya dapat merusak pandangan mata dan menggugurkan kandungan.\""},"3491":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ الْفَأْلُ الْحَسَنُ وَيَكْرَهُ الطِّيَرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyukai ucapan yang baik dan membenci thiyarah (menganggap sial ketika melihat burung atau yang semisalnya).\""},"3492":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَدْوَى وَلَا طِيَرَةَ وَأُحِبُّ الْفَأْلَ الصَّالِحَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"\"Tidak ada 'Adwa dan Thiyarah, namun yang aku sukai adalah ucapan yang bagus.\" "},"3493":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلَمَةَ عَنْ عِيسَى بْنِ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطِّيَرَةُ شِرْكٌ وَمَا مِنَّا إِلَّا وَلَكِنَّ اللَّهَ يُذْهِبُهُ بِالتَّوَكُّلِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Salamah] dari [Isa bin 'Ashim] dari [Zirr] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Thiyarah adalah perbuatan syirik, dan hal itu hanyalah prasangka kita, akan tetapi Allah akan menghilangkan dengan tawakkal.\" "},"3494":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَدْوَى وَلَا طِيَرَةَ وَلَا هَامَةَ وَلَا صَفَرَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari ['Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'Adwa, Thiyarah, Hammah dan juga Shafar.\" "},"3495":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أَبِي جَنَابٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَدْوَى وَلَا طِيَرَةَ وَلَا هَامَةَ فَقَامَ إِلَيْهِ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ الْبَعِيرُ يَكُونُ بِهِ الْجَرَبُ فَتَجْرَبُ بِهِ الْإِبِلُ قَالَ ذَلِكَ الْقَدَرُ فَمَنْ أَجْرَبَ الْأَوَّلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Abu Janab] dari [Ayahnya] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'Adwa, tidak ada Thiyarah dan tidak ada Hammah.\" Lalu ada salah seorang laki-laki berdiri menghampiri beliau sambil berkata, 'Wahai Rasulullah, unta betina telah menderita penyakit gatal, lalu ia menularkan kepada yang lain?\" Beliau menjawab: \"Itu adalah takdir, lalu siapakah yang pertama kali menciptakan penyakit gatal?\" "},"3496":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُورِدُ الْمُمْرِضُ عَلَى الْمُصِحِّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang sakit tidak akan menularkan penyakit kepada orang yang sehat.\""},"3497":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ وَمُجَاهِدُ بْنُ مُوسَى وَمُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ قَالُوا حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُفَضَّلُ بْنُ فَضَالَةَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِ رَجُلٍ مَجْذُومٍ فَأَدْخَلَهَا مَعَهُ فِي الْقَصْعَةِ ثُمَّ قَالَ كُلْ ثِقَةً بِاللَّهِ وَتَوَكُّلًا عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Abu Bakr] dan [Mujahid bin Musa] dan [Muhammad bin Khalaf Al 'Asqalani] mereka berkata; telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Mufadldlal bin Fadlalah] dari [Habib bin As Syahid] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam memegang tangan seorang yang terkena lepra, kemudian beliau memasukkan tangannya bersama tangan laki-laki tersebut ke suatu mangkuk, kemudian beliau bersabda: \"Makanlah dengan percaya dan tawakkal kepada Allah.\""},"3498":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ ابْنِ أَبِي الزِّنَادِ ح و حَدَّثَنَا عَلِيُّ بْنُ أَبِي الْخَصِيبِ حَدَّثَنَا وَكِيعٌ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ جَمِيعًا عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عُثْمَانَ عَنْ أُمِّهِ فَاطِمَةَ بِنْتِ الْحُسَيْنِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُدِيمُوا النَّظَرَ إِلَى الْمَجْذُومِينَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Abdullah bin Nafi'] dari [Ibnu Az Zinnad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ali bin Abu Al Khashib] telah menceritakan kepada kami [Waki'] dari [Abdullah bin Sa'id bin Abu Hind] semuanya dari [Muhammad bin Abdullah bin 'Amru bin 'Utsman] dari ibunya [Fatimah binti Al Husain] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah berlama-lama memandangi orang yang terkena penyakit lepra.\""},"3499":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ رَجُلٍ مِنْ آلِ الشَّرِيدِ يُقَالُ لَهُ عَمْرٌو عَنْ أَبِيهِ قَالَكَانَ فِي وَفْدِ ثَقِيفٍ رَجُلٌ مَجْذُومٌ فَأَرْسَلَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ فَقَدْ بَايَعْنَاكَ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Husyaim] dari [Ya'la bin 'Atha] dari seorang laki-laki dari keluarga As Syarid yang bernama ['Amru] dari [Ayahnya] dia berkata, \"Di antara utusan Tsaqif ada seseorang yang menderita sakit lepra, maka Nabi shallallahu 'alaihi wasallam mengutus utusan untuk menyampaikan: \"Kembalilah pulang, sesungguhnya kami telah membai'atmu.\""},"3500":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسَحَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَهُودِيٌّ مِنْ يَهُودِ بَنِي زُرَيْقٍ يُقَالُ لَهُ لَبِيدُ بْنُ الْأَعْصَمِ حَتَّى كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَيَّلُ إِلَيْهِ أَنَّهُ يَفْعَلُ الشَّيْءَ وَلَا يَفْعَلُهُ قَالَتْ حَتَّى إِذَا كَانَ ذَاتَ يَوْمٍ أَوْ كَانَ ذَاتَ لَيْلَةٍ دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ دَعَا ثُمَّ دَعَا ثُمَّ قَالَ يَا عَائِشَةُ أَشَعَرْتِ أَنَّ اللَّهَ قَدْ أَفْتَانِي فِيمَا اسْتَفْتَيْتُهُ فِيهِ جَاءَنِي رَجُلَانِ فَجَلَسَ أَحَدُهُمَا عِنْدَ رَأْسِي وَالْآخَرُ عِنْدَ رِجْلِي فَقَالَ الَّذِي عِنْدَ رَأْسِي لِلَّذِي عِنْدَ رِجْلِي أَوْ الَّذِي عِنْدَ رِجْلِي لِلَّذِي عِنْدَ رَأْسِي مَا وَجَعُ الرَّجُلِ قَالَ مَطْبُوبٌ قَالَ مَنْ طَبَّهُ قَالَ لَبِيدُ بْنُ الْأَعْصَمِ قَالَ فِي أَيِّ شَيْءٍ قَالَ فِي مُشْطٍ وَمُشَاطَةٍ وَجُفِّ طَلْعَةِ ذَكَرٍ قَالَ وَأَيْنَ هُوَ قَالَ فِي بِئْرِ ذِي أَرْوَانَ قَالَتْ فَأَتَاهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُنَاسٍ مِنْ أَصْحَابِهِ ثُمَّ جَاءَ فَقَالَ وَاللَّهِ يَا عَائِشَةُ لَكَأَنَّ مَاءَهَا نُقَاعَةُ الْحِنَّاءِ وَلَكَأَنَّ نَخْلَهَا رُءُوسُ الشَّيَاطِينِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ أَفَلَا أَحْرَقْتَهُ قَالَ لَا أَمَّا أَنَا فَقَدْ عَافَانِي اللَّهُ وَكَرِهْتُ أَنْ أُثِيرَ عَلَى النَّاسِ مِنْهُ شَرًّا فَأَمَرَ بِهَا فَدُفِنَتْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dari [Hisyam] dari [Ayahnya] dari [Aisyah] dia berkata, \"Seorang Yahudi dari Bani Zuraiq yang bernama Labid bin Al A'sham telah menyishir Rasulullah shallallahu 'alaihi wasallam, sehingga Nabi shallallahu 'alaihi wasallam pun di buat seakan-akan telah melakukan sesuatu pekerjaan yang beliau tidak kerjakan.\" Aisyah melanjutkan, \"Sampai di suatu hari -atau suatu malam-, Rasulullah shallallahu 'alaihi wasallam berdo'a, berdo'a dan berdo'a, kemudian beliau bersabda: \"Wahai Aisyah, apakah kamu telah merasakan bahwa Allah telah memberikan fatwa (menghukumi) dengan apa yang telah aku fatwakan (hukumi)? Dua orang laki-laki telah datang kepadaku, lalu salah seorang dari keduanya duduk di atas kepalaku dan satunya lagi di kakiku. Kemudian orang yang berada di kepalaku berkata kepada orang yang berada di kakiku, atau orang yang berada di kakiku berkata kepada orang yang berada di kepalaku; \"Menderita sakit apakah laki-laki ini?\" dia (salah seorang malaikat yang berada di kaki beliau atau kepala beliau) berkata, 'Terkena sihir.' Lalu salah satunya bertanya, 'Siapakah yang menyihirnya? ' dia menjawab, 'Labid bin Al A'sham.' Dia bertanya lagi, 'Dengan benda apakah dia menyishir? ' dia menjawab, 'Dengan rambut yang terjatuh ketika di sisir dan sebatang mayang kurma.\" Dia bertanya lagi, \"Di manakah benda itu diletakkan?\" dia menjawab, \"Di dalam sumur milik Dzu Arwan.' Aisyah berkata, \"Kemudian Nabi shallallahu 'alaihi wasallam mendatanginya bersama beberapa orang sahabatnya, lantas bersabda: \"Demi Allah, wahai Aisyah seakan-akan airnya berubah bagaikan rendaman pohon inai dan seakan-akan pohon kurmanya bagaikan kepada setan.\" Aisyah berkata, \"Aku bertanya, \"Wahai Rasulullah, apakah anda membakarnya?\" beliau menjawab: \"Tidak, sesungguhnya Allah telah menyembuhkanku dan aku hanya tidak suka memberikan kesan buruk kepada orang lain dari peristiwa itu.\" Kemudian beliau memerintahkan seseorang membawanya (barang yang di pakai untuk menyihir) lalu menguburnya.\""}};
